def normalize_markdown_text(markdown_content: str) -> str:
    text = markdown_content.replace("\r\n", "\n")
    text = re.sub(r"```.*?```", " ", text, flags=re.S)
    text = re.sub(r"`([^`]*)`", r"\1", text)
    text = re.sub(r"!\[[^\]]*\]\([^)]+\)", " ", text)
    text = re.sub(r"\[([^\]]+)\]\([^)]+\)", r"\1", text)
    text = re.sub(r"^#{1,6}\s*", "", text, flags=re.M)
    text = re.sub(r"^\s*[-*+]\s+", "", text, flags=re.M)
    text = re.sub(r"^\s*\d+\.\s+", "", text, flags=re.M)
    text = re.sub(r"[>*_~#|-]", " ", text)
    text = re.sub(r"\n{3,}", "\n\n", text)
    text = re.sub(r"[ \t]{2,}", " ", text)
    return text.strip()


def summarize_markdown_document(title: str, normalized_text: str) -> str:
    clean = normalized_text.strip()
    if not clean:
        return f"{title}当前还没有可用内容，请重新上传完整 Markdown 文档。"
    paragraphs = [segment.strip() for segment in re.split(r"\n{2,}", clean) if segment.strip()]
    lead = paragraphs[0] if paragraphs else clean
    detail = paragraphs[1] if len(paragraphs) > 1 else ""
    summary = lead[:160]
    if detail:
        summary = f"{summary} {detail[:120]}".strip()
    if len(summary) < 80 and len(clean) > len(summary):
        summary = f"{summary} {clean[len(summary):len(summary) + 120]}".strip()
    return summary[:320]


def normalize_configured_cloud_api_url(raw_url: str | None) -> str:
    value = (raw_url or "").strip().rstrip("/")
    if not value:
        return ""
    normalized_value = value if re.match(r"^https?://", value, flags=re.I) else f"http://{value}"
    parsed = urlparse(normalized_value)
    if parsed.scheme not in {"http", "https"} or not parsed.netloc or re.search(r"\s", parsed.netloc):
        raise ValueError("云端服务地址必须是有效的公网 IP 或域名")
    return normalized_value


def resolve_initial_cloud_api_url(db: Database) -> str:
    raw_env_url = os.environ.get("YIYU_CLOUD_API_URL")
    raw_url = raw_env_url if raw_env_url is not None else db.get_setting("cloud_api_url", "")
    try:
        return normalize_configured_cloud_api_url(raw_url)
    except ValueError as exc:
        logging.getLogger(__name__).warning("Invalid cloud API URL ignored: %s", exc)
        return ""


