def create_pre_migration_backup(data_dir: Path, db_path: Path) -> Path | None:
    if not db_path.exists():
        return None
    conn: sqlite3.Connection | None = None
    try:
        conn = sqlite3.connect(db_path)
        schema_version = int(conn.execute("PRAGMA user_version").fetchone()[0] or 0)
        tag_columns = {
            str(row[1])
            for row in conn.execute("PRAGMA table_info(task_tags)").fetchall()
        }
        needs_migration = schema_version < BACKEND_SCHEMA_VERSION or "operator_id" not in tag_columns
        if not needs_migration:
            return None
    except Exception:
        # 无法安全判定时，保守地先备份。
        pass
    finally:
        if conn is not None:
            conn.close()
    backup_dir = data_dir / "backups" / "migrations"
    backup_dir.mkdir(parents=True, exist_ok=True)
    stamp = datetime.now().strftime("%Y%m%d-%H%M%S")
    backup_path = backup_dir / f"app-pre-migrate-{stamp}.db"
    shutil.copy2(db_path, backup_path)
    for suffix in ("-wal", "-shm"):
        shadow = db_path.with_name(f"{db_path.name}{suffix}")
        if shadow.exists():
            shutil.copy2(shadow, backup_dir / f"{backup_path.name}{suffix}")
    return backup_path


def rollback_database_from_backup(db_path: Path, backup_path: Path | None) -> None:
    if not backup_path or not backup_path.exists():
        return
    for suffix in ("", "-wal", "-shm"):
        target = db_path if not suffix else db_path.with_name(f"{db_path.name}{suffix}")
        if target.exists():
            target.unlink()
    shutil.copy2(backup_path, db_path)
    backup_dir = backup_path.parent
    for suffix in ("-wal", "-shm"):
        shadow_backup = backup_dir / f"{backup_path.name}{suffix}"
        if shadow_backup.exists():
            shutil.copy2(shadow_backup, db_path.with_name(f"{db_path.name}{suffix}"))


def init_database_with_migration_guard(data_dir: Path) -> tuple[Database, Path | None]:
    db_path = data_dir / "app.db"
    backup_path = create_pre_migration_backup(data_dir, db_path)
    try:
        return Database(db_path), backup_path
    except Exception:
        rollback_database_from_backup(db_path, backup_path)
        raise


def create_app(data_dir: Path | None = None) -> FastAPI:
    resolved_data_dir = data_dir or Path(
        os.getenv("YIYU_WORKBENCH_DATA_DIR") or (Path.home() / "Library" / "Application Support" / "YiyuThinkTankWorkbench")
    )
    resolved_data_dir.mkdir(parents=True, exist_ok=True)
    try:
        db, migration_backup_path = init_database_with_migration_guard(resolved_data_dir)
    except Exception as error:
        raise RuntimeError(f"数据库迁移失败，已回滚并阻断启动：{error}") from error
    def build_secret_store(service_name: str, account_name: str = "default"):
        try:
            store = MacOSKeychainSecretStore(service_name=service_name, account_name=account_name)
            store.get_api_key()
            return store
        except Exception:
            return MemorySecretStore()

    openai_compatible_store = build_secret_store("com.yiyu.self-workbench.openai-compatible")
    qwen_store = build_secret_store("com.yiyu.self-workbench.qwen")
    doubao_store = build_secret_store("com.yiyu.self-workbench.doubao")
    online_primary_store = build_secret_store("com.yiyu.self-workbench.ai-profile.online-primary")
    local_text_deep_store = build_secret_store("com.yiyu.self-workbench.ai-profile.local-text-deep")
    local_vision_ocr_store = build_secret_store("com.yiyu.self-workbench.ai-profile.local-vision-ocr")
    local_fast_store = build_secret_store("com.yiyu.self-workbench.ai-profile.local-fast")
    feishu_secret_store = build_secret_store("com.yiyu.self-workbench.feishu")
    ai = AiService(
        db,
        {
            OPENAI_COMPATIBLE_PROVIDER: openai_compatible_store,
            "qwen": qwen_store,
            "doubao": doubao_store,
            "ai_profile:online_primary": online_primary_store,
            "ai_profile:local_text_deep": local_text_deep_store,
            "ai_profile:local_vision_ocr": local_vision_ocr_store,
            "ai_profile:local_fast": local_fast_store,
        },
    )
    backup_dir = resolved_data_dir / "backups"
    state = AppState(
        data_dir=resolved_data_dir,
        backup_dir=backup_dir,
        db=db,
        ai=ai,
        feishu_secret_store=feishu_secret_store,
        cloud_api_url=resolve_initial_cloud_api_url(db),
        job_stop=Event(),
        topic_insight_executor=ThreadPoolExecutor(max_workers=3),
        chat_answer_executor=ThreadPoolExecutor(max_workers=2),
        template_fill_executor=ThreadPoolExecutor(max_workers=1),
        link_material_executor=ThreadPoolExecutor(max_workers=1),
    )
    state.system_logger = _SystemLogger(resolved_data_dir / "logs")
    state.system_logger.info("system", f"后端启动: data_dir={resolved_data_dir}")
    state.system_logger.info(
        "system",
        (
            f"后端指纹: runtime_mode={BACKEND_RUNTIME_MODE}, "
            f"build_hash={BACKEND_BUILD_HASH}, schema={state.db.get_schema_version()}/{BACKEND_SCHEMA_VERSION}, "
            f"migration_backup={str(migration_backup_path) if migration_backup_path else 'none'}"
        ),
    )
    workspace_chat_start_locks_guard = Lock()
    workspace_chat_start_locks: dict[str, Lock] = {}

    def workspace_chat_start_lock_for_client(client_id: str) -> Lock:
        lock_key = str(client_id or "").strip() or "__unknown_client__"
        with workspace_chat_start_locks_guard:
            lock = workspace_chat_start_locks.get(lock_key)
            if lock is None:
                lock = Lock()
                workspace_chat_start_locks[lock_key] = lock
            return lock

    def cloud_api_base_url() -> str:
        base_url = (state.cloud_api_url or "").strip().rstrip("/")
        if not base_url:
            raise HTTPException(status_code=503, detail="尚未配置云端服务地址，请先在设置页填写云端服务地址。")
        return base_url

    seed_defaults(state)
    state.db.set_setting("runtime.build_version", APP_BUILD_VERSION)
    state.db.set_setting("runtime.git_commit", APP_GIT_COMMIT or "")
    state.db.set_setting("runtime.backend_build_hash", BACKEND_BUILD_HASH)
    state.db.set_setting("runtime.backend_root", str(Path(__file__).resolve().parents[1]))
    state.db.set_setting("runtime.mode", BACKEND_RUNTIME_MODE)
    state.db.set_setting("runtime.data_dir", str(resolved_data_dir))
    if state.db.get_setting("demo_data_loaded", "0") != "1":
        clear_demo_dataset(state)
    ensure_data_center_schema(state.db)
    purge_private_task_ingest_events(state.db)

    app = FastAPI(title=APP_NAME, version=APP_VERSION)
    app.state.app_state = state

    # 迭代 2 F3：把版本查找回调注入 data_center_kernel，让 _to_search_hit
    # 能给前端塞版本徽章信息（"v2 · 最新" / "已被 v3 取代"）。
    def _lookup_version_info_for_kernel(document_id: str) -> dict[str, object]:
        row = state.db.fetchone(
            "SELECT version_chain_id, version_number, lifecycle_status "
            "FROM knowledge_documents WHERE document_id = ?",
            (document_id,),
        )
        if not row:
            return {}
        chain_id = str(row["version_chain_id"] or "")
        chain_total = 1
        if chain_id:
            count_row = state.db.fetchone(
                "SELECT COUNT(1) AS n FROM knowledge_documents WHERE version_chain_id = ?",
                (chain_id,),
            )
            if count_row:
                chain_total = int(count_row["n"] or 1)
        return {
            "versionNumber": int(row["version_number"] or 1),
            "versionChainId": chain_id or None,
            "lifecycleStatus": str(row["lifecycle_status"] or "current"),
            "chainTotalVersions": chain_total,
        }

    set_version_info_lookup(_lookup_version_info_for_kernel)

    # 迭代 4：把"代表性语义类型"查找注入 data_center_kernel。
    # 每份文档的 chunks 可能跨多种语义类型，这里取"出现次数最多、置信度
    # 最高"的那一档作为 doc 级代表，给前端引证面板的类型徽章用。
    def _lookup_semantic_info_for_kernel(document_id: str) -> dict[str, object]:
        row = state.db.fetchone(
            """
            SELECT vc.semantic_type AS semantic_type,
                   AVG(vc.semantic_confidence) AS avg_conf,
                   COUNT(1) AS hit_count
            FROM v2_chunks vc
            JOIN v2_documents vd ON vd.id = vc.v2_document_id
            WHERE vd.document_id = ?
              AND vc.semantic_type IS NOT NULL
              AND vc.semantic_type != 'unclassified'
            GROUP BY vc.semantic_type
            ORDER BY hit_count DESC, avg_conf DESC
            LIMIT 1
            """,
            (document_id,),
        )
        if not row or not row["semantic_type"]:
            return {}
        return {
            "semanticType": str(row["semantic_type"]),
            "semanticConfidence": float(row["avg_conf"] or 0.0),
        }

    set_semantic_info_lookup(_lookup_semantic_info_for_kernel)

    def _safe_data_center_ingest(label: str, callback) -> None:
        try:
            callback()
        except Exception as exc:
            logger.warning("DataCenterIngest %s failed: %s", label, exc)

    def _safe_growth_ingest(label: str, callback) -> None:
        try:
            callback()
        except Exception as exc:
            logger.warning("GrowthIngest %s failed: %s", label, exc)

    app.add_middleware(
        CORSMiddleware,
        allow_origins=list(ALLOWED_LOCAL_ORIGINS),
        allow_origin_regex=ALLOWED_LOCAL_ORIGIN_REGEX,
        allow_credentials=True,
        allow_methods=["*"],
        allow_headers=["*"],
    )

    @app.exception_handler(Exception)
    async def _unhandled_exception_cors_safe(request: Request, exc: Exception):
        # starlette 的 BaseHTTPMiddleware 在异常路径会绕过 CORSMiddleware，
        # 导致 500 响应缺 Access-Control-Allow-Origin → 浏览器 fetch 抛
        # "Failed to fetch" 把真实错误盖住。这里全局兜底未捕获异常，手工补
        # CORS header，让前端能看到真正的错误信息。HTTPException 仍走 FastAPI
        # 默认 handler（它返回的 JSONResponse 经过正常 middleware 链，CORS 没问题）。
        if isinstance(exc, HTTPException):
            raise exc
        logger.exception("Unhandled exception in %s %s", request.method, request.url.path)
        response = JSONResponse(
            status_code=500,
            content={"detail": f"{exc.__class__.__name__}: {exc}"},
        )
        origin = request.headers.get("origin")
        if origin and is_allowed_local_origin(origin):
            response.headers["Access-Control-Allow-Origin"] = origin
            response.headers["Access-Control-Allow-Credentials"] = "true"
            response.headers["Vary"] = "Origin"
        return response

    @app.middleware("http")
    async def _local_browser_origin_guard(request: Request, call_next):
        rejection_reason = validate_local_browser_request(request.url.path, request.headers, request.method)
        if rejection_reason:
            return JSONResponse(status_code=403, content={"detail": rejection_reason})
        return await call_next(request)

    @app.middleware("http")
    async def _request_logging_middleware(request: Request, call_next):
        if not state.system_logger:
            return await call_next(request)
        path = request.url.path
        method = request.method
        # Skip logging for high-frequency/static endpoints
        if path.startswith("/api/public/") or path in ("/", "/favicon.ico"):
            return await call_next(request)
        start = time.perf_counter()
        error_msg = None
        error_tb = None
        status_code = 500
        try:
            response = await call_next(request)
            status_code = response.status_code
            return response
        except Exception as exc:
            error_msg = str(exc)
            error_tb = traceback.format_exc()
            raise
        finally:
            duration_ms = (time.perf_counter() - start) * 1000
            user = ""
            try:
                session_user = get_cached_session_user()
                if session_user:
                    user = session_user.fullName
            except Exception:
                pass
            state.system_logger.api_request(
                method=method,
                path=path,
                status=status_code,
                duration_ms=duration_ms,
                user=user,
                error_msg=error_msg,
                error_traceback=error_tb,
            )

    def _enqueue_workspace_refresh_safe(
        *,
        client_id: str | None,
        source_type: str,
        reason: str,
        source_id: str | None = None,
        scope_type: str = "client",
        scope_id: str | None = None,
        priority: Literal["low", "normal", "high"] = "normal",
    ) -> WorkspaceContextRefreshEventRecord | None:
        normalized_client_id = str(client_id or "").strip()
        if not normalized_client_id:
            return None
        try:
            event, _deduped = enqueue_workspace_context_refresh(
                state.db,
                client_id=normalized_client_id,
                source_type=source_type,
                source_id=source_id,
                reason=reason,
                scope_type=scope_type,
                scope_id=scope_id or (normalized_client_id if scope_type == "client" else source_id),
                priority=priority,
            )
            return event
        except Exception:
            return None

    def _resolve_client_id_for_scope_ref(
        *,
        scope_type: str | None,
        scope_id: str | None,
    ) -> str | None:
        normalized_scope_type = str(scope_type or "").strip().lower()
        normalized_scope_id = str(scope_id or "").strip()
        if not normalized_scope_id:
            return None
        if normalized_scope_type in {"", "client"}:
            return normalized_scope_id
        if normalized_scope_type == "task":
            row = state.db.fetchone(
                """
                SELECT client_id
                FROM tasks
                WHERE id = ?
                  AND COALESCE(scope_mode, 'COLLAB_SHARED') != 'PERSONAL_ONLY'
                """,
                (normalized_scope_id,),
            )
            return str(row["client_id"]) if row and row["client_id"] else None
        if normalized_scope_type == "meeting":
            row = state.db.fetchone("SELECT client_id FROM meetings WHERE id = ?", (normalized_scope_id,))
            return str(row["client_id"]) if row and row["client_id"] else None
        if normalized_scope_type == "event_line":
            row = state.db.fetchone("SELECT primary_client_id FROM event_lines WHERE id = ?", (normalized_scope_id,))
            return str(row["primary_client_id"]) if row and row["primary_client_id"] else None
        if normalized_scope_type == "project_module":
            row = state.db.fetchone("SELECT client_id FROM project_modules WHERE id = ?", (normalized_scope_id,))
            return str(row["client_id"]) if row and row["client_id"] else None
        if normalized_scope_type == "project_flow":
            row = state.db.fetchone("SELECT client_id FROM project_flows WHERE id = ?", (normalized_scope_id,))
            return str(row["client_id"]) if row and row["client_id"] else None
        if normalized_scope_type == "topic":
            # topic scope is global and may not bind to a client directly.
            # Do not infer client via topic_radars; that table has no client_id.
            return None
        return None

    def _resolve_client_id_for_evidence_quality_annotation(annotation: EvidenceQualityAnnotationRecord) -> str | None:
        if annotation.documentId:
            doc_row = state.db.fetchone("SELECT client_id FROM documents WHERE id = ?", (annotation.documentId,))
            if doc_row and doc_row["client_id"]:
                return str(doc_row["client_id"])
            v2_row = state.db.fetchone("SELECT client_id FROM v2_documents WHERE document_id = ? LIMIT 1", (annotation.documentId,))
            if v2_row and v2_row["client_id"]:
                return str(v2_row["client_id"])

        source_type = str(annotation.sourceType or "").strip().lower()
        source_id = str(annotation.sourceId or "").strip()
        if not source_id:
            return None
        if source_type in {"client", "client_workspace"}:
            return source_id
        if source_type in {"task", "task_attachment", "task_activity", "task_cloud_attachment"}:
            task_row = state.db.fetchone(
                """
                SELECT client_id
                FROM tasks
                WHERE id = ?
                  AND COALESCE(scope_mode, 'COLLAB_SHARED') != 'PERSONAL_ONLY'
                """,
                (source_id,),
            )
            if task_row and task_row["client_id"]:
                return str(task_row["client_id"])
            task_attachment_row = state.db.fetchone(
                "SELECT client_id FROM task_attachments WHERE id = ? LIMIT 1",
                (source_id,),
            )
            if task_attachment_row and task_attachment_row["client_id"]:
                return str(task_attachment_row["client_id"])
            task_attachment_cloud_row = state.db.fetchone(
                "SELECT client_id FROM task_attachments_cloud WHERE id = ? LIMIT 1",
                (source_id,),
            )
            if task_attachment_cloud_row and task_attachment_cloud_row["client_id"]:
                return str(task_attachment_cloud_row["client_id"])
            return None
        if source_type in {"meeting", "meeting_note", "meeting_decision", "meeting_action", "meeting_risk"}:
            meeting_row = state.db.fetchone("SELECT client_id FROM meetings WHERE id = ?", (source_id,))
            if meeting_row and meeting_row["client_id"]:
                return str(meeting_row["client_id"])
            decision_row = state.db.fetchone("SELECT meeting_id FROM decisions WHERE id = ?", (source_id,))
            if decision_row and decision_row["meeting_id"]:
                meeting_row = state.db.fetchone("SELECT client_id FROM meetings WHERE id = ?", (str(decision_row["meeting_id"]),))
                return str(meeting_row["client_id"]) if meeting_row and meeting_row["client_id"] else None
            action_row = state.db.fetchone("SELECT meeting_id FROM action_items WHERE id = ?", (source_id,))
            if action_row and action_row["meeting_id"]:
                meeting_row = state.db.fetchone("SELECT client_id FROM meetings WHERE id = ?", (str(action_row["meeting_id"]),))
                return str(meeting_row["client_id"]) if meeting_row and meeting_row["client_id"] else None
            risk_row = state.db.fetchone("SELECT meeting_id FROM risks WHERE id = ?", (source_id,))
            if risk_row and risk_row["meeting_id"]:
                meeting_row = state.db.fetchone("SELECT client_id FROM meetings WHERE id = ?", (str(risk_row["meeting_id"]),))
                return str(meeting_row["client_id"]) if meeting_row and meeting_row["client_id"] else None
            return None
        if source_type in {"judgment", "official_judgment", "candidate_judgment"}:
            row = state.db.fetchone("SELECT client_id FROM judgment_versions WHERE id = ?", (source_id,))
            return str(row["client_id"]) if row and row["client_id"] else None
        if source_type in {"topic_candidate", "topic"}:
            return _resolve_client_id_for_scope_ref(scope_type="topic", scope_id=source_id)
        if source_type in {"external_evidence_card"}:
            card_row = state.db.fetchone(
                """
                SELECT related_scope_type, related_scope_id
                FROM external_evidence_cards
                WHERE id = ?
                LIMIT 1
                """,
                (source_id,),
            )
            if not card_row:
                return None
            return _resolve_client_id_for_scope_ref(
                scope_type=str(card_row["related_scope_type"] or ""),
                scope_id=str(card_row["related_scope_id"] or ""),
            )
        if source_type in {"chat_message", "workspace_chat", "generated_answer", "memory_answer"}:
            row = state.db.fetchone(
                """
                SELECT t.client_id
                FROM chat_messages m
                LEFT JOIN chat_threads t ON t.id = m.thread_id
                WHERE m.id = ?
                LIMIT 1
                """,
                (source_id,),
            )
            return str(row["client_id"]) if row and row["client_id"] else None
        return None

    @app.on_event("startup")
    def _startup_worker() -> None:
        if os.getenv("YIYU_DISABLE_STARTUP_WORKERS", "0") == "1":
            return
        if state.job_thread and state.job_thread.is_alive():
            if state.analysis_job_thread and state.analysis_job_thread.is_alive():
                return
        recover_stale_knowledge_jobs()
        recover_stale_imports()
        recover_stale_template_fill_runs()
        recover_stale_loading_chat_messages()
        recover_stale_analysis_jobs(state.db)
        recover_stale_workspace_context_refresh_events(state.db)
        state.job_stop.clear()
        state.job_thread = Thread(target=knowledge_worker_loop, name="knowledge-worker", daemon=True)
        state.job_thread.start()
        state.analysis_job_thread = Thread(target=analysis_job_worker_loop, name="analysis-job-worker", daemon=True)
        state.analysis_job_thread.start()
        # Probe cloud backend connectivity at startup — clear circuit breaker if reachable
        if state.cloud_api_url and get_cloud_token():
            def _probe_cloud():
                import time as _time
                try:
                    httpx.get(f"{cloud_api_base_url()}/health", timeout=3.0)
                    _cloud_circuit_breaker["last_failure"] = 0.0  # cloud OK — clear breaker
                except Exception:
                    _cloud_circuit_breaker["last_failure"] = _time.time()  # cloud down — keep breaker
            Thread(target=_probe_cloud, name="cloud-probe", daemon=True).start()

    @app.on_event("shutdown")
    def _shutdown_worker() -> None:
        state.job_stop.set()
        if state.job_thread and state.job_thread.is_alive():
            state.job_thread.join(timeout=1.5)
        if state.analysis_job_thread and state.analysis_job_thread.is_alive():
            state.analysis_job_thread.join(timeout=1.5)
        if state.topic_insight_executor:
            state.topic_insight_executor.shutdown(wait=False, cancel_futures=False)
        if state.chat_answer_executor:
            state.chat_answer_executor.shutdown(wait=False, cancel_futures=False)
        if state.template_fill_executor:
            state.template_fill_executor.shutdown(wait=False, cancel_futures=False)
        if state.link_material_executor:
            state.link_material_executor.shutdown(wait=False, cancel_futures=False)

    def current_operator_row():
        operator_id = state.db.get_setting("current_operator_id", "")
        if operator_id:
            row = state.db.fetchone("SELECT * FROM operators WHERE id = ?", (operator_id,))
            if row:
                return row
        row = state.db.fetchone("SELECT * FROM operators ORDER BY created_at LIMIT 1")
        if not row:
            raise HTTPException(status_code=500, detail="No operator configured")
        state.db.set_setting("current_operator_id", str(row["id"]))
        state.db.execute("UPDATE operators SET is_current = CASE WHEN id = ? THEN 1 ELSE 0 END", (str(row["id"]),))
        return row

    def current_operator_name() -> str:
        row = current_operator_row()
        return str(row["name"]) if row and row["name"] else "系统"

    def _local_task_tag_record(row) -> TaskTagRecord:
        return TaskTagRecord(
            id=str(row["id"]),
            name=str(row["name"]),
            color=str(row["color"] or ("#9CA3AF" if str(row["scope"]) == "self" else "#5B7BFE")),
            scope=str(row["scope"]),
            ownerUserId=str(row["owner_operator_id"]) if str(row["owner_operator_id"]) else None,
            createdBy=str(row["created_by"]) if str(row["created_by"]) else None,
            updatedAt=str(row["updated_at"] or row["created_at"] or now_iso()),
            archivedAt=str(row["archived_at"]) if row["archived_at"] else None,
        )

    def _local_task_list_record(row) -> TaskListRecord:
        return TaskListRecord(
            id=str(row["id"]),
            name=str(row["name"]),
            color=str(row["color"]),
            sortOrder=int(row["sort_order"] or 0),
            isDefault=bool(int(row["is_default"] or 0)),
            scope=str(row["scope"] or "org"),
            archivedAt=str(row["archived_at"]) if row["archived_at"] else None,
        )

    def _is_task_settings_default_local_list_row(row) -> bool:
        if row is None:
            return False
        if row["archived_at"]:
            return False
        if str(row["scope"] or "org") != "org":
            return False
        normalized_name = " ".join(str(row["name"] or "").strip().split()).casefold()
        return str(row["id"]) == "list-0" or normalized_name in {"收集箱", "收件箱", "组织任务"}

    def _task_settings_default_local_destination_row():
        rows = state.db.fetchall(
            """
            SELECT *
            FROM task_lists
            WHERE scope = 'org' AND (archived_at IS NULL OR archived_at = '')
            ORDER BY sort_order ASC, name COLLATE NOCASE ASC, id ASC
            """
        )
        candidates = [row for row in rows if _is_task_settings_default_local_list_row(row)]
        if not candidates:
            return None
        return sorted(
            candidates,
            key=lambda row: (
                0 if str(row["id"]) == "list-0" else 1 if " ".join(str(row["name"] or "").strip().split()).casefold() in {"收集箱", "收件箱"} else 2,
                int(row["sort_order"] or 0),
                str(row["id"]),
            ),
        )[0]

    def _is_task_settings_default_local_list_id(list_id: str | None) -> bool:
        if not list_id:
            return False
        row = state.db.fetchone("SELECT * FROM task_lists WHERE id = ?", (list_id,))
        return _is_task_settings_default_local_list_row(row)

    def _local_default_list_id() -> str | None:
        default_row = _task_settings_default_local_destination_row()
        return str(default_row["id"]) if default_row else None

    def _default_local_task_settings() -> TaskSettingsRecord:
        return TaskSettingsRecord(
            defaultListId=_local_default_list_id(),
            defaultPriority="normal",
            defaultDueDatePreset="today",
            defaultViewMode="calendar",
            listSortMode="manual",
            showCompletedTasks=False,
            defaultReviewScope="work",
            autoAssignSelf=True,
            updatedAt=now_iso(),
        )

    def _local_task_settings_record(row) -> TaskSettingsRecord:
        defaults = _default_local_task_settings()
        stored_default_list_id = str(row["default_list_id"]) if row["default_list_id"] else None
        resolved_default_list_id = stored_default_list_id if _is_task_settings_default_local_list_id(stored_default_list_id) else defaults.defaultListId
        return TaskSettingsRecord(
            defaultListId=resolved_default_list_id,
            defaultPriority=str(row["default_priority"] or defaults.defaultPriority),  # type: ignore[arg-type]
            defaultDueDatePreset=str(row["default_due_date_preset"] or defaults.defaultDueDatePreset),  # type: ignore[arg-type]
            defaultViewMode=str(row["default_view_mode"] or defaults.defaultViewMode),  # type: ignore[arg-type]
            listSortMode=str(row["list_sort_mode"] or defaults.listSortMode),  # type: ignore[arg-type]
            showCompletedTasks=bool(int(row["show_completed_tasks"] or 0)),
            defaultReviewScope=str(row["default_review_scope"] or defaults.defaultReviewScope),  # type: ignore[arg-type]
            autoAssignSelf=bool(int(row["auto_assign_self"] if row["auto_assign_self"] is not None else 1)),
            updatedAt=str(row["updated_at"] or defaults.updatedAt),
        )

    def _get_local_task_settings(operator_id: str | None = None) -> TaskSettingsRecord:
        resolved_operator_id = operator_id or str(current_operator_row()["id"])
        row = state.db.fetchone("SELECT * FROM task_settings WHERE operator_id = ?", (resolved_operator_id,))
        if row:
            return _local_task_settings_record(row)
        defaults = _default_local_task_settings()
        state.db.execute(
            """
            INSERT OR REPLACE INTO task_settings(
                operator_id, default_list_id, default_priority, default_due_date_preset,
                default_view_mode, list_sort_mode, show_completed_tasks, default_review_scope,
                auto_assign_self, updated_at
            ) VALUES(?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                resolved_operator_id,
                defaults.defaultListId,
                defaults.defaultPriority,
                defaults.defaultDueDatePreset,
                defaults.defaultViewMode,
                defaults.listSortMode,
                1 if defaults.showCompletedTasks else 0,
                defaults.defaultReviewScope,
                1 if defaults.autoAssignSelf else 0,
                defaults.updatedAt,
            ),
        )
        return defaults

    def _visible_local_task_tag_rows(db: Database, operator_id: str) -> list:
        return db.fetchall(
            """
            SELECT *
            FROM task_tags
            WHERE scope = 'org' OR owner_operator_id = ?
            ORDER BY CASE WHEN archived_at IS NULL OR archived_at = '' THEN 0 ELSE 1 END,
                     CASE scope WHEN 'org' THEN 0 ELSE 1 END,
                     name COLLATE NOCASE ASC
            """,
            (operator_id,),
        )

    def _visible_local_task_tags(db: Database, operator_id: str) -> list[TaskTagRecord]:
        return [_local_task_tag_record(row) for row in _visible_local_task_tag_rows(db, operator_id)]

    def _local_tag_rows_by_ids(db: Database, tag_ids: list[str]) -> list:
        if not tag_ids:
            return []
        rows = db.fetchall(
            f"SELECT * FROM task_tags WHERE id IN ({_sql_placeholders(tag_ids)})",
            tuple(tag_ids),
        )
        by_id = {str(row["id"]): row for row in rows}
        return [by_id[tag_id] for tag_id in tag_ids if tag_id in by_id]

    def _ensure_local_tag(
        db: Database,
        operator_id: str,
        name: str,
        scope: str = "org",
        color: str | None = None,
        created_by: str | None = None,
    ) -> TaskTagRecord:
        trimmed = name.strip()
        if not trimmed:
            raise HTTPException(status_code=400, detail="Tag name is required")
        owner_operator_id = operator_id if scope == "self" else ""
        resolved_color = color or ("#9CA3AF" if scope == "self" else "#5B7BFE")
        resolved_creator = created_by or str(current_operator_row()["name"])
        existing = db.fetchone(
            "SELECT * FROM task_tags WHERE name = ? AND scope = ? AND owner_operator_id = ?",
            (trimmed, scope, owner_operator_id),
        )
        timestamp = now_iso()
        if existing:
            db.execute(
                """
                UPDATE task_tags
                SET color = COALESCE(NULLIF(?, ''), color),
                    archived_at = NULL,
                    updated_at = ?
                WHERE id = ?
                """,
                (resolved_color, timestamp, str(existing["id"])),
            )
            row = db.fetchone("SELECT * FROM task_tags WHERE id = ?", (str(existing["id"]),))
            if row:
                return _local_task_tag_record(row)
        tag_id = new_id("tag")
        db.execute(
            """
            INSERT INTO task_tags(
                id, name, color, scope, owner_operator_id, created_by, archived_at, created_at, updated_at
            ) VALUES(?, ?, ?, ?, ?, ?, NULL, ?, ?)
            """,
            (tag_id, trimmed, resolved_color, scope, owner_operator_id, resolved_creator, timestamp, timestamp),
        )
        row = db.fetchone("SELECT * FROM task_tags WHERE id = ?", (tag_id,))
        if not row:
            raise HTTPException(status_code=500, detail="Failed to create task tag")
        return _local_task_tag_record(row)

    def _resolve_local_task_tags(db: Database, operator_id: str, tag_ids: list[str], legacy_names: list[str]) -> list[TaskTagRecord]:
        rows = _local_tag_rows_by_ids(db, tag_ids)
        if rows:
            return [_local_task_tag_record(row) for row in rows]
        if not legacy_names:
            return []
        return [_ensure_local_tag(db, operator_id, name, "org") for name in legacy_names if name.strip()]

    def log_activity(action: str, entity_type: str, entity_id: str, detail: dict[str, object]) -> None:
        session_user = get_cached_session_user()
        actor_name = session_user.fullName if session_user else current_operator_row()["name"]
        state.db.execute(
            """
            INSERT INTO activity_logs(id, actor_name, action, entity_type, entity_id, detail_json, created_at)
            VALUES(?, ?, ?, ?, ?, ?, ?)
            """,
            (new_id("log"), actor_name, action, entity_type, entity_id, to_json(detail), now_iso()),
        )
        if state.system_logger:
            state.system_logger.activity(action, entity_type, entity_id, actor_name, detail)

    def append_knowledge_job_event(job_id: str, level: str, message: str, detail: dict[str, object] | None = None) -> None:
        state.db.execute(
            """
            INSERT INTO knowledge_job_events(id, job_id, level, message, detail_json, created_at)
            VALUES(?, ?, ?, ?, ?, ?)
            """,
            (new_id("kje"), job_id, level, message, to_json(detail or {}), now_iso()),
        )

    def enqueue_knowledge_job(client_id: str, job_type: str, payload: dict[str, object], total_items: int) -> KnowledgeJobRecord:
        job_id = new_id("kjob")
        timestamp = now_iso()
        state.db.execute(
            """
            INSERT INTO knowledge_jobs(
                id, client_id, job_type, status, payload_json, total_items, processed_items,
                last_error, created_at, started_at, finished_at, updated_at
            )
            VALUES(?, ?, ?, 'queued', ?, ?, 0, NULL, ?, NULL, NULL, ?)
            """,
            (job_id, client_id, job_type, to_json(payload), total_items, timestamp, timestamp),
        )
        append_knowledge_job_event(job_id, "info", "知识加工任务已入队", {"jobType": job_type, "totalItems": total_items})
        return KnowledgeJobRecord(
            id=job_id,
            clientId=client_id,
            jobType=job_type,
            status="queued",
            totalItems=total_items,
            processedItems=0,
            createdAt=timestamp,
            updatedAt=timestamp,
        )

    def resolve_import_id_for_job(job_row: dict[str, object] | None) -> str | None:
        if not job_row or str(job_row.get("job_type") or "") != "ingest_import":
            return None
        payload = from_json(str(job_row.get("payload_json") or "{}"), {})
        if not isinstance(payload, dict):
            return None
        import_id = payload.get("importId")
        return str(import_id) if import_id else None

    def update_import_status(import_id: str, *, status: str, imported_count: int | None = None, skipped_count: int | None = None) -> None:
        existing = state.db.fetchone("SELECT imported_count, skipped_count FROM imports WHERE id = ?", (import_id,))
        if not existing:
            return
        next_imported = int(imported_count) if imported_count is not None else int(existing["imported_count"] or 0)
        next_skipped = int(skipped_count) if skipped_count is not None else int(existing["skipped_count"] or 0)
        state.db.execute(
            """
            UPDATE imports
            SET status = ?, imported_count = ?, skipped_count = ?
            WHERE id = ?
            """,
            (status, next_imported, next_skipped, import_id),
        )

    def recover_stale_knowledge_jobs() -> None:
        stale_rows = state.db.fetchall(
            """
            SELECT id
            FROM knowledge_jobs
            WHERE status = 'running'
            ORDER BY created_at ASC
            """
        )
        if not stale_rows:
            return
        timestamp = now_iso()
        for row in stale_rows:
            job_id = str(row["id"])
            state.db.execute(
                """
                UPDATE knowledge_jobs
                SET status = 'queued', started_at = NULL, finished_at = NULL, last_error = ?, updated_at = ?
                WHERE id = ?
                """,
                ("worker_restart_requeued", timestamp, job_id),
            )
            append_knowledge_job_event(job_id, "warning", "检测到旧的运行中任务，已在启动时重新入队")

    def recover_stale_imports() -> None:
        stale_imports = state.db.fetchall(
            """
            SELECT id, client_id, status
            FROM imports
            WHERE status IN ('queued', 'processing')
            ORDER BY created_at ASC
            """
        )
        for row in stale_imports:
            import_id = str(row["id"])
            jobs = state.db.fetchall(
                """
                SELECT *
                FROM knowledge_jobs
                WHERE client_id = ? AND job_type = 'ingest_import'
                ORDER BY created_at DESC
                """,
                (str(row["client_id"]),),
            )
            matched_job: dict[str, object] | None = None
            for job in jobs:
                if resolve_import_id_for_job(dict(job)) == import_id:
                    matched_job = dict(job)
                    break
            if matched_job is None:
                if str(row["status"]) == "processing":
                    update_import_status(import_id, status="failed")
                continue
            job_status = str(matched_job.get("status") or "")
            processed_items = int(matched_job.get("processed_items") or 0)
            if job_status == "completed":
                update_import_status(import_id, status="completed", imported_count=processed_items)
            elif job_status == "failed":
                update_import_status(import_id, status="failed", imported_count=processed_items)
            elif job_status == "running":
                update_import_status(import_id, status="processing", imported_count=processed_items)
            elif job_status == "queued":
                update_import_status(import_id, status="queued", imported_count=processed_items)

    def recover_stale_template_fill_runs() -> None:
        stale_runs = state.db.fetchall(
            """
            SELECT id
            FROM client_template_fill_runs
            WHERE status IN ('queued', 'running')
            ORDER BY created_at ASC
            """
        )
        if not stale_runs:
            return
        timestamp = now_iso()
        for row in stale_runs:
            state.db.execute(
                """
                UPDATE client_template_fill_runs
                SET status = 'failed',
                    phase = 'failed',
                    progress = CASE
                        WHEN progress IS NULL THEN 8.0
                        WHEN progress > 96.0 THEN 96.0
                        WHEN progress < 8.0 THEN 8.0
                        ELSE progress
                    END,
                    stage_label = '模板填写已中断',
                    error_message = COALESCE(NULLIF(error_message, ''), '应用重启或后台中断，当前填写任务已停止，请重新发起。'),
                    updated_at = ?
                WHERE id = ?
                """,
                (timestamp, str(row["id"])),
            )

    TEMPLATE_FILL_STALE_IDLE_SECONDS = 180

    def _parse_template_fill_timestamp(value: str | None) -> datetime | None:
        raw = str(value or "").strip()
        if not raw:
            return None
        normalized = raw.replace("Z", "+00:00")
        try:
            return datetime.fromisoformat(normalized)
        except ValueError:
            return None

    def refresh_template_fill_executor(reason: str = "") -> None:
        if state.template_fill_executor is not None:
            state.template_fill_executor.shutdown(wait=False, cancel_futures=False)
        state.template_fill_executor = ThreadPoolExecutor(max_workers=1)
        if state.system_logger:
            suffix = f" reason={reason}" if reason else ""
            state.system_logger.info("template_fill", f"模板填写执行器已重建{suffix}")

    def expire_stuck_template_fill_runs(max_idle_seconds: int = TEMPLATE_FILL_STALE_IDLE_SECONDS) -> int:
        running_rows = state.db.fetchall(
            """
            SELECT id, phase, progress, current_field_label, updated_at, created_at
            FROM client_template_fill_runs
            WHERE status IN ('queued', 'running')
            ORDER BY created_at ASC
            """
        )
        if not running_rows:
            return 0
        now_dt = datetime.now()
        expired_ids: list[str] = []
        for row in running_rows:
            updated_at = _parse_template_fill_timestamp(str(row["updated_at"] or "")) or _parse_template_fill_timestamp(str(row["created_at"] or ""))
            if updated_at is None:
                continue
            if updated_at.tzinfo is not None:
                updated_at = updated_at.astimezone().replace(tzinfo=None)
            idle_seconds = (now_dt - updated_at).total_seconds()
            if idle_seconds < max_idle_seconds:
                continue
            run_id = str(row["id"])
            update_client_template_fill_run(
                run_id,
                status="failed",
                phase="failed",
                progress=max(8.0, min(float(row["progress"] or 0.0), 96.0)),
                stage_label="模板填写超时，已自动停止",
                clear_current_field_label=True,
                error_message=(
                    f"模板填写在“{str(row['phase'] or 'running')}”阶段超过 {max_idle_seconds} 秒未推进，"
                    "已自动终止，请重新发起。"
                ),
            )
            expired_ids.append(run_id)
            if state.system_logger:
                state.system_logger.error(
                    "template_fill",
                    f"检测到僵尸模板填写任务，已自动终止: {run_id}",
                    phase=str(row["phase"] or ""),
                    current_field=str(row["current_field_label"] or ""),
                    idleSeconds=round(idle_seconds, 2),
                )
        if expired_ids:
            refresh_template_fill_executor(reason=f"expired_runs={len(expired_ids)}")
        return len(expired_ids)

    STALE_LOADING_CHAT_QUEUED_SECONDS = 300
    STALE_LOADING_CHAT_GENERATING_SECONDS = 420
    STALE_LOADING_CHAT_ORPHAN_SECONDS = 900

    def _parse_local_datetime(value: object, *, fallback: datetime) -> datetime:
        raw = str(value or "").strip()
        if not raw:
            return fallback
        try:
            parsed = datetime.fromisoformat(raw.replace("Z", "+00:00"))
        except ValueError:
            return fallback
        if parsed.tzinfo is not None:
            parsed = parsed.astimezone().replace(tzinfo=None)
        return parsed

    def _loading_message_has_partial_content(row) -> bool:
        content = str(row["content"] or "").strip()
        if not content:
            return False
        placeholders = {
            "庆华正在整理背景材料，并组织分析答案……",
            "数据中心主链已就绪，正在组织回答……",
            "庆华暂时没能完成这次回答。",
            "正在调用模型生成回答",
        }
        return content not in placeholders

    def _recover_one_stale_loading_chat_message(
        row,
        *,
        reason: Literal["analysis_run_stale_recovered", "orphan_loading_message_recovered"],
        basis: str,
        basis_time: datetime,
        threshold_seconds: int,
        now: datetime,
        run_row=None,
    ) -> bool:
        age_seconds = max((now - basis_time).total_seconds(), 0.0)
        if age_seconds < threshold_seconds:
            return False

        timestamp = now_iso()
        summary = from_json(str(row["retrieval_summary_json"] or "{}"), {})
        if not isinstance(summary, dict):
            summary = {}
        summary.update(
            {
                "staleRecoveryBasis": basis,
                "runUpdatedAt": str(run_row["updated_at"]) if run_row and run_row["updated_at"] else None,
                "staleThresholdSeconds": threshold_seconds,
                "recoveredAt": timestamp,
                "lastUpdatedAt": timestamp,
            }
        )
        timing = {"totalMs": round(age_seconds * 1000, 2), "retrievalMs": 0.0, "llmMs": 0.0}
        message_id = str(row["id"])

        if _loading_message_has_partial_content(row):
            partial_content = str(row["content"] or "").strip()
            structured = AiStructuredResponse(
                content=partial_content,
                judgment="模型生成过程超时，系统已保留已经生成的部分有效回答。",
                analysis="后台回答任务长时间没有继续推进，系统按 stale recovery 收口，但没有覆盖已生成正文。",
                actions="可以基于这段回答继续追问，或重新生成一次完整回答。",
                timeline=f"自动收口时间：{timestamp}",
            )
            summary.update(
                {
                    "phase": "completed",
                    "progress": 100.0,
                    "progressFloor": 100.0,
                    "progressCeiling": 100.0,
                    "stageLabel": "已保留部分回答",
                    "failureReason": "llm_partial_preserved_after_stale_recovery",
                    "partialGenerationPreserved": True,
                    "finalFailureStage": "stale_recovery_partial_preserved",
                }
            )
            state.db.execute(
                """
                UPDATE chat_messages
                SET content = ?, structured_data_json = ?, model_route = ?, llm_invoked = 1,
                    provider_used = COALESCE(provider_used, ?), answer_mode = 'grounded_fallback',
                    evidence_status = 'partial', failure_reason = ?, timing_json = ?,
                    retrieval_summary_json = ?, evidence_json = COALESCE(evidence_json, '[]'),
                    status = 'success'
                WHERE id = ? AND status = 'loading'
                """,
                (
                    partial_content,
                    to_json(structured.model_dump()),
                    "AI 调用中断",
                    state.ai.current_provider(),
                    "llm_partial_preserved_after_stale_recovery",
                    to_json(timing),
                    to_json(summary),
                    message_id,
                ),
            )
            if run_row:
                state.db.execute(
                    """
                    UPDATE client_analysis_runs
                    SET status = 'completed',
                        phase = 'completed',
                        progress = 100.0,
                        progress_floor = 100.0,
                        progress_ceiling = 100.0,
                        stage_label = '已保留部分回答',
                        long_answer = ?,
                        structured_summary_json = ?,
                        long_answer_status = 'fallback',
                        summary_status = 'fallback',
                        answer_mode = 'grounded_fallback',
                        llm_invoked = 1,
                        provider_used = COALESCE(provider_used, ?),
                        failure_reason = 'llm_partial_preserved_after_stale_recovery',
                        elapsed_ms = ?,
                        timing_json = ?,
                        updated_at = ?
                    WHERE id = ? AND status IN ('queued', 'running')
                    """,
                    (
                        partial_content,
                        to_json(structured.model_dump()),
                        state.ai.current_provider(),
                        round(age_seconds * 1000, 2),
                        to_json(timing),
                        timestamp,
                        str(run_row["id"]),
                    ),
                )
            return True

        summary.update(
            {
                "phase": "failed",
                "progress": 100.0,
                "progressFloor": 100.0,
                "progressCeiling": 100.0,
                "stageLabel": "回答生成失败",
                "failureReason": "后台回答任务中断或超时，已自动收口。",
            }
        )
        state.db.execute(
            """
            UPDATE chat_messages
            SET content = ?, structured_data_json = ?, model_route = ?, llm_invoked = 0, provider_used = COALESCE(provider_used, ?),
                answer_mode = 'system_failure', evidence_status = 'none', failure_reason = ?, timing_json = ?,
                retrieval_summary_json = ?, evidence_json = COALESCE(evidence_json, '[]'), status = 'success'
            WHERE id = ? AND status = 'loading'
            """,
            (
                "庆华暂时没能完成这次回答。",
                to_json(
                    AiStructuredResponse(
                        content="庆华暂时没能完成这次回答。",
                        judgment="后台回答任务中断或超时，本次回答已自动收口为失败态。",
                        analysis="该消息此前一直停留在生成中，没有成功写回最终结果。系统已自动把它标记为失败，避免前端一直卡在加载状态。",
                        actions="请直接重试这个问题；如果反复出现，请检查本地后端与模型连接状态。",
                        timeline="修复后可立即重新生成。",
                    ).model_dump()
                ),
                "AI 调用失败",
                state.ai.current_provider(),
                reason,
                to_json(timing),
                to_json(summary),
                message_id,
            ),
        )
        if run_row:
            state.db.execute(
                """
                UPDATE client_analysis_runs
                SET status = 'failed',
                    phase = 'failed',
                    progress = 100.0,
                    progress_floor = 100.0,
                    progress_ceiling = 100.0,
                    stage_label = '回答生成失败',
                    long_answer_status = 'failed',
                    summary_status = 'failed',
                    answer_mode = 'system_failure',
                    failure_reason = ?,
                    elapsed_ms = ?,
                    timing_json = ?,
                    updated_at = ?
                WHERE id = ? AND status IN ('queued', 'running')
                """,
                (
                    reason,
                    round(age_seconds * 1000, 2),
                    to_json(timing),
                    timestamp,
                    str(run_row["id"]),
                ),
            )
        return True

    def recover_stale_loading_chat_messages(*, run_id: str | None = None, message_id: str | None = None) -> int:
        filters: list[str] = ["role = 'assistant'", "status = 'loading'"]
        params: list[object] = []
        if message_id:
            filters.append("id = ?")
            params.append(message_id)
        elif run_id:
            filters.append("id IN (SELECT assistant_message_id FROM client_analysis_runs WHERE id = ?)")
            params.append(run_id)
        stale_rows = state.db.fetchall(
            f"""
            SELECT id, content, retrieval_summary_json, created_at
            FROM chat_messages
            WHERE {' AND '.join(filters)}
            ORDER BY created_at ASC
            """,
            tuple(params),
        )
        if not stale_rows:
            return 0
        now = datetime.now()
        recovered = 0
        for row in stale_rows:
            latest_run = state.db.fetchone(
                """
                SELECT *
                FROM client_analysis_runs
                WHERE assistant_message_id = ?
                ORDER BY updated_at DESC, created_at DESC
                LIMIT 1
                """,
                (str(row["id"]),),
            )
            if latest_run:
                run_status = str(latest_run["status"] or "")
                if run_status in {"completed", "failed", "canceled"}:
                    continue
                run_phase = str(latest_run["phase"] or "queued")
                threshold = (
                    STALE_LOADING_CHAT_GENERATING_SECONDS
                    if run_phase == "generating_long_answer"
                    else STALE_LOADING_CHAT_QUEUED_SECONDS
                )
                basis_time = _parse_local_datetime(
                    latest_run["updated_at"] or latest_run["created_at"],
                    fallback=now,
                )
                if _recover_one_stale_loading_chat_message(
                    row,
                    reason="analysis_run_stale_recovered",
                    basis=f"analysis_run.{run_phase}.updated_at",
                    basis_time=basis_time,
                    threshold_seconds=threshold,
                    now=now,
                    run_row=latest_run,
                ):
                    recovered += 1
                continue
            message_created_at = _parse_local_datetime(row["created_at"], fallback=now)
            if _recover_one_stale_loading_chat_message(
                row,
                reason="orphan_loading_message_recovered",
                basis="chat_message.created_at",
                basis_time=message_created_at,
                threshold_seconds=STALE_LOADING_CHAT_ORPHAN_SECONDS,
                now=now,
                run_row=None,
            ):
                recovered += 1
        return recovered

    def claim_next_knowledge_job() -> dict[str, object] | None:
        row = state.db.fetchone(
            """
            SELECT *
            FROM knowledge_jobs
            WHERE status = 'queued'
            ORDER BY created_at ASC
            LIMIT 1
            """,
        )
        if not row:
            return None
        timestamp = now_iso()
        state.db.execute(
            "UPDATE knowledge_jobs SET status = 'running', started_at = ?, updated_at = ? WHERE id = ? AND status = 'queued'",
            (timestamp, timestamp, str(row["id"])),
        )
        claimed = state.db.fetchone("SELECT * FROM knowledge_jobs WHERE id = ?", (str(row["id"]),))
        if not claimed or str(claimed["status"]) != "running":
            return None
        append_knowledge_job_event(str(claimed["id"]), "info", "知识加工任务开始执行")
        return dict(claimed)

    def finish_knowledge_job(job_id: str, *, status: str, processed_items: int, last_error: str | None = None) -> None:
        timestamp = now_iso()
        existing_job = state.db.fetchone("SELECT * FROM knowledge_jobs WHERE id = ?", (job_id,))
        state.db.execute(
            """
            UPDATE knowledge_jobs
            SET status = ?, processed_items = ?, last_error = ?, finished_at = ?, updated_at = ?
            WHERE id = ?
            """,
            (status, processed_items, last_error, timestamp, timestamp, job_id),
        )
        append_knowledge_job_event(
            job_id,
            "error" if status == "failed" else "info",
            "知识加工任务执行失败" if status == "failed" else "知识加工任务执行完成",
            {"processedItems": processed_items, "lastError": last_error},
        )
        import_id = resolve_import_id_for_job(dict(existing_job)) if existing_job else None
        if import_id:
            update_import_status(import_id, status="failed" if status == "failed" else "completed", imported_count=processed_items)

    def update_knowledge_job_progress(job_id: str, processed_items: int, message: str) -> None:
        state.db.execute(
            "UPDATE knowledge_jobs SET processed_items = ?, updated_at = ? WHERE id = ?",
            (processed_items, now_iso(), job_id),
        )
        append_knowledge_job_event(job_id, "info", message, {"processedItems": processed_items})

    def _apply_version_chain(
        db,
        *,
        document_id: str,
        version_chain_id: object,
        version_number: int,
        predecessor_kd_id: object,
    ) -> None:
        """迭代 2 F3：把闸门决定的版本链信息落到 knowledge_documents。

        - 新文档：找到由 ingest 创建的 knowledge_documents 行，写入 version_chain_id
          （null 表示新链 → 用自己的 id 当链头）和 version_number。
        - 升级版本：把前一版 lifecycle_status 改为 superseded，并设 superseded_by_id。
        """
        kd_row = db.fetchone(
            "SELECT id FROM knowledge_documents WHERE document_id = ?",
            (document_id,),
        )
        if not kd_row:
            return
        new_kd_id = str(kd_row["id"])
        final_chain_id = str(version_chain_id) if version_chain_id else new_kd_id
        timestamp = now_iso()
        db.execute(
            "UPDATE knowledge_documents "
            "SET version_chain_id = ?, version_number = ?, "
            "    lifecycle_status = 'current', updated_at = ? "
            "WHERE id = ?",
            (final_chain_id, version_number, timestamp, new_kd_id),
        )
        if predecessor_kd_id:
            db.execute(
                "UPDATE knowledge_documents "
                "SET lifecycle_status = 'superseded', superseded_by_id = ?, "
                "    updated_at = ? "
                "WHERE id = ?",
                (new_kd_id, timestamp, str(predecessor_kd_id)),
            )

    def process_knowledge_job(job: dict[str, object]) -> None:
        job_id = str(job["id"])
        client_id = str(job["client_id"])
        job_type = str(job["job_type"])
        payload = from_json(str(job["payload_json"]), {})
        processed_items = 0
        if job_type == "ingest_import":
            import_id = str(payload.get("importId"))
            documents = payload.get("documents", [])
            docs = documents if isinstance(documents, list) else []
            state.db.execute("UPDATE imports SET status = 'processing' WHERE id = ?", (import_id,))
            ensure_standard_client_folders(client_id)
            for item in docs:
                if not isinstance(item, dict):
                    continue
                document_id = str(item.get("documentId", ""))
                path = Path(str(item.get("sourcePath", "")))
                original_source_path = Path(str(item.get("originalSourcePath", ""))).expanduser() if item.get("originalSourcePath") else path
                if not document_id or not path.exists():
                    if document_id:
                        append_knowledge_job_event(
                            job_id,
                            "warning",
                            "跳过缺失的原始文件",
                            {"documentId": document_id, "sourcePath": str(path)},
                        )
                    continue
                excerpt = build_excerpt(path)
                prepared = ingest_document_knowledge(
                    state.db,
                    data_dir=state.data_dir,
                    client_id=client_id,
                    import_id=import_id,
                    document_id=document_id,
                    source_path=path,
                    original_source_path=original_source_path,
                    title=str(item.get("title", path.name)),
                    kind=str(item.get("kind", path.suffix.lower().lstrip("."))),
                    source=str(item.get("source", payload.get("mode", "file"))),
                    fallback_excerpt=excerpt,
                    created_at=str(item.get("createdAt", now_iso())),
                    ai_service=state.ai,
                )
                # 迭代 2 F3：回写版本链元数据。
                # ingest 已创建/更新了 knowledge_documents 行（按 document_id 查），
                # 现在把闸门期决定的 version_chain_id / version_number 应用上去，
                # 并把前一版（如果有）标记为 superseded。
                _apply_version_chain(
                    state.db,
                    document_id=document_id,
                    version_chain_id=item.get("versionChainId"),
                    version_number=int(item.get("versionNumber") or 1),
                    predecessor_kd_id=item.get("predecessorKnowledgeDocumentId"),
                )
                record_imported_document_writeback(
                    state.db,
                    client_id=client_id,
                    document_id=document_id,
                    title=str(item.get("title", path.name)),
                    prepared=prepared,
                )
                prepared_title = str(prepared.get("title") or path.name)
                prepared_category = str(prepared.get("primary_category") or "其他资料")
                target_folder = state.db.fetchone(
                    "SELECT id FROM client_folders WHERE client_id = ? AND label = ?",
                    (client_id, prepared_category),
                )
                state.db.execute(
                    """
                    UPDATE documents
                    SET folder_id = ?
                    WHERE id = ?
                    """,
                    (
                        str(target_folder["id"]) if target_folder else None,
                        document_id,
                    ),
                )
                processed_items += 1
                state.db.execute(
                    "UPDATE imports SET imported_count = ?, status = 'processing' WHERE id = ?",
                    (processed_items, import_id),
                )
                update_knowledge_job_progress(job_id, processed_items, f"已处理 {prepared_title}")
            append_knowledge_job_event(job_id, "info", f"已完成 {V2_PIPELINE_VERSION} 文档索引、章节定位与原文切块")
            ensure_standard_client_folders(client_id)
            total_items = int(job.get("total_items") or len(docs))
            existing_import = state.db.fetchone("SELECT skipped_count FROM imports WHERE id = ?", (import_id,))
            existing_skipped = int(existing_import["skipped_count"] or 0) if existing_import else 0
            skipped_items = existing_skipped + max(0, total_items - processed_items)
            state.db.execute(
                "UPDATE imports SET status = 'completed', imported_count = ?, skipped_count = ? WHERE id = ?",
                (processed_items, skipped_items, import_id),
            )
            finish_knowledge_job(job_id, status="completed", processed_items=processed_items)
            _enqueue_workspace_refresh_safe(
                client_id=client_id,
                source_type="document_import_complete",
                source_id=import_id or job_id,
                reason="document_import_completed",
                scope_type="client",
                scope_id=client_id,
                priority="normal",
            )
            maybe_enqueue_client_dna_generation_job(client_id)
            # Auto-rebuild client profile blocks after import completes
            if processed_items > 0:
                try:
                    build_client_profile(state.db, data_dir=state.data_dir, client_id=client_id, ai_service=state.ai)
                except Exception:
                    pass  # profile rebuild is best-effort
                try:
                    from app.services.memory_foundation import backfill_document_knowledge_to_memory
                    backfill_document_knowledge_to_memory(state.db)
                    refresh_organization_notebook_snapshot(state.db, client_id)
                except Exception:
                    pass
            return
        if job_type == "workspace_document_auto_repair":
            _run_workspace_document_auto_repair_job(client_id, payload if isinstance(payload, dict) else {}, job_id)
            processed_items = int(
                state.db.scalar(
                    "SELECT processed_items FROM knowledge_jobs WHERE id = ?",
                    (job_id,),
                )
                or 0
            )
            finish_knowledge_job(job_id, status="completed", processed_items=processed_items)
            return
        if job_type == "retry_parse":
            document_ids_payload = payload.get("documentIds", [])
            document_ids = [str(item) for item in document_ids_payload] if isinstance(document_ids_payload, list) else []
            retry_result = execute_parse_failure_retry_batch(
                client_id,
                KnowledgeParseFailureRetryPayloadRecord(
                    documentIds=document_ids,
                    force=bool(payload.get("force")),
                    ocrMaxPages=int(payload.get("ocrMaxPages") or 60),
                    ocrBatchSize=int(payload.get("ocrBatchSize") or 8),
                    ocrContinueToEnd=bool(payload.get("ocrContinueToEnd", True)),
                    forceOcr=bool(payload.get("forceOcr")),
                ),
                batch_id=job_id,
                job_id=job_id,
                source=str(payload.get("source") or "retry_parse_job"),
            )
            processed_items = int(retry_result.attempted)
            job_status = "failed" if retry_result.attempted > 0 and retry_result.succeeded == 0 and retry_result.failed > 0 else "completed"
            last_error = None
            if job_status == "failed":
                last_error = f"解析重试全部失败：{retry_result.failureBuckets}"
            finish_knowledge_job(job_id, status=job_status, processed_items=processed_items, last_error=last_error)
            return
        if job_type == "internet_enrichment":
            enrichment_result = run_internet_enrichment(
                state.db,
                data_dir=state.data_dir,
                client_id=client_id,
                ai_service=state.ai,
                payload=payload if isinstance(payload, dict) else {},
                event_callback=lambda level, message, detail=None: append_knowledge_job_event(job_id, level, message, detail or {}),
                progress_callback=lambda count, message: update_knowledge_job_progress(job_id, count, message),
            )
            processed_items = int(enrichment_result.source_doc_count)
            job_status = "completed" if enrichment_result.source_doc_count > 0 or enrichment_result.fact_card_count > 0 else "failed"
            last_error = None if job_status == "completed" else "互联网资料补全未抓取到可入库正文"
            finish_knowledge_job(job_id, status=job_status, processed_items=processed_items, last_error=last_error)
            if job_status == "completed":
                _enqueue_workspace_refresh_safe(
                    client_id=client_id,
                    source_type="internet_enrichment_complete",
                    source_id=job_id,
                    reason="internet_enrichment_completed",
                    scope_type="client",
                    scope_id=client_id,
                    priority="normal",
                )
            return
        if job_type == "rebuild_client_knowledge":
            summary = backfill_knowledge_documents(
                state.db,
                data_dir=state.data_dir,
                client_id=client_id,
                ai_service=state.ai,
                progress_callback=lambda count: update_knowledge_job_progress(job_id, count, f"已回填 {count} 份文档"),
            )
            processed_items = int(summary.get("processed", 0))
            missing_items = int(summary.get("missing", 0))
            if missing_items > 0:
                append_knowledge_job_event(
                    job_id,
                    "warning",
                    "部分原始文件已丢失，已跳过缺失文件并继续重建",
                    {"missingItems": missing_items},
                )
            append_knowledge_job_event(job_id, "info", f"已完成 {V2_PIPELINE_VERSION} 文档索引、章节定位与原文切块")
            ensure_standard_client_folders(client_id)
            finish_knowledge_job(job_id, status="completed", processed_items=processed_items)
            _enqueue_workspace_refresh_safe(
                client_id=client_id,
                source_type="knowledge_rebuild_complete",
                source_id=job_id,
                reason="rebuild_client_knowledge_completed",
                scope_type="client",
                scope_id=client_id,
                priority="normal",
            )
            maybe_enqueue_client_dna_generation_job(client_id)
            # Auto-rebuild client profile blocks after knowledge rebuild
            if processed_items > 0:
                try:
                    build_client_profile(state.db, data_dir=state.data_dir, client_id=client_id, ai_service=state.ai)
                except Exception:
                    pass
            return
        if job_type == "generate_client_dna_candidates":
            module_keys = payload.get("moduleKeys", [])
            module_key_list = [str(item) for item in module_keys] if isinstance(module_keys, list) else []
            refresh_generated = bool(payload.get("refreshGenerated"))
            if not module_key_list:
                module_key_list = [module.moduleKey for module in resolve_client_dna_modules_for_generation(client_id, refresh_generated=refresh_generated)]
            if not module_key_list:
                finish_knowledge_job(job_id, status="completed", processed_items=0)
                _enqueue_workspace_refresh_safe(
                    client_id=client_id,
                    source_type="client_dna_generate_complete",
                    source_id=job_id,
                    reason="client_dna_generation_completed",
                    scope_type="client",
                    scope_id=client_id,
                    priority="low",
                )
                return
            for module_key in module_key_list:
                markdown_content, missing_items = build_client_dna_candidate_markdown(client_id, module_key)
                save_client_dna_module(
                    client_id,
                    module_key,
                    markdown_content=markdown_content,
                    file_name=f"{safe_filename(build_client_summary(client_id).name)}-{module_key}-candidate.md",
                    source_kind="generated",
                    updated_by="系统候选生成",
                    missing_info=missing_items,
                )
                processed_items += 1
                update_knowledge_job_progress(job_id, processed_items, f"已生成 {dict(CLIENT_DNA_MODULES).get(module_key, module_key)} 候选文档")
            finish_knowledge_job(job_id, status="completed", processed_items=processed_items)
            _enqueue_workspace_refresh_safe(
                client_id=client_id,
                source_type="client_dna_generate_complete",
                source_id=job_id,
                reason="client_dna_generation_completed",
                scope_type="client",
                scope_id=client_id,
                priority="normal",
            )
            return
        finish_knowledge_job(job_id, status="failed", processed_items=0, last_error=f"未知任务类型：{job_type}")

    def knowledge_worker_loop() -> None:
        while not state.job_stop.is_set():
            job = claim_next_knowledge_job()
            if not job:
                time.sleep(0.5)
                continue
            try:
                process_knowledge_job(job)
            except Exception as error:
                finish_knowledge_job(str(job["id"]), status="failed", processed_items=int(job.get("processed_items") or 0), last_error=str(error))
            time.sleep(0.05)

    def analysis_job_worker_loop() -> None:
        worker_id = f"analysis-worker-{os.getpid()}"
        while not state.job_stop.is_set():
            job = claim_next_analysis_job(state.db, worker_id)
            if not job:
                time.sleep(0.75)
                continue
            try:
                workspace = workspace_for_client(job.clientId)
                execute_analysis_job_projection(
                    state.db,
                    job,
                    workspace,
                    notebook_summary=workspace.notebookSummary,
                    memory_status=workspace.memoryStatus,
                )
            except Exception as error:
                fail_analysis_job(
                    state.db,
                    job.id,
                    stage_name="analysis_pipeline",
                    error=str(error),
                )
            time.sleep(0.05)

    def build_health() -> HealthResponse:
        ai_health = state.ai.get_health()
        ai_profile_health = state.ai.get_profile_health_map()

        def _health_ai_state(health: object) -> HealthAiState:
            return HealthAiState(
                provider=getattr(health, "provider"),  # type: ignore[arg-type]
                providerLabel=getattr(health, "provider_label"),
                baseUrl=getattr(health, "base_url"),
                model=getattr(health, "model"),
                ready=getattr(health, "ready"),
                detail=getattr(health, "detail"),
                credentialSource=getattr(health, "credential_source"),
                fingerprint=getattr(health, "fingerprint"),
                profileKey=getattr(health, "profile_key", "unified"),
                mode=getattr(health, "mode", state.ai.current_ai_model_mode()),  # type: ignore[arg-type]
            )

        return HealthResponse(
            appName=APP_NAME,
            appVersion=APP_VERSION,
            buildVersion=APP_BUILD_VERSION,
            gitCommit=APP_GIT_COMMIT,
            bundleManifestId=BUNDLE_MANIFEST_ID,
            backendBuildHash=BACKEND_BUILD_HASH,
            backendSourceHash=BACKEND_SOURCE_HASH,
            frontendRendererEntry=FRONTEND_RENDERER_ENTRY,
            frontendRendererHash=FRONTEND_RENDERER_HASH,
            backendSchemaVersion=state.db.get_schema_version(),
            runtimeMode=BACKEND_RUNTIME_MODE,
            installPathStatus=INSTALL_PATH_STATUS,
            startedAt=APP_STARTED_AT,
            featureFlags=BACKEND_FEATURE_FLAGS,
            dataDir=str(state.data_dir),
            stats={
                "clients": state.db.scalar("SELECT COUNT(1) AS count FROM clients"),
                "tasks": state.db.scalar("SELECT COUNT(1) AS count FROM tasks"),
                "topics": state.db.scalar("SELECT COUNT(1) AS count FROM topic_candidates"),
                "handbookEntries": state.db.scalar("SELECT COUNT(1) AS count FROM handbook_entries"),
                "analysisRuns": state.db.scalar("SELECT COUNT(1) AS count FROM analysis_runs"),
            },
            ai=_health_ai_state(ai_health),
            aiProfiles={key: _health_ai_state(value) for key, value in ai_profile_health.items()},
            advancedAiRoutingEnabled=state.ai.advanced_ai_routing_enabled(),
            aiModelMode=state.ai.current_ai_model_mode(),  # type: ignore[arg-type]
            linkMaterialDiagnostics=build_link_material_runtime_diagnostics(),
        )

    def build_settings_response() -> SettingsResponse:
        operator = current_operator_row()
        ai_health = state.ai.get_health()
        settings = AppSettingsResponse(
            currentOperatorId=str(operator["id"]),
            aiProvider=state.ai.current_provider(),  # type: ignore[arg-type]
            aiProviderLabel=state.ai.current_provider_label(),
            aiBaseUrl=state.ai.current_base_url(),
            aiModel=state.ai.current_model(),
            dataDir=str(state.data_dir),
            backupDir=str(state.backup_dir),
            cloudApiUrl=state.cloud_api_url,
            lastBackupAt=state.db.get_setting("last_backup_at", "") or None,
            foldersRootLabel=state.db.get_setting("folders_root_label", "桌面客户资料"),
            aiConfigured=bool(ai_health.ready and ai_health.provider != "mock"),
            aiCredentialSource=ai_health.credential_source,
            aiFingerprint=ai_health.fingerprint,
            advancedAiRoutingEnabled=state.ai.advanced_ai_routing_enabled(),
            aiModelMode=state.ai.current_ai_model_mode(),  # type: ignore[arg-type]
            aiModelProfiles=state.ai.current_ai_model_profiles(),  # type: ignore[arg-type]
            demoDataLoaded=demo_data_loaded(state.db),
        )
        operators = [
            OperatorRecord(
                id=str(row["id"]),
                name=str(row["name"]),
                role=str(row["role"]),
                team=str(row["team"]),
                color=str(row["color"]),
                isCurrent=bool(row["is_current"]),
            )
            for row in state.db.fetchall("SELECT * FROM operators ORDER BY created_at")
        ]
        return SettingsResponse(
            settings=settings,
            operators=operators,
            health=build_health(),
            lastCloudAiSyncStatus=LastCloudAiSyncStatusRecord(**_cloud_ai_sync_status),
        )

    def _has_persisted_cloud_session() -> bool:
        return bool(state.db.get_setting("cloud_access_token", "") or state.db.get_setting("cloud_refresh_token", ""))

    def get_cloud_token() -> str:
        token = state.db.get_setting("cloud_access_token", "")
        if token:
            state.cloud_session_persistent = True
            return token
        return state.volatile_cloud_access_token

    def get_cloud_refresh_token() -> str:
        token = state.db.get_setting("cloud_refresh_token", "")
        if token:
            state.cloud_session_persistent = True
            return token
        return state.volatile_cloud_refresh_token

    def set_cloud_session(token: str | None, user: SessionUserRecord | None, *, persist: bool = True) -> None:
        state.cloud_session_persistent = persist
        session_user_json = to_json(user.model_dump()) if user else ""
        if persist:
            state.db.set_setting("cloud_access_token", token or "")
            state.db.set_setting("cloud_session_user", session_user_json)
            state.volatile_cloud_access_token = ""
            state.volatile_cloud_session_user_json = ""
            return
        state.db.set_setting("cloud_access_token", "")
        state.db.set_setting("cloud_session_user", "")
        state.volatile_cloud_access_token = token or ""
        state.volatile_cloud_session_user_json = session_user_json

    def set_cloud_refresh_token(token: str | None, *, persist: bool = True) -> None:
        state.cloud_session_persistent = persist
        if persist:
            state.db.set_setting("cloud_refresh_token", token or "")
            state.volatile_cloud_refresh_token = ""
            return
        state.db.set_setting("cloud_refresh_token", "")
        state.volatile_cloud_refresh_token = token or ""

    def clear_cloud_session() -> None:
        set_cloud_session(None, None, persist=True)
        set_cloud_refresh_token(None, persist=True)
        state.volatile_cloud_access_token = ""
        state.volatile_cloud_refresh_token = ""
        state.volatile_cloud_session_user_json = ""
        state.cloud_session_persistent = False
        with state.maintenance_mode_lock:
            state.maintenance_mode_active = False
            state.maintenance_mode_user_id = ""
            state.maintenance_mode_entered_at = ""

    def get_cached_session_user() -> SessionUserRecord | None:
        raw = state.db.get_setting("cloud_session_user", "")
        if not raw:
            raw = state.volatile_cloud_session_user_json
        parsed = from_json(raw, {}) if raw else {}
        if not isinstance(parsed, dict) or not parsed:
            return None
        try:
            return SessionUserRecord(**parsed)
        except Exception:
            return None

    def current_session_is_admin() -> bool:
        session_user = get_cached_session_user()
        return bool(session_user and session_user.primaryRole == "admin")

    def _load_json_settings_record(key: str, default_factory, model_cls):
        raw = state.db.get_setting(key, "")
        if raw:
            parsed = from_json(raw, {})
            if isinstance(parsed, dict):
                try:
                    return model_cls(**parsed)
                except Exception:
                    pass
        record = default_factory()
        state.db.set_setting(key, to_json(record.model_dump()))
        return record

    def _save_json_settings_record(key: str, record) -> object:
        state.db.set_setting(key, to_json(record.model_dump()))
        return record

