    def list_client_memory_cards(client_id: str, limit: int = 80) -> list[KnowledgeMemoryRecord]:
        rows = state.db.fetchall(
            """
            SELECT id, client_id, source_type, title, folder_category, surrogate_md_path,
                   overview_summary, retrieval_summary, document_role, source_links_json,
                   created_at, updated_at
            FROM knowledge_surrogates
            WHERE client_id = ? AND source_type = 'memory_answer'
            ORDER BY updated_at DESC
            LIMIT ?
            """,
            (client_id, limit),
        )
        cards: list[KnowledgeMemoryRecord] = []
        for row in rows:
            source_links = from_json(row["source_links_json"], []) if row["source_links_json"] else []
            if not isinstance(source_links, list):
                source_links = []
            cards.append(
                KnowledgeMemoryRecord(
                    id=str(row["id"]),
                    clientId=str(row["client_id"]),
                    sourceType=str(row["source_type"]),
                    title=str(row["title"]),
                    folderCategory=str(row["folder_category"]),
                    surrogateMdPath=str(row["surrogate_md_path"]),
                    overviewSummary=str(row["overview_summary"] or ""),
                    retrievalSummary=str(row["retrieval_summary"] or ""),
                    documentRole=str(row["document_role"] or "战略陪伴记忆"),
                    sourceLinks=[item for item in source_links if isinstance(item, dict)],
                    createdAt=str(row["created_at"]),
                    updatedAt=str(row["updated_at"]),
                )
            )
        return cards

