    def classify_workspace_chat_intent(prompt: str) -> WorkspaceAnswerIntent:
        normalized = re.sub(r"\s+", "", (prompt or "").lower())
        if not normalized:
            return "general"
        if any(token in normalized for token in OFFICIAL_INTENT_TOKENS):
            return "official_judgment_registry"
