    from app.services.self_heal import SelfHealEngine

    _heal_engine: SelfHealEngine | None = None

    def _get_heal_engine() -> SelfHealEngine:
        nonlocal _heal_engine
        if _heal_engine is None:
            _heal_engine = SelfHealEngine(state.db, state.data_dir, state.ai)
        return _heal_engine

    @app.get("/api/v1/system/health-check")
    def system_health_check() -> dict:
        engine = _get_heal_engine()
        probes = engine.run_health_check()
        healthy_count = sum(1 for p in probes if p["healthy"])
        sick_count = len(probes) - healthy_count
        return {
            "timestamp": now_iso(),
            "totalProbes": len(probes),
            "healthy": healthy_count,
            "sick": sick_count,
            "probes": probes,
        }

    @app.post("/api/v1/system/self-heal")
    def system_self_heal(remedy_id: str | None = None) -> dict:
        engine = _get_heal_engine()
        if remedy_id:
            record = engine.heal(remedy_id=remedy_id, diagnosis="手动触发")
            return {"mode": "manual", "records": [asdict(record)]}
        records = engine.auto_heal()
        return {
            "mode": "auto",
            "records": [asdict(r) for r in records],
            "healed": sum(1 for r in records if r.status == "healed"),
            "failed": sum(1 for r in records if r.status == "failed"),
            "skipped": sum(1 for r in records if r.status == "skipped"),
        }

    @app.post("/api/v1/system/diagnose")
    def system_diagnose(error_logs: list[str] = Body(default=[])) -> dict:
        engine = _get_heal_engine()
        logs = error_logs
        if not logs:
            rows = state.db.fetchall(
                "SELECT action, detail_json, created_at FROM activity_logs WHERE action LIKE '%.error%' ORDER BY created_at DESC LIMIT 20"
            )
            logs = [f"[{row['created_at']}] {row['action']}: {row['detail_json']}" for row in rows]
        if not logs:
            return {"matched": False, "reason": "无错误日志可分析"}
        return engine.diagnose_with_ai(logs)

    @app.get("/api/v1/system/heal-log")
    def system_heal_log(limit: int = 50) -> dict:
        engine = _get_heal_engine()
        return {"records": engine.get_heal_log(limit)}

    _cloud_ai_sync_status: dict[str, object] = {"state": "never"}

    def _sync_org_ai_config_from_cloud() -> None:
        """Pull org-level AI config from cloud and apply locally (background, non-blocking).

        Writes non-sensitive diagnostics into _cloud_ai_sync_status so settings
        response can surface why cloud sync did/didn't take effect. Never logs
        or stores the raw API key — only hasApiKey + fingerprint (from state.ai).
        """
        try:
            secret_payload = cloud_request("GET", "/api/v1/settings/org-ai-config/secret")
            if not isinstance(secret_payload, dict):
                _cloud_ai_sync_status.clear()
                _cloud_ai_sync_status.update({
                    "state": "failed",
                    "at": now_iso(),
                    "reason": "云端响应非 JSON 对象",
                })
                logger.warning("[cloud-ai-sync] pull failed: non-dict payload")
                return
            provider = str(secret_payload.get("aiProvider", "")).strip()
            provider_label = str(secret_payload.get("aiProviderLabel", "")).strip()
            base_url = str(secret_payload.get("aiBaseUrl", "")).strip()
            model = str(secret_payload.get("aiModel", "")).strip()
            api_key = str(secret_payload.get("apiKey", "")).strip()
            if not provider or provider == "mock":
                _cloud_ai_sync_status.clear()
                _cloud_ai_sync_status.update({
                    "state": "skipped",
                    "at": now_iso(),
                    "reason": "云端组织 AI 配置为空或为 mock，未覆盖本机",
                    "provider": provider or None,
                    "providerLabel": provider_label or None,
                    "model": model or None,
                    "baseUrl": base_url or None,
                    "hasApiKey": bool(api_key),
                })
                logger.info(
                    "[cloud-ai-sync] skipped: provider=%s hasApiKey=%s",
                    provider or "<empty>",
                    bool(api_key),
                )
                return
            if state.ai.advanced_ai_routing_enabled():
                state.ai.configure_cloud_online_profile(
                    provider=provider,
                    model=model,
                    api_key=api_key,
                    provider_label=provider_label or None,
                    base_url=base_url or None,
                )
            else:
                state.ai.configure(
                    provider,
                    model,
                    api_key,
                    False,
                    provider_label=provider_label or None,
                    base_url=base_url or None,
                )
            applied_fingerprint = state.ai.get_health().fingerprint
            _cloud_ai_sync_status.clear()
            _cloud_ai_sync_status.update({
                "state": "synced",
                "at": now_iso(),
                "reason": None,
                "provider": provider,
                "providerLabel": provider_label or None,
                "model": model or None,
                "baseUrl": base_url or None,
                "hasApiKey": bool(api_key),
                "fingerprint": applied_fingerprint or None,
            })
            logger.info(
                "[cloud-ai-sync] synced: provider=%s model=%s baseUrl=%s hasApiKey=%s fingerprint=%s",
                provider,
                model or "<empty>",
                base_url or "<empty>",
                bool(api_key),
                applied_fingerprint or "<none>",
            )
        except Exception as exc:
            _cloud_ai_sync_status.clear()
            _cloud_ai_sync_status.update({
                "state": "failed",
                "at": now_iso(),
                "reason": str(exc)[:200] or exc.__class__.__name__,
            })
            logger.warning("[cloud-ai-sync] pull failed: %s", exc)

    def _push_current_ai_config_to_cloud() -> dict[str, object]:
        """Push the locally-configured AI (incl. Keychain API key) to the cloud org config.

        Returns a status dict describing the outcome. Updates _cloud_ai_sync_status
        in the same shape used by the pull path so the settings response can surface
        a uniform diagnostic regardless of sync direction. Never logs the raw key.
        """
        provider = state.ai.current_provider()
        provider_label = state.ai.current_provider_label()
        base_url = state.ai.current_base_url()
        model = state.ai.current_model()
        if not provider or provider == "mock":
            _cloud_ai_sync_status.clear()
            _cloud_ai_sync_status.update({
                "state": "skipped",
                "at": now_iso(),
                "reason": "本机当前 provider 为空或为 mock，未上传",
                "provider": provider or None,
                "providerLabel": provider_label or None,
                "model": model or None,
                "baseUrl": base_url or None,
                "hasApiKey": False,
            })
            logger.info("[cloud-ai-sync] push skipped: provider=%s", provider or "<empty>")
            return dict(_cloud_ai_sync_status)
        api_key = state.ai.export_current_api_key()
        if not api_key:
            _cloud_ai_sync_status.clear()
            _cloud_ai_sync_status.update({
                "state": "skipped",
                "at": now_iso(),
                "reason": "本机 Keychain 内未配置 API Key，未上传",
                "provider": provider,
                "providerLabel": provider_label or None,
                "model": model or None,
                "baseUrl": base_url or None,
                "hasApiKey": False,
            })
            logger.info("[cloud-ai-sync] push skipped: no api_key in keychain for provider=%s", provider)
            return dict(_cloud_ai_sync_status)
        local_fingerprint = state.ai.get_health().fingerprint
        try:
            response = cloud_request(
                "POST",
                "/api/v1/settings/org-ai-config",
                json_body={
                    "aiProvider": provider,
                    "aiProviderLabel": provider_label or "",
                    "aiBaseUrl": base_url or "",
                    "aiModel": model or "",
                    "apiKey": api_key,
                    "clearApiKey": False,
                },
            )
            if not isinstance(response, dict):
                raise RuntimeError("云端响应非 JSON 对象")
            _cloud_ai_sync_status.clear()
            _cloud_ai_sync_status.update({
                "state": "uploaded",
                "at": now_iso(),
                "reason": None,
                "provider": provider,
                "providerLabel": provider_label or None,
                "model": model or None,
                "baseUrl": base_url or None,
                "hasApiKey": True,
                "fingerprint": local_fingerprint or None,
            })
            logger.info(
                "[cloud-ai-sync] pushed: provider=%s model=%s baseUrl=%s fingerprint=%s",
                provider,
                model or "<empty>",
                base_url or "<empty>",
                local_fingerprint or "<none>",
            )
        except HTTPException as exc:
            _cloud_ai_sync_status.clear()
            _cloud_ai_sync_status.update({
                "state": "failed",
                "at": now_iso(),
                "reason": f"HTTP {exc.status_code}: {str(exc.detail)[:200]}",
                "provider": provider,
                "model": model or None,
                "hasApiKey": True,
                "fingerprint": local_fingerprint or None,
            })
            logger.warning("[cloud-ai-sync] push failed: HTTP %s: %s", exc.status_code, exc.detail)
        except Exception as exc:
            _cloud_ai_sync_status.clear()
            _cloud_ai_sync_status.update({
                "state": "failed",
                "at": now_iso(),
                "reason": str(exc)[:200] or exc.__class__.__name__,
                "provider": provider,
                "model": model or None,
                "hasApiKey": True,
                "fingerprint": local_fingerprint or None,
            })
            logger.warning("[cloud-ai-sync] push failed: %s", exc)
        return dict(_cloud_ai_sync_status)

    @app.get("/api/v1/auth/me", response_model=AuthStateResponse)
    def auth_me() -> AuthStateResponse:
        def _local_session_user() -> SessionUserRecord:
            return SessionUserRecord(
                id="local-device-user",
                organizationId="local-device",
                email="local@device.yiyu",
                fullName="本机用户",
                primaryRole="employee",
                accountStatus="approved",
                membershipStatus="approved",
            )

        def _local_auth_state(message: str | None = None) -> AuthStateResponse:
            return AuthStateResponse(
                authenticated=True,
                user=_local_session_user(),
                message=message,
                sessionMode="local",
            )

        token = get_cloud_token()
        refresh_token = get_cloud_refresh_token()
        if not token and not refresh_token:
            return _local_auth_state()
        if not state.cloud_api_url:
            clear_cloud_session()
            return _local_auth_state("尚未配置云端服务地址，已切回本机模式。")
        cached_user = get_cached_session_user()
        try:
            user = require_session_user()
            _ensure_local_organization_workspace_from_cloud_membership()
        except HTTPException as exc:
            if exc.status_code in {401, 403}:
                clear_cloud_session()
                return _local_auth_state(str(exc.detail))
            if exc.status_code in {502, 503, 504} and cached_user is not None:
                return AuthStateResponse(
                    authenticated=True,
                    user=cached_user,
                    message="云端暂时不可用，已保留当前设备上的登录状态。",
                    sessionMode="cloud",
                )
            raise
        import threading
        threading.Thread(target=_sync_org_ai_config_from_cloud, daemon=True).start()
        return AuthStateResponse(authenticated=True, user=user, sessionMode="cloud")

