    @app.get("/api/v1/local-input-memory", response_model=LocalInputMemoryResponse)
    def get_local_input_memory() -> LocalInputMemoryResponse:
        return _hydrate_local_input_memory()

    @app.post("/api/v1/local-input-memory/cloud-auth", response_model=LocalInputMemoryResponse)
    def save_cloud_auth_input_memory(payload: SaveCloudAuthInputMemoryPayload) -> LocalInputMemoryResponse:
        current = _get_local_input_memory_record()
        existing_accounts = current.cloudAuth.accounts
        for account in existing_accounts:
            if not payload.rememberInputs:
                try:
                    _remembered_cloud_auth_store(account.identifier or account.email).delete_api_key()
                except Exception:
                    pass
        if not payload.rememberInputs:
            record = current.model_copy(
                update={
                    "cloudAuth": LocalInputMemoryCloudAuth(
                        rememberInputs=False,
                        lastEmail=None,
                        accounts=[],
                    )
                }
            )
            _save_local_input_memory_record(record)
            return _hydrate_local_input_memory(record)

        identifier = (payload.identifier or payload.email).strip().lower()
        if not identifier:
            raise HTTPException(status_code=400, detail="请先填写邮箱或手机号，再决定是否记住账号和密码。")
        previous_account = next((account for account in existing_accounts if (account.identifier or account.email).strip().lower() == identifier), None)
        payload_email = payload.email.strip().lower()
        cached_user = get_cached_session_user()
        cached_email = (cached_user.email or "").strip().lower() if cached_user else ""
        cached_phone = (cached_user.phone or "").strip().lower() if cached_user and cached_user.phone else ""
        cached_identifiers = {value for value in (cached_email, cached_phone) if value}
        use_cached_identity = bool(cached_user and (identifier in cached_identifiers or payload_email in cached_identifiers))
        if use_cached_identity:
            full_name = cached_user.fullName.strip() or (previous_account.fullName if previous_account else "")
            account_email = cached_email or payload_email or identifier
        else:
            full_name = (payload.fullName or "").strip() or (previous_account.fullName if previous_account else "")
            account_email = payload_email or identifier
        password = (payload.password or "").strip()
        if password:
            _remembered_cloud_auth_store(identifier).set_api_key(password)
        updated_account = RememberedCloudAuthAccount(
            email=account_email,
            identifier=identifier,
            fullName=full_name,
            updatedAt=now_iso(),
        )
        next_accounts = [updated_account]
        seen_emails = {identifier}
        for account in existing_accounts:
            normalized_email = (account.identifier or account.email).strip().lower()
            if not normalized_email or normalized_email in seen_emails:
                continue
            seen_emails.add(normalized_email)
            next_accounts.append(
                account.model_copy(
                    update={
                        "identifier": normalized_email,
                        "email": account.email.strip().lower() or normalized_email,
                        "fullName": full_name if normalized_email == identifier and full_name else account.fullName,
                    }
                )
            )
        record = current.model_copy(
            update={
                "cloudAuth": LocalInputMemoryCloudAuth(
                    rememberInputs=True,
                    lastEmail=identifier,
                    accounts=next_accounts[:8],
                )
            }
        )
        _save_local_input_memory_record(record)
        return _hydrate_local_input_memory(record)

    @app.post("/api/v1/local-input-memory/ai", response_model=LocalInputMemoryResponse)
    def save_ai_input_memory(payload: SaveAiInputMemoryPayload) -> LocalInputMemoryResponse:
        current = _get_local_input_memory_record()
        store = _remembered_ai_store()
        api_key = (payload.apiKey or "").strip()
        if payload.rememberApiKey and api_key:
            store.set_api_key(api_key)
            ai_record = LocalInputMemoryAiSettings(rememberApiKey=True)
        else:
            try:
                store.delete_api_key()
            except Exception:
                pass
            ai_record = LocalInputMemoryAiSettings(rememberApiKey=False)
        record = current.model_copy(update={"aiSettings": ai_record})
        _save_local_input_memory_record(record)
        return _hydrate_local_input_memory(record)

