    @app.post("/api/v1/proposals/batch-approve", response_model=ProposalBatchResultRecord)
    def batch_approve_proposals(payload: ProposalBatchActionPayloadRecord) -> ProposalBatchResultRecord:
        proposal_ids = [str(item).strip() for item in payload.proposalIds if str(item).strip()]
        failed_ids: list[str] = []
        succeeded = 0
        decided_by = payload.decidedBy.strip() or "user"
        note = (payload.note or "").strip()
        for proposal_id in proposal_ids:
            try:
                result = approve_proposal_record_v2(
                    state.db,
                    proposal_id=proposal_id,
                    decided_by=decided_by,
                    note=note,
                )
                _enqueue_workspace_refresh_safe(
                    client_id=result.proposal.clientId,
                    source_type="proposal_batch_approve",
                    source_id=result.proposal.id,
                    reason="proposal_batch_approved",
                    scope_type="client",
                    scope_id=result.proposal.clientId,
                    priority="normal",
                )
                succeeded += 1
            except Exception:
                failed_ids.append(proposal_id)
        return ProposalBatchResultRecord(
            total=len(proposal_ids),
            succeeded=succeeded,
            failed=len(failed_ids),
            failedIds=failed_ids,
        )

    @app.post("/api/v1/proposals/batch-reject", response_model=ProposalBatchResultRecord)
    def batch_reject_proposals(payload: ProposalBatchActionPayloadRecord) -> ProposalBatchResultRecord:
        proposal_ids = [str(item).strip() for item in payload.proposalIds if str(item).strip()]
        failed_ids: list[str] = []
        succeeded = 0
        decided_by = payload.decidedBy.strip() or "user"
        note = (payload.note or "").strip() or "人工批量驳回"
        for proposal_id in proposal_ids:
            try:
                proposal = reject_proposal_record_v2(
                    state.db,
                    proposal_id=proposal_id,
                    decided_by=decided_by,
                    reason=note,
                )
                _enqueue_workspace_refresh_safe(
                    client_id=proposal.clientId,
                    source_type="proposal_batch_reject",
                    source_id=proposal.id,
                    reason="proposal_batch_rejected",
                    scope_type="client",
                    scope_id=proposal.clientId,
                    priority="normal",
                )
                succeeded += 1
            except Exception:
                failed_ids.append(proposal_id)
        return ProposalBatchResultRecord(
            total=len(proposal_ids),
            succeeded=succeeded,
            failed=len(failed_ids),
            failedIds=failed_ids,
        )

