    @app.post("/api/v1/proposals/{proposal_id}/execute", response_model=ProposalExecutionResponse)
    def execute_proposal(proposal_id: str, payload: ProposalDecisionPayload) -> ProposalExecutionResponse:
        requested_by = payload.comment.strip() or "user"
        try:
            execution_result = create_execution_ticket_for_proposal(
                state.db,
                proposal_id=proposal_id,
                requested_by=requested_by,
                dry_run=False,
            )
            ticket = execution_result.executionTicket
            if ticket is None:
                proposal = get_proposal_record_v2(state.db, proposal_id=proposal_id)
                return ProposalExecutionResponse(proposal=proposal, executionTicket=None)
            completed_ticket = execute_proposal_ticket(
                state.db,
                ticket_id=ticket.id,
                executor=_execute_ticket_actions,
            )
            proposal = get_proposal_record_v2(state.db, proposal_id=proposal_id)
            _enqueue_workspace_refresh_safe(
                client_id=proposal.clientId,
                source_type="proposal_execute",
                source_id=completed_ticket.id,
                reason="proposal_executed" if completed_ticket.status == "executed" else "proposal_execution_failed",
                scope_type="client",
                scope_id=proposal.clientId,
                priority="high" if completed_ticket.status == "executed" else "normal",
            )
            return ProposalExecutionResponse(proposal=proposal, executionTicket=completed_ticket)
        except KeyError as exc:
            raise HTTPException(status_code=404, detail="Proposal not found") from exc
        except ValueError as exc:
            raise HTTPException(status_code=409, detail=str(exc)) from exc

    @app.post("/api/v1/event-lines/{event_line_id}/attachments")
    def upload_event_line_attachment(
        event_line_id: str,
        file: UploadFile = File(...),
        title: str | None = Form(default=None),
    ) -> dict:
        if not get_cloud_token():
            raise HTTPException(status_code=400, detail="需要登录云端才能上传事件线附件")
        content = file.file.read()
        if not content:
            raise HTTPException(status_code=400, detail="上传内容为空")
        try:
            result = cloud_upload_file(
                f"/api/v1/event-lines/{event_line_id}/attachments",
                file_name=file.filename or "attachment",
                file_content=content,
                content_type=file.content_type or "application/octet-stream",
                form_fields={"title": title or file.filename or "事件线附件"},
            )
            event_line_row = state.db.fetchone("SELECT primary_client_id FROM event_lines WHERE id = ?", (event_line_id,))
            _enqueue_workspace_refresh_safe(
                client_id=str(event_line_row["primary_client_id"]) if event_line_row and event_line_row["primary_client_id"] else None,
                source_type="event_line_attachment_upload",
                source_id=event_line_id,
                reason="event_line_attachment_uploaded",
                scope_type="event_line",
                scope_id=event_line_id,
                priority="normal",
            )
            return result if isinstance(result, dict) else {}
        except HTTPException:
            raise
        except Exception as exc:
            raise HTTPException(status_code=502, detail=f"附件上传失败：{exc}") from exc

    def _build_local_event_line_report_snapshot(event_line_id: str) -> dict:
        import mimetypes

        row = state.db.fetchone("SELECT * FROM event_lines WHERE id = ?", (event_line_id,))
        if not row:
            raise HTTPException(status_code=404, detail="Event line not found")

        activity_rows = state.db.fetchall(
            """
            SELECT *
            FROM event_line_activities
            WHERE event_line_id = ?
            ORDER BY happened_at ASC, created_at ASC
            """,
            (event_line_id,),
        )
        referenced_task_ids: set[str] = set()
        referenced_attachment_ids: set[str] = set()
        for activity in activity_rows:
            metadata = from_json(activity["metadata_json"], {})
            metadata = metadata if isinstance(metadata, dict) else {}
            source_type = str(activity["source_type"] or "")
            source_id = str(activity["source_id"] or "").strip()
            if source_type == "task_activity" and source_id:
                referenced_task_ids.add(source_id)
            for key in ("taskId", "task_id"):
                value = str(metadata.get(key) or "").strip()
                if value:
                    referenced_task_ids.add(value)
            if source_type == "attachment" and source_id:
                referenced_attachment_ids.add(source_id)
            for key in ("attachmentId", "attachment_id", "taskAttachmentId", "task_attachment_id"):
                value = str(metadata.get(key) or "").strip()
                if value:
                    referenced_attachment_ids.add(value)

        def _or_clause(base_field: str, base_value: str, extra_fields: list[tuple[str, set[str]]]) -> tuple[str, list[str]]:
            parts = [f"{base_field} = ?"]
            params = [base_value]
            for field, values in extra_fields:
                normalized = sorted({str(value).strip() for value in values if str(value).strip()})
                if not normalized:
                    continue
                placeholders = ", ".join("?" for _ in normalized)
                parts.append(f"{field} IN ({placeholders})")
                params.extend(normalized)
            return " OR ".join(parts), params

        task_attachment_where, task_attachment_params = _or_clause(
            "event_line_id",
            event_line_id,
            [("id", referenced_attachment_ids), ("task_id", referenced_task_ids)],
        )
        task_attachment_rows = state.db.fetchall(
            f"""
            SELECT id, task_id, title, path, kind, size_bytes, created_at, document_id, 'task_attachment' AS source_kind
            FROM task_attachments
            WHERE {task_attachment_where}
            UNION ALL
            SELECT id, task_id, title, path, kind, size_bytes, created_at, document_id, 'task_attachment' AS source_kind
            FROM task_attachments_cloud
            WHERE {task_attachment_where}
            ORDER BY created_at ASC
            """,
            tuple(task_attachment_params + task_attachment_params),
        )
        for attachment_row in task_attachment_rows:
            task_id = str(attachment_row["task_id"] or "").strip()
            if task_id:
                referenced_task_ids.add(task_id)

        event_attachment_where, event_attachment_params = _or_clause(
            "event_line_id",
            event_line_id,
            [("id", referenced_attachment_ids)],
        )
        event_attachment_rows = state.db.fetchall(
            f"""
            SELECT id, document_id, file_name, file_type, uploaded_by, uploaded_at, local_path, preview_url
            FROM event_line_attachments
            WHERE {event_attachment_where}
            ORDER BY uploaded_at ASC
            """,
            tuple(event_attachment_params),
        )

        def _guess_mime(title: str, path: str = "") -> str | None:
            guessed, _encoding = mimetypes.guess_type(path or title)
            return guessed

        def _size_from_path(path: str) -> int:
            if not path:
                return 0
            try:
                candidate = Path(path)
                return candidate.stat().st_size if candidate.exists() and candidate.is_file() else 0
            except Exception:
                return 0

        def _compact_preview(value: object | None, limit: int = 520) -> str:
            text = " ".join(str(value or "").replace("#", " ").split()).strip()
            if not text:
                return ""
            return text if len(text) <= limit else f"{text[: max(0, limit - 1)].rstrip()}…"

        def _document_parse_info(document_id: str | None) -> dict[str, object]:
            normalized_doc_id = str(document_id or "").strip()
            if not normalized_doc_id:
                return {
                    "documentId": None,
                    "parseStatus": "missing_document",
                    "parsedPreview": "",
                    "chunkCount": 0,
                    "sectionCount": 0,
                }
            document_row = state.db.fetchone("SELECT excerpt FROM documents WHERE id = ?", (normalized_doc_id,))
            v2_row = state.db.fetchone(
                """
                SELECT parse_status, preview_text, markdown_content, markdown_path, chunk_count, section_count
                FROM v2_documents
                WHERE document_id = ?
                LIMIT 1
                """,
                (normalized_doc_id,),
            )
            parse_status = "unparsed"
            preview = ""
            chunk_count = 0
            section_count = 0
            if v2_row:
                parse_status = str(v2_row["parse_status"] or "unparsed")
                chunk_count = int(v2_row["chunk_count"] or 0)
                section_count = int(v2_row["section_count"] or 0)
                preview = _compact_preview(v2_row["preview_text"], 520)
                if not preview:
                    preview = _compact_preview(v2_row["markdown_content"], 520)
                if not preview and v2_row["markdown_path"]:
                    try:
                        markdown_path = Path(str(v2_row["markdown_path"]))
                        if markdown_path.exists() and markdown_path.is_file():
                            preview = _compact_preview(markdown_path.read_text(encoding="utf-8", errors="ignore"), 520)
                    except Exception:
                        preview = ""
            if not preview and document_row:
                preview = _compact_preview(document_row["excerpt"], 520)
            return {
                "documentId": normalized_doc_id,
                "parseStatus": parse_status,
                "parsedPreview": preview,
                "chunkCount": chunk_count,
                "sectionCount": section_count,
            }

        def _resolve_event_attachment_document_id(att) -> str | None:
            existing = str(att["document_id"] or "").strip() if "document_id" in att.keys() else ""
            if existing:
                return existing
            client_id = str(row["primary_client_id"] or "").strip()
            raw_path = str(att["local_path"] or "").strip()
            if not client_id or not raw_path:
                return None
            candidate = Path(raw_path)
            if not candidate.is_absolute():
                candidate = Path(state.data_dir) / raw_path
            if not candidate.exists() or not candidate.is_file():
                return None
            title = str(att["file_name"] or candidate.name or "事件线附件")
            kind = str(att["file_type"] or candidate.suffix.lower().lstrip(".") or "file")
            timestamp = str(att["uploaded_at"] or now_iso())
            existing_doc = state.db.fetchone(
                "SELECT id FROM documents WHERE client_id = ? AND path = ? LIMIT 1",
                (client_id, str(candidate)),
            )
            if existing_doc:
                document_id = str(existing_doc["id"])
            else:
                folder_row = state.db.fetchone(
                    "SELECT id FROM client_folders WHERE client_id = ? AND label = ?",
                    (client_id, "项目与业务"),
                )
                document_id = new_id("doc")
                fallback_excerpt = f"{title} 已作为事件线附件进入项目资料库，可用于后续检索、问答与事件线证据引用。"
                state.db.execute(
                    """
                    INSERT INTO documents(id, client_id, folder_id, title, path, original_source_path, kind, source, excerpt, tags_json, created_at)
                    VALUES(?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                    """,
                    (
                        document_id,
                        client_id,
                        str(folder_row["id"]) if folder_row else None,
                        title,
                        str(candidate),
                        str(candidate),
                        kind,
                        "event_line_attachment",
                        fallback_excerpt,
                        to_json(["event_line_attachment", kind]),
                        timestamp,
                    ),
                )
                ingest_document_knowledge(
                    state.db,
                    data_dir=state.data_dir,
                    client_id=client_id,
                    import_id=None,
                    document_id=document_id,
                    source_path=candidate,
                    original_source_path=candidate,
                    title=title,
                    kind=kind,
                    source="event_line_attachment",
                    fallback_excerpt=fallback_excerpt,
                    created_at=timestamp,
                    ai_service=None,
                )
            state.db.execute(
                "UPDATE event_line_attachments SET document_id = ? WHERE id = ?",
                (document_id, str(att["id"])),
            )
            return document_id

        attachments: list[dict[str, object]] = []
        for att in task_attachment_rows:
            title = str(att["title"] or "任务附件")
            path = str(att["path"] or "")
            size_bytes = int(att["size_bytes"] or 0) or _size_from_path(path)
            parse_info = _document_parse_info(str(att["document_id"] or ""))
            attachments.append(
                {
                    "id": str(att["id"]),
                    "taskId": str(att["task_id"]),
                    "documentId": parse_info["documentId"],
                    "sourceKind": "task_attachment",
                    "title": title,
                    "fileName": title,
                    "kind": str(att["kind"] or "attachment"),
                    "mimeType": _guess_mime(title, path),
                    "sizeBytes": size_bytes,
                    "downloadUrl": f"/api/public/task-attachments/{att['id']}",
                    "openUrl": f"/api/public/task-attachments/{att['id']}",
                    "actorName": None,
                    "createdAt": str(att["created_at"]),
                    "parseStatus": parse_info["parseStatus"],
                    "parsedPreview": parse_info["parsedPreview"],
                    "chunkCount": parse_info["chunkCount"],
                    "sectionCount": parse_info["sectionCount"],
                }
            )
        for att in event_attachment_rows:
            path = str(att["local_path"] or "")
            title = str(att["file_name"] or (Path(path).name if path else "事件线附件"))
            document_id = _resolve_event_attachment_document_id(att)
            parse_info = _document_parse_info(document_id)
            if not parse_info["documentId"]:
                raw_path = Path(path) if path else None
                if raw_path and not raw_path.is_absolute():
                    raw_path = Path(state.data_dir) / path
                if not raw_path or not raw_path.exists() or not raw_path.is_file():
                    parse_info["parseStatus"] = "missing_source"
            attachments.append(
                {
                    "id": str(att["id"]),
                    "taskId": "",
                    "documentId": parse_info["documentId"],
                    "sourceKind": "event_line_attachment",
                    "title": title,
                    "fileName": title,
                    "kind": str(att["file_type"] or "event_line_attachment"),
                    "mimeType": _guess_mime(title, path),
                    "sizeBytes": _size_from_path(path),
                    "downloadUrl": str(att["preview_url"] or f"/api/public/task-attachments/{att['id']}"),
                    "openUrl": str(att["preview_url"] or f"/api/public/task-attachments/{att['id']}"),
                    "actorName": str(att["uploaded_by"]) if att["uploaded_by"] else None,
                    "createdAt": str(att["uploaded_at"] or now_iso()),
                    "parseStatus": parse_info["parseStatus"],
                    "parsedPreview": parse_info["parsedPreview"],
                    "chunkCount": parse_info["chunkCount"],
                    "sectionCount": parse_info["sectionCount"],
                }
            )

        participant_names: list[str] = []
        for participant_id in [str(item) for item in from_json(row["participant_ids_json"], []) if str(item).strip()]:
            operator_row = state.db.fetchone("SELECT name FROM operators WHERE id = ?", (participant_id,))
            if operator_row and operator_row["name"]:
                participant_names.append(str(operator_row["name"]))

        task_where = "t.event_line_id = ?"
        task_params: list[str] = [event_line_id]
        normalized_task_ids = sorted({task_id for task_id in referenced_task_ids if task_id})
        if normalized_task_ids:
            placeholders = ", ".join("?" for _ in normalized_task_ids)
            task_where = f"t.event_line_id = ? OR t.id IN ({placeholders})"
            task_params.extend(normalized_task_ids)
        event_line_payload = build_event_line(row).model_dump(mode="json")
        activities_payload = [build_event_line_activity(item).model_dump(mode="json") for item in activity_rows]
        tasks_payload = [task.model_dump(mode="json") for task in fetch_tasks(shared_task_where(f"({task_where})"), tuple(task_params))]
        snapshot_at = now_iso()
        timeline_nodes = build_event_line_timeline_nodes(
            event_line=event_line_payload,
            tasks=tasks_payload,
            activities=activities_payload,
            attachments=attachments,
            snapshot_at=snapshot_at,
        )

        return {
            "eventLine": event_line_payload,
            "activities": activities_payload,
            "tasks": tasks_payload,
            "attachments": attachments,
            "participantNames": participant_names,
            "snapshotAt": snapshot_at,
            "timelineNodes": timeline_nodes,
        }

    def _compact_report_document_preview(value: object | None, limit: int = 520) -> str:
        text = " ".join(str(value or "").replace("#", " ").split()).strip()
        if not text:
            return ""
        return text if len(text) <= limit else f"{text[: max(0, limit - 1)].rstrip()}…"

    def _local_report_document_parse_info(document_id: str | None) -> dict[str, object]:
        normalized_doc_id = str(document_id or "").strip()
        if not normalized_doc_id:
            return {
                "documentId": None,
                "parseStatus": "missing_document",
                "parsedPreview": "",
                "chunkCount": 0,
                "sectionCount": 0,
            }
        document_row = state.db.fetchone("SELECT excerpt FROM documents WHERE id = ?", (normalized_doc_id,))
        v2_row = state.db.fetchone(
            """
            SELECT parse_status, preview_text, markdown_content, markdown_path, chunk_count, section_count
            FROM v2_documents
            WHERE document_id = ?
            LIMIT 1
            """,
            (normalized_doc_id,),
        )
        parse_status = "unparsed"
        preview = ""
        chunk_count = 0
        section_count = 0
        if v2_row:
            parse_status = str(v2_row["parse_status"] or "unparsed")
            chunk_count = int(v2_row["chunk_count"] or 0)
            section_count = int(v2_row["section_count"] or 0)
            preview = _compact_report_document_preview(v2_row["preview_text"], 520)
            if not preview:
                preview = _compact_report_document_preview(v2_row["markdown_content"], 520)
            if not preview and v2_row["markdown_path"]:
                try:
                    markdown_path = Path(str(v2_row["markdown_path"]))
                    if markdown_path.exists() and markdown_path.is_file():
                        preview = _compact_report_document_preview(markdown_path.read_text(encoding="utf-8", errors="ignore"), 520)
                except Exception:
                    preview = ""
        if not preview and document_row:
            preview = _compact_report_document_preview(document_row["excerpt"], 520)
        return {
            "documentId": normalized_doc_id,
            "parseStatus": parse_status,
            "parsedPreview": preview,
            "chunkCount": chunk_count,
            "sectionCount": section_count,
        }

    def _event_line_primary_client_id(event_line_id: str) -> str:
        row = state.db.fetchone("SELECT primary_client_id FROM event_lines WHERE id = ?", (event_line_id,))
        return str(row["primary_client_id"] or "").strip() if row else ""

    def _document_id_for_report_attachment(attachment_id: str) -> str:
        if not attachment_id:
            return ""
        for table in ("task_attachments_cloud", "task_attachments", "event_line_attachments"):
            row = state.db.fetchone(f"SELECT document_id FROM {table} WHERE id = ?", (attachment_id,))
            if row and row["document_id"]:
                return str(row["document_id"])
        return ""

    def _ensure_cloud_event_attachment_document(event_line_id: str, attachment: dict) -> str | None:
        attachment_id = str(attachment.get("id") or "").strip()
        if not attachment_id:
            return None
        existing = state.db.fetchone("SELECT document_id FROM event_line_attachments WHERE id = ?", (attachment_id,))
        if existing and existing["document_id"]:
            return str(existing["document_id"])
        client_id = _event_line_primary_client_id(event_line_id)
        if not client_id:
            return None
        download_url = str(attachment.get("downloadUrl") or "").strip()
        if not download_url:
            return None
        title = safe_filename(str(attachment.get("title") or "事件线附件"))
        timestamp = str(attachment.get("createdAt") or now_iso())
        kind = str(attachment.get("kind") or Path(title).suffix.lower().lstrip(".") or "file")
        target_dir = state.data_dir / "event-line-attachments" / "cloud-cache" / event_line_id
        target_dir.mkdir(parents=True, exist_ok=True)
        target_path = target_dir / safe_filename(f"{attachment_id}_{title}")
        try:
            if not target_path.exists():
                url = download_url if download_url.startswith("http") else f"{cloud_api_base_url()}{download_url}"
                response = httpx.get(url, timeout=20.0)
                if response.status_code >= 400 or not response.content:
                    return None
                target_path.write_bytes(response.content)
        except Exception as exc:
            logger.warning("event line cloud attachment download failed: %s", exc)
            return None

        existing_doc = state.db.fetchone(
            "SELECT id FROM documents WHERE client_id = ? AND path = ? LIMIT 1",
            (client_id, str(target_path)),
        )
        if existing_doc:
            document_id = str(existing_doc["id"])
        else:
            folder_row = state.db.fetchone(
                "SELECT id FROM client_folders WHERE client_id = ? AND label = ?",
                (client_id, "项目与业务"),
            )
            document_id = new_id("doc")
            fallback_excerpt = f"{title} 已作为事件线附件进入项目资料库，可用于后续检索、问答与事件线证据引用。"
            state.db.execute(
                """
                INSERT INTO documents(id, client_id, folder_id, title, path, original_source_path, kind, source, excerpt, tags_json, created_at)
                VALUES(?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                (
                    document_id,
                    client_id,
                    str(folder_row["id"]) if folder_row else None,
                    title,
                    str(target_path),
                    str(target_path),
                    kind,
                    "event_line_attachment",
                    fallback_excerpt,
                    to_json(["event_line_attachment", kind]),
                    timestamp,
                ),
            )
            try:
                ingest_document_knowledge(
                    state.db,
                    data_dir=state.data_dir,
                    client_id=client_id,
                    import_id=None,
                    document_id=document_id,
                    source_path=target_path,
                    original_source_path=target_path,
                    title=title,
                    kind=kind,
                    source="event_line_attachment",
                    fallback_excerpt=fallback_excerpt,
                    created_at=timestamp,
                    ai_service=None,
                )
            except Exception as exc:
                logger.warning("event line attachment ingest failed: %s", exc)
        state.db.execute(
            """
            INSERT INTO event_line_attachments(
                id, event_line_id, document_id, file_name, file_type, display_mode,
                description, uploaded_by, uploaded_at, local_path, preview_url
            )
            VALUES(?, ?, ?, ?, ?, 'collapsed', ?, ?, ?, ?, ?)
            ON CONFLICT(id) DO UPDATE SET
                document_id = excluded.document_id,
                local_path = excluded.local_path,
                preview_url = excluded.preview_url
            """,
            (
                attachment_id,
                event_line_id,
                document_id,
                title,
                kind,
                str(attachment.get("summary") or ""),
                str(attachment.get("actorName") or ""),
                timestamp,
                str(target_path),
                download_url,
            ),
        )
        return document_id

    def _enrich_report_snapshot_with_local_parse(payload: dict, event_line_id: str) -> dict:
        import mimetypes

        attachments = payload.get("attachments")
        if not isinstance(attachments, list):
            attachments = []
            payload["attachments"] = attachments
        existing_attachment_ids = {
            str(attachment.get("id") or "").strip()
            for attachment in attachments
            if isinstance(attachment, dict)
        }

        def _attachment_signature(item: dict) -> tuple[str, int, str]:
            return (
                str(item.get("title") or "").strip(),
                int(item.get("sizeBytes") or item.get("size_bytes") or 0),
                str(item.get("createdAt") or item.get("created_at") or "")[:16],
            )

        existing_by_signature = {
            _attachment_signature(attachment): attachment
            for attachment in attachments
            if isinstance(attachment, dict) and str(attachment.get("title") or "").strip()
        }
        local_attachment_rows = state.db.fetchall(
            """
            SELECT id, task_id, title, path, kind, size_bytes, created_at, document_id, 'task_attachment' AS source_kind
            FROM task_attachments_cloud
            WHERE event_line_id = ?
            UNION ALL
            SELECT id, task_id, title, path, kind, size_bytes, created_at, document_id, 'task_attachment' AS source_kind
            FROM task_attachments
            WHERE event_line_id = ?
            ORDER BY created_at ASC
            """,
            (event_line_id, event_line_id),
        )
        for row in local_attachment_rows:
            attachment_id = str(row["id"] or "").strip()
            if not attachment_id or attachment_id in existing_attachment_ids:
                continue
            title = str(row["title"] or "任务附件")
            path = str(row["path"] or "")
            guessed_mime, _encoding = mimetypes.guess_type(path or title)
            parse_info = _local_report_document_parse_info(str(row["document_id"] or ""))
            signature = (
                title,
                int(row["size_bytes"] or 0),
                str(row["created_at"] or "")[:16],
            )
            existing_mirror = existing_by_signature.get(signature)
            if existing_mirror is not None:
                if not str(existing_mirror.get("taskId") or "").strip():
                    existing_mirror["taskId"] = str(row["task_id"] or "")
                if parse_info["documentId"]:
                    existing_mirror["documentId"] = parse_info["documentId"]
                    existing_mirror["parseStatus"] = parse_info["parseStatus"]
                    existing_mirror["parsedPreview"] = parse_info["parsedPreview"]
                    existing_mirror["chunkCount"] = parse_info["chunkCount"]
                    existing_mirror["sectionCount"] = parse_info["sectionCount"]
                existing_mirror.setdefault("sourceKind", "task_attachment")
                existing_mirror.setdefault("fileName", title)
                existing_mirror.setdefault("downloadUrl", f"/api/public/task-attachments/{attachment_id}")
                existing_mirror.setdefault("openUrl", existing_mirror.get("downloadUrl") or f"/api/public/task-attachments/{attachment_id}")
                if not str(existing_mirror.get("mimeType") or "").strip():
                    existing_mirror["mimeType"] = guessed_mime
                continue
            attachments.append(
                {
                    "id": attachment_id,
                    "taskId": str(row["task_id"] or ""),
                    "documentId": parse_info["documentId"],
                    "sourceKind": "task_attachment",
                    "title": title,
                    "fileName": title,
                    "kind": str(row["kind"] or "attachment"),
                    "mimeType": guessed_mime,
                    "sizeBytes": int(row["size_bytes"] or 0),
                    "downloadUrl": f"/api/public/task-attachments/{attachment_id}",
                    "openUrl": f"/api/public/task-attachments/{attachment_id}",
                    "actorName": None,
                    "createdAt": str(row["created_at"] or now_iso()),
                    "parseStatus": parse_info["parseStatus"],
                    "parsedPreview": parse_info["parsedPreview"],
                    "chunkCount": parse_info["chunkCount"],
                    "sectionCount": parse_info["sectionCount"],
                }
            )
            existing_attachment_ids.add(attachment_id)
            existing_by_signature[signature] = attachments[-1]

        tasks_payload = payload.get("tasks")
        if not isinstance(tasks_payload, list):
            tasks_payload = []
            payload["tasks"] = tasks_payload
        existing_task_ids = {
            str(task.get("id") or "").strip()
            for task in tasks_payload
            if isinstance(task, dict)
        }
        referenced_task_ids = sorted({
            str(attachment.get("taskId") or "").strip()
            for attachment in attachments
            if isinstance(attachment, dict) and str(attachment.get("taskId") or "").strip()
        })
        missing_task_ids = [task_id for task_id in referenced_task_ids if task_id not in existing_task_ids]
        if missing_task_ids:
            placeholders = ", ".join("?" for _ in missing_task_ids)
            try:
                tasks_payload.extend(
                    task.model_dump(mode="json")
                    for task in fetch_tasks(shared_task_where(f"t.id IN ({placeholders})"), tuple(missing_task_ids))
                    if task.id not in existing_task_ids
                )
            except Exception as exc:
                logger.warning("event line snapshot local task enrichment failed: %s", exc)
        for attachment in attachments:
            if not isinstance(attachment, dict):
                continue
            document_id = str(attachment.get("documentId") or "").strip()
            if not document_id:
                document_id = _document_id_for_report_attachment(str(attachment.get("id") or "").strip())
            if not document_id and str(attachment.get("sourceKind") or "") == "event_line_attachment":
                document_id = _ensure_cloud_event_attachment_document(event_line_id, attachment) or ""
            parse_info = _local_report_document_parse_info(document_id)
            if parse_info["documentId"]:
                attachment["documentId"] = parse_info["documentId"]
                attachment["parseStatus"] = parse_info["parseStatus"]
                attachment["chunkCount"] = parse_info["chunkCount"]
                attachment["sectionCount"] = parse_info["sectionCount"]
                parsed_preview = str(parse_info["parsedPreview"] or "").strip()
                if parsed_preview:
                    attachment["parsedPreview"] = parsed_preview
            else:
                attachment.setdefault("documentId", None)
                attachment.setdefault("parseStatus", "missing_document")
                attachment.setdefault("parsedPreview", "")
                attachment.setdefault("chunkCount", 0)
                attachment.setdefault("sectionCount", 0)
            attachment.setdefault("fileName", str(attachment.get("title") or "附件"))
            attachment.setdefault("downloadUrl", f"/api/public/task-attachments/{str(attachment.get('id') or '').strip()}")
            attachment.setdefault("openUrl", attachment.get("downloadUrl"))
        event_line_payload = payload.get("eventLine")
        activities_payload = payload.get("activities")
        tasks_payload = payload.get("tasks")
        if isinstance(event_line_payload, dict):
            payload["timelineNodes"] = build_event_line_timeline_nodes(
                event_line=event_line_payload,
                tasks=[item for item in tasks_payload if isinstance(item, dict)] if isinstance(tasks_payload, list) else [],
                activities=[item for item in activities_payload if isinstance(item, dict)] if isinstance(activities_payload, list) else [],
                attachments=[item for item in attachments if isinstance(item, dict)],
                snapshot_at=str(payload.get("snapshotAt") or now_iso()),
            )
        return payload

    @app.get("/api/v1/event-lines/{event_line_id}/report-snapshot")
    def get_event_line_report_snapshot(event_line_id: str) -> dict:
        cloud_error: HTTPException | None = None
        if get_cloud_token():
            try:
                payload = cloud_request("GET", f"/api/v1/event-lines/{event_line_id}/report-snapshot")
                if not isinstance(payload, dict):
                    raise HTTPException(status_code=502, detail="Invalid report snapshot payload")
                return _enrich_report_snapshot_with_local_parse(payload, event_line_id)
            except HTTPException as exc:
                cloud_error = exc

        try:
            return _build_local_event_line_report_snapshot(event_line_id)
        except HTTPException as local_exc:
            if local_exc.status_code == 404 and cloud_error is not None:
                raise cloud_error
            raise

    @app.post("/api/v1/event-lines/{event_line_id}/export-word")
    def export_event_line_word(event_line_id: str, draft: dict = Body(...)) -> dict:
        from docx.shared import Pt, Cm, Inches, RGBColor
        from docx.enum.text import WD_ALIGN_PARAGRAPH
        from docx.oxml.ns import qn

        doc = WordDocument()

        event_line_kind_labels = {
            "project_line": "项目线",
            "issue_line": "议题线",
            "coordination_line": "协同线",
            "case_line": "案例线",
            "custom": "事件线",
        }
        event_line_status_labels = {
            "active": "推进中",
            "blocked": "存在阻点",
            "paused": "暂缓中",
            "done": "已完成",
            "archived": "已归档",
        }

        def _clean_text(value: object | None) -> str:
            return " ".join(str(value or "").split()).strip()

        def _truncate_text(value: object | None, limit: int) -> str:
            normalized = _clean_text(value)
            if not normalized:
                return ""
            if len(normalized) <= limit:
                return normalized
            return f"{normalized[: max(0, limit - 1)].rstrip()}…"

        def _format_doc_date(value: object | None) -> str:
            normalized = _clean_text(value)
            if not normalized:
                return "待补充"
            return normalized[:10].replace("-", ".")

        def _activity_title(activity: dict) -> str:
            return _clean_text(activity.get("editedTitle") or activity.get("title") or "未命名活动")

        def _activity_summary(activity: dict) -> str:
            return _clean_text(activity.get("editedSummary") or activity.get("summary") or "")

        def _is_key(activity: dict) -> bool:
            if activity.get("isKey") is not None:
                return bool(activity["isKey"])
            source_type = str(activity.get("sourceType", ""))
            if source_type in ("manual_note", "attachment"):
                return True
            metadata = activity.get("metadata") or {}
            if source_type == "task_activity" and isinstance(metadata, dict) and metadata.get("eventType") == "created":
                return True
            return False

        def _is_bootstrap_activity(activity: dict) -> bool:
            source_type = str(activity.get("sourceType", ""))
            metadata = activity.get("metadata") or {}
            event_type = str(metadata.get("eventType", "")).lower() if isinstance(metadata, dict) else ""
            if source_type == "task_activity" and event_type == "created":
                return True
            if event_type in {"event_line_created", "line_created"}:
                return True
            text = f"{_activity_title(activity)} {_activity_summary(activity)}".lower()
            return "创建事件线" in text or "created event line" in text

        def _attachment_family_label(att: dict) -> str:
            mime = str(att.get("mimeType") or att.get("mime_type") or "")
            title = str(att.get("title") or "")
            lower_title = title.lower()
            if mime.startswith("image/") or lower_title.endswith((".jpg", ".jpeg", ".png", ".gif", ".webp")):
                return "图像证据"
            if lower_title.endswith(".pdf"):
                return "PDF 资料"
            if lower_title.endswith((".doc", ".docx")):
                return "Word 文档"
            if lower_title.endswith((".xls", ".xlsx")):
                return "表格资料"
            if lower_title.endswith((".ppt", ".pptx")):
                return "汇报材料"
            return "补充资料"

        def _dedupe_texts(items: list[str]) -> list[str]:
            seen: set[str] = set()
            results: list[str] = []
            for item in items:
                normalized = _clean_text(item)
                if not normalized or normalized in seen:
                    continue
                seen.add(normalized)
                results.append(normalized)
            return results

        def _build_core_judgment(
            blocker_text: str,
            decision_text: str,
            next_step_text: str,
            latest_signals: list[str],
        ) -> str:
            if decision_text and next_step_text:
                return f"已形成“{_truncate_text(decision_text, 28)}”，当前要把“{_truncate_text(next_step_text, 28)}”继续推进到明确结果。"
            if blocker_text and next_step_text:
                return f"当前卡点是“{_truncate_text(blocker_text, 28)}”，需要围绕“{_truncate_text(next_step_text, 28)}”继续收束责任人与时间点。"
            if decision_text:
                return f"最近已经形成“{_truncate_text(decision_text, 34)}”，下一步重点是确认这个判断是否真正带动了后续推进。"
            if next_step_text:
                return f"当前最需要盯住的是“{_truncate_text(next_step_text, 34)}”，确保这一步不再停留在口头判断。"
            if len(latest_signals) >= 2:
                return f"最近的关键推进集中在“{_truncate_text(latest_signals[0], 26)}”和“{_truncate_text(latest_signals[1], 26)}”。"
            if len(latest_signals) == 1:
                return f"目前最值得关注的进展是“{_truncate_text(latest_signals[0], 40)}”。"
            return "当前资料不足，建议先补活动记录、阶段判断或附件材料，再生成对外汇报。"

        # ── Page setup ──
        section = doc.sections[0]
        section.page_width = Cm(21)
        section.page_height = Cm(29.7)
        section.top_margin = Cm(2.5)
        section.bottom_margin = Cm(2)
        section.left_margin = Cm(2.5)
        section.right_margin = Cm(2.5)

        event_line_name = str(draft.get("eventLineName", "事件线汇报"))
        summary = str(draft.get("summary", ""))
        participants = draft.get("participantNames", [])
        snapshot_at = str(draft.get("snapshotAt", now_iso()))

        # ── Gather cover data ──
        el_row = state.db.fetchone("SELECT * FROM event_lines WHERE id = ?", (event_line_id,))
        client_name = ""
        owner_name = ""
        stage = ""
        created_at = ""
        event_line_status = "archived"
        event_line_kind = "custom"
        event_line_intent = ""
        event_line_summary = ""
        current_blocker = ""
        recent_decision = ""
        next_step = ""
        if el_row:
            client_name = str(el_row["primary_client_name"] or "")
            owner_name = str(el_row["owner_name"] or "")
            stage = str(el_row["stage"] or "")
            created_at = str(el_row["created_at"] or "")[:10]
            event_line_status = str(el_row["status"] or "archived")
            event_line_kind = str(el_row["kind"] or "custom")
            event_line_intent = str(el_row["intent"] or "")
            event_line_summary = str(el_row["summary"] or "")
            current_blocker = str(el_row["current_blocker"] or "")
            recent_decision = str(el_row["recent_decision"] or "")
            next_step = str(el_row["next_step"] or "")

        activities = draft.get("activities", [])
        visible_activities = [a for a in activities if not a.get("hidden")]
        attachments = draft.get("attachments", [])
        tasks = draft.get("tasks", [])
        timeline_nodes = [item for item in draft.get("timelineNodes", []) if isinstance(item, dict)]
        if not timeline_nodes:
            try:
                snapshot_payload = get_event_line_report_snapshot(event_line_id)
                if isinstance(snapshot_payload, dict):
                    timeline_nodes = [
                        item
                        for item in snapshot_payload.get("timelineNodes", [])
                        if isinstance(item, dict)
                    ]
            except Exception as exc:
                logger.warning("event line export timeline fallback failed: %s", exc)

        sorted_visible_activities = sorted(visible_activities, key=lambda item: str(item.get("happenedAt", "")))
        meaningful_activities = [item for item in sorted_visible_activities if not _is_bootstrap_activity(item)]
        key_activities = [item for item in meaningful_activities if _is_key(item)]
        milestone_source = key_activities or meaningful_activities
        latest_milestone = milestone_source[-1] if milestone_source else None
        latest_milestone_signal = (_activity_summary(latest_milestone) or _activity_title(latest_milestone)) if latest_milestone else ""
        latest_signals = [
            (_activity_summary(item) or _activity_title(item))
            for item in reversed(milestone_source[-2:])
        ]
        kind_label = event_line_kind_labels.get(event_line_kind, "事件线")
        status_label = event_line_status_labels.get(event_line_status, event_line_status or "已归档")
        report_subtitle = f"{client_name} · {kind_label}汇报" if _clean_text(client_name) else f"{kind_label}汇报"
        task_count = len(tasks)
        attachment_count = len(attachments)
        has_narrative_evidence = any(
            len(_clean_text(value)) >= 6
            for value in [
                event_line_intent,
                summary,
                event_line_summary,
                current_blocker,
                recent_decision,
                next_step,
            ]
        )
        has_renderable_content = (
            len(timeline_nodes) > 0
            or len(meaningful_activities) >= 2
            or (len(meaningful_activities) >= 1 and (attachment_count > 0 or task_count > 0))
            or has_narrative_evidence
            or attachment_count > 0
            or task_count >= 2
        )
        event_line_name = _clean_text(event_line_name or (str(el_row["name"]) if el_row else "")) or "事件线汇报"
        summary_fallback = "当前资料不足，暂无法生成模拟汇报。请先补充活动说明、阶段判断或附件材料。"
        summary_source = (
            _clean_text(event_line_intent)
            or _clean_text(summary)
            or _clean_text(event_line_summary)
            or (latest_milestone_signal if has_renderable_content else "")
        )
        summary = _truncate_text(
            summary_source or summary_fallback,
            180,
        ) or summary_fallback
        core_judgment = _build_core_judgment(
            _clean_text(current_blocker),
            _clean_text(recent_decision),
            _clean_text(next_step),
            latest_signals,
        )
        core_judgment_note = " · ".join(_dedupe_texts([
            f"最近决策：{_truncate_text(recent_decision, 28)}" if _clean_text(recent_decision) else "",
            f"当前阻点：{_truncate_text(current_blocker, 28)}" if _clean_text(current_blocker) else "",
            f"下一步：{_truncate_text(next_step, 28)}" if _clean_text(next_step) else "",
            f"最近关键活动 {len(milestone_source)} 条" if milestone_source else "",
        ])[:2]) or "当前仅能基于已有快照生成基础判断，建议继续补充活动说明与附件。"
        completed_task_count = sum(1 for task in tasks if str(task.get("status", "")) == "done")
        pending_task_count = sum(1 for task in tasks if str(task.get("status", "")) not in {"done", "rejected"})

        family_counts: dict[str, int] = {}
        for attachment in attachments:
            family = _attachment_family_label(attachment)
            family_counts[family] = family_counts.get(family, 0) + 1
        family_entries = sorted(family_counts.items(), key=lambda item: (-item[1], item[0]))
        family_summary = "、".join([f"{label}{count}份" for label, count in family_entries[:3]]) if family_entries else "暂无附件材料"

        # Count by source type
        source_counts: dict[str, int] = {}
        for a in visible_activities:
            st = str(a.get("sourceType", ""))
            source_counts[st] = source_counts.get(st, 0) + 1

        source_labels_cn = {
            "task_activity": "任务动态",
            "meeting": "会议纪要",
            "support_request": "支持请求",
            "review": "复核审批",
            "attachment": "文档附件",
            "manual_note": "工作备注",
        }
        category_parts = [f"{source_labels_cn.get(k, k)} {v}" for k, v in source_counts.items() if v > 0]

        export_date = snapshot_at[:10]
        start_date = str(sorted_visible_activities[0].get("happenedAt", ""))[:10] if sorted_visible_activities else (created_at or export_date)
        end_date = str(sorted_visible_activities[-1].get("happenedAt", ""))[:10] if sorted_visible_activities else export_date
        review_window = f"{_format_doc_date(start_date)} - {_format_doc_date(end_date)}"
        stage_badge = " · ".join([part for part in [_clean_text(stage), status_label] if part]) or kind_label
        content_scale_value = f"节点 {len(timeline_nodes)} / 活动 {len(sorted_visible_activities)}" if timeline_nodes else f"关键 {len(milestone_source)} / 活动 {len(sorted_visible_activities)}"
        content_scale_note = f"附件 {attachment_count} · 任务 {task_count}"
        org_model_profile = _load_org_model_profile_safe()
        organization_label = ""
        if org_model_profile:
            organization_label = _clean_text(org_model_profile.organization.name)
        if not organization_label:
            organization_label = _clean_text(client_name) or "当前组织"

        # Days span
        try:
            from datetime import datetime as _dt
            d1 = _dt.fromisoformat(start_date)
            d2 = _dt.fromisoformat(end_date)
            days_span = max((d2 - d1).days, 1)
        except Exception:
            days_span = 0

        brand_color = RGBColor(0x5B, 0x7B, 0xFE)
        dark_color = RGBColor(0x1A, 0x1A, 0x1A)
        mid_gray = RGBColor(0x6B, 0x72, 0x80)
        light_gray = RGBColor(0x9C, 0xA3, 0xAF)

        # ══════════════════════════════════════════════
        #  COVER PAGE
        # ══════════════════════════════════════════════

        # ── Top line: 组织名 · 事件线汇报 ──
        p = doc.add_paragraph()
        p.alignment = WD_ALIGN_PARAGRAPH.LEFT
        run = p.add_run(organization_label)
        run.font.size = Pt(11)
        run.font.color.rgb = brand_color
        run.font.bold = True
        run = p.add_run("  ·  事件线汇报")
        run.font.size = Pt(11)
        run.font.color.rgb = light_gray

        # ── Brand color thin line ──
        p = doc.add_paragraph()
        p.paragraph_format.space_before = Pt(4)
        p.paragraph_format.space_after = Pt(0)
        pPr = p._p.get_or_add_pPr()
        pBdr = pPr.makeelement(qn("w:pBdr"), {})
        bottom = pBdr.makeelement(qn("w:bottom"), {
            qn("w:val"): "single",
            qn("w:sz"): "4",
            qn("w:space"): "1",
            qn("w:color"): "5B7BFE",
        })
        pBdr.append(bottom)
        pPr.append(pBdr)

        # ── Spacer ──
        for _ in range(3):
            sp = doc.add_paragraph()
            sp.paragraph_format.space_before = Pt(0)
            sp.paragraph_format.space_after = Pt(0)
            sp.add_run(" ").font.size = Pt(6)

        # ── Subtitle ──
        if report_subtitle:
            p = doc.add_paragraph()
            p.alignment = WD_ALIGN_PARAGRAPH.LEFT
            p.paragraph_format.space_after = Pt(4)
            run = p.add_run(report_subtitle)
            run.font.size = Pt(12)
            run.font.color.rgb = mid_gray

        # ── Main title ──
        p = doc.add_paragraph()
        p.alignment = WD_ALIGN_PARAGRAPH.LEFT
        p.paragraph_format.space_before = Pt(4)
        p.paragraph_format.space_after = Pt(8)
        run = p.add_run(event_line_name)
        run.font.size = Pt(36)
        run.font.bold = True
        run.font.color.rgb = dark_color

        # ── Stage badge ──
        if stage_badge:
            p = doc.add_paragraph()
            p.alignment = WD_ALIGN_PARAGRAPH.LEFT
            p.paragraph_format.space_after = Pt(12)
            run = p.add_run(f"  {stage_badge}  ")
            run.font.size = Pt(10)
            run.font.bold = True
            run.font.color.rgb = brand_color
            # Use shading as badge background
            shd = run._r.get_or_add_rPr().makeelement(qn("w:shd"), {
                qn("w:val"): "clear",
                qn("w:color"): "auto",
                qn("w:fill"): "E8EEFF",
            })
            run._r.get_or_add_rPr().append(shd)

        # ── Summary (max 3 lines) ──
        if summary:
            lines = summary.strip().split("\n")[:3]
            display_summary = "\n".join(lines)
            if len(summary.strip().split("\n")) > 3:
                display_summary += "……"
            p = doc.add_paragraph()
            p.alignment = WD_ALIGN_PARAGRAPH.LEFT
            p.paragraph_format.space_after = Pt(20)
            run = p.add_run(display_summary[:200])
            run.font.size = Pt(12)
            run.font.color.rgb = mid_gray

        # ── Current judgment ──
        if core_judgment:
            p = doc.add_paragraph()
            p.alignment = WD_ALIGN_PARAGRAPH.LEFT
            p.paragraph_format.space_after = Pt(6)
            run = p.add_run(core_judgment)
            run.font.size = Pt(20)
            run.font.bold = True
            run.font.color.rgb = dark_color

        if core_judgment_note:
            p = doc.add_paragraph()
            p.alignment = WD_ALIGN_PARAGRAPH.LEFT
            p.paragraph_format.space_after = Pt(14)
            run = p.add_run(core_judgment_note[:180])
            run.font.size = Pt(10)
            run.font.color.rgb = light_gray

        # ── Spacer before stats ──
        for _ in range(2):
            sp = doc.add_paragraph()
            sp.paragraph_format.space_before = Pt(0)
            sp.paragraph_format.space_after = Pt(0)
            sp.add_run(" ").font.size = Pt(6)

        # ── Thin line before stats ──
        p = doc.add_paragraph()
        p.paragraph_format.space_before = Pt(0)
        p.paragraph_format.space_after = Pt(12)
        pPr = p._p.get_or_add_pPr()
        pBdr = pPr.makeelement(qn("w:pBdr"), {})
        top_line = pBdr.makeelement(qn("w:top"), {
            qn("w:val"): "single",
            qn("w:sz"): "4",
            qn("w:space"): "1",
            qn("w:color"): "5B7BFE",
        })
        pBdr.append(top_line)
        pPr.append(pBdr)

        # ── Stats row — 3 columns table ──
        stat_items = [
            ("汇报类型", "事件线汇报", f"{kind_label} · {status_label}"),
            ("时间范围", review_window, f"快照日期 {_format_doc_date(snapshot_at)}"),
            ("内容规模", content_scale_value, content_scale_note),
        ]
        stats_table = doc.add_table(rows=3, cols=3)
        stats_table.alignment = WD_ALIGN_PARAGRAPH.CENTER
        for i, (label, value, note) in enumerate(stat_items):
            cell = stats_table.cell(0, i)
            cell.text = ""
            p = cell.paragraphs[0]
            p.alignment = WD_ALIGN_PARAGRAPH.CENTER
            run = p.add_run(label)
            run.font.size = Pt(9)
            run.font.bold = True
            run.font.color.rgb = light_gray

            cell = stats_table.cell(1, i)
            cell.text = ""
            p = cell.paragraphs[0]
            p.alignment = WD_ALIGN_PARAGRAPH.CENTER
            run = p.add_run(value)
            run.font.size = Pt(18)
            run.font.bold = True
            run.font.color.rgb = dark_color

            cell = stats_table.cell(2, i)
            cell.text = ""
            p = cell.paragraphs[0]
            p.alignment = WD_ALIGN_PARAGRAPH.CENTER
            run = p.add_run(note)
            run.font.size = Pt(9)
            run.font.color.rgb = light_gray
        # Style: remove borders, add light background
        for row in stats_table.rows:
            for cell in row.cells:
                tc = cell._tc
                tcPr = tc.get_or_add_tcPr()
                # Light blue background
                shd = tcPr.makeelement(qn("w:shd"), {
                    qn("w:val"): "clear",
                    qn("w:color"): "auto",
                    qn("w:fill"): "F0F3FF",
                })
                tcPr.append(shd)
                # Remove borders
                tcBorders = tcPr.makeelement(qn("w:tcBorders"), {})
                for edge in ("top", "left", "bottom", "right"):
                    border = tcBorders.makeelement(qn(f"w:{edge}"), {
                        qn("w:val"): "none", qn("w:sz"): "0", qn("w:space"): "0", qn("w:color"): "auto",
                    })
                    tcBorders.append(border)
                tcPr.append(tcBorders)

        # ── Category breakdown ──
        if category_parts:
            p = doc.add_paragraph()
            p.alignment = WD_ALIGN_PARAGRAPH.CENTER
            p.paragraph_format.space_before = Pt(8)
            run = p.add_run(" · ".join(category_parts))
            run.font.size = Pt(9)
            run.font.color.rgb = light_gray

        # ── Spacer before bottom ──
        for _ in range(4):
            sp = doc.add_paragraph()
            sp.paragraph_format.space_before = Pt(0)
            sp.paragraph_format.space_after = Pt(0)
            sp.add_run(" ").font.size = Pt(6)

        # ── Bottom info bar ──
        bottom_parts = []
        if owner_name:
            bottom_parts.append(f"负责人：{owner_name}")
        bottom_parts.append(f"时间范围：{review_window}")
        bottom_parts.append(f"导出日期：{_format_doc_date(export_date)}")
        p = doc.add_paragraph()
        p.alignment = WD_ALIGN_PARAGRAPH.CENTER
        p.paragraph_format.space_after = Pt(16)
        run = p.add_run("  |  ".join(bottom_parts))
        run.font.size = Pt(9)
        run.font.color.rgb = light_gray

        # ── Bottom brand ──
        p = doc.add_paragraph()
        p.alignment = WD_ALIGN_PARAGRAPH.CENTER
        run = p.add_run(f"— {organization_label} —")
        run.font.size = Pt(10)
        run.font.color.rgb = brand_color
        run.font.bold = True

        # ── Page break after cover ──
        doc.add_page_break()

        # ══════════════════════════════════════════════
        #  CONTENT PAGES — mirrors the preview exactly
        # ══════════════════════════════════════════════

        from io import BytesIO as _BytesIO

        source_labels_word = {
            "task_activity": "任务",
            "meeting": "会议",
            "support_request": "支持请求",
            "review": "复核",
            "attachment": "附件",
            "manual_note": "备注",
        }

        def _file_type_label(filename: str) -> str:
            ext = filename.rsplit(".", 1)[-1].lower() if "." in filename else ""
            return {"doc": "Word", "docx": "Word", "xls": "Excel", "xlsx": "Excel",
                    "ppt": "PPT", "pptx": "PPT", "pdf": "PDF", "txt": "TXT", "md": "TXT",
                    "jpg": "JPG", "jpeg": "JPEG", "png": "PNG", "gif": "GIF", "webp": "WEBP"}.get(ext, ext.upper() or "文件")

        def _size_label(size_bytes: int) -> str:
            if size_bytes < 1024:
                return f"{size_bytes} B"
            if size_bytes < 1024 * 1024:
                return f"{size_bytes // 1024} KB"
            return f"{size_bytes / (1024 * 1024):.1f} MB"

        def _styled_para(text: str, size: int = 11, bold: bool = False, color: RGBColor = dark_color,
                         space_before: int = 0, space_after: int = 4, align: int | None = None):
            p = doc.add_paragraph()
            if align is not None:
                p.alignment = align
            p.paragraph_format.space_before = Pt(space_before)
            p.paragraph_format.space_after = Pt(space_after)
            run = p.add_run(text)
            run.font.size = Pt(size)
            run.font.bold = bold
            run.font.color.rgb = color
            return p

        def _add_thin_border_para():
            p = doc.add_paragraph()
            p.paragraph_format.space_before = Pt(6)
            p.paragraph_format.space_after = Pt(6)
            pPr = p._p.get_or_add_pPr()
            pBdr = pPr.makeelement(qn("w:pBdr"), {})
            b = pBdr.makeelement(qn("w:bottom"), {
                qn("w:val"): "single", qn("w:sz"): "2", qn("w:space"): "1", qn("w:color"): "E5E7EB",
            })
            pBdr.append(b)
            pPr.append(pBdr)

        # Read preview display state
        show_system = bool(draft.get("showSystemTraces", False))
        docs_expanded_ids = set(draft.get("docsExpandedActivityIds", []))
        images_expanded_ids = set(draft.get("imagesExpandedActivityIds", []))

        # Build task lookup
        task_map: dict[str, dict] = {}
        for t in tasks:
            tid = str(t.get("id", ""))
            if tid:
                task_map[tid] = t

        # Build attachment lookup by activity (same logic as frontend)
        att_by_activity: dict[str, list[dict]] = {}
        for att in attachments:
            att_task_id = str(att.get("taskId", ""))
            matched_activity_id = ""
            for a in activities:
                meta = a.get("metadata") or {}
                if isinstance(meta, dict):
                    if meta.get("taskId") and str(meta["taskId"]) == att_task_id:
                        matched_activity_id = str(a.get("id", ""))
                        break
                    if meta.get("attachmentId") and str(meta["attachmentId"]) == str(att.get("id", "")):
                        matched_activity_id = str(a.get("id", ""))
                        break
                if a.get("sourceType") == "attachment" and str(a.get("sourceId", "")) == str(att.get("id", "")):
                    matched_activity_id = str(a.get("id", ""))
                    break
            if matched_activity_id:
                att_by_activity.setdefault(matched_activity_id, []).append(att)

        # ── Content header ──
        _styled_para(event_line_name, size=20, bold=True, space_before=0, space_after=8)
        if summary:
            _styled_para(summary, size=11, color=mid_gray, space_after=4)
        meta_parts_str = f"导出时间：{snapshot_at[:16].replace('T', ' ')}"
        if participants:
            meta_parts_str += f"  |  参与者：{', '.join(str(n) for n in participants)}"
        _styled_para(meta_parts_str, size=9, color=light_gray, space_after=12)

        timeline_kind_labels = {
            "project_start": "项目启动",
            "material_intake": "材料入库",
            "project_review": "项目复盘",
            "continuing_task": "持续推进",
            "admin_archive": "行政归档",
            "needs_review": "待确认",
            "system_trace": "系统痕迹",
            "project_milestone": "里程碑",
            "task_bundle": "任务节点",
            "meeting_material": "会议材料",
            "attachment_bundle": "附件材料",
            "admin_material": "行政材料",
            "system": "系统痕迹",
        }
        sorted_timeline_nodes = sorted(
            [item for item in timeline_nodes if show_system or str(item.get("kind") or "") != "system_trace"],
            key=lambda item: str(item.get("time") or ""),
        )
        if sorted_timeline_nodes:
            _styled_para("关键时间线", size=14, bold=True, space_before=4, space_after=8)
            for index, node in enumerate(sorted_timeline_nodes, start=1):
                node_title = _clean_text(node.get("title")) or f"节点 {index}"
                node_kind = str(node.get("kind") or "")
                node_time = str(node.get("time") or "")[:16].replace("T", " ")
                node_summary = _clean_text(node.get("summary"))
                node_evidence = _clean_text(node.get("evidenceSummary"))
                node_tags = [str(item) for item in node.get("tags", []) if str(item).strip()] if isinstance(node.get("tags"), list) else []
                node_warnings = [str(item) for item in node.get("warnings", []) if str(item).strip()] if isinstance(node.get("warnings"), list) else []
                node_attachments = [item for item in node.get("attachments", []) if isinstance(item, dict)] if isinstance(node.get("attachments"), list) else []

                _styled_para(f"{index:02d}  {node_title}", size=12, bold=True, space_before=10, space_after=2)
                meta_parts = [timeline_kind_labels.get(node_kind, node_kind or "节点")]
                if node_time:
                    meta_parts.append(node_time)
                owner = _clean_text(node.get("ownerName") or node.get("actorName"))
                if owner:
                    meta_parts.append(f"负责人/记录人：{owner}")
                if node_tags:
                    meta_parts.append("、".join(node_tags[:4]))
                _styled_para("  |  ".join(meta_parts), size=9, color=light_gray, space_after=4)
                if node_summary:
                    _styled_para(node_summary, size=10, color=mid_gray, space_after=4)
                if node_evidence:
                    _styled_para(f"解析依据：{node_evidence}", size=9, color=mid_gray, space_before=2, space_after=4)
                if node_warnings:
                    _styled_para(f"待确认：{'；'.join(node_warnings[:3])}", size=9, color=RGBColor(0xB4, 0x53, 0x09), space_after=4)
                if node_attachments:
                    _styled_para(f"附件 {len(node_attachments)} 份", size=9, bold=True, color=brand_color, space_before=2, space_after=2)
                    for att in node_attachments[:12]:
                        att_title = _clean_text(att.get("title")) or "未命名附件"
                        type_label = _file_type_label(att_title)
                        size_str = _size_label(int(att.get("sizeBytes") or 0))
                        parse_label = ""
                        if att.get("parseStatus"):
                            parse_label = " · 已解析" if str(att.get("parseStatus")) == "ready" else " · 待解析"
                        preview = _truncate_text(att.get("parsedPreview"), 120)
                        line = f"[{type_label}] {att_title}（{size_str}{parse_label}）"
                        if preview:
                            line += f"：{preview}"
                        _styled_para(line, size=9, color=mid_gray, space_after=1)
                    if len(node_attachments) > 12:
                        _styled_para(f"另有 {len(node_attachments) - 12} 份附件未在正文展开。", size=9, color=light_gray, space_after=2)
                _add_thin_border_para()

        # Determine which activities to show (matching preview filter)
        def _is_key(act: dict) -> bool:
            if act.get("isKey") is not None:
                return bool(act["isKey"])
            st = str(act.get("sourceType", ""))
            if st in ("manual_note", "attachment"):
                return True
            if st == "task_activity":
                meta = act.get("metadata") or {}
                if isinstance(meta, dict) and meta.get("eventType") == "created":
                    return True
            return False

        display_activities = [] if sorted_timeline_nodes else [a for a in activities if not a.get("hidden") and (show_system or _is_key(a))]

        if not sorted_timeline_nodes and not display_activities:
            _styled_para("（无活动记录）", size=11, color=light_gray)

        for activity in display_activities:
            activity_id = str(activity.get("id", ""))
            title = str(activity.get("editedTitle") or activity.get("title", ""))
            summary_text = str(activity.get("editedSummary") or activity.get("summary", ""))
            happened_at = str(activity.get("happenedAt", ""))[:16].replace("T", " ")
            actor = str(activity.get("actorName", ""))
            source_type = str(activity.get("sourceType", ""))
            label = source_labels_word.get(source_type, source_type)

            # ── Activity title (bold) ──
            _styled_para(title, size=12, bold=True, space_before=10, space_after=2)

            # ── Type badge + time + actor ──
            meta_line = f"[{label}]  {happened_at}"
            if actor:
                meta_line += f"  — {actor}"
            _styled_para(meta_line, size=9, color=light_gray, space_after=4)

            # ── Summary ──
            if summary_text:
                _styled_para(summary_text, size=10, color=mid_gray, space_after=4)

            # ── Task detail (if linked) ──
            task_id = activity.get("sourceId", "") if source_type == "task_activity" else ""
            if not task_id:
                meta = activity.get("metadata") or {}
                if isinstance(meta, dict):
                    task_id = str(meta.get("taskId", ""))
            linked_task = task_map.get(task_id) if task_id else None
            if linked_task:
                task_desc = str(linked_task.get("desc") or linked_task.get("description") or "")
                if task_desc:
                    # Shaded box for task detail
                    p = doc.add_paragraph()
                    p.paragraph_format.space_before = Pt(2)
                    p.paragraph_format.space_after = Pt(2)
                    # Indent to visually distinguish
                    p.paragraph_format.left_indent = Cm(0.5)
                    run = p.add_run(str(linked_task.get("title", "")))
                    run.font.size = Pt(10)
                    run.font.bold = True
                    run.font.color.rgb = mid_gray
                    shd = run._r.get_or_add_rPr().makeelement(qn("w:shd"), {
                        qn("w:val"): "clear", qn("w:color"): "auto", qn("w:fill"): "F8FAFC",
                    })
                    run._r.get_or_add_rPr().append(shd)
                    p2 = doc.add_paragraph()
                    p2.paragraph_format.space_before = Pt(0)
                    p2.paragraph_format.space_after = Pt(6)
                    p2.paragraph_format.left_indent = Cm(0.5)
                    run2 = p2.add_run(task_desc[:500])
                    run2.font.size = Pt(9)
                    run2.font.color.rgb = light_gray

            # ── Attachments for this activity ──
            activity_atts = att_by_activity.get(activity_id, [])
            is_docs_expanded = activity_id in docs_expanded_ids
            is_images_expanded = activity_id in images_expanded_ids

            if activity_atts:
                for att in activity_atts:
                    att_title = str(att.get("title", ""))
                    att_id = str(att.get("id", ""))
                    mime = str(att.get("mimeType") or "").lower()
                    is_image = mime.startswith("image/") or att_title.lower().endswith((".jpg", ".jpeg", ".png", ".gif", ".webp"))
                    is_doc_file = att_title.lower().endswith((".docx", ".doc", ".md", ".txt", ".pdf", ".xlsx", ".xls", ".pptx", ".ppt"))
                    download_url = str(att.get("downloadUrl", ""))

                    if is_image and is_images_expanded:
                        # Show image inline (like preview expanded)
                        try:
                            if download_url:
                                img_resp = httpx.get(f"{cloud_api_base_url()}{download_url}", timeout=15.0)
                                if img_resp.status_code == 200:
                                    img_stream = _BytesIO(img_resp.content)
                                    doc.add_picture(img_stream, width=Inches(4.5))
                                    _styled_para(att_title, size=9, color=light_gray, space_after=6)
                        except Exception:
                            _styled_para(f"（图片加载失败：{att_title}）", size=9, color=light_gray)

                    elif is_doc_file and is_docs_expanded:
                        # Show file card with summary (like preview expanded DocContentViewer)
                        type_label = _file_type_label(att_title)
                        size_str = _size_label(int(att.get("sizeBytes", 0)))
                        p = doc.add_paragraph()
                        p.paragraph_format.space_before = Pt(4)
                        p.paragraph_format.space_after = Pt(2)
                        run = p.add_run(f"[{type_label}]  ")
                        run.font.size = Pt(9)
                        run.font.bold = True
                        run.font.color.rgb = brand_color
                        run = p.add_run(f"{att_title}  ({size_str})")
                        run.font.size = Pt(10)
                        run.font.color.rgb = dark_color

                        # Fetch document summary
                        try:
                            text_resp = httpx.get(
                                f"{cloud_api_base_url()}/api/public/task-attachments/{att_id}/text-content",
                                timeout=15.0,
                            )
                            doc_text = ""
                            if text_resp.status_code == 200:
                                text_data = text_resp.json()
                                raw = str(text_data.get("text", "")).strip()
                                if raw and "提取失败" not in raw and "No module" not in raw:
                                    doc_text = raw
                            if doc_text:
                                _styled_para(doc_text, size=9, color=mid_gray, space_after=6)
                            else:
                                _styled_para("（暂无文档摘要）", size=9, color=light_gray, space_after=6)
                        except Exception:
                            _styled_para("（文档摘要加载失败）", size=9, color=light_gray, space_after=6)

                    else:
                        # Collapsed — just show file type + full name (like preview)
                        type_label = _file_type_label(att_title)
                        p = doc.add_paragraph()
                        p.paragraph_format.space_before = Pt(1)
                        p.paragraph_format.space_after = Pt(1)
                        run = p.add_run(f"[{type_label}] ")
                        run.font.size = Pt(9)
                        run.font.bold = True
                        run.font.color.rgb = brand_color
                        run = p.add_run(att_title)
                        run.font.size = Pt(9)
                        run.font.color.rgb = mid_gray

            # ── Separator between activities ──
            _add_thin_border_para()

        import tempfile
        safe_name = safe_filename(f"{event_line_name[:30]}_汇报.docx")
        tmp_dir = os.path.join(tempfile.gettempdir(), "yiyu_exports")
        os.makedirs(tmp_dir, exist_ok=True)
        tmp_path = os.path.join(tmp_dir, safe_name)
        doc.save(tmp_path)
        return {"filePath": tmp_path, "fileName": safe_name}

    @app.patch("/api/v1/event-lines/{event_line_id}", response_model=EventLineRecord)
    def update_event_line(event_line_id: str, payload: EventLineUpdatePayload) -> EventLineRecord:
        row = state.db.fetchone("SELECT * FROM event_lines WHERE id = ? OR cloud_id = ?", (event_line_id, event_line_id))
        if not row:
            raise HTTPException(status_code=404, detail="Event line not found")
        local_event_line_id = str(row["id"])
        updates = payload.model_dump(exclude_unset=True)
        previous_client_id = str(row["primary_client_id"]).strip() if row["primary_client_id"] else None
        previous_client_name = str(row["primary_client_name"]).strip() if row["primary_client_name"] else None
        next_client_id = str(updates.get("primaryClientId")).strip() if updates.get("primaryClientId") else (str(row["primary_client_id"]) if row["primary_client_id"] else None)
        client_row = state.db.fetchone("SELECT name FROM clients WHERE id = ?", (next_client_id,)) if next_client_id else None
        next_client_name = str(client_row["name"]).strip() if client_row and client_row["name"] else (str(row["primary_client_name"]).strip() if row["primary_client_name"] else None)
        should_sync_linked_task_client_ids = (
            bool(updates.get("syncLinkedTaskClientIds"))
            and bool(next_client_id)
            and next_client_id != previous_client_id
        )
        participant_ids = updates.get("participantIds")
        updated_at = now_iso()
        state.db.execute(
            """
            UPDATE event_lines
            SET name = ?, kind = ?, status = ?, business_category = ?, stage = ?, summary = ?, intent = ?,
                current_blocker = ?, recent_decision = ?, next_step = ?, evidence_count = ?, owner_id = ?, owner_name = ?,
                primary_client_id = ?, primary_client_name = ?, primary_department_id = ?, primary_department_name = ?,
                participant_ids_json = ?, updated_at = ?
            WHERE id = ?
            """,
            (
                updates.get("name", row["name"]),
                updates.get("kind", row["kind"]),
                updates.get("status", row["status"]),
                updates.get("businessCategory", row["business_category"]),
                updates.get("stage", row["stage"]),
                updates.get("summary", row["summary"]),
                updates.get("intent", row["intent"]),
                updates.get("currentBlocker", row["current_blocker"]),
                updates.get("recentDecision", row["recent_decision"]),
                updates.get("nextStep", row["next_step"]),
                _event_line_evidence_count_or_zero(
                    updates["evidenceCount"] if "evidenceCount" in updates else row["evidence_count"],
                    default=int(row["evidence_count"] or 0),
                ),
                updates.get("ownerId", row["owner_id"]),
                updates.get("ownerName", row["owner_name"]),
                next_client_id,
                str(client_row["name"]) if client_row else (updates.get("primaryClientName", row["primary_client_name"])),
                updates.get("primaryDepartmentId", row["primary_department_id"]),
                updates.get("primaryDepartmentName", row["primary_department_name"]),
                to_json(participant_ids if participant_ids is not None else from_json(row["participant_ids_json"], [])),
                updated_at,
                local_event_line_id,
            ),
        )
        if should_sync_linked_task_client_ids:
            state.db.execute(
                """
                UPDATE tasks
                SET client_id = ?, updated_at = ?
                WHERE event_line_id = ?
                  AND COALESCE(scope_mode, 'COLLAB_SHARED') != 'PERSONAL_ONLY'
                """,
                (next_client_id, updated_at, local_event_line_id),
            )
            task_rows = state.db.fetchall(
                """
                SELECT id
                FROM tasks
                WHERE event_line_id = ?
                  AND COALESCE(scope_mode, 'COLLAB_SHARED') != 'PERSONAL_ONLY'
                """,
                (local_event_line_id,),
            )
            for task_row in task_rows:
                task_id = str(task_row["id"])
                _sync_task_attachment_scope(
                    state.db,
                    state.data_dir,
                    build_task_attachment,
                    build_attachment_event_line_activity,
                    ensure_standard_client_folders,
                    task_id,
                    next_client_id,
                    local_event_line_id,
                    cloud=False,
                )
                _sync_task_attachment_scope(
                    state.db,
                    state.data_dir,
                    build_task_attachment,
                    build_attachment_event_line_activity,
                    ensure_standard_client_folders,
                    task_id,
                    next_client_id,
                    local_event_line_id,
                    cloud=True,
                )
            _sync_event_line_client_scope_records(
                state.db,
                event_line_id=local_event_line_id,
                client_id=next_client_id,
                client_name=next_client_name,
                updated_at=updated_at,
            )
            if previous_client_id and next_client_name:
                rehome_event_line_memory(
                    state.data_dir,
                    previous_client_id,
                    next_client_id,
                    local_event_line_id,
                    str(updates.get("name", row["name"])),
                    next_client_name,
                )
            for affected_client_id in {previous_client_id, next_client_id}:
                if affected_client_id:
                    refresh_organization_notebook_snapshot(state.db, affected_client_id)
            refresh_event_line_memory_snapshot(state.db, local_event_line_id)
            _invalidate_event_line_snapshot_cache(local_event_line_id)
        updated_row = state.db.fetchone("SELECT * FROM event_lines WHERE id = ?", (local_event_line_id,))
        if not updated_row:
            raise HTTPException(status_code=500, detail="Event line update failed")
        if get_cloud_token():
            action = "update" if updated_row["cloud_id"] else "create"
            state.db.execute(
                """
                UPDATE event_lines
                SET sync_status = 'syncing',
                    pending_sync_action = ?,
                    cloud_payload_json = ?,
                    last_sync_error = ''
                WHERE id = ?
                """,
                (action, to_json(_event_line_cloud_payload_from_row(updated_row, include_id=action == "create")), local_event_line_id),
            )
            updated_row = state.db.fetchone("SELECT * FROM event_lines WHERE id = ?", (local_event_line_id,))
            if updated_row:
                _sync_event_line_row_to_cloud(updated_row, forced_action=action)
                updated_row = state.db.fetchone("SELECT * FROM event_lines WHERE id = ?", (local_event_line_id,))
        if not updated_row:
            raise HTTPException(status_code=500, detail="Event line update failed")
        _safe_data_center_ingest(
            "event_line_manual_update",
            lambda: ingest_event_line_by_id(state.db, state.data_dir, local_event_line_id),
        )
        _enqueue_workspace_refresh_safe(
            client_id=next_client_id or previous_client_id,
            source_type="event_line_update",
            source_id=local_event_line_id,
            reason="event_line_updated",
            scope_type="event_line",
            scope_id=local_event_line_id,
            priority="normal",
        )
        return build_event_line(updated_row)

    def _event_line_dependency_counts(event_line_id: str) -> dict[str, int]:
        task_count = state.db.fetchone(
            """
            SELECT COUNT(1) AS cnt
            FROM tasks
            WHERE event_line_id = ?
              AND COALESCE(scope_mode, 'COLLAB_SHARED') != 'PERSONAL_ONLY'
            """,
            (event_line_id,),
        )
        activity_count = state.db.fetchone("SELECT COUNT(1) AS cnt FROM event_line_activities WHERE event_line_id = ?", (event_line_id,))
        attachment_count = state.db.fetchone("SELECT COUNT(1) AS cnt FROM event_line_attachments WHERE event_line_id = ?", (event_line_id,))
        memory_count = state.db.fetchone("SELECT COUNT(1) AS cnt FROM event_line_memory_snapshots WHERE event_line_id = ?", (event_line_id,))
        weekly_count = state.db.fetchone("SELECT COUNT(1) AS cnt FROM event_line_weekly_snapshots WHERE event_line_id = ?", (event_line_id,))
        approval_count = state.db.fetchone("SELECT COUNT(1) AS cnt FROM event_line_approval_nodes WHERE event_line_id = ?", (event_line_id,))
        return {
            "tasks": int(task_count["cnt"] if task_count else 0),
            "activities": int(activity_count["cnt"] if activity_count else 0),
            "attachments": int(attachment_count["cnt"] if attachment_count else 0),
            "memorySnapshots": int(memory_count["cnt"] if memory_count else 0),
            "weeklySnapshots": int(weekly_count["cnt"] if weekly_count else 0),
            "approvalNodes": int(approval_count["cnt"] if approval_count else 0),
        }

    @app.post("/api/v1/event-lines/{event_line_id}/close")
    def close_event_line(event_line_id: str) -> dict:
        row = state.db.fetchone("SELECT * FROM event_lines WHERE id = ? OR cloud_id = ?", (event_line_id, event_line_id))
        if not row:
            raise HTTPException(status_code=404, detail="Event line not found")
        local_event_line_id = str(row["id"])
        if row and str(row["status"]) not in ("done", "archived"):
            timestamp = now_iso()
            state.db.execute(
                """
                UPDATE event_lines
                SET status = 'archived',
                    closed_at = ?,
                    closed_by_user_id = ?,
                    sync_status = CASE WHEN ? THEN 'syncing' ELSE sync_status END,
                    pending_sync_action = CASE WHEN ? THEN 'archive' ELSE pending_sync_action END,
                    last_sync_error = CASE WHEN ? THEN '' ELSE last_sync_error END,
                    updated_at = ?
                WHERE id = ?
                """,
                (
                    timestamp,
                    current_operator_name(),
                    1 if get_cloud_token() else 0,
                    1 if get_cloud_token() else 0,
                    1 if get_cloud_token() else 0,
                    timestamp,
                    local_event_line_id,
                ),
            )
            _enqueue_workspace_refresh_safe(
                client_id=str(row["primary_client_id"] or "").strip() or None,
                source_type="event_line_close",
                source_id=local_event_line_id,
                reason="event_line_closed",
                scope_type="event_line",
                scope_id=local_event_line_id,
                priority="normal",
            )
        if get_cloud_token():
            updated_row = state.db.fetchone("SELECT * FROM event_lines WHERE id = ?", (local_event_line_id,))
            if updated_row:
                _sync_event_line_row_to_cloud(updated_row, forced_action="archive")
        return {"status": "archived"}

    @app.post("/api/v1/event-lines/{event_line_id}/reopen")
    def reopen_event_line(event_line_id: str) -> dict:
        row = state.db.fetchone("SELECT * FROM event_lines WHERE id = ? OR cloud_id = ?", (event_line_id, event_line_id))
        if not row:
            raise HTTPException(status_code=404, detail="Event line not found")
        local_event_line_id = str(row["id"])
        has_cloud = bool(get_cloud_token())
        timestamp = now_iso()
        state.db.execute(
            """
            UPDATE event_lines
            SET status = 'active',
                closed_at = NULL,
                closed_by_user_id = NULL,
                sync_status = CASE WHEN ? THEN 'syncing' ELSE sync_status END,
                pending_sync_action = CASE WHEN ? THEN CASE WHEN cloud_id IS NULL OR cloud_id = '' THEN 'create' ELSE 'update' END ELSE pending_sync_action END,
                last_sync_error = CASE WHEN ? THEN '' ELSE last_sync_error END,
                updated_at = ?
            WHERE id = ?
            """,
            (1 if has_cloud else 0, 1 if has_cloud else 0, 1 if has_cloud else 0, timestamp, local_event_line_id),
        )
        _enqueue_workspace_refresh_safe(
            client_id=str(row["primary_client_id"] or "").strip() or None,
            source_type="event_line_reopen",
            source_id=local_event_line_id,
            reason="event_line_reopened",
            scope_type="event_line",
            scope_id=local_event_line_id,
            priority="normal",
        )
        if has_cloud:
            updated_row = state.db.fetchone("SELECT * FROM event_lines WHERE id = ?", (local_event_line_id,))
            if updated_row:
                _sync_event_line_row_to_cloud(updated_row, forced_action="update" if updated_row["cloud_id"] else "create")
        return {"status": "active"}

    @app.post("/api/v1/event-lines/{event_line_id}/retry-sync")
    def retry_event_line_sync(event_line_id: str) -> dict:
        if not get_cloud_token():
            raise HTTPException(status_code=400, detail="云端账号未登录，无法重试同步")
        row = state.db.fetchone("SELECT * FROM event_lines WHERE id = ? OR cloud_id = ?", (event_line_id, event_line_id))
        if not row:
            raise HTTPException(status_code=404, detail="Event line not found")
        local_event_line_id = str(row["id"])
        current_sync_status = str(row["sync_status"] or "").strip()
        if current_sync_status == "synced" and not (row["pending_sync_action"] or "").strip():
            return {"status": "already_synced", "syncStatus": "synced"}
        forced_action = str(row["pending_sync_action"] or "").strip() or None
        state.db.execute(
            "UPDATE event_lines SET sync_status = 'syncing', last_sync_error = '', updated_at = ? WHERE id = ?",
            (now_iso(), local_event_line_id),
        )
        refreshed = state.db.fetchone("SELECT * FROM event_lines WHERE id = ?", (local_event_line_id,))
        try:
            ok = _sync_event_line_row_to_cloud(refreshed, forced_action=forced_action) if refreshed else False
        except HTTPException:
            raise
        final = state.db.fetchone("SELECT sync_status, last_sync_error FROM event_lines WHERE id = ?", (local_event_line_id,))
        return {
            "status": "ok" if ok else "failed",
            "syncStatus": str(final["sync_status"]) if final and final["sync_status"] else None,
            "lastSyncError": str(final["last_sync_error"]) if final and final["last_sync_error"] else None,
        }

    @app.delete("/api/v1/event-lines/{event_line_id}")
    def delete_event_line(event_line_id: str) -> dict:
        cloud_deleted = False
        if get_cloud_token():
            # Try real DELETE first; if cloud returns 405 (not supported), fall back to PATCH archived
            for attempt_method in ("DELETE", "PATCH_ARCHIVED"):
                try:
                    if attempt_method == "DELETE":
                        resp = cloud_request("DELETE", f"/api/v1/event-lines/{event_line_id}")
                    else:
                        resp = cloud_request("PATCH", f"/api/v1/event-lines/{event_line_id}", json_body={"status": "archived"})
                    if isinstance(resp, dict):
                        _upsert_cloud_event_line_shadow_local(resp)
                    cloud_deleted = True
                    break
                except HTTPException as exc:
                    if exc.status_code == 403:
                        raise
                    if exc.status_code == 405 and attempt_method == "DELETE":
                        continue  # try PATCH fallback
                    break  # 404 or other — cloud doesn't have it
        # Always clean local copy
        row = state.db.fetchone("SELECT id, visibility_scope, primary_client_id FROM event_lines WHERE id = ?", (event_line_id,))
        if row and not cloud_deleted:
            # Local-only fallback: only admin can delete
            if not current_session_is_admin():
                raise HTTPException(status_code=403, detail="只有管理员可以删除事件线。")
            task_count = int(
                state.db.scalar(
                    """
                    SELECT COUNT(1)
                    FROM tasks
                    WHERE event_line_id = ?
                      AND COALESCE(scope_mode, 'COLLAB_SHARED') != 'PERSONAL_ONLY'
                    """,
                    (event_line_id,),
                )
                or 0
            )
            if task_count > 0:
                raise HTTPException(status_code=403, detail="事件线已有关联任务，不能删除，请使用「结束事件线」功能进行归档。")
        if row:
            row_client_id = str(row["primary_client_id"] or "").strip()
            state.db.execute("UPDATE tasks SET event_line_id = NULL, updated_at = ? WHERE event_line_id = ?", (now_iso(), event_line_id))
            state.db.execute("DELETE FROM event_line_activities WHERE event_line_id = ?", (event_line_id,))
            state.db.execute("DELETE FROM event_line_attachments WHERE event_line_id = ?", (event_line_id,))
            state.db.execute("DELETE FROM event_lines WHERE id = ?", (event_line_id,))
            _enqueue_workspace_refresh_safe(
                client_id=row_client_id or None,
                source_type="event_line_delete",
                source_id=event_line_id,
                reason="event_line_deleted",
                scope_type="event_line",
                scope_id=event_line_id,
                priority="high",
            )
        if not row and not cloud_deleted:
            raise HTTPException(status_code=404, detail="Event line not found")
        return {"status": "deleted"}

    @app.post("/api/v1/event-lines/{event_line_id}/notes")
    def add_event_line_note(event_line_id: str, payload: dict = Body(...)) -> dict:
        note_text = str(payload.get("text", "")).strip()
        if not note_text:
            raise HTTPException(status_code=400, detail="Note text is required")
        row = state.db.fetchone("SELECT id FROM event_lines WHERE id = ?", (event_line_id,))
        if not row:
            raise HTTPException(status_code=404, detail="Event line not found")
        activity_id = new_id("ela")
        timestamp = now_iso()
        state.db.execute(
            """
            INSERT INTO event_line_activities(
                id, event_line_id, source_type, source_id, happened_at, actor_id, actor_name, title, summary, metadata_json, is_key, created_at
            ) VALUES(?, ?, 'manual_note', ?, ?, NULL, ?, ?, ?, ?, 1, ?)
            """,
            (
                activity_id,
                event_line_id,
                activity_id,
                timestamp,
                current_operator_name(),
                "补充备注",
                note_text,
                to_json({}),
                timestamp,
            ),
        )
        log_activity("event_line.note", "event_line", event_line_id, {"noteLength": len(note_text)})
        event_line_row = state.db.fetchone("SELECT primary_client_id FROM event_lines WHERE id = ?", (event_line_id,))
        _enqueue_workspace_refresh_safe(
            client_id=str(event_line_row["primary_client_id"] or "").strip() if event_line_row else None,
            source_type="event_line_note",
            source_id=activity_id,
            reason="event_line_note_added",
            scope_type="event_line",
            scope_id=event_line_id,
            priority="normal",
        )
        return {
            "id": activity_id,
            "eventLineId": event_line_id,
            "text": note_text[:500],
            "createdAt": timestamp,
        }

    @app.get("/api/v1/task-views", response_model=TaskViewsResponse)
    def list_task_views() -> TaskViewsResponse:
        views = _ensure_builtin_task_views()
        rows = state.db.fetchall(
            """
            SELECT *
            FROM task_views
            ORDER BY built_in DESC,
                     CASE kind WHEN 'custom' THEN 1 ELSE 0 END,
                     updated_at DESC,
                     name ASC
            """
        )
        views = [_task_view_record_from_row(row) for row in rows]
        return TaskViewsResponse(
            views=views,
            presets=_task_view_presets(views),
        )

    @app.post("/api/v1/task-views", response_model=TaskViewDefinitionRecord)
    def create_task_view(payload: TaskViewMutationPayload) -> TaskViewDefinitionRecord:
        _ensure_builtin_task_views()
        if payload.kind != "custom":
            raise HTTPException(status_code=400, detail="Only custom task views can be created")
        name = payload.name.strip()
        if not name:
            raise HTTPException(status_code=400, detail="Task view name is required")
        timestamp = now_iso()
        view_id = new_id("tview")
        state.db.execute(
            """
            INSERT INTO task_views(
                id, name, kind, description, calendar_scope, shareability, sort_by, sort_direction,
                visible_fields_json, filter_set_json, built_in, created_at, updated_at
            ) VALUES(?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 0, ?, ?)
            """,
            (
                view_id,
                name,
                payload.kind,
                payload.description,
                payload.calendarScope,
                payload.shareability,
                payload.sortBy,
                payload.sortDirection,
                to_json(payload.visibleFields),
                to_json(payload.filterSet.model_dump()),
                timestamp,
                timestamp,
            ),
        )
        row = state.db.fetchone("SELECT * FROM task_views WHERE id = ?", (view_id,))
        if not row:
            raise HTTPException(status_code=500, detail="Task view creation failed")
        return _task_view_record_from_row(row)

    @app.patch("/api/v1/task-views/{view_id}", response_model=TaskViewDefinitionRecord)
    def update_task_view(view_id: str, payload: TaskViewMutationPayload) -> TaskViewDefinitionRecord:
        _ensure_builtin_task_views()
        row = state.db.fetchone("SELECT * FROM task_views WHERE id = ?", (view_id,))
        if not row:
            raise HTTPException(status_code=404, detail="Task view not found")
        if str(row["kind"]) != "custom":
            raise HTTPException(status_code=400, detail="Built-in task views cannot be edited")
        timestamp = now_iso()
        next_name = payload.name.strip() if payload.name is not None else str(row["name"])
        if not next_name:
            raise HTTPException(status_code=400, detail="Task view name is required")
        next_filter_set = payload.filterSet.model_dump() if payload.filterSet is not None else from_json(row["filter_set_json"], {})
        next_visible_fields = payload.visibleFields if payload.visibleFields is not None else from_json(row["visible_fields_json"], [])
        state.db.execute(
            """
            UPDATE task_views
            SET name = ?, description = ?, filter_set_json = ?, sort_by = ?, sort_direction = ?, visible_fields_json = ?,
                calendar_scope = ?, shareability = ?, updated_at = ?
            WHERE id = ?
            """,
            (
                next_name,
                payload.description if payload.description is not None else str(row["description"] or ""),
                to_json(next_filter_set),
                payload.sortBy or str(row["sort_by"]),
                payload.sortDirection or str(row["sort_direction"]),
                to_json(next_visible_fields),
                payload.calendarScope or str(row["calendar_scope"]),
                payload.shareability or str(row["shareability"]),
                timestamp,
                view_id,
            ),
        )
        updated_row = state.db.fetchone("SELECT * FROM task_views WHERE id = ?", (view_id,))
        if not updated_row:
            raise HTTPException(status_code=500, detail="Task view update failed")
        return _task_view_record_from_row(updated_row)

    @app.get("/api/v1/reviews/dashboard/drill-target", response_model=ReviewDashboardDrillTargetResponse)
    def get_review_dashboard_drill_target(
        targetType: str,
        targetId: str,
        targetLabel: str | None = None,
        targetFilters: str | None = None,
    ) -> ReviewDashboardDrillTargetResponse:
        parsed_filters: dict[str, object] = {}
        if targetFilters:
            try:
                candidate = json.loads(targetFilters)
            except json.JSONDecodeError as exc:
                raise HTTPException(status_code=400, detail="Invalid targetFilters payload") from exc
            if not isinstance(candidate, dict):
                raise HTTPException(status_code=400, detail="targetFilters must be an object")
            parsed_filters = candidate
        target = ReviewDashboardCardTargetRecord(
            targetType=targetType,
            targetId=targetId,
            targetLabel=targetLabel,
            targetFilters=parsed_filters,
        )
        if target.targetType == "event_line":
            return _drill_target_response_for_event_line(target)
        if target.targetType == "task_view":
            return _drill_target_response_for_task_view(target)
        if target.targetType == "meeting":
            return _drill_target_response_for_meeting(target)
        if target.targetType == "support_request":
            return _drill_target_response_for_support_request(target)
        if target.targetType == "attachment_group":
            return _drill_target_response_for_attachment_group(target)
        raise HTTPException(status_code=400, detail=f"Unsupported dashboard drill target: {target.targetType}")

