    @app.post("/api/v1/strategic/thoughts/{thought_id}/state", response_model=StrategicThoughtRecord)
    def update_strategic_thought_state(thought_id: str, payload: StrategicThoughtStatePayload) -> StrategicThoughtRecord:
        row = state.db.fetchone("SELECT * FROM strategic_thought_insights WHERE id = ?", (thought_id,))
        if row is None:
            raise HTTPException(status_code=404, detail="Thought not found")
        now = now_iso()
        if payload.action == "favorite":
            state.db.execute("UPDATE strategic_thought_insights SET is_favorite = 1, updated_at = ? WHERE id = ?", (now, thought_id))
        elif payload.action == "unfavorite":
            state.db.execute("UPDATE strategic_thought_insights SET is_favorite = 0, updated_at = ? WHERE id = ?", (now, thought_id))
        elif payload.action == "delete":
            state.db.execute("UPDATE strategic_thought_insights SET is_deleted = 1, updated_at = ? WHERE id = ?", (now, thought_id))
        elif payload.action == "restore":
            state.db.execute("UPDATE strategic_thought_insights SET is_deleted = 0, updated_at = ? WHERE id = ?", (now, thought_id))
        updated = state.db.fetchone("SELECT * FROM strategic_thought_insights WHERE id = ?", (thought_id,))
        if updated is None:
            raise HTTPException(status_code=404, detail="Thought not found")
        thought = _strategic_thought_from_insight_row(updated)
        merged = _merge_strategic_thought_reviews([thought], include_dismissed=True)
        return merged[0] if merged else thought

    @app.post("/api/v1/strategic/thoughts/{thought_id}/review", response_model=StrategicThoughtRecord)
    def review_strategic_thought(thought_id: str, payload: StrategicThoughtReviewPayload) -> StrategicThoughtRecord:
        thought = _find_strategic_thought_by_id(thought_id)
        if thought is None:
            raise HTTPException(status_code=404, detail="Thought not found")

        operator = current_operator_row()
        session_user = get_cached_session_user()
        reviewer_id = session_user.id if session_user else str(operator["id"] or "")
        reviewer_name = (
            session_user.fullName
            if session_user and session_user.fullName
            else str(operator["name"] or "系统")
        )
        note = (payload.note or "").strip()

        if payload.action == "mark_task_created" and not (payload.taskId or "").strip():
            raise HTTPException(status_code=400, detail="taskId is required when action=mark_task_created")

        status_map: dict[str, Literal["confirmed", "dismissed", "task_created"]] = {
            "confirm": "confirmed",
            "dismiss": "dismissed",
            "mark_task_created": "task_created",
        }
        review_status = status_map[payload.action]
        judgment_id: str | None = None
        if payload.action == "confirm" and payload.createJudgment:
            for source in thought.sources:
                if source.sourceType == "judgment_version" and source.sourceId:
                    try:
                        confirmed = confirm_judgment(
                            state.db,
                            JudgmentConfirmPayload(
                                judgmentId=source.sourceId,
                                action="approved",
                                note=note,
                            ),
                            actor_id=reviewer_id,
                            actor_name=reviewer_name,
                        )
                        judgment_id = confirmed.id
                        break
                    except ValueError:
                        continue

        review = _save_strategic_thought_review(
            thought=thought,
            status=review_status,
            note=note,
            task_id=(payload.taskId or "").strip() or None,
            judgment_id=judgment_id,
            reviewer_id=reviewer_id,
            reviewer_name=reviewer_name,
        )
        thought.status = review.status
        thought.review = review
        return thought

