    @app.get("/api/v1/clients/{client_id}/knowledge/parse-failures", response_model=list[KnowledgeParseFailureRecord])
    def list_client_parse_failures(client_id: str) -> list[KnowledgeParseFailureRecord]:
        build_client_summary(client_id)
        rows = state.db.fetchall(
            """
            SELECT id, document_id, file_name, managed_path, original_path, kind, parse_status, parse_error
            FROM v2_documents
            WHERE client_id = ? AND COALESCE(parse_status, 'ready') NOT IN ('ready', 'partial_ready')
            ORDER BY updated_at DESC
            LIMIT 300
            """,
            (client_id,),
        )
        retry_summary = from_json(state.db.get_setting(f"knowledge.parse_retry_summary:{client_id}", "{}"), {})
        last_retry_at = (
            str(retry_summary.get("lastRetryAt") or "").strip() or None
            if isinstance(retry_summary, dict)
            else None
        )
        failures: list[KnowledgeParseFailureRecord] = []
        for row in rows:
            kind = str(row["kind"] or "")
            failure_type = classify_parse_retry_failure(str(row["parse_error"] or ""), kind=kind)
            source_path_for_pages = Path(str(row["managed_path"] or row["original_path"] or "")).expanduser()
            page_count = inspect_pdf_page_count(source_path_for_pages) if kind.lower().lstrip(".") == "pdf" and source_path_for_pages.exists() else None
            recommended = "请补充可解析正文后重试。"
            if failure_type in {"empty_pdf", "ocr_required"}:
                recommended = "建议排队 OCR 重试；长 PDF 会先生成可检索的 partial_ready。"
            elif failure_type == "file_missing":
                recommended = "源文件已缺失，请重新导入原文件后再解析。"
            elif failure_type == "permission_denied":
                recommended = "请检查文件权限后重试。"
            elif kind in {"ppt", "pptx"}:
                recommended = "建议先导出为 PDF 或补充摘要再重试解析。"
            elif kind in {"pdf"}:
                recommended = "建议检查 PDF 是否可复制文本，必要时 OCR 后重试。"
            elif kind in {"doc", "docx"}:
                recommended = "建议检查文档编码或先转为 PDF 再重试。"
            failures.append(
                KnowledgeParseFailureRecord(
                    documentId=str(row["document_id"] or str(row["id"]).replace("v2doc_", "")),
                    title=str(row["file_name"] or "未命名资料"),
                    path=str(row["managed_path"] or row["original_path"] or ""),
                    kind=kind or "unknown",
                    parseStatus=str(row["parse_status"] or "failed"),
                    error=str(row["parse_error"] or "未能解析出可用正文"),
                    failureType=failure_type,
                    recoverable=parse_failure_recoverable(failure_type, kind=kind),
                    pageCount=page_count,
                    lastRetryAt=last_retry_at,
                    recommendedAction=recommended,
                )
            )
        return failures

    def classify_parse_retry_failure(error_text: str, *, kind: str = "") -> str:
        return classify_parse_failure_type(error_text, kind=kind)

    def count_parse_retry_targets(client_id: str, document_ids: list[str] | None = None, *, force: bool = False) -> int:
        wanted_ids = {item.strip() for item in (document_ids or []) if item and item.strip()}
        if not wanted_ids:
            row = state.db.fetchone(
                """
                SELECT COUNT(1) AS count
                FROM v2_documents
                WHERE client_id = ? AND COALESCE(parse_status, 'ready') NOT IN ('ready', 'partial_ready')
                """,
                (client_id,),
            )
            return int(row["count"] or 0) if row else 0
        placeholders = _sql_placeholders(wanted_ids)
        status_predicate = "" if force else "AND COALESCE(parse_status, 'ready') NOT IN ('ready', 'partial_ready')"
        row = state.db.fetchone(
            f"""
            SELECT COUNT(1) AS count
            FROM v2_documents
            WHERE client_id = ?
              {status_predicate}
              AND (document_id IN ({placeholders}) OR id IN ({placeholders}))
            """,
            (client_id, *wanted_ids, *wanted_ids),
        )
        return int(row["count"] or 0) if row else 0

    def resolve_parse_retry_source_file(
        client_id: str,
        row: dict[str, Any],
        *,
        title: str,
    ) -> tuple[Path | None, str]:
        """Resolve stale retry paths without trusting the old human-facing folder path."""

        def is_usable_source_file(candidate: Path) -> bool:
            try:
                if not candidate.exists() or not candidate.is_file() or candidate.stat().st_size <= 0:
                    return False
                if candidate.suffix.lower() == ".md":
                    sample = candidate.read_text(encoding="utf-8", errors="ignore")[:600]
                    if not has_effective_machine_text(sample):
                        return False
                return True
            except OSError:
                return False

        def source_family_key(name: str) -> str:
            stem = safe_filename(Path(name).stem).lower()
            stem = re.sub(r"^doc_[a-z0-9]+_", "", stem)
            for _ in range(4):
                stem = re.sub(r"[\s_-]*20\d{6,8}$", "", stem)
                stem = re.sub(r"[\s_-]*(日慈|cffc|cfc|cffc)$", "", stem)
                stem = re.sub(r"[\s_-]*(副本|copy|复制)$", "", stem)
                stem = re.sub(r"[\s_-]*[（(]?\d+[）)]?$", "", stem)
            return re.sub(r"[^0-9a-z\u4e00-\u9fff]+", "", stem)

        for key in ("managed_path", "original_path"):
            value = str(row.get(key) or "").strip()
            if not value:
                continue
            candidate = Path(value).expanduser()
            if is_usable_source_file(candidate):
                return candidate, key

        file_name = str(row.get("file_name") or title or "").strip()
        if not file_name:
            return None, "missing_path"

        workspace_root = state.data_dir / "client_workspace" / client_id
        search_roots = [workspace_root / "_imports", workspace_root]
        seen: set[Path] = set()
        usable_files: list[Path] = []
        for search_root in search_roots:
            if not search_root.exists():
                continue
            for candidate in search_root.rglob("*"):
                if candidate in seen:
                    continue
                seen.add(candidate)
                if not is_usable_source_file(candidate):
                    continue
                usable_files.append(candidate)
                if candidate.name == file_name:
                    return candidate, "workspace_import_name"
        wanted_key = source_family_key(file_name)
        wanted_suffix = Path(file_name).suffix.lower()
        if wanted_key:
            family_matches = [
                candidate
                for candidate in usable_files
                if candidate.suffix.lower() == wanted_suffix
                and source_family_key(candidate.name) == wanted_key
            ]
            if not family_matches:
                family_matches = [
                    candidate
                    for candidate in usable_files
                    if candidate.suffix.lower() == wanted_suffix
                    and len(source_family_key(candidate.name)) >= 6
                    and (
                        source_family_key(candidate.name) in wanted_key
                        or wanted_key in source_family_key(candidate.name)
                    )
                ]
            if family_matches:
                family_matches.sort(key=lambda item: item.stat().st_size, reverse=True)
                return family_matches[0], "workspace_import_family"
        return None, "file_missing"

    def is_parse_retry_placeholder_text(text: str) -> bool:
        return is_placeholder_machine_text(text)

    def verify_parse_retry_ready(client_id: str, document_id: str) -> tuple[bool, dict[str, Any]]:
        row = state.db.fetchone(
            """
            SELECT parse_status, parse_error, section_count, chunk_count, preview_text, doc_index_text, kind
            FROM v2_documents
            WHERE client_id = ? AND document_id = ?
            """,
            (client_id, document_id),
        )
        if not row:
            return False, {"failureType": "unknown", "message": "解析后未找到文档记录。"}
        parse_status = str(row["parse_status"] or "").strip()
        section_count = int(row["section_count"] or 0)
        chunk_count = int(row["chunk_count"] or 0)
        preview = str(row["preview_text"] or "").strip()
        index_text = str(row["doc_index_text"] or "").strip()
        if (
            parse_status in {"ready", "partial_ready"}
            and (section_count > 0 or chunk_count > 0)
            and (preview or index_text)
            and not is_parse_retry_placeholder_text(preview)
        ):
            return True, {
                "parseStatus": parse_status,
                "sectionCount": section_count,
                "chunkCount": chunk_count,
            }
        failure_type = classify_parse_retry_failure(
            str(row["parse_error"] or "未能解析出可用正文"),
            kind=str(row["kind"] or ""),
        )
        return False, {
            "failureType": failure_type,
            "parseStatus": parse_status,
            "sectionCount": section_count,
            "chunkCount": chunk_count,
            "message": str(row["parse_error"] or "解析重试完成但未产生可用正文。"),
        }

    def execute_parse_failure_retry_batch(
        client_id: str,
        payload: KnowledgeParseFailureRetryPayloadRecord,
        *,
        batch_id: str | None = None,
        job_id: str | None = None,
        source: str = "sync_retry",
    ) -> KnowledgeParseFailureRetryResultRecord:
        wanted_ids = {item.strip() for item in payload.documentIds if item and item.strip()}
        include_ready_targets = bool(payload.force and wanted_ids)
        rows = state.db.fetchall(
            """
            SELECT id, document_id, file_name, managed_path, original_path, markdown_path, kind, parse_status
            FROM v2_documents
            WHERE client_id = ?
              AND (? = 1 OR COALESCE(parse_status, 'ready') NOT IN ('ready', 'partial_ready'))
            ORDER BY updated_at DESC
            """,
            (client_id, 1 if include_ready_targets else 0),
        )
        target_rows = []
        for row in rows:
            doc_id = str(row["document_id"] or "").strip()
            v2_id = str(row["id"] or "").strip()
            if wanted_ids and doc_id not in wanted_ids and v2_id not in wanted_ids:
                continue
            target_rows.append(row)

        resolved_batch_id = batch_id or f"parse_retry_{uuid4().hex[:10]}"
        attempted = 0
        succeeded = 0
        failed = 0
        skipped = 0
        failure_buckets: dict[str, int] = {}
        items: list[dict[str, object]] = []
        timestamp = now_iso()
        for row in target_rows:
            attempted += 1
            doc_id = str(row["document_id"] or str(row["id"]).replace("v2doc_", "")).strip()
            title = str(row["file_name"] or doc_id or "未命名资料")
            source_file, source_resolution = resolve_parse_retry_source_file(client_id, dict(row), title=title)
            source_kind = str(row["kind"] or "").strip().lower().lstrip(".")
            if source_file is None:
                failure_type = "managed_path_missing"
                if source_resolution == "file_missing":
                    failure_type = "file_missing"
                failed += 1
                failure_buckets[failure_type] = failure_buckets.get(failure_type, 0) + 1
                if job_id:
                    append_knowledge_job_event(
                        job_id,
                        "warning",
                        "解析重试失败：未找到可用源文件",
                        {"documentId": doc_id, "title": title, "resolution": source_resolution},
                    )
                items.append(
                    {
                        "documentId": doc_id,
                        "title": title,
                        "status": "failed",
                        "failureType": failure_type,
                        "message": "未找到 managed_path/original_path/markdown_path 或 _imports 中的可用源文件。",
                    }
                )
                continue
            try:
                file_size_bytes = None
                page_count = None
                try:
                    file_size_bytes = int(source_file.stat().st_size)
                except Exception:
                    file_size_bytes = None
                if source_kind == "pdf":
                    try:
                        page_count = inspect_pdf_page_count(source_file)
                    except Exception:
                        page_count = None

                def emit_ocr_progress(detail: dict[str, object]) -> None:
                    if not job_id:
                        return
                    append_knowledge_job_event(
                        job_id,
                        "info",
                        "OCR 分页进度",
                        {
                            "documentId": doc_id,
                            "title": title,
                            "failureType": "ocr_required",
                            "sourceResolution": source_resolution,
                            "fileSizeBytes": file_size_bytes,
                            "pageCount": page_count,
                            **detail,
                        },
                    )

                ingest_result = ingest_document_knowledge(
                    state.db,
                    data_dir=state.data_dir,
                    client_id=client_id,
                    import_id=None,
                    document_id=doc_id,
                    source_path=source_file,
                    original_source_path=Path(str(row["original_path"])) if row["original_path"] else None,
                    title=str(row["file_name"] or doc_id),
                    kind=str(row["kind"] or source_file.suffix.lstrip(".") or "unknown"),
                    source=source,
                    fallback_excerpt="解析重试",
                    created_at=timestamp,
                    ai_service=state.ai,
                    ocr_start_page=1,
                    ocr_max_pages=payload.ocrMaxPages,
                    ocr_batch_size=payload.ocrBatchSize,
                    ocr_continue_to_end=payload.ocrContinueToEnd,
                    force_ocr=payload.forceOcr,
                    ocr_progress_callback=emit_ocr_progress,
                )
                is_ready, verification = verify_parse_retry_ready(client_id, doc_id)
                verification = {
                    **verification,
                    "sourceResolution": source_resolution,
                    "fileSizeBytes": file_size_bytes,
                    "pageCount": page_count,
                    "ocrMetadata": ingest_result.get("ocr_metadata") if isinstance(ingest_result, dict) else None,
                }
                if not is_ready:
                    failure_type = str(verification.get("failureType") or "empty_text")
                    failed += 1
                    failure_buckets[failure_type] = failure_buckets.get(failure_type, 0) + 1
                    if job_id:
                        append_knowledge_job_event(
                            job_id,
                            "warning",
                            "解析重试未产生可用正文",
                            {"documentId": doc_id, "title": title, **verification},
                        )
                    items.append(
                        {
                            "documentId": doc_id,
                            "title": title,
                            "status": "failed",
                            "failureType": failure_type,
                            "message": str(verification.get("message") or "解析重试完成但未产生可用正文。"),
                        }
                    )
                    if job_id:
                        update_knowledge_job_progress(job_id, attempted, f"解析重试进度：{attempted}/{len(target_rows)}")
                    continue
                succeeded += 1
                if job_id:
                    append_knowledge_job_event(
                        job_id,
                        "info",
                        "解析重试成功",
                        {"documentId": doc_id, "title": title, **verification},
                    )
                items.append(
                    {
                        "documentId": doc_id,
                        "title": title,
                        "status": "succeeded",
                        "failureType": None,
                        "message": "解析重试成功。",
                    }
                )
            except Exception as error:
                failure_type = classify_parse_retry_failure(str(error), kind=source_kind)
                failed += 1
                failure_buckets[failure_type] = failure_buckets.get(failure_type, 0) + 1
                if job_id:
                    append_knowledge_job_event(
                        job_id,
                        "warning",
                        "解析重试失败",
                        {"documentId": doc_id, "title": title, "failureType": failure_type, "message": str(error)},
                    )
                items.append(
                    {
                        "documentId": doc_id,
                        "title": title,
                        "status": "failed",
                        "failureType": failure_type,
                        "message": str(error),
                    }
                )
            if job_id:
                update_knowledge_job_progress(job_id, attempted, f"解析重试进度：{attempted}/{len(target_rows)}")
        if wanted_ids:
            resolved_ids = {
                str(item.get("documentId") or "").strip()
                for item in items
                if str(item.get("documentId") or "").strip()
            }
            unresolved = sorted(wanted_ids - resolved_ids)
            for missing in unresolved:
                skipped += 1
                if job_id:
                    append_knowledge_job_event(job_id, "warning", "解析重试跳过：未找到待重试文档", {"documentId": missing})
                items.append(
                    {
                        "documentId": missing,
                        "title": missing,
                        "status": "skipped",
                        "failureType": None,
                        "message": "未找到待重试文档，已跳过。",
                    }
                )
        result = KnowledgeParseFailureRetryResultRecord(
            batchId=resolved_batch_id,
            attempted=attempted,
            succeeded=succeeded,
            failed=failed,
            skipped=skipped,
            failureBuckets=failure_buckets,
            items=items,
        )
        state.db.set_setting(
            f"knowledge.parse_retry_summary:{client_id}",
            to_json(
                {
                    **result.model_dump(mode="json"),
                    "lastRetryAt": timestamp,
                    "lastRetrySucceeded": bool(failed == 0 and attempted > 0),
                }
            ),
        )
        if succeeded > 0:
            ensure_standard_client_folders(client_id)
            _enqueue_workspace_refresh_safe(
                client_id=client_id,
                source_type="parse_retry_complete",
                source_id=job_id or resolved_batch_id,
                reason="parse_retry_completed",
                scope_type="client",
                scope_id=client_id,
                priority="normal",
            )
        return result

    def enqueue_parse_retry_job(
        client_id: str,
        payload: KnowledgeParseFailureRetryPayloadRecord,
        *,
        reason: str = "",
    ) -> KnowledgeJobRecord:
        total_items = count_parse_retry_targets(client_id, payload.documentIds, force=payload.force)
        return enqueue_knowledge_job(
            client_id,
            "retry_parse",
            {
                "documentIds": payload.documentIds,
                "force": payload.force,
                "ocrMaxPages": payload.ocrMaxPages,
                "ocrBatchSize": payload.ocrBatchSize,
                "ocrContinueToEnd": payload.ocrContinueToEnd,
                "forceOcr": payload.forceOcr,
                "reason": reason,
                "source": "readiness_action",
            },
            total_items,
        )

    @app.post(
        "/api/v1/clients/{client_id}/knowledge/parse-failures/retry",
        response_model=KnowledgeParseFailureRetryResultRecord,
    )
    def retry_client_parse_failures(
        client_id: str,
        payload: KnowledgeParseFailureRetryPayloadRecord,
    ) -> KnowledgeParseFailureRetryResultRecord:
        build_client_summary(client_id)
        return execute_parse_failure_retry_batch(client_id, payload, source="retry")

    @app.get(
        "/api/v1/clients/{client_id}/workspace/data-center-readiness",
        response_model=WorkspaceDataCenterReadinessRecord,
    )
    def get_workspace_data_center_readiness(client_id: str) -> WorkspaceDataCenterReadinessRecord:
        client_summary = build_client_summary(client_id)
        ensure_standard_client_folders(client_id)
        knowledge_status = build_knowledge_status_record(client_id)
        vector_status_payload = get_vector_index_manifest_status(
            state.db,
            data_dir=state.data_dir,
            client_id=client_id,
            ai_service=state.ai,
        )

        def classify_parse_error_category(error_text: str, *, kind: str = "") -> str | None:
            if not str(error_text or "").strip():
                return None
            return classify_parse_failure_type(error_text, kind=kind)

        rows = state.db.fetchall(
            """
            SELECT
                v2.document_id AS document_id,
                v2.id AS v2_document_id,
                kd.id AS knowledge_document_id,
                COALESCE(d.title, v2.file_name, '') AS title,
                v2.file_name AS file_name,
                v2.kind AS kind,
                v2.material_layer AS material_layer,
                v2.parse_status AS parse_status,
                v2.parse_error AS parse_error,
                v2.preview_text AS preview_text,
                v2.doc_index_text AS doc_index_text,
                v2.markdown_content AS markdown_content,
                v2.original_path AS original_path,
                v2.managed_path AS managed_path,
                v2.markdown_path AS markdown_path,
                v2.canonical_kind AS canonical_kind,
                v2.lifecycle_status AS lifecycle_status,
                v2.is_searchable AS is_searchable,
                d.path AS document_path,
                d.original_source_path AS original_source_path,
                v2.chunk_count AS chunk_count,
                v2.section_count AS section_count,
                v2.updated_at AS updated_at,
                CASE WHEN dc.id IS NULL THEN 0 ELSE 1 END AS has_document_card,
                CASE WHEN ks.id IS NULL THEN 0 ELSE 1 END AS has_surrogate,
                CASE WHEN kmi.id IS NULL THEN 0 ELSE 1 END AS has_master_index,
                COALESCE(kd.vector_status, 'pending') AS vector_status
            FROM v2_documents v2
            LEFT JOIN documents d ON d.id = v2.document_id
            LEFT JOIN knowledge_documents kd ON kd.id = v2.document_id
            LEFT JOIN document_cards dc ON dc.knowledge_document_id = kd.id
            LEFT JOIN knowledge_surrogates ks ON ks.knowledge_document_id = kd.id
            LEFT JOIN knowledge_master_index kmi ON kmi.surrogate_id = ks.id
            WHERE v2.client_id = ?
            ORDER BY v2.updated_at DESC
            LIMIT 500
            """,
            (client_id,),
        )
        document_items: list[WorkspaceDocumentProcessingStatusRecord] = []
        for row in rows:
            source_info = classify_source_availability_for_row(row)
            source_availability = str(source_info.get("sourceAvailability") or "unknown")
            placeholder_only = not has_effective_machine_text(
                row["markdown_content"],
                row["preview_text"],
                row["doc_index_text"],
            )
            stored_parse_error = str(row["parse_error"] or "").strip()
            parse_status = str(row["parse_status"] or "queued")
            parse_error = stored_parse_error or None
            if source_availability == "invalid_source" or placeholder_only:
                parse_status = "failed"
                if source_availability == "invalid_source":
                    parse_error = "原文件缺失或为空，且没有有效机读稿。"
                elif placeholder_only:
                    parse_error = "机读稿为占位内容，没有有效正文。"
            document_items.append(
                WorkspaceDocumentProcessingStatusRecord(
                    documentId=str(row["document_id"] or ""),
                    v2DocumentId=str(row["v2_document_id"] or "") or None,
                    knowledgeDocumentId=str(row["knowledge_document_id"] or "") or None,
                    title=str(row["title"] or row["file_name"] or "未命名资料"),
                    fileName=str(row["file_name"] or "未命名资料"),
                    kind=str(row["kind"] or "unknown"),
                    materialLayer=str(row["material_layer"] or "evidence"),
                    parseStatus=parse_status,
                    parseError=parse_error,
                    parseErrorCategory=classify_parse_error_category(str(parse_error or "").strip(), kind=str(row["kind"] or "")),
                    hasDocumentCard=bool(int(row["has_document_card"] or 0)),
                    hasSurrogate=bool(int(row["has_surrogate"] or 0)),
                    hasMasterIndex=bool(int(row["has_master_index"] or 0)),
                    vectorStatus=str(row["vector_status"] or "pending"),
                    chunkCount=int(row["chunk_count"] or 0),
                    sectionCount=int(row["section_count"] or 0),
                    usedByLatestContextPack=False,
                    lastHitAt=None,
                    updatedAt=str(row["updated_at"] or now_iso()),
                    sourceAvailability=source_availability if source_availability in {"original_available", "machine_readable_only", "invalid_source"} else "unknown",
                    originalAvailable=bool(source_info.get("originalAvailable")),
                    machineReadableAvailable=bool(source_info.get("machineReadableAvailable")),
                    openOriginalDisabledReason=str(source_info.get("openOriginalDisabledReason") or "") or None,
                )
            )
        ready_statuses = {"ready"}
        partial_ready_statuses = {"partial_ready"}
        queued_statuses = {"queued"}
        running_statuses = {"running", "processing", "parsing"}
        parsing_statuses = queued_statuses | running_statuses
        failed_document_ids: list[str] = []
        missing_card_ids: list[str] = []
        missing_index_ids: list[str] = []
        stale_vector_ids: list[str] = []
        parse_failure_buckets: dict[str, int] = {}
        ready_documents = 0
        partial_ready_documents = 0
        queued_documents = 0
        running_documents = 0
        parsing_documents = 0
        failed_documents = 0
        invalid_documents = 0
        source_missing_documents = 0
        placeholder_only_documents = 0
        invalid_document_ids: list[str] = []
        for item in document_items:
            normalized_status = item.parseStatus.strip().lower()
            if item.sourceAvailability == "invalid_source":
                invalid_documents += 1
                if item.documentId:
                    invalid_document_ids.append(item.documentId)
            if item.sourceAvailability in {"invalid_source", "machine_readable_only"} and not item.originalAvailable:
                source_missing_documents += 1
            if item.parseError and "占位内容" in item.parseError:
                placeholder_only_documents += 1
            if normalized_status in ready_statuses:
                ready_documents += 1
            elif normalized_status in partial_ready_statuses:
                partial_ready_documents += 1
            elif normalized_status in queued_statuses:
                parsing_documents += 1
                queued_documents += 1
            elif normalized_status in running_statuses:
                parsing_documents += 1
                running_documents += 1
            elif normalized_status in parsing_statuses:
                parsing_documents += 1
            else:
                failed_documents += 1
                failure_type = item.parseErrorCategory or classify_parse_failure_type(str(item.parseError or ""), kind=item.kind)
                parse_failure_buckets[failure_type] = parse_failure_buckets.get(failure_type, 0) + 1
                if item.documentId:
                    failed_document_ids.append(item.documentId)
            if not item.hasDocumentCard and item.documentId:
                missing_card_ids.append(item.documentId)
            if (not item.hasSurrogate or not item.hasMasterIndex) and item.documentId:
                missing_index_ids.append(item.documentId)
            if str(item.vectorStatus or "").strip().lower() not in {"ready", "chunk_indexed"} and item.documentId:
                stale_vector_ids.append(item.documentId)

        auto_repairable_documents = 0
        zero_byte_documents = 0
        legacy_folder_documents_without_v2 = 0
        machine_readable_only_documents = 0
        dedupe_candidate_documents = 0
        auto_repair_target_ids: list[str] = []
        try:
            auto_repair_preview = _build_document_auto_repair_preview(
                client_id,
                DocumentAutoRepairPreviewPayloadRecord(limit=500),
            )
            auto_repairable_documents = int(auto_repair_preview.summary.get("autoRepairable", 0) or 0)
            zero_byte_documents = sum(1 for item in auto_repair_preview.items if item.healthStatus == "zero_byte_original")
            legacy_folder_documents_without_v2 = sum(1 for item in auto_repair_preview.items if item.healthStatus == "original_nonzero_no_v2")
            machine_readable_only_documents = sum(1 for item in auto_repair_preview.items if item.healthStatus == "md_compat_candidate")
            dedupe_candidate_documents = sum(1 for item in auto_repair_preview.items if item.healthStatus == "duplicate_candidate")
            auto_repair_target_ids = [
                item.documentId
                for item in auto_repair_preview.items
                if item.stage in AUTO_REPAIR_LOW_RISK_STAGES and not item.requiresHuman
            ][:120]
        except Exception:
            logger.warning("[readiness] failed to build auto repair preview for %s", client_id, exc_info=True)

        ensure_data_center_ingest_schema(state.db)
        orphan_task_count = int(
            state.db.scalar(
                """
                SELECT COUNT(1) AS count
                FROM tasks t
                LEFT JOIN clients c ON c.id = t.client_id
                WHERE COALESCE(t.client_id, '') != ''
                  AND c.id IS NULL
                """
            )
            or 0
        )
        orphan_event_line_count = int(
            state.db.scalar(
                """
                SELECT COUNT(1) AS count
                FROM event_lines e
                LEFT JOIN clients c ON c.id = e.primary_client_id
                WHERE COALESCE(e.primary_client_id, '') != ''
                  AND c.id IS NULL
                """
            )
            or 0
        )
        skipped_orphan_client_ingest_count = int(
            state.db.scalar(
                """
                SELECT COUNT(1) AS count
                FROM data_center_ingest_events
                WHERE status = ?
                """,
                (SKIPPED_ORPHAN_CLIENT_STATUS,),
            )
            or 0
        )

        running_knowledge_jobs = int(
            state.db.scalar(
                "SELECT COUNT(1) AS count FROM knowledge_jobs WHERE client_id = ? AND status IN ('queued', 'running')",
                (client_id,),
            )
            or 0
        )
        failed_knowledge_jobs = int(
            state.db.scalar(
                "SELECT COUNT(1) AS count FROM knowledge_jobs WHERE client_id = ? AND status = 'failed'",
                (client_id,),
            )
            or 0
        )
        latest_job_event_rows = state.db.fetchall(
            """
            SELECT e.job_id, e.level, e.message, e.created_at
            FROM knowledge_job_events e
            JOIN knowledge_jobs j ON j.id = e.job_id
            WHERE j.client_id = ?
            ORDER BY e.created_at DESC
            LIMIT 20
            """,
            (client_id,),
        )
        latest_job_events = [
            WorkspaceDataCenterReadinessJobEventRecord(
                jobId=str(row["job_id"] or ""),
                level=str(row["level"] or "info"),
                message=str(row["message"] or ""),
                createdAt=str(row["created_at"] or now_iso()),
            )
            for row in latest_job_event_rows
        ]

        recent_job_rows = state.db.fetchall(
            """
            SELECT id, job_type, status, processed_items, total_items, last_error, updated_at
            FROM knowledge_jobs
            WHERE client_id = ?
            ORDER BY updated_at DESC
            LIMIT 20
            """,
            (client_id,),
        )
        recent_jobs = [
            WorkspaceDataCenterReadinessRecentJobRecord(
                id=str(row["id"] or ""),
                jobType=str(row["job_type"] or "unknown"),
                status=str(row["status"] or "unknown"),
                processedItems=int(row["processed_items"] or 0),
                totalItems=int(row["total_items"] or 0),
                lastError=str(row["last_error"] or "").strip() or None,
                updatedAt=str(row["updated_at"] or now_iso()),
            )
            for row in recent_job_rows
        ]

        internet_source_kinds = [
            "internet_source_doc",
            "evaluation_reference_doc",
            "similar_case_doc",
            "policy_context_doc",
        ]
        internet_source_placeholders = _sql_placeholders(internet_source_kinds)
        internet_source_count = int(
            state.db.scalar(
                f"""
                SELECT COUNT(1) AS count
                FROM v2_documents
                WHERE client_id = ?
                  AND COALESCE(is_searchable, 1) = 1
                  AND COALESCE(lifecycle_status, 'active') = 'active'
                  AND canonical_kind IN ({internet_source_placeholders})
                """,
                (client_id, *internet_source_kinds),
            )
            or 0
        )
        internet_fact_card_count = int(
            state.db.scalar(
                """
                SELECT COUNT(1) AS count
                FROM v2_documents
                WHERE client_id = ?
                  AND COALESCE(is_searchable, 1) = 1
                  AND COALESCE(lifecycle_status, 'active') = 'active'
                  AND canonical_kind = 'internet_fact_card'
                """,
                (client_id,),
            )
            or 0
        )
        latest_internet_doc_row = state.db.fetchone(
            """
            SELECT MAX(updated_at) AS latest
            FROM v2_documents
            WHERE client_id = ?
              AND (
                COALESCE(content_domain, '') = 'internet_enrichment'
                OR canonical_kind IN ('internet_source_doc', 'internet_fact_card', 'project_enrichment_doc',
                                      'evaluation_reference_doc', 'similar_case_doc', 'policy_context_doc')
              )
            """,
            (client_id,),
        )
        latest_internet_doc_at = str(latest_internet_doc_row["latest"] or "").strip() if latest_internet_doc_row else ""
        latest_internet_job_row = state.db.fetchone(
            """
            SELECT status, updated_at, last_error
            FROM knowledge_jobs
            WHERE client_id = ? AND job_type = 'internet_enrichment'
            ORDER BY updated_at DESC
            LIMIT 1
            """,
            (client_id,),
        )
        latest_internet_job_status = str(latest_internet_job_row["status"] or "").strip().lower() if latest_internet_job_row else ""
        if latest_internet_job_status in {"queued", "running"}:
            internet_enrichment_status = latest_internet_job_status
        elif internet_source_count > 0 or internet_fact_card_count > 0:
            internet_enrichment_status = "ready"
        elif latest_internet_job_status == "failed":
            internet_enrichment_status = "failed"
        else:
            internet_enrichment_status = "none"

        def _extract_remaining_user_required_gaps(markdown_text: str | None) -> list[str]:
            text = str(markdown_text or "")
            if "## 仍需用户补充" not in text:
                return []
            tail = text.split("## 仍需用户补充", 1)[1]
            block = tail.split("\n## ", 1)[0]
            gaps: list[str] = []
            for raw_line in block.splitlines():
                line = raw_line.strip()
                if not line.startswith("- "):
                    continue
                item = line[2:].strip()
                if not item or "暂未识别" in item:
                    continue
                gaps.append(item)
            return gaps[:12]

        latest_project_enrichment_row = state.db.fetchone(
            """
            SELECT markdown_content
            FROM v2_documents
            WHERE client_id = ?
              AND canonical_kind = 'project_enrichment_doc'
              AND COALESCE(content_domain, '') = 'internet_enrichment'
            ORDER BY updated_at DESC
            LIMIT 1
            """,
            (client_id,),
        )
        remaining_user_required_gaps = _extract_remaining_user_required_gaps(
            str(latest_project_enrichment_row["markdown_content"] or "") if latest_project_enrichment_row else ""
        )

        latest_context_pack_row = state.db.fetchone(
            "SELECT MAX(updated_at) AS latest FROM context_packs WHERE client_id = ?",
            (client_id,),
        )
        latest_context_pack_at = (
            str(latest_context_pack_row["latest"]).strip()
            if latest_context_pack_row and latest_context_pack_row["latest"]
            else None
        )
        latest_document_update_at = (
            max((str(item.updatedAt or "").strip() for item in document_items if str(item.updatedAt or "").strip()), default=None)
            if document_items
            else None
        )

        def _parse_iso_datetime(value: str | None) -> datetime | None:
            text = str(value or "").strip()
            if not text:
                return None
            try:
                parsed = datetime.fromisoformat(text.replace("Z", "+00:00"))
                return parsed.replace(tzinfo=None) if parsed.tzinfo is not None else parsed
            except ValueError:
                return None

        latest_context_pack_dt = _parse_iso_datetime(latest_context_pack_at)
        latest_document_update_dt = _parse_iso_datetime(latest_document_update_at)
        context_pack_stale = False
        if ready_documents + partial_ready_documents > 0:
            if latest_context_pack_dt is None:
                context_pack_stale = True
            elif latest_document_update_dt and latest_document_update_dt > latest_context_pack_dt + timedelta(minutes=5):
                context_pack_stale = True

        context_quality = "none"
        missing_context_count = 0
        try:
            workspace_snapshot = workspace_for_client(client_id)
            context_pack = build_client_page_context_pack(
                state.db,
                data_dir=state.data_dir,
                client_id=client_id,
                prompt="",
                page="workspace_chat",
                include_raw_evidence=False,
                workspace=workspace_snapshot,
            )
            context_quality = str(context_pack.quality.contextQuality or "none")
            missing_context_count = len(context_pack.missingContext)
            raw_evidence_doc_ids: set[str] = set()
            for evidence_item in list(context_pack.rawEvidence or []):
                try:
                    evidence_doc_id = str(getattr(evidence_item, "documentId", "") or "").strip()
                    if evidence_doc_id:
                        raw_evidence_doc_ids.add(evidence_doc_id)
                except Exception:
                    continue
            if raw_evidence_doc_ids:
                for item in document_items:
                    item.usedByLatestContextPack = bool(item.documentId and item.documentId in raw_evidence_doc_ids)
                    if item.usedByLatestContextPack and not item.lastHitAt:
                        item.lastHitAt = item.updatedAt
        except Exception:
            context_quality = "none"
            missing_context_count = 0

        refresh_events = list_workspace_context_refresh_events(
            state.db,
            client_id=client_id,
            active_only=False,
            limit=50,
        )
        refresh_event_queued_count = int(sum(1 for item in refresh_events if item.status == "queued"))
        refresh_event_running_count = int(sum(1 for item in refresh_events if item.status == "running"))
        refresh_event_failed_count = int(sum(1 for item in refresh_events if item.status == "failed"))

        recommended_fixes: list[WorkspaceDataCenterReadinessFixRecord] = []
        if auto_repair_target_ids:
            recommended_fixes.append(
                WorkspaceDataCenterReadinessFixRecord(
                    id="fix_auto_repair_documents",
                    label="自动整理待处理资料",
                    actionType="auto_repair_documents",
                    severity="warning",
                    reason=f"当前有 {len(auto_repair_target_ids)} 份资料可由系统自动解析、归并、软清理或重分类。",
                    targetIds=list(dict.fromkeys(auto_repair_target_ids)),
                    estimatedImpact="系统先处理低风险项，减少待整理资料数量，并刷新数据中心上下文。",
                )
            )
        if invalid_document_ids:
            recommended_fixes.append(
                WorkspaceDataCenterReadinessFixRecord(
                    id="fix_cleanup_invalid_documents",
                    label="清理无效资料",
                    actionType="cleanup_invalid_documents",
                    severity="critical",
                    reason=f"当前有 {len(invalid_document_ids)} 份资料原文件缺失/为空且机读稿无效，应从检索中软清理。",
                    targetIds=list(dict.fromkeys(invalid_document_ids[:120])),
                    estimatedImpact="无效资料会从检索和引证中退出，避免占位内容污染回答。",
                )
            )
            recommended_fixes.append(
                WorkspaceDataCenterReadinessFixRecord(
                    id="fix_rebind_original_file",
                    label="重绑原文件",
                    actionType="rebind_original_file",
                    severity="warning",
                    reason="部分资料可能存在同族真实原文件，可在后续人工重绑。",
                    targetIds=list(dict.fromkeys(invalid_document_ids[:60])),
                    estimatedImpact="找到真实原文件后，可重新解析并恢复为可用资料。",
                )
            )
        if failed_document_ids:
            recommended_fixes.append(
                WorkspaceDataCenterReadinessFixRecord(
                    id="fix_retry_parse",
                    label="重试失败解析",
                    actionType="retry_parse",
                    severity="critical",
                    reason=f"当前有 {len(failed_document_ids)} 份资料解析失败。",
                    targetIds=list(dict.fromkeys(failed_document_ids[:120])),
                    estimatedImpact="失败资料将重新进入解析与索引流程，提升可检索率。",
                )
            )
            recommended_fixes.append(
                WorkspaceDataCenterReadinessFixRecord(
                    id="fix_inspect_failed_documents",
                    label="检查失败资料",
                    actionType="inspect_failed_documents",
                    severity="warning",
                    reason="先检查失败资料的错误类型，再决定是否批量重试。",
                    targetIds=list(dict.fromkeys(failed_document_ids[:60])),
                    estimatedImpact="减少无效重试，优先处理可恢复错误。",
                )
            )
        ocr_recoverable_count = sum(
            count
            for failure_type, count in parse_failure_buckets.items()
            if parse_failure_recoverable(failure_type)
        )
        if (ready_documents + partial_ready_documents) < len(document_items) and running_knowledge_jobs == 0:
            recommended_fixes.append(
                WorkspaceDataCenterReadinessFixRecord(
                    id="fix_rebuild_client_knowledge",
                    label="重建客户知识库",
                    actionType="rebuild_client_knowledge",
                    severity="warning",
                    reason="资料加工链路未完整收敛，建议重新排队重建。",
                    targetIds=[],
                    estimatedImpact="重新计算资料加工链路，修复隐藏漏处理文档。",
                )
            )
        if missing_card_ids:
            recommended_fixes.append(
                WorkspaceDataCenterReadinessFixRecord(
                    id="fix_regenerate_document_cards",
                    label="重建资料卡",
                    actionType="regenerate_document_cards",
                    severity="warning",
                    reason=f"当前有 {len(missing_card_ids)} 份资料缺少 document card。",
                    targetIds=list(dict.fromkeys(missing_card_ids[:120])),
                    estimatedImpact="补全资料卡后，摘要检索与上下文组织质量会提升。",
                )
            )
        if missing_index_ids:
            recommended_fixes.append(
                WorkspaceDataCenterReadinessFixRecord(
                    id="fix_sync_master_index",
                    label="同步主索引",
                    actionType="sync_master_index",
                    severity="warning",
                    reason=f"当前有 {len(missing_index_ids)} 份资料缺少 surrogate/master index 映射。",
                    targetIds=list(dict.fromkeys(missing_index_ids[:120])),
                    estimatedImpact="主索引补齐后，语义召回和跨资料路由稳定性提升。",
                )
            )
        if stale_vector_ids:
            recommended_fixes.append(
                WorkspaceDataCenterReadinessFixRecord(
                    id="fix_sync_vector_index",
                    label="同步向量索引",
                    actionType="sync_vector_index",
                    severity="warning",
                    reason=f"当前有 {len(stale_vector_ids)} 份资料向量状态不是 ready。",
                    targetIds=list(dict.fromkeys(stale_vector_ids[:120])),
                    estimatedImpact="向量索引恢复后，语义相关资料可被召回。",
                )
            )
        if missing_context_count >= 6 and not any(
            item.actionType == "inspect_failed_documents" for item in recommended_fixes
        ):
            inspect_targets = list(
                dict.fromkeys(
                    [
                        *failed_document_ids[:30],
                        *missing_index_ids[:20],
                        *stale_vector_ids[:20],
                    ]
                )
            )
            recommended_fixes.append(
                WorkspaceDataCenterReadinessFixRecord(
                    id="fix_inspect_missing_context_high",
                    label="检查上下文缺口来源",
                    actionType="inspect_failed_documents",
                    severity="warning",
                    reason=f"当前 missingContext 达到 {missing_context_count} 项，建议先定位加工链缺口。",
                    targetIds=inspect_targets,
                    estimatedImpact="优先识别导致上下文缺口的资料链路，减少盲目重试。",
                )
            )
        if missing_context_count > 0 or refresh_event_failed_count > 0 or context_pack_stale:
            refresh_fix_reason = (
                f"检测到 {refresh_event_failed_count} 条上下文刷新失败事件，建议刷新上下文包。"
                if refresh_event_failed_count > 0
                else (
                    "检测到资料更新时间晚于最新 context pack，建议刷新上下文包。"
                    if context_pack_stale
                    else f"当前仍有 {missing_context_count} 项上下文缺口待补齐。"
                )
            )
            recommended_fixes.append(
                WorkspaceDataCenterReadinessFixRecord(
                    id="fix_refresh_context_pack",
                    label="刷新上下文包",
                    actionType="refresh_context_pack",
                    severity="warning" if (refresh_event_failed_count > 0 or context_pack_stale) else "info",
                    reason=refresh_fix_reason,
                    targetIds=[],
                    estimatedImpact="触发新一轮上下文构建，减少 stale 回答。",
                )
            )
        if internet_enrichment_status in {"none", "failed"} and latest_internet_job_status not in {"queued", "running"}:
            recommended_fixes.append(
                WorkspaceDataCenterReadinessFixRecord(
                    id="fix_internet_enrichment",
                    label="补全互联网资料",
                    actionType="internet_enrichment",
                    severity="info",
                    reason=f"当前客户“{client_summary.name}”还没有可检索的互联网补充资料；可按任务、事件线或项目缺口抓取官网、项目页、报告和同类案例。",
                    targetIds=[],
                    estimatedImpact="互联网资料会先沉淀为 clean markdown、事实卡和项目补全文档，再进入 raw_reading_pack_v2。",
                )
            )

        summary = WorkspaceDataCenterReadinessSummaryRecord(
            totalDocuments=len(document_items),
            readyDocuments=ready_documents,
            partialReadyDocuments=partial_ready_documents,
            parsingDocuments=parsing_documents,
            queuedDocuments=queued_documents,
            runningDocuments=running_documents,
            failedDocuments=failed_documents,
            invalidDocuments=invalid_documents,
            sourceMissingDocuments=source_missing_documents,
            placeholderOnlyDocuments=placeholder_only_documents,
            autoRepairableDocuments=auto_repairable_documents,
            zeroByteDocuments=zero_byte_documents,
            legacyFolderDocumentsWithoutV2=legacy_folder_documents_without_v2,
            machineReadableOnlyDocuments=machine_readable_only_documents,
            dedupeCandidateDocuments=dedupe_candidate_documents,
            orphanTaskCount=orphan_task_count,
            orphanEventLineCount=orphan_event_line_count,
            skippedOrphanClientIngestCount=skipped_orphan_client_ingest_count,
            parseFailureBuckets=parse_failure_buckets,
            ocrRecoverableCount=ocr_recoverable_count,
            documentCards=int(sum(1 for item in document_items if item.hasDocumentCard)),
            surrogates=int(sum(1 for item in document_items if item.hasSurrogate)),
            masterIndexEntries=int(sum(1 for item in document_items if item.hasMasterIndex)),
            vectorReadyDocuments=int(sum(1 for item in document_items if str(item.vectorStatus or "").strip().lower() in {"ready", "chunk_indexed"})),
            vectorStatus=str(vector_status_payload.get("status") or "unknown"),
            vectorMasterIndexed=int(vector_status_payload.get("masterIndexed") or 0),
            vectorChunkIndexed=int(vector_status_payload.get("chunkIndexed") or 0),
            latestContextPackAt=latest_context_pack_at,
            contextQuality=context_quality,
            missingContextCount=missing_context_count,
            refreshEventQueuedCount=refresh_event_queued_count,
            refreshEventRunningCount=refresh_event_running_count,
            refreshEventFailedCount=refresh_event_failed_count,
            internetEnrichmentStatus=internet_enrichment_status,
            internetSourceCount=internet_source_count,
            internetFactCardCount=internet_fact_card_count,
            remainingUserRequiredGaps=remaining_user_required_gaps,
            lastInternetEnrichmentAt=str(latest_internet_doc_at or (latest_internet_job_row["updated_at"] if latest_internet_job_row else "")).strip()
            or None,
        )
        jobs = WorkspaceDataCenterReadinessJobsRecord(
            runningKnowledgeJobs=running_knowledge_jobs,
            failedKnowledgeJobs=failed_knowledge_jobs,
            latestJobEvents=latest_job_events,
            localOptimization=get_local_model_optimization_stats(state.db, client_id=client_id),
        )
        return WorkspaceDataCenterReadinessRecord(
            clientId=client_id,
            generatedAt=now_iso(),
            summary=summary,
            documents=document_items,
            jobs=jobs,
            recommendedFixes=recommended_fixes,
            recentJobs=recent_jobs,
            recentRefreshEvents=refresh_events[:20],
        )

    @app.post(
        "/api/v1/clients/{client_id}/workspace/data-center-readiness/actions",
        response_model=WorkspaceDataCenterReadinessActionResultRecord,
    )
    def run_workspace_data_center_readiness_action(
        client_id: str,
        payload: WorkspaceDataCenterReadinessActionPayloadRecord,
    ) -> WorkspaceDataCenterReadinessActionResultRecord:
        build_client_summary(client_id)
        action_type = payload.actionType
        refresh_reason = str(payload.reason or "").strip() or f"readiness_action:{action_type}"
        refresh_event, _deduped = enqueue_workspace_context_refresh(
            state.db,
            client_id=client_id,
            source_type=f"readiness_action:{action_type}",
            source_id=payload.targetIds[0] if payload.targetIds else None,
            reason=refresh_reason,
            scope_type="client",
            scope_id=client_id,
            priority="normal",
        )
        mark_workspace_context_refresh_event_running(state.db, event_id=refresh_event.id)
        try:
            if action_type == "auto_repair_documents":
                preview = _build_document_auto_repair_preview(
                    client_id,
                    DocumentAutoRepairPreviewPayloadRecord(documentIds=payload.targetIds),
                )
                actionable = [
                    item
                    for item in preview.items
                    if item.stage in AUTO_REPAIR_LOW_RISK_STAGES and not item.requiresHuman
                ]
                if not actionable:
                    result = WorkspaceDataCenterReadinessActionResultRecord(
                        actionType=action_type,
                        status="completed",
                        jobId=None,
                        refreshEventId=refresh_event.id,
                        affectedCount=0,
                        message="当前没有可自动整理的低风险资料。",
                        errors=[],
                    )
                    mark_workspace_context_refresh_event_completed(state.db, event_id=refresh_event.id)
                    return result
                job = enqueue_knowledge_job(
                    client_id,
                    "workspace_document_auto_repair",
                    {
                        "documentIds": [item.documentId for item in actionable],
                        "includeHumanRequired": False,
                        "source": "readiness_action",
                    },
                    total_items=len(actionable),
                )
                result = WorkspaceDataCenterReadinessActionResultRecord(
                    actionType=action_type,
                    status="queued",
                    jobId=job.id,
                    refreshEventId=refresh_event.id,
                    affectedCount=len(actionable),
                    message=f"自动整理已入队：{len(actionable)} 份资料。",
                    errors=[],
                )
                mark_workspace_context_refresh_event_status(
                    state.db,
                    event_id=refresh_event.id,
                    status="queued",
                    job_id=job.id,
                )
                return result
            if action_type == "retry_parse":
                retry_payload = KnowledgeParseFailureRetryPayloadRecord(
                    documentIds=payload.targetIds,
                    force=False,
                    ocrMaxPages=payload.ocrMaxPages,
                    ocrBatchSize=payload.ocrBatchSize,
                    ocrContinueToEnd=payload.ocrContinueToEnd,
                    forceOcr=payload.forceOcr,
                )
                target_count = count_parse_retry_targets(client_id, retry_payload.documentIds)
                if target_count <= 0:
                    result = WorkspaceDataCenterReadinessActionResultRecord(
                        actionType=action_type,
                        status="completed",
                        jobId=None,
                        refreshEventId=refresh_event.id,
                        affectedCount=0,
                        message="当前没有需要重试解析的文档。",
                        errors=[],
                    )
                    mark_workspace_context_refresh_event_completed(
                        state.db,
                        event_id=refresh_event.id,
                        job_id=result.jobId,
                    )
                    return result
                job = enqueue_parse_retry_job(
                    client_id,
                    retry_payload,
                    reason=refresh_reason,
                )
                result = WorkspaceDataCenterReadinessActionResultRecord(
                    actionType=action_type,
                    status="queued",
                    jobId=job.id,
                    refreshEventId=refresh_event.id,
                    affectedCount=target_count,
                    message=f"解析重试已入队：{target_count} 份文档。",
                    errors=[],
                )
                mark_workspace_context_refresh_event_completed(
                    state.db,
                    event_id=refresh_event.id,
                    job_id=result.jobId,
                )
                return result
            if action_type == "enqueue_local_model_optimization":
                enqueue_result = enqueue_local_model_optimization_tasks(
                    state.db,
                    client_id=client_id,
                    document_ids=payload.targetIds or None,
                )
                created_count = int(enqueue_result.get("created") or 0)
                attempted_count = int(enqueue_result.get("attempted") or 0)
                result = WorkspaceDataCenterReadinessActionResultRecord(
                    actionType=action_type,
                    status="queued" if created_count > 0 else "completed",
                    jobId=None,
                    refreshEventId=refresh_event.id,
                    affectedCount=created_count,
                    message=(
                        f"本地模型优化已入队：新增 {created_count} 个任务，检查 {attempted_count} 个候选项。"
                        if created_count > 0
                        else "当前没有新的本地模型优化任务需要加入队列。"
                    ),
                    errors=[],
                )
                if created_count > 0:
                    mark_workspace_context_refresh_event_status(
                        state.db,
                        event_id=refresh_event.id,
                        status="queued",
                    )
                else:
                    mark_workspace_context_refresh_event_completed(state.db, event_id=refresh_event.id)
                return result
            if action_type == "retry_local_model_optimization":
                affected_count = retry_failed_local_model_optimization_tasks(
                    state.db,
                    client_id=client_id,
                    task_ids=payload.targetIds or None,
                )
                result = WorkspaceDataCenterReadinessActionResultRecord(
                    actionType=action_type,
                    status="queued" if affected_count > 0 else "completed",
                    jobId=None,
                    refreshEventId=refresh_event.id,
                    affectedCount=affected_count,
                    message=(
                        f"本地模型优化失败任务已重新排队：{affected_count} 个。"
                        if affected_count > 0
                        else "当前没有可重试的本地模型优化失败任务。"
                    ),
                    errors=[],
                )
                if affected_count > 0:
                    mark_workspace_context_refresh_event_status(
                        state.db,
                        event_id=refresh_event.id,
                        status="queued",
                    )
                else:
                    mark_workspace_context_refresh_event_completed(state.db, event_id=refresh_event.id)
                return result
            if action_type == "internet_enrichment":
                client_summary = build_client_summary(client_id)
                seed_urls = [item.strip() for item in payload.seedUrls if item and item.strip()]
                seed_queries = [item.strip() for item in payload.seedQueries if item and item.strip()]
                if not seed_queries:
                    seed_queries = [
                        f"{client_summary.name} 项目 介绍",
                        f"{client_summary.name} 公益 项目 报告",
                        f"{client_summary.name} 新闻 动态",
                        f"{client_summary.name} filetype:pdf",
                    ]
                gaps = [item.strip() for item in payload.gaps if item and item.strip()]
                if not gaps:
                    gaps = [
                        "项目基本信息、执行方法和合作方",
                        "项目时间线、典型案例和传播资料",
                        "成效数据、评估指标和仍需用户补充的信息",
                    ]
                target_type = str(payload.targetType or "client").strip() or "client"
                target_id = str(payload.targetId or client_id).strip() or client_id
                job_payload: dict[str, object] = {
                    "clientId": client_id,
                    "targetType": target_type,
                    "targetId": target_id,
                    "seedUrls": seed_urls,
                    "seedQueries": seed_queries,
                    "gaps": gaps,
                    "maxPages": max(1, min(int(payload.maxPages or 30), 100)),
                    "maxDepth": max(0, min(int(payload.maxDepth or 2), 4)),
                    "reason": refresh_reason,
                    "source": "readiness_action",
                    "title": payload.title.strip() if payload.title.strip() else f"{client_summary.name}互联网资料补全文档",
                }
                total_items = int(job_payload["maxPages"])
                job = enqueue_knowledge_job(client_id, "internet_enrichment", job_payload, total_items=total_items)
                result = WorkspaceDataCenterReadinessActionResultRecord(
                    actionType=action_type,
                    status="queued",
                    jobId=job.id,
                    refreshEventId=refresh_event.id,
                    affectedCount=total_items,
                    message=f"互联网资料补全已入队：最多抓取 {total_items} 条来源。",
                    errors=[],
                )
                mark_workspace_context_refresh_event_status(
                    state.db,
                    event_id=refresh_event.id,
                    status="queued",
                    job_id=job.id,
                )
                return result
            if action_type == "rebuild_client_knowledge":
                job = rebuild_client_knowledge(client_id)
                normalized_job_status = str(job.status or "").strip().lower()
                if normalized_job_status == "running":
                    job_status: Literal["queued", "running", "completed"] = "running"
                elif normalized_job_status == "queued":
                    job_status = "queued"
                else:
                    job_status = "completed"
                result = WorkspaceDataCenterReadinessActionResultRecord(
                    actionType=action_type,
                    status=job_status,
                    jobId=job.id,
                    refreshEventId=refresh_event.id,
                    affectedCount=int(job.totalItems or 0),
                    message="已提交知识重建任务。",
                    errors=[],
                )
                if job_status == "completed":
                    mark_workspace_context_refresh_event_completed(
                        state.db,
                        event_id=refresh_event.id,
                        job_id=job.id,
                    )
                elif job_status == "running":
                    mark_workspace_context_refresh_event_running(
                        state.db,
                        event_id=refresh_event.id,
                        job_id=job.id,
                    )
                else:
                    mark_workspace_context_refresh_event_status(
                        state.db,
                        event_id=refresh_event.id,
                        status="queued",
                        job_id=job.id,
                    )
                return result
            if action_type == "regenerate_document_cards":
                job = rebuild_client_knowledge(client_id)
                normalized_job_status = str(job.status or "").strip().lower()
                if normalized_job_status == "running":
                    job_status: Literal["queued", "running", "completed"] = "running"
                elif normalized_job_status == "queued":
                    job_status = "queued"
                else:
                    job_status = "completed"
                result = WorkspaceDataCenterReadinessActionResultRecord(
                    actionType=action_type,
                    status=job_status,
                    jobId=job.id,
                    refreshEventId=refresh_event.id,
                    affectedCount=int(job.totalItems or 0),
                    message="已排队重建资料卡（通过知识重建作业执行）。",
                    errors=[],
                )
                if job_status == "completed":
                    mark_workspace_context_refresh_event_completed(
                        state.db,
                        event_id=refresh_event.id,
                        job_id=job.id,
                    )
                elif job_status == "running":
                    mark_workspace_context_refresh_event_running(
                        state.db,
                        event_id=refresh_event.id,
                        job_id=job.id,
                    )
                else:
                    mark_workspace_context_refresh_event_status(
                        state.db,
                        event_id=refresh_event.id,
                        status="queued",
                        job_id=job.id,
                    )
                return result
            if action_type == "sync_master_index":
                sync_master_index_fts(state.db, client_id)
                affected_count = int(
                    state.db.scalar(
                        "SELECT COUNT(1) AS count FROM knowledge_master_index WHERE client_id = ?",
                        (client_id,),
                    )
                    or 0
                )
                result = WorkspaceDataCenterReadinessActionResultRecord(
                    actionType=action_type,
                    status="completed",
                    jobId=None,
                    refreshEventId=refresh_event.id,
                    affectedCount=affected_count,
                    message="主索引 FTS 已同步。",
                    errors=[],
                )
                mark_workspace_context_refresh_event_completed(state.db, event_id=refresh_event.id)
                return result
            if action_type == "sync_vector_index":
                result = reindex_client_vector(
                    state.db,
                    data_dir=state.data_dir,
                    client_id=client_id,
                    ai_service=state.ai,
                )
                vector_status = str(result.get("status") or "").strip().lower()
                if vector_status in {"ready", "completed", "success"}:
                    mapped_status: Literal["queued", "running", "completed", "failed"] = "completed"
                elif vector_status in {"running", "building", "processing"}:
                    mapped_status = "running"
                elif vector_status in {"failed", "error"}:
                    mapped_status = "failed"
                else:
                    mapped_status = "queued"
                result_error = str(result.get("error") or "").strip()
                action_result = WorkspaceDataCenterReadinessActionResultRecord(
                    actionType=action_type,
                    status=mapped_status,
                    jobId=None,
                    refreshEventId=refresh_event.id,
                    affectedCount=int(result.get("masterIndexed") or 0),
                    message=f"向量索引同步完成，状态：{result.get('status') or 'unknown'}",
                    errors=[result_error] if result_error else [],
                )
                if action_result.status == "completed":
                    mark_workspace_context_refresh_event_completed(state.db, event_id=refresh_event.id)
                elif action_result.status == "running":
                    mark_workspace_context_refresh_event_running(state.db, event_id=refresh_event.id)
                elif action_result.status == "failed":
                    mark_workspace_context_refresh_event_failed(
                        state.db,
                        event_id=refresh_event.id,
                        error=result_error or "vector_index_sync_failed",
                    )
                else:
                    mark_workspace_context_refresh_event_status(
                        state.db,
                        event_id=refresh_event.id,
                        status="queued",
                    )
                return action_result
            if action_type == "refresh_context_pack":
                result = WorkspaceDataCenterReadinessActionResultRecord(
                    actionType=action_type,
                    status="queued",
                    jobId=None,
                    refreshEventId=refresh_event.id,
                    affectedCount=0,
                    message="上下文刷新事件已入队。",
                    errors=[],
                )
                mark_workspace_context_refresh_event_status(
                    state.db,
                    event_id=refresh_event.id,
                    status="queued",
                )
                return result
            if action_type == "cleanup_invalid_documents":
                wanted_ids = [item.strip() for item in payload.targetIds if item and item.strip()]
                where_target = ""
                params: tuple[Any, ...] = (client_id,)
                if wanted_ids:
                    placeholders = _sql_placeholders(wanted_ids)
                    where_target = f"AND (v2.document_id IN ({placeholders}) OR v2.id IN ({placeholders}))"
                    params = (client_id, *wanted_ids, *wanted_ids)
                candidate_rows = state.db.fetchall(
                    f"""
                    SELECT v2.*, d.path AS document_path, d.original_source_path AS original_source_path
                    FROM v2_documents v2
                    LEFT JOIN documents d ON d.id = v2.document_id
                    WHERE v2.client_id = ?
                      {where_target}
                    """,
                    params,
                )
                invalid_ids: list[str] = []
                for row in candidate_rows:
                    source_info = classify_source_availability_for_row(row)
                    placeholder_only = not has_effective_machine_text(
                        row["markdown_content"],
                        row["preview_text"],
                        row["doc_index_text"],
                    )
                    if str(source_info.get("sourceAvailability") or "") == "invalid_source" or placeholder_only:
                        doc_id = str(row["document_id"] or "").strip()
                        if doc_id:
                            invalid_ids.append(doc_id)
                invalid_ids = list(dict.fromkeys(invalid_ids))
                if invalid_ids:
                    placeholders = _sql_placeholders(invalid_ids)
                    timestamp = now_iso()
                    state.db.execute(
                        f"""
                        UPDATE documents
                        SET is_searchable = 0,
                            lifecycle_status = 'invalid'
                        WHERE client_id = ? AND id IN ({placeholders})
                        """,
                        (client_id, *invalid_ids),
                    )
                    state.db.execute(
                        f"""
                        UPDATE v2_documents
                        SET is_searchable = 0,
                            lifecycle_status = 'invalid',
                            parse_status = 'failed',
                            parse_error = CASE
                                WHEN COALESCE(parse_error, '') = '' THEN '原文件缺失或为空，且机读稿为占位内容。'
                                ELSE parse_error
                            END,
                            updated_at = ?
                        WHERE client_id = ? AND document_id IN ({placeholders})
                        """,
                        (timestamp, client_id, *invalid_ids),
                    )
                    state.db.execute(
                        f"""
                        UPDATE document_chunks
                        SET is_searchable = 0
                        WHERE knowledge_document_id IN ({placeholders})
                        """,
                        tuple(invalid_ids),
                    )
                result = WorkspaceDataCenterReadinessActionResultRecord(
                    actionType=action_type,
                    status="completed",
                    jobId=None,
                    refreshEventId=refresh_event.id,
                    affectedCount=len(invalid_ids),
                    message=f"已软清理 {len(invalid_ids)} 份无效资料；记录保留用于追溯。",
                    errors=[],
                )
                mark_workspace_context_refresh_event_completed(state.db, event_id=refresh_event.id)
                return result
            if action_type == "rebind_original_file":
                result = WorkspaceDataCenterReadinessActionResultRecord(
                    actionType=action_type,
                    status="completed",
                    jobId=None,
                    refreshEventId=refresh_event.id,
                    affectedCount=0,
                    message="当前版本只识别并提示原文件重绑，不自动改写文件路径；请先清理无效资料或重新上传真实原文件。",
                    errors=[],
                )
                mark_workspace_context_refresh_event_completed(state.db, event_id=refresh_event.id)
                return result
            if action_type == "inspect_failed_documents":
                failed_count = int(
                    state.db.scalar(
                        "SELECT COUNT(1) AS count FROM v2_documents WHERE client_id = ? AND COALESCE(parse_status, 'ready') NOT IN ('ready', 'partial_ready', 'queued', 'running', 'processing', 'parsing')",
                        (client_id,),
                    )
                    or 0
                )
                result = WorkspaceDataCenterReadinessActionResultRecord(
                    actionType=action_type,
                    status="completed",
                    jobId=None,
                    refreshEventId=refresh_event.id,
                    affectedCount=failed_count,
                    message=f"已输出失败资料检查结果，共 {failed_count} 条。",
                    errors=[],
                )
                mark_workspace_context_refresh_event_completed(state.db, event_id=refresh_event.id)
                return result
        except Exception as error:
            mark_workspace_context_refresh_event_failed(
                state.db,
                event_id=refresh_event.id,
                error=str(error),
            )
            return WorkspaceDataCenterReadinessActionResultRecord(
                actionType=action_type,
                status="failed",
                jobId=None,
                refreshEventId=refresh_event.id,
                affectedCount=0,
                message=str(error),
                errors=[str(error)],
            )
        mark_workspace_context_refresh_event_status(
            state.db,
            event_id=refresh_event.id,
            status="canceled",
            error=f"unsupported action type: {action_type}",
        )
        return WorkspaceDataCenterReadinessActionResultRecord(
            actionType=action_type,
            status="failed",
            jobId=None,
            refreshEventId=refresh_event.id,
            affectedCount=0,
            message="不支持的 actionType。",
            errors=[f"unsupported action type: {action_type}"],
        )

