    @app.get("/api/v1/clients/{client_id}/data-center/mobile-snapshot")
    def get_client_mobile_data_center_snapshot(client_id: str) -> dict[str, object]:
        workspace = workspace_for_client(client_id)
        bundle = get_client_analysis_bundle(state.db, workspace)
        page_context = build_client_page_context_pack(
            state.db,
            data_dir=state.data_dir,
            client_id=client_id,
            prompt="",
            page="workspace_chat",
            include_raw_evidence=False,
            workspace=workspace,
        )
        ensure_data_center_proposal_draft_schema(state.db)
        ensure_evidence_quality_annotation_schema(state.db)
        proposal_draft_rows = state.db.fetchall(
            """
            SELECT status, COUNT(1) AS count
            FROM data_center_proposal_drafts
            WHERE client_id = ?
            GROUP BY status
            """,
            (client_id,),
        )
        proposal_draft_summary = {str(row["status"] or "unknown"): int(row["count"] or 0) for row in proposal_draft_rows}
        proposal_rows = state.db.fetchall(
            """
            SELECT status, COUNT(1) AS count
            FROM proposal_records
            WHERE client_id = ?
            GROUP BY status
            """,
            (client_id,),
        )
        open_proposal_summary = {str(row["status"] or "unknown"): int(row["count"] or 0) for row in proposal_rows}
        latest_execution_tickets = list_execution_tickets(
            state.db,
            client_id=client_id,
            limit=8,
        )
        quality_rows = state.db.fetchall(
            """
            SELECT COALESCE(human_label, 'unlabeled') AS label, COUNT(1) AS count
            FROM evidence_quality_annotations
            WHERE source_id = ?
            GROUP BY COALESCE(human_label, 'unlabeled')
            """,
            (client_id,),
        )
        evidence_quality_summary = {str(row["label"] or "unlabeled"): int(row["count"] or 0) for row in quality_rows}
        context_quality = str(page_context.quality.contextQuality or "none").strip().lower()
        if context_quality == "strong":
            kernel_readiness = "ready"
        elif context_quality == "usable":
            kernel_readiness = "partial"
        else:
            kernel_readiness = "weak"
        return {
            "clientId": client_id,
            "latestContextPack": bundle.latest_context_pack.model_dump(mode="json") if bundle.latest_context_pack else None,
            "latestJudgments": [item.model_dump(mode="json") for item in bundle.latest_judgments[:8]],
            "openQuestions": [item.model_dump(mode="json") for item in bundle.latest_open_questions[:10]],
            "conflicts": [item.model_dump(mode="json") for item in bundle.latest_conflicts[:10]],
            "relatedTasks": [item.model_dump(mode="json") for item in workspace.relatedTasks[:12]],
            "recentMeetings": [item.model_dump(mode="json") for item in workspace.meetings[:8]],
            "stateProjection": page_context.stateProjection,
            "proposalDraftSummary": proposal_draft_summary,
            "openProposalSummary": open_proposal_summary,
            "latestExecutionTickets": [item.model_dump(mode="json") for item in latest_execution_tickets],
            "evidenceQualitySummary": evidence_quality_summary,
            "kernelReadiness": kernel_readiness,
            "generatedAt": now_iso(),
        }

