    @app.post(
        "/api/v1/workspace-answer-action-cards/{message_id}/create-proposal",
        response_model=WorkspaceAnswerActionCardResultRecord,
    )
    def create_workspace_answer_action_proposal_api(message_id: str) -> WorkspaceAnswerActionCardResultRecord:
        summary, card, client_id = _workspace_answer_action_card_from_message(
            message_id=message_id,
            action_type="create_proposal",
        )
        if not client_id:
            raise HTTPException(status_code=400, detail="workspace answer message has no client")
        build_client_summary(client_id)
        existing_draft_id = str(card.get("draftId") or "").strip()
        if existing_draft_id:
            draft = get_data_center_proposal_draft(state.db, draft_id=existing_draft_id)
            return WorkspaceAnswerActionCardResultRecord(
                messageId=message_id,
                actionType="create_proposal",
                status="reused",
                summary=f"已复用提案草稿：{draft.title}",
                draftId=draft.id,
                proposalId=draft.promotedProposalId,
            )
        answer_experience = summary.get("workspaceAnswerExperience")
        direct_answer = ""
        next_actions: list[str] = []
        card_action_type = str(card.get("actionType") or "").strip()
        if isinstance(answer_experience, dict):
            direct_answer = str(answer_experience.get("directAnswer") or "").strip()
            raw_next_actions = answer_experience.get("nextActions")
            if isinstance(raw_next_actions, list):
                next_actions = [str(item).strip() for item in raw_next_actions if str(item).strip()]
        draft_kind = "task_prep"
        if card_action_type == "review_judgment":
            draft_kind = "judgment_review"
        elif card_action_type == "refresh_context":
            draft_kind = "context_refresh"
        elif card_action_type == "prepare_meeting":
            draft_kind = "meeting_prep"
        draft = create_data_center_proposal_draft(
            state.db,
            scope_type="client",
            scope_id=client_id,
            client_id=client_id,
            page="workspace_chat",
            source_prompt=str(summary.get("prompt") or "workspace_answer_action"),
            draft=DataCenterProposalDraftRecord(
                kind=draft_kind,  # type: ignore[arg-type]
                title=str(card.get("title") or "从回答生成提案").strip() or "从回答生成提案",
                summary=str(card.get("summary") or direct_answer or "从当前客户工作台回答整理出的可执行提案。").strip(),
                rationale=direct_answer or "基于客户工作台中的可用回答形成提案。",
                riskLevel=str(card.get("riskLevel") or "medium"),  # type: ignore[arg-type]
                targetRefs=[ProposalTargetRefRecord(targetType="client", targetId=client_id, label="客户")],
                sourceRefs=[message_id],
                boundaryNotes=[],
                payload={
                    "workspaceAnswerMessageId": message_id,
                    "sourceType": "workspace_answer_action",
                    "directAnswer": direct_answer,
                    "nextActions": next_actions[:5],
                },
            ),
        )
        return WorkspaceAnswerActionCardResultRecord(
            messageId=message_id,
            actionType="create_proposal",
            status="created",
            summary=f"已生成提案草稿：{draft.title}",
            draftId=draft.id,
        )

