    @app.post(
        "/api/v1/clients/{client_id}/workspace/proposal-drafts",
        response_model=DataCenterProposalDraftRecord,
    )
    def create_workspace_proposal_draft_api(
        client_id: str,
        payload: WorkspaceProposalDraftCreatePayloadRecord,
    ) -> DataCenterProposalDraftRecord:
        build_client_summary(client_id)
        scope_type = payload.scopeType
        scope_id = str(payload.scopeId or "").strip()
        if not scope_id:
            if scope_type == "client":
                scope_id = client_id
            else:
                raise HTTPException(status_code=400, detail="scopeId is required for non-client scope")
        target_refs = payload.targetRefs or [ProposalTargetRefRecord(targetType="client", targetId=client_id, label="客户")]
        draft = create_data_center_proposal_draft(
            state.db,
            scope_type=scope_type,
            scope_id=scope_id,
            client_id=client_id,
            page="workspace_chat",
            source_prompt=payload.sourceMessageId or "",
            draft=DataCenterProposalDraftRecord(
                kind=payload.kind,
                title=payload.title.strip() or "未命名提案",
                summary=payload.summary.strip() or payload.title.strip() or "无摘要",
                rationale=payload.rationale.strip() or "来自客户工作台人工确认",
                riskLevel=payload.riskLevel,
                targetRefs=target_refs,
                sourceRefs=[str(item) for item in payload.sourceRefs if str(item).strip()],
                boundaryNotes=[str(item) for item in payload.boundaryNotes if str(item).strip()],
                payload={
                    **payload.payload,
                    "workspaceSourceType": payload.sourceType,
                    "sourceMessageId": payload.sourceMessageId,
                    "actionSuggestionId": payload.actionSuggestionId,
                    "sourceMessageDraftId": payload.sourceMessageDraftId,
                    "sourceMessageDraftPayload": payload.sourceMessageDraftPayload,
                },
                requiresApproval=True,
                scopeType=scope_type,
                scopeId=scope_id,
                clientId=client_id,
                page="workspace_chat",
                mode="proposal",
            ),
        )
        enqueue_workspace_context_refresh(
            state.db,
            client_id=client_id,
            source_type="workspace_proposal_draft",
            source_id=draft.id,
            reason="workspace_proposal_draft_created",
            scope_type=scope_type,
            scope_id=scope_id,
            priority="normal",
        )
        return draft

