    @app.post(
        "/api/v1/data-center/proposal-drafts/{draft_id}/promote",
        response_model=DataCenterProposalDraftPromoteResponseRecord,
    )
    def promote_data_center_proposal_draft_api(
        draft_id: str,
        payload: DataCenterProposalDraftPromotePayloadRecord,
    ) -> DataCenterProposalDraftPromoteResponseRecord:
        effect_type = payload.promoteTo or "proposal_record"
        if effect_type == "proposal":
            effect_type = "proposal_record"
        try:
            if effect_type == "proposal_record":
                draft, proposal_id = promote_data_center_proposal_draft(
                    state.db,
                    draft_id=draft_id,
                    created_by=payload.createdBy,
                    note=payload.note,
                )
                refresh_event_id: str | None = None
                if draft.clientId:
                    refresh_event, _ = enqueue_workspace_context_refresh(
                        state.db,
                        client_id=draft.clientId,
                        source_type="proposal_draft_promote",
                        source_id=draft.id,
                        reason="proposal_draft_promoted_to_proposal_record",
                        scope_type=draft.scopeType or "client",
                        scope_id=draft.scopeId or draft.clientId,
                        priority="normal",
                    )
                    refresh_event_id = refresh_event.id
                return DataCenterProposalDraftPromoteResponseRecord(
                    draft=draft,
                    proposalId=proposal_id,
                    taskId=None,
                    refreshEventId=refresh_event_id,
                    effectType="proposal_record",
                )

            draft = get_data_center_proposal_draft(state.db, draft_id=draft_id)
            if draft is None:
                raise KeyError("proposal_draft_not_found")
            if not draft.clientId:
                raise ValueError("proposal_draft_missing_client")
            scope_type = draft.scopeType or "client"
            scope_id = draft.scopeId or draft.clientId

            if effect_type in {"task", "evidence_request", "meeting_prep"}:
                options_payload = payload.options if isinstance(payload.options, dict) else {}
                title_prefix_map = {
                    "task": "",
                    "evidence_request": "补资料：",
                    "meeting_prep": "会议准备：",
                }
                business_category_map = {
                    "task": "任务推进",
                    "evidence_request": "补资料",
                    "meeting_prep": "会议准备",
                }
                source_type_map = {
                    "task": "data_center_proposal_draft",
                    "evidence_request": "data_center_evidence_request",
                    "meeting_prep": "data_center_meeting_prep",
                }
                task_title = f"{title_prefix_map[effect_type]}{draft.title}".strip()
                task_desc_parts = [draft.summary.strip()]
                if draft.rationale.strip():
                    task_desc_parts.append(f"原因：{draft.rationale.strip()}")
                if draft.boundaryNotes:
                    boundary_line = "；".join(item.strip() for item in draft.boundaryNotes[:3] if item.strip())
                    if boundary_line:
                        task_desc_parts.append(f"边界：{boundary_line}")
                option_meeting_id = str(options_payload.get("meetingId") or "").strip()
                payload_meeting_id = str(draft.payload.get("meetingId") or "").strip() if isinstance(draft.payload, dict) else ""
                meeting_id = option_meeting_id or payload_meeting_id
                if effect_type == "meeting_prep" and meeting_id:
                    task_desc_parts.append(f"关联会议：{meeting_id}")
                option_due_date = str(options_payload.get("dueDate") or "").strip() or None
                option_owner_name = str(options_payload.get("ownerName") or "").strip()
                option_list_id = str(options_payload.get("listId") or "").strip() or (_get_local_task_settings().defaultListId or "list-0")
                task = create_task(
                    TaskPayload(
                        title=task_title or "数据中心建议任务",
                        desc="\n".join(part for part in task_desc_parts if part).strip(),
                        listId=option_list_id,
                        scopeMode="COLLAB_SHARED",
                        clientId=draft.clientId,
                        dueDate=option_due_date,
                        ownerName=option_owner_name,
                        sourceType=source_type_map[effect_type],
                        sourceId=draft.id,
                        businessCategory=business_category_map[effect_type],
                    )
                )
                updated_draft = mark_data_center_proposal_draft_promoted(
                    state.db,
                    draft_id=draft_id,
                    promoted_ref_id=task.id,
                )
                refresh_event, _ = enqueue_workspace_context_refresh(
                    state.db,
                    client_id=draft.clientId,
                    source_type="proposal_draft_promote_task",
                    source_id=draft.id,
                    reason=f"proposal_draft_promoted_to_{effect_type}",
                    scope_type=scope_type,
                    scope_id=scope_id,
                    priority="high",
                )
                return DataCenterProposalDraftPromoteResponseRecord(
                    draft=updated_draft,
                    proposalId=None,
                    taskId=task.id,
                    refreshEventId=refresh_event.id,
                    effectType=effect_type,
                )

            if effect_type == "judgment_confirmation":
                updated_draft = mark_data_center_proposal_draft_reviewed(
                    state.db,
                    draft_id=draft_id,
                    note=payload.note.strip() or "人工确认：进入判断复核流程",
                )
                refresh_event, _ = enqueue_workspace_context_refresh(
                    state.db,
                    client_id=draft.clientId,
                    source_type="proposal_draft_judgment_confirmation",
                    source_id=draft.id,
                    reason="proposal_draft_judgment_confirmation",
                    scope_type=scope_type,
                    scope_id=scope_id,
                    priority="normal",
                )
                return DataCenterProposalDraftPromoteResponseRecord(
                    draft=updated_draft,
                    proposalId=None,
                    taskId=None,
                    refreshEventId=refresh_event.id,
                    effectType="judgment_confirmation",
                )

            if effect_type == "context_refresh":
                updated_draft = mark_data_center_proposal_draft_reviewed(
                    state.db,
                    draft_id=draft_id,
                    note=payload.note.strip() or "人工确认：触发上下文刷新",
                )
                refresh_event, _ = enqueue_workspace_context_refresh(
                    state.db,
                    client_id=draft.clientId,
                    source_type="proposal_draft_context_refresh",
                    source_id=draft.id,
                    reason="proposal_draft_promoted_to_context_refresh",
                    scope_type=scope_type,
                    scope_id=scope_id,
                    priority="high",
                )
                return DataCenterProposalDraftPromoteResponseRecord(
                    draft=updated_draft,
                    proposalId=None,
                    taskId=None,
                    refreshEventId=refresh_event.id,
                    effectType="context_refresh",
                )

            raise HTTPException(status_code=400, detail=f"unsupported promoteTo: {effect_type}")
        except KeyError as exc:
            raise HTTPException(status_code=404, detail="proposal draft not found") from exc
        except ValueError as exc:
            raise HTTPException(status_code=409, detail=str(exc)) from exc

