    @app.get("/api/v1/system/source-integrity")
    def get_system_source_integrity(
        workspaceBackendRoot: str | None = Query(default=None),
        frontendBuildVersion: str | None = Query(default=None),
        frontendGitCommit: str | None = Query(default=None),
    ) -> dict[str, object]:
        running_root = Path(__file__).resolve().parents[1]
        workspace_root: Path | None = None
        if workspaceBackendRoot:
            workspace_root = Path(workspaceBackendRoot).resolve()
        else:
            cwd_candidate = (Path.cwd() / "backend").resolve()
            if cwd_candidate.exists():
                workspace_root = cwd_candidate
        return build_source_integrity_report(
            running_backend_root=running_root,
            expected_workspace_root=workspace_root,
            build_version=APP_BUILD_VERSION,
            git_commit=APP_GIT_COMMIT,
            runtime_mode=BACKEND_RUNTIME_MODE,
            frontend_build_version=str(frontendBuildVersion or "").strip() or None,
            frontend_git_commit=str(frontendGitCommit or "").strip() or None,
        )

