    @app.post("/api/v1/imports", response_model=list[ImportRecord])
    def import_documents(payload: ImportPayload) -> list[ImportRecord]:
        build_client_summary(payload.clientId)
        ensure_standard_client_folders(payload.clientId)
        results: list[ImportRecord] = []
        allowed_extensions = set(SUPPORTED_IMPORT_EXTENSIONS)
        if payload.allowLegacy:
            allowed_extensions.update(LEGACY_IMPORT_EXTENSIONS)
        for raw_path in payload.paths:
            source_path = Path(raw_path).expanduser()
            if not source_path.exists():
                continue
            import_id = new_id("imp")
            timestamp = now_iso()
            queued = 0
            skipped = 0
            state.db.execute(
                """
                INSERT INTO imports(id, client_id, source_path, mode, status, imported_count, skipped_count, created_at)
                VALUES(?, ?, ?, ?, 'queued', 0, 0, ?)
                """,
                (import_id, payload.clientId, str(source_path), payload.mode, timestamp),
            )
            _enqueue_workspace_refresh_safe(
                client_id=payload.clientId,
                source_type="document_import_create",
                source_id=import_id,
                reason="document_import_queued",
                scope_type="client",
                scope_id=payload.clientId,
                priority="normal",
            )
            if payload.mode == "folder":
                candidates = [path for path in source_path.rglob("*") if path.is_file()]
            else:
                candidates = [source_path]
            ensure_source_tree_snapshot(
                state.db,
                import_id=import_id,
                client_id=payload.clientId,
                source_path=source_path,
                mode=payload.mode,
                created_at=timestamp,
            )
            # 迭代 2 F3：拆分 skip 原因（unsupported / duplicate / version_upgrade）
            duplicate_count = 0
            unsupported_count = 0
            version_upgrade_count = 0
            queued_documents: list[dict[str, object]] = []
            for path in candidates:
                if path.suffix.lower() not in allowed_extensions:
                    unsupported_count += 1
                    skipped += 1
                    continue
                # 闸门期算文件内容 hash，支撑"按内容去重 + 版本识别"
                file_hash = hash_file_bytes(path)
                # 查同客户、同路径的 current 版（lifecycle_status='current'）
                existing_same_path = state.db.fetchone(
                    """
                    SELECT id, document_id, binary_hash, version_chain_id, version_number
                    FROM knowledge_documents
                    WHERE client_id = ?
                      AND lifecycle_status = 'current'
                      AND (import_source_path = ? OR current_human_path = ? OR original_path = ?)
                    ORDER BY version_number DESC
                    LIMIT 1
                    """,
                    (payload.clientId, str(path), str(path), str(path)),
                )
                version_chain_id: str | None = None
                version_number = 1
                predecessor_kd_id: str | None = None
                if existing_same_path:
                    existing_hash = str(existing_same_path["binary_hash"] or "")
                    if file_hash and existing_hash and file_hash == existing_hash:
                        # 同路径 + 同内容 = 真重复
                        duplicate_count += 1
                        skipped += 1
                        continue
                    # 同路径 + 内容已变 → 视为版本升级
                    version_upgrade_count += 1
                    version_chain_id = str(
                        existing_same_path["version_chain_id"]
                        or existing_same_path["id"]
                    )
                    version_number = int(existing_same_path["version_number"] or 1) + 1
                    predecessor_kd_id = str(existing_same_path["id"])
                elif file_hash:
                    # 不同路径但内容已存在（用户从别处拖入同样的文件）→ 当重复
                    existing_same_hash = state.db.fetchone(
                        """
                        SELECT 1 FROM knowledge_documents
                        WHERE client_id = ?
                          AND lifecycle_status = 'current'
                          AND binary_hash = ?
                        LIMIT 1
                        """,
                        (payload.clientId, file_hash),
                    )
                    if existing_same_hash:
                        duplicate_count += 1
                        skipped += 1
                        continue
                managed_import_path = stage_import_copy(state.data_dir, payload.clientId, import_id, path)
                excerpt = build_excerpt(path)
                document_id = new_id("doc")
                state.db.execute(
                    """
                    INSERT INTO documents(id, client_id, folder_id, title, path, original_source_path, kind, source, excerpt, tags_json, created_at)
                    VALUES(?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                    """,
                    (
                        document_id,
                        payload.clientId,
                        None,
                        path.name,
                        str(managed_import_path),
                        str(path),
                        path.suffix.lower().lstrip("."),
                        payload.mode,
                        excerpt,
                        to_json([path.suffix.lower().lstrip(".")]),
                        timestamp,
                    ),
                )
                queued_documents.append(
                    {
                        "documentId": document_id,
                        "sourcePath": str(managed_import_path),
                        "originalSourcePath": str(path),
                        "title": path.name,
                        "kind": path.suffix.lower().lstrip("."),
                        "source": payload.mode,
                        "createdAt": timestamp,
                        # 迭代 2 F3：版本链元数据，由 ingest 后步骤回写
                        "versionChainId": version_chain_id,
                        "versionNumber": version_number,
                        "predecessorKnowledgeDocumentId": predecessor_kd_id,
                    }
                )
                queued += 1
            state.db.execute(
                "UPDATE imports SET skipped_count = ?, duplicate_count = ?, "
                "    unsupported_count = ?, version_upgrade_count = ? WHERE id = ?",
                (skipped, duplicate_count, unsupported_count, version_upgrade_count, import_id),
            )
            if queued == 0:
                state.db.execute(
                    "UPDATE imports SET status = 'completed', imported_count = 0, skipped_count = ? WHERE id = ?",
                    (skipped, import_id),
                )
                _enqueue_workspace_refresh_safe(
                    client_id=payload.clientId,
                    source_type="document_import_complete",
                    source_id=import_id,
                    reason="document_import_completed",
                    scope_type="client",
                    scope_id=payload.clientId,
                    priority="normal",
                )
                log_activity("import.create", "import", import_id, {"clientId": payload.clientId, "sourcePath": str(source_path), "queued": queued, "skipped": skipped, "jobId": None})
                results.append(
                    ImportRecord(
                        id=import_id,
                        clientId=payload.clientId,
                        sourcePath=str(source_path),
                        mode=payload.mode,
                        status="completed",
                        importedCount=0,
                        skippedCount=skipped,
                        duplicateCount=duplicate_count,
                        versionUpgradeCount=version_upgrade_count,
                        unsupportedCount=unsupported_count,
                        createdAt=timestamp,
                        jobId=None,
                        documents=[],
                    )
                )
                continue
            job = enqueue_knowledge_job(
                payload.clientId,
                "ingest_import",
                {
                    "clientId": payload.clientId,
                    "importId": import_id,
                    "mode": payload.mode,
                    "documents": queued_documents,
                },
                total_items=queued,
            )
            log_activity("import.create", "import", import_id, {"clientId": payload.clientId, "sourcePath": str(source_path), "queued": queued, "skipped": skipped, "jobId": job.id})
            results.append(
                ImportRecord(
                    id=import_id,
                    clientId=payload.clientId,
                    sourcePath=str(source_path),
                    mode=payload.mode,
                    status="queued",
                    importedCount=queued,
                    skippedCount=skipped,
                    duplicateCount=duplicate_count,
                    versionUpgradeCount=version_upgrade_count,
                    unsupportedCount=unsupported_count,
                    createdAt=timestamp,
                    jobId=job.id,
                    documents=[
                        {
                            "documentId": str(item.get("documentId") or ""),
                            "title": str(item.get("title") or item.get("fileName") or "资料"),
                            "fileName": str(item.get("title") or item.get("fileName") or "资料"),
                            "path": str(item.get("sourcePath") or ""),
                        }
                        for item in queued_documents
                    ],
                )
            )
        return results

    def build_document_reading_preview_record(client_id: str, document_id: str) -> DocumentReadingPreviewRecord:
        row = state.db.fetchone(
            """
            SELECT
                d.id AS document_id,
                d.title AS document_title,
                d.excerpt AS document_excerpt,
                d.kind AS document_kind,
                cf.label AS folder_label,
                vd.id AS v2_document_id,
                vd.file_name AS v2_file_name,
                vd.parse_status AS parse_status,
                vd.parse_error AS parse_error,
                vd.preview_text AS preview_text,
                vd.doc_index_text AS doc_index_text,
                vd.canonical_kind AS canonical_kind,
                vd.visible_category AS visible_category
            FROM documents d
            LEFT JOIN client_folders cf ON cf.id = d.folder_id
            LEFT JOIN v2_documents vd ON vd.document_id = d.id
            WHERE d.client_id = ? AND d.id = ?
            """,
            (client_id, document_id),
        )
        if row is None:
            raise HTTPException(status_code=404, detail="document_not_found")
        v2_document_id = str(row["v2_document_id"] or "")
        parse_status = str(row["parse_status"] or "processing")
        section_count = 0
        chunk_count = 0
        key_headings: list[str] = []
        if v2_document_id:
            section_count = int(state.db.scalar("SELECT COUNT(1) AS count FROM v2_sections WHERE v2_document_id = ?", (v2_document_id,)) or 0)
            chunk_count = int(state.db.scalar("SELECT COUNT(1) AS count FROM v2_chunks WHERE v2_document_id = ?", (v2_document_id,)) or 0)
            heading_rows = state.db.fetchall(
                """
                SELECT title
                FROM v2_sections
                WHERE v2_document_id = ?
                ORDER BY section_index ASC
                LIMIT 12
                """,
                (v2_document_id,),
            )
            for heading_row in heading_rows:
                title = re.sub(r"\s+", " ", str(heading_row["title"] or "").strip())
                if not title or title == "正文" or title in key_headings:
                    continue
                key_headings.append(title[:80])
        if chunk_count <= 0:
            knowledge_row = state.db.fetchone("SELECT id FROM knowledge_documents WHERE document_id = ?", (document_id,))
            if knowledge_row:
                chunk_count = int(state.db.scalar("SELECT COUNT(1) AS count FROM document_chunks WHERE knowledge_document_id = ?", (str(knowledge_row["id"]),)) or 0)
        summary_source = str(row["preview_text"] or row["doc_index_text"] or row["document_excerpt"] or "").strip()
        read_summary = re.sub(r"\s+", " ", summary_source).strip()[:420]
        available_for_chat = parse_status in {"ready", "partial_ready"} and (section_count > 0 or chunk_count > 0 or bool(read_summary))
        return DocumentReadingPreviewRecord(
            documentId=document_id,
            title=str(row["v2_file_name"] or row["document_title"] or "资料"),
            parseStatus=parse_status,
            folderLabel=str(row["folder_label"] or row["visible_category"] or "") or None,
            sectionCount=section_count,
            chunkCount=chunk_count,
            sourceKind=str(row["canonical_kind"] or "raw_file"),
            readSummary=read_summary,
            keyHeadings=key_headings[:8],
            availableForChat=available_for_chat,
            failureReason=str(row["parse_error"] or "") or None,
        )

    @app.get("/api/v1/clients/{client_id}/documents/{document_id}/reading-preview", response_model=DocumentReadingPreviewRecord)
    def get_document_reading_preview(client_id: str, document_id: str) -> DocumentReadingPreviewRecord:
        build_client_summary(client_id)
        return build_document_reading_preview_record(client_id, document_id)

    def ensure_chat_thread(client_id: str, thread_id: str | None, prompt: str, timestamp: str) -> str:
        existing_thread_id = thread_id
        if existing_thread_id:
            existing_row = state.db.fetchone(
                "SELECT client_id FROM chat_threads WHERE id = ?",
                (existing_thread_id,),
            )
            if existing_row and str(existing_row["client_id"]) == client_id:
                return existing_thread_id
        next_thread_id = new_id("thread")
        state.db.execute(
            "INSERT INTO chat_threads(id, client_id, title, created_at, updated_at) VALUES(?, ?, ?, ?, ?)",
            (next_thread_id, client_id, prompt[:16], timestamp, timestamp),
        )
        return next_thread_id

    def insert_user_chat_message(thread_id: str, prompt: str, timestamp: str) -> str:
        message_id = new_id("msg")
        state.db.execute(
            """
            INSERT INTO chat_messages(
                id, thread_id, role, content, structured_data_json, model_route, llm_invoked, provider_used,
                answer_mode, evidence_status, failure_reason, timing_json, retrieval_summary_json, evidence_json, status, created_at
            )
            VALUES(?, ?, 'user', ?, NULL, NULL, 0, NULL, NULL, NULL, NULL, '{}', '{}', '[]', 'success', ?)
            """,
            (message_id, thread_id, prompt, timestamp),
        )
        return message_id

    def phase_progress_window(phase: str) -> tuple[float, float]:
        if phase == "retrieving":
            return 0.0, 25.0
        if phase == "grounding":
            return 25.0, 55.0
        if phase == "generating":
            return 55.0, 92.0
        return 100.0, 100.0

    def insert_loading_assistant_message(thread_id: str, retrieval_summary: dict[str, object], timestamp: str) -> str:
        assistant_id = new_id("msg")
        provider_used = state.ai.current_provider()
        model_used = state.ai.current_model()
        model_label = state.ai.model_label(provider_used, model_used)
        merged_summary = dict(retrieval_summary)
        merged_summary.setdefault("providerUsed", provider_used)
        merged_summary.setdefault("modelUsed", model_used)
        merged_summary.setdefault("modelLabel", model_label)
        merged_summary.setdefault("startedAt", timestamp)
        phase = str(merged_summary.get("phase") or "").strip()
        if not phase:
            has_hits = any(int(merged_summary.get(key, 0) or 0) > 0 for key in ("masterHitCount", "surrogateHitCount", "rawChunkHitCount"))
            phase = "grounding" if has_hits else "retrieving"
        merged_summary["phase"] = phase
        merged_summary.setdefault("progress", 36.0 if phase == "grounding" else 6.0)
        floor, ceiling = phase_progress_window(phase)
        merged_summary["progressFloor"] = float(merged_summary.get("progressFloor", floor) or floor)
        merged_summary["progressCeiling"] = float(merged_summary.get("progressCeiling", ceiling) or ceiling)
        merged_summary.setdefault(
            "stageLabel",
            f"背景材料已整理完成，正在准备调用{model_label}组织答案" if phase == "grounding" else "正在整理客户背景材料",
        )
        merged_summary["lastUpdatedAt"] = timestamp
        loading_content = str(merged_summary.get("stageLabel") or "庆华正在整理背景材料，并组织分析答案……")
        state.db.execute(
            """
            INSERT INTO chat_messages(
                id, thread_id, role, content, structured_data_json, model_route, llm_invoked, provider_used,
                answer_mode, evidence_status, failure_reason, timing_json, retrieval_summary_json, evidence_json, status, created_at
            )
            VALUES(?, ?, 'assistant', ?, NULL, ?, 0, ?, NULL, NULL, NULL, '{}', ?, '[]', 'loading', ?)
            """,
            (
                assistant_id,
                thread_id,
                loading_content,
                f"AI · {model_label}",
                provider_used,
                to_json(merged_summary),
                timestamp,
            ),
        )
        return assistant_id

    def update_loading_assistant_message(
        assistant_id: str,
        *,
        retrieval_summary: dict[str, object] | None = None,
        timing: dict[str, float] | None = None,
        content: str | None = None,
    ) -> None:
        current_row = state.db.fetchone("SELECT retrieval_summary_json, timing_json, content FROM chat_messages WHERE id = ?", (assistant_id,))
        if not current_row:
            return
        merged_summary = from_json(str(current_row["retrieval_summary_json"] or "{}"), {})
        if not isinstance(merged_summary, dict):
            merged_summary = {}
        if retrieval_summary:
            merged_summary.update(retrieval_summary)
        merged_timing = from_json(str(current_row["timing_json"] or "{}"), {})
        if not isinstance(merged_timing, dict):
            merged_timing = {}
        if timing:
            merged_timing.update(timing)
        phase = str(merged_summary.get("phase") or "retrieving").strip() or "retrieving"
        floor, ceiling = phase_progress_window(phase)
        merged_summary["progressFloor"] = float(merged_summary.get("progressFloor", floor) or floor)
        merged_summary["progressCeiling"] = float(merged_summary.get("progressCeiling", ceiling) or ceiling)
        merged_summary["lastUpdatedAt"] = now_iso()
        next_content = content if content is not None else str(current_row["content"] or "")
        state.db.execute(
            """
            UPDATE chat_messages
            SET content = ?, retrieval_summary_json = ?, timing_json = ?
            WHERE id = ? AND status = 'loading'
            """,
            (next_content, to_json(merged_summary), to_json(merged_timing), assistant_id),
        )

    def _workspace_bool_setting(key: str, default: bool) -> bool:
        raw = str(state.db.get_setting(key, "1" if default else "0") or "").strip().lower()
        if not raw:
            return default
        return raw in {"1", "true", "yes", "on", "enabled"}

    def workspace_chat_data_center_primary_enabled(client_id: str) -> bool:
        workspace_switch_enabled = _workspace_bool_setting("workspace_chat_data_center_primary", True)
        if not workspace_switch_enabled:
            return False
        # Default strategy: workspace switch is the single source of truth.
        # Optional compatibility gate can be re-enabled by setting this flag to 1.
        if not _workspace_bool_setting("workspace_chat_data_center_gate_enforced", False):
            return True
        retrieval_settings = get_retrieval_model_settings(state.db)
        enabled, _reason = decide_kernel_primary_gate(
            workspace_switch_enabled=workspace_switch_enabled,
            settings=retrieval_settings,
            client_id=client_id,
        )
        return enabled

    def workspace_chat_use_legacy_fallback_enabled() -> bool:
        return _workspace_bool_setting("workspace_chat_use_legacy_fallback", False)

    def _context_quality_to_state_confidence(level: str) -> Literal["low", "medium", "high"]:
        normalized = str(level or "").strip().lower()
        if normalized == "strong":
            return "high"
        if normalized == "usable":
            return "medium"
        return "low"

    def _state_sources_from_page_context(page_context: PageContextPackRecord | None) -> list[str]:
        if page_context is None:
            return []
        sources: list[str] = []
        if page_context.officialJudgments:
            sources.append("judgment")
        if page_context.candidateJudgments:
            sources.append("candidate_judgment")
        if page_context.relatedMeetings:
            sources.append("meeting")
        if page_context.relatedTasks:
            sources.append("task")
        if page_context.openQuestions:
            sources.append("open_question")
        if page_context.conflicts:
            sources.append("conflict")
        if page_context.relatedDocuments or page_context.rawEvidence:
            sources.append("document")
        if page_context.memoryFacts:
            sources.append("memory")
        if page_context.evidenceCards:
            sources.append("evidence_card")
        return sources

    def _state_answer_sections_from_page_context(
        page_context: PageContextPackRecord | None,
        evidence: list[EvidenceItem],
        question_focus_frame: dict[str, object] | None = None,
    ) -> StateAnswerSectionsRecord:
        if page_context is None:
            return StateAnswerSectionsRecord()
        focus_goal = str(question_focus_frame.get("goal") or "").strip() if isinstance(question_focus_frame, dict) else ""
        focus_facet = str(question_focus_frame.get("subjectFacet") or "").strip() if isinstance(question_focus_frame, dict) else ""
        suppress_state_noise = focus_goal in {"define", "explain", "evidence"} and focus_facet in {"identity", "project", "method", "strategy"}
        official = [
            str(item.get("summary") or item.get("topic") or item.get("statement") or "").strip()
            for item in page_context.officialJudgments[:4]
            if str(item.get("summary") or item.get("topic") or item.get("statement") or "").strip()
        ]
        candidate = [] if suppress_state_noise else [
            str(item.get("summary") or item.get("topic") or item.get("statement") or "").strip()
            for item in page_context.candidateJudgments[:4]
            if str(item.get("summary") or item.get("topic") or item.get("statement") or "").strip()
        ]
        actions = [] if suppress_state_noise else [
            str(item.get("title") or item.get("summary") or "").strip()
            for item in page_context.relatedTasks[:4]
            if str(item.get("title") or item.get("summary") or "").strip()
        ]
        risks = [] if suppress_state_noise else [
            str(item.get("summary") or item.get("title") or "").strip()
            for item in page_context.conflicts[:4]
            if str(item.get("summary") or item.get("title") or "").strip()
        ]
        unknowns = [str(item).strip() for item in page_context.missingContext[:4] if str(item).strip()]
        evidence_support = []
        for item in evidence[:4]:
            label = str(item.title or "").strip()
            excerpt = re.sub(r"\s+", " ", str(item.excerpt or "")).strip()
            if label and excerpt:
                evidence_support.append(f"{label}：{excerpt[:120]}")
            elif label:
                evidence_support.append(label)
        draft_findings = [
            str(item.get("summary") or item.get("title") or "").strip()
            for item in page_context.evidenceCards[:3]
            if str(item.get("summary") or item.get("title") or "").strip()
        ]
        return StateAnswerSectionsRecord(
            official=official,
            candidate=candidate,
            draftFindings=draft_findings,
            evidenceSupport=evidence_support,
            actions=actions,
            risks=risks,
            unknowns=unknowns,
        )

    def _state_source_summary_from_page_context(page_context: PageContextPackRecord | None) -> StateSourceSummaryRecord:
        if page_context is None:
            return StateSourceSummaryRecord()
        return StateSourceSummaryRecord(
            judgments=len(page_context.officialJudgments) + len(page_context.candidateJudgments),
            meetings=len(page_context.relatedMeetings),
            tasks=len(page_context.relatedTasks),
            openQuestions=len(page_context.openQuestions),
            conflicts=len(page_context.conflicts),
            documents=len(page_context.relatedDocuments) + len(page_context.rawEvidence),
        )

    def _coerce_evidence_from_payload(
        payload: dict[str, object],
        *,
        index: int,
    ) -> EvidenceItem:
        return EvidenceItem(
            id=str(payload.get("id") or f"dc_ev_{index}"),
            title=str(payload.get("title") or f"资料片段 {index}"),
            excerpt=str(payload.get("excerpt") or payload.get("summary") or ""),
            sourceType=str(payload.get("sourceType") or "data_center"),
            documentId=str(payload.get("documentId")) if payload.get("documentId") else None,
            path=str(payload.get("path")) if payload.get("path") else None,
            score=float(payload["score"]) if payload.get("score") is not None else None,
            coverage=float(payload["coverage"]) if payload.get("coverage") is not None else None,
            sectionLabel=str(payload.get("sectionLabel")) if payload.get("sectionLabel") else None,
            retrievalStage=str(payload.get("retrievalStage")) if payload.get("retrievalStage") else None,
            isFallback=False,
            matchedTerms=[str(item) for item in payload.get("matchedTerms", []) if str(item).strip()]
            if isinstance(payload.get("matchedTerms"), list)
            else [],
        )

    def _resolve_primary_evidence(kernel_result: DataCenterKernelResultRecord) -> list[EvidenceItem]:
        answer_material = kernel_result.answerMaterial
        if answer_material is not None and answer_material.evidenceHighlights:
            return list(answer_material.evidenceHighlights[:20])
        page_context = kernel_result.pageContext
        if page_context is None:
            return []
        raw_payloads = [item for item in page_context.rawEvidence if isinstance(item, dict)]
        if raw_payloads:
            return [
                _coerce_evidence_from_payload(item, index=index)
                for index, item in enumerate(raw_payloads[:20], start=1)
            ]
        related_documents = [item for item in page_context.relatedDocuments if isinstance(item, dict)]
        return [
            _coerce_evidence_from_payload(item, index=index)
            for index, item in enumerate(related_documents[:12], start=1)
        ]

    _CONTRACT_SOURCE_TOKENS = ("合同", "协议", "报价", "申请书", "标书", "0907")
    _CONTRACT_FACT_TOKENS = ("甲方", "乙方", "服务期限", "40万", "付款", "发票", "知识产权", "保密", "不可抗力", "服务费", "合同")

    def _citation_normalized_text(value: str | None) -> str:
        return re.sub(r"\s+", "", str(value or "").lower())

    def _evidence_source_text(item: EvidenceItem) -> str:
        return " ".join(
            str(value or "")
            for value in (
                item.title,
                item.path,
                item.originalPath,
                item.managedPath,
                item.markdownPath,
                item.sectionLabel,
            )
        )

    def _is_contract_source_evidence(item: EvidenceItem) -> bool:
        return any(token in _evidence_source_text(item) for token in _CONTRACT_SOURCE_TOKENS)

    def _answer_contains_contract_facts(prompt: str, content: str) -> bool:
        combined = f"{prompt}\n{content}"
        return any(token in combined for token in _CONTRACT_FACT_TOKENS)

    def _evidence_excerpt_overlaps_answer(item: EvidenceItem, content: str) -> bool:
        normalized_content = _citation_normalized_text(content)
        if not normalized_content:
            return False
        excerpt = re.sub(r"\s+", " ", str(item.excerpt or "")).strip()
        if not excerpt:
            return False
        segments = [
            segment.strip()
            for segment in re.split(r"[。！？!?；;\n\r]+", excerpt)
            if len(segment.strip()) >= 12
        ]
        for segment in segments[:8]:
            normalized_segment = _citation_normalized_text(segment)
            if len(normalized_segment) >= 12 and normalized_segment in normalized_content:
                return True
        return False

    def prioritize_answer_citations(
        *,
        prompt: str,
        answer_content: str,
        evidence: list[EvidenceItem],
    ) -> tuple[list[EvidenceItem], dict[str, object]]:
        if not evidence:
            return evidence, {
                "answerUsedEvidenceIds": [],
                "pinnedCitationCount": 0,
                "citationPrioritizationReason": None,
            }
        should_prioritize_contract = _answer_contains_contract_facts(prompt, answer_content)
        if not should_prioritize_contract:
            return evidence, {
                "answerUsedEvidenceIds": [],
                "pinnedCitationCount": 0,
                "citationPrioritizationReason": None,
            }

        prioritized: list[tuple[int, int, EvidenceItem]] = []
        answer_used_ids: list[str] = []
        pinned_count = 0
        for index, item in enumerate(evidence):
            if _is_contract_source_evidence(item):
                is_direct_quote = _evidence_excerpt_overlaps_answer(item, answer_content)
                priority = 120 if is_direct_quote else 100
                role = "direct_quote" if is_direct_quote else "direct_support"
                reason = "contract_fact_overlap" if is_direct_quote else "contract_facts_answered_from_contract_source"
                next_item = item.model_copy(
                    update={
                        "citationRole": role,
                        "citationPriority": priority,
                        "citationReason": reason,
                    }
                )
                answer_used_ids.append(str(item.id))
                pinned_count += 1
                prioritized.append((priority, index, next_item))
                continue
            next_item = item
            if item.citationRole is None:
                next_item = item.model_copy(
                    update={
                        "citationRole": "background",
                        "citationPriority": int(item.citationPriority or 0),
                        "citationReason": item.citationReason or "related_background",
                    }
                )
            prioritized.append((int(next_item.citationPriority or 0), index, next_item))

        prioritized.sort(key=lambda item: (-item[0], item[1]))
        return [item for _priority, _index, item in prioritized], {
            "answerUsedEvidenceIds": answer_used_ids,
            "pinnedCitationCount": pinned_count,
            "citationPrioritizationReason": "contract_facts_answered_from_contract_source" if pinned_count else None,
        }

    def _extract_workspace_followup_candidates(text: str) -> list[str]:
        candidates: list[str] = []
        for raw_line in str(text or "").splitlines():
            line = re.sub(r"^[\-\*\d\.\)\(（）、\s]+", "", raw_line).strip()
            if not line:
                continue
            candidates.append(line)
        if candidates:
            return candidates
        return [
            segment.strip()
            for segment in re.split(r"[\n。！？!?；;]+", str(text or ""))
            if segment.strip()
        ]

    def build_workspace_followup_questions(
        *,
        prompt: str,
        answer_content: str,
        workspace_workflow: str,
        client_name: str,
        primary_sources: list[str],
        missing_context: list[str],
        search_result: DataCenterSearchResultRecord | None = None,
        raise_on_generation_error: bool = False,
    ) -> WorkspaceFollowupResult:
        scenario = classify_workspace_followup_scenario(
            prompt=prompt,
            answer_content=answer_content,
            workspace_workflow=workspace_workflow,
            primary_sources=primary_sources,
            missing_context=missing_context,
        )
        if workspace_workflow == "file_search" and search_result is not None and getattr(search_result, "suggestedFollowups", None):
            return build_workspace_followup_result_from_candidates(
                list(search_result.suggestedFollowups or []),
                scenario=scenario,
                generation_mode="file_search",
                client_name=client_name,
                workspace_workflow=workspace_workflow,
            )
        if not str(answer_content or "").strip():
            return WorkspaceFollowupResult(
                questions=[],
                scenario=scenario,
                generation_mode="fallback",
                rejected_count=0,
            )
        followup_context = build_workspace_followup_context(
            prompt=prompt,
            answer_content=answer_content,
            workspace_workflow=workspace_workflow,
            scenario=scenario,
            client_name=client_name,
            primary_sources=primary_sources,
            missing_context=missing_context,
        )
        try:
            followup_structured = state.ai.generate_chat_response(
                "请基于当前问题和刚生成的回答，给出恰好 3 个下一轮继续追问的问题。",
                build_workspace_followup_instruction(scenario),
                followup_context,
            )
            raw_candidates: list[str] = []
            for block in (
                followup_structured.content,
                followup_structured.judgment,
                followup_structured.analysis,
                followup_structured.actions,
            ):
                raw_candidates.extend(_extract_workspace_followup_candidates(str(block or "")))
            return build_workspace_followup_result_from_candidates(
                raw_candidates,
                scenario=scenario,
                generation_mode="consulting",
                client_name=client_name,
                workspace_workflow=workspace_workflow,
            )
        except Exception:
            if raise_on_generation_error:
                raise
            return build_workspace_followup_result_from_candidates(
                [],
                scenario=scenario,
                generation_mode="fallback",
                client_name=client_name,
                workspace_workflow=workspace_workflow,
            )

    def resolve_chat_answer_data_center_primary(
        client_id: str,
        thread_id: str,
        prompt: str,
        assistant_id: str,
        search_id: str | None,
        request_started: float,
        run_id: str | None = None,
        working_document_ids: list[str] | None = None,
    ) -> ChatMessageRecord:
        del search_id
        if is_client_analysis_run_canceled(run_id):
            return fetch_chat_message_for_client(client_id, assistant_id)
        # P2.16 REMOVE(raw-document-pack-legacy-fallback): legacy fallback setting is ignored for
        # workspace/chat main answers; failures may use only the open short fault fallback below.
        use_legacy_fallback = False
        thread_memory_pack = load_thread_context_pack(state.db, client_id, thread_id, bootstrap=True)
        thread_memory_resolved_references = resolve_thread_references(prompt, thread_memory_pack)
        thread_memory_context = (
            render_thread_memory_context(thread_memory_pack, thread_memory_resolved_references)
            if thread_memory_resolved_references
            else ""
        )
        thread_memory_applied = bool(thread_memory_resolved_references and thread_memory_context)
        prompt_for_context = build_contextual_prompt(prompt, thread_memory_context) if thread_memory_context else prompt
        workspace_snapshot = workspace_for_client(client_id)
        page_intent = infer_page_intent(prompt_for_context, "workspace_chat")
        state_context_pack = build_state_answer_context_pack(workspace_snapshot, prompt_for_context)
        workspace_route = route_workspace_query(
            prompt=prompt_for_context,
            client_id=client_id,
            current_page="workspace_chat",
            selected_scope_type="client",
            selected_scope_id=client_id,
        )
        legacy_intent = classify_workspace_chat_intent(prompt_for_context)
        legacy_judgment_mode = detect_judgment_query_mode(prompt_for_context, state_context_pack)
        _, legacy_retrieval_reason = decide_workspace_chat_retrieval_strategy(
            prompt_for_context,
            state_context_pack,
            search_id=None,
            judgment_query_mode=legacy_judgment_mode,
            answer_intent=legacy_intent,
        )
        kernel_request = build_workspace_data_center_request_from_route(
            route=workspace_route,
            prompt=prompt_for_context,
            shadow=True,
            persist_drafts=False,
            working_document_ids=working_document_ids,
        )
        kernel_result = resolve_data_center_kernel(
            state.db,
            data_dir=state.data_dir,
            request=kernel_request,
            ai_service=state.ai,
        )
        page_context_pack = kernel_result.pageContext or build_client_page_context_pack(
            state.db,
            data_dir=state.data_dir,
            client_id=client_id,
            prompt=prompt_for_context,
            page="workspace_chat",
            intent=page_intent,
            include_raw_evidence=True,
            workspace=workspace_snapshot,
        )
        if kernel_result.pageContext is None:
            kernel_result = kernel_result.model_copy(update={"pageContext": page_context_pack})
        retrieval_settings = get_retrieval_model_settings(state.db)
        route_decision_source: Literal["data_center", "legacy"] = "data_center"
        route_decision = route_page_query(
            state.db,
            page="workspace_chat",
            prompt=prompt_for_context,
            client_id=client_id,
            page_context=page_context_pack,
            settings=retrieval_settings,
            ai_service=state.ai,
        )
        kernel_result = kernel_result.model_copy(update={"routeDecision": route_decision})
        answer_intent = map_route_intent_to_workspace_intent(route_decision.intent)
        retrieval_decision_reason = route_decision_to_retrieval_reason(
            route_decision,
            state_pack=state_context_pack,
            current_reason="default_hybrid_evidence",
        )
        should_run_retrieval = answer_intent != "official_judgment_registry"
        if answer_intent == "official_judgment_registry":
            retrieval_decision_reason = "official_registry_requested" if state_context_pack.hits else "state_pool_empty"

        evidence = _resolve_primary_evidence(kernel_result)
        workspace_workflow = workspace_route.workflow
        workspace_generation_mode = workspace_route.generationMode
        primary_sources = list(workspace_route.dataSources)
        question_focus_frame = build_question_focus_frame(
            prompt=prompt_for_context,
            route_decision=route_decision,
            page_context=page_context_pack,
        ).model_dump(mode="json")
        state_answer_sections = _state_answer_sections_from_page_context(
            page_context_pack,
            evidence,
            question_focus_frame=question_focus_frame if isinstance(question_focus_frame, dict) else None,
        )
        state_source_summary = _state_source_summary_from_page_context(page_context_pack)
        quality_summary = build_workspace_context_quality_summary(page_context_pack, kernel_result.quality)
        state_confidence = _context_quality_to_state_confidence(str(quality_summary.get("contextQuality") or "none"))
        state_sources = _state_sources_from_page_context(page_context_pack)
        judgment_query_mode = route_decision.judgmentQueryMode or detect_judgment_query_mode(prompt_for_context, state_context_pack)
        focus_goal = str(question_focus_frame.get("goal") or "") if isinstance(question_focus_frame, dict) else ""
        focus_subject_facet = str(question_focus_frame.get("subjectFacet") or "") if isinstance(question_focus_frame, dict) else ""
        focus_suppressed = (
            [str(item) for item in question_focus_frame.get("suppressedExpansions", []) if str(item).strip()]
            if isinstance(question_focus_frame, dict)
            else []
        )
        generation_policy = decide_generation_runtime_policy(
            state.db,
            client_id=client_id,
            answer_intent=str(answer_intent or "general"),
            provider=state.ai.current_provider(),
            model=state.ai.current_model(),
            mode="data_center_primary",
        )
        # P2.14 FREEZE(answer-shaping-main-open-path): 旧 raw_document_pack 主路径已经冻结，不能再回流。
        # P2.15 V2(answer-reading-main-open-path): workspace/chat 主回答主链切到 raw_reading_pack_v2，
        # 统一文档层 + 两段式阅读替换旧 raw_document_pack。
        material_access_mode = "raw_reading_pack_v2"
        generation_profile = material_access_mode
        primary_context_chars = 100000
        consultant_material_pack = None
        dna_tool_context = build_dna_tool_context_from_workspace(
            workspace_snapshot,
            prompt=prompt_for_context,
            purpose=None,
            max_chars=22000,
        )
        if workspace_generation_mode == "no_generation":
            generation_profile = "search_only"
        if workspace_generation_mode == "consultant_synthesis":
            material_access_mode = "consultant_synthesis_v1"
            generation_profile = "consultant_synthesis"
            primary_context_chars = 36000
            consultant_material_pack = build_consultant_synthesis_material_pack(
                prompt=prompt_for_context,
                kernel_result=kernel_result,
                workspace_snapshot=workspace_snapshot,
                max_chars=primary_context_chars,
            )
            open_context = consultant_material_pack.content
        else:
            open_context = build_open_workspace_answer_context(
                prompt=prompt_for_context,
                kernel_result=kernel_result,
                workspace_snapshot=workspace_snapshot,
                max_chars=primary_context_chars,
                question_focus_frame=question_focus_frame if isinstance(question_focus_frame, dict) else None,
                profile_draft=None,
                dna_tool_context=dna_tool_context,
            )
        open_context = inject_thread_memory_into_context(open_context, thread_memory_context)
        evidence_summary = build_analysis_evidence_summary(
            client_id,
            prompt_for_context,
            evidence=evidence,
            retrieval_trace=kernel_result.retrievalTrace,
            search_result=kernel_result.searchResult,
        )
        live_work_trace = build_kernel_primary_work_trace(
            prompt_for_context,
            evidence,
            evidence_summary,
            focus_frame=question_focus_frame,
        )
        source_integrity_report = build_source_integrity_report(
            running_backend_root=Path(__file__).resolve().parents[1],
            expected_workspace_root=((Path.cwd() / "backend").resolve() if (Path.cwd() / "backend").exists() else None),
            build_version=APP_BUILD_VERSION,
            git_commit=APP_GIT_COMMIT,
            runtime_mode=BACKEND_RUNTIME_MODE,
        )
        source_integrity_match = source_integrity_report.get("match")
        retrieval_elapsed_ms = 0.0
        if kernel_result.retrievalTrace is not None and isinstance(kernel_result.retrievalTrace.latencyMs, dict):
            retrieval_elapsed_ms = float(
                kernel_result.retrievalTrace.latencyMs.get("totalMs")
                or kernel_result.retrievalTrace.latencyMs.get("retrievalMs")
                or 0.0
            )
        generation_timeout_seconds = 300.0
        generation_started_at = now_iso()
        generation_snapshot = state.ai.resolved_model_snapshot(task_kind="deep_analysis")
        generation_provider = str(generation_snapshot.get("provider") or state.ai.current_provider())
        generation_model = str(generation_snapshot.get("model") or state.ai.current_model())
        generation_model_label = str(generation_snapshot.get("modelLabel") or state.ai.model_label(generation_provider, generation_model))
        generation_profile_key = str(generation_snapshot.get("profileKey") or "unified")
        generation_model_mode = str(generation_snapshot.get("mode") or state.ai.current_ai_model_mode())
        pre_llm_meta = {
            "phase": "generating",
            "stageLabel": f"数据中心已完成路由与供料，正在调用{generation_model_label}生成回答",
            "progress": 62.0,
            "progressFloor": 58.0,
            "progressCeiling": 96.0,
            "dataCenterPrimaryEnabled": True,
            "legacyIntent": legacy_intent,
            "legacyRetrievalReason": legacy_retrieval_reason,
            "answerIntent": answer_intent,
            "retrievalDecisionReason": retrieval_decision_reason,
            "contextQuality": quality_summary,
            "sourceIntegrityMatch": source_integrity_match,
            "previewSummary": evidence_summary.summaryText,
            "workTrace": live_work_trace,
            "materialAccessMode": material_access_mode,
            "masterHitCount": int(evidence_summary.masterHitCount or 0),
            "surrogateHitCount": int(evidence_summary.surrogateHitCount or 0),
            "rawChunkHitCount": int(evidence_summary.rawChunkHitCount or 0),
            "readingPassCount": int(getattr(kernel_result.retrievalTrace, "readingPassCount", 0) or 0),
            "selectedDocumentFamilyCount": int(getattr(kernel_result.retrievalTrace, "selectedDocumentFamilyCount", 0) or 0),
            "selectedCanonicalKinds": list(getattr(kernel_result.retrievalTrace, "selectedCanonicalKinds", []) or []),
            "softwareMaterialIncluded": bool(getattr(kernel_result.retrievalTrace, "softwareMaterialIncluded", False)),
            "dnaToolPurpose": dna_tool_context.purpose,
            "dnaToolChars": dna_tool_context.context_chars,
            "selectedDnaModules": dna_tool_context.selected_modules,
            "selectedDnaKinds": dna_tool_context.selected_kinds,
            "dnaToolSourceLevelSummary": dna_tool_context.source_level_summary,
            "dnaToolTimeScopeSummary": dna_tool_context.time_scope_summary,
            "dnaToolWarnings": dna_tool_context.warnings,
            "generationStartedAt": generation_started_at,
            "generationTimeoutSeconds": generation_timeout_seconds,
            "providerUsed": generation_provider,
            "modelUsed": generation_model,
            "modelLabel": generation_model_label,
            "modelProfileKey": generation_profile_key,
            "aiModelMode": generation_model_mode,
            "threadMemoryApplied": thread_memory_applied,
            "threadMemoryVersion": thread_memory_pack.version,
            "threadMemoryResolvedReferences": [item.model_dump(mode="json") for item in thread_memory_resolved_references],
            "threadMemoryContextChars": len(thread_memory_context),
            "threadMemoryUpdateMode": "pending",
            "workingDocumentIds": [str(item).strip() for item in (working_document_ids or []) if str(item).strip()],
            "workingDocumentHitCount": int(getattr(kernel_result.retrievalTrace, "workingDocumentHitCount", 0) or 0),
        }
        if consultant_material_pack is not None:
            pre_llm_meta.update(
                {
                    "materialPackProfile": consultant_material_pack.profile,
                    "materialPackSourceCounts": consultant_material_pack.source_counts,
                    "excludedNoiseCount": consultant_material_pack.excluded_noise_count,
                    "consultantContextChars": consultant_material_pack.context_chars,
                    "consultantBoundaryNotes": consultant_material_pack.boundary_notes,
                }
            )
        update_loading_assistant_message(
            assistant_id,
            retrieval_summary=pre_llm_meta,
            timing={"retrievalMs": retrieval_elapsed_ms},
            content="数据中心主链已就绪，正在组织回答……",
        )
        if run_id:
            update_client_analysis_run(
                run_id,
                phase="generating_long_answer",
                progress=62.0,
                progress_floor=58.0,
                progress_ceiling=96.0,
                stage_label=f"数据中心已完成路由与供料，正在调用{generation_model_label}生成回答",
                elapsed_ms=retrieval_elapsed_ms,
                evidence_summary=evidence_summary,
            )
        if is_client_analysis_run_canceled(run_id):
            return fetch_chat_message_for_client(client_id, assistant_id)

        intro_like_prompt = any(
            token in re.sub(r"\s+", "", str(prompt or "").lower())
            for token in ("介绍", "简介", "核心定位", "项目特点", "怎么做", "创始人")
        )
        if workspace_generation_mode == "consultant_synthesis":
            open_model_system_instruction = (
                "你是一名资深战略咨询顾问，长期陪伴公益组织做战略、组织、业务和品牌升级。"
                "这个身份只用于内部思考，不要在正文中自称顾问。\n"
                "请根据资料直接回答用户问题，详细、开放、深入地介绍客户。\n"
                "像真正了解这个组织的人在向合作伙伴或内部决策者介绍客户，而不是资料摘要器。\n"
                "可以自由组织结构，不需要套固定模板。\n"
                "要讲清楚客户是什么组织、为什么重要、解决什么问题、怎么做、业务线之间的关系、当前变化、核心资产和未来值得关注什么。\n"
                "可以做综合判断和解释，但不要编造资料中没有的硬事实；不确定信息自然说明是当前资料显示或仍需进一步确认。\n"
                "不要输出系统过程，不要列资料名，不要写成检索报告。请写得充分一些，不要太短。"
            )
        else:
            open_model_system_instruction = (
                "直接回答用户问题。\n"
                "只基于给定资料判断。\n"
                "可以自由组织结构和长度。\n"
                "不要编造，也不要暴露系统过程。"
            )
        if intro_like_prompt and workspace_generation_mode != "consultant_synthesis":
            open_model_system_instruction += "\n回答应尽量覆盖机构定位、核心问题、主要方法/项目和当前升级方向。"

        latest_partial_content = ""
        latest_partial_structured: dict[str, object] | None = None

        def has_meaningful_partial_content(value: str) -> bool:
            cleaned = str(value or "").strip()
            if not cleaned:
                return False
            normalized = re.sub(r"\s+", "", cleaned)
            model_generation_placeholder_suffix = re.sub(r"\s+", "", "正在基于完整材料直接生成长文回答。")
            placeholder_variants = {
                re.sub(r"\s+", "", "正在围绕核心判断、关键张力和潜在风险整合原始证据，准备输出连续长文分析。"),
                re.sub(r"\s+", "", f"{generation_model_label}正在基于完整材料直接生成长文回答。"),
                re.sub(r"\s+", "", "数据中心主链已就绪，正在组织回答……"),
                re.sub(r"\s+", "", "庆华正在整理背景材料，并组织分析答案……"),
                re.sub(r"\s+", "", "正在调用模型生成回答"),
            }
            return normalized not in placeholder_variants and not normalized.endswith(model_generation_placeholder_suffix)

        def load_preserved_partial() -> tuple[str, dict[str, object] | None]:
            preserved_content = latest_partial_content
            preserved_structured = latest_partial_structured
            if run_id and not preserved_content:
                row = state.db.fetchone(
                    "SELECT long_answer, structured_summary_json FROM client_analysis_runs WHERE id = ?",
                    (run_id,),
                )
                if row:
                    if row["long_answer"]:
                        preserved_content = str(row["long_answer"]).strip()
                    structured_payload = from_json(str(row["structured_summary_json"] or "{}"), {})
                    if isinstance(structured_payload, dict) and structured_payload:
                        preserved_structured = structured_payload
            if preserved_content and not has_meaningful_partial_content(preserved_content):
                return "", None
            return preserved_content, preserved_structured

        def push_partial_analysis(partial: dict[str, object]) -> None:
            nonlocal latest_partial_content, latest_partial_structured
            if is_client_analysis_run_canceled(run_id):
                return
            partial_content = str(partial.get("content") or "").strip()
            if not partial_content:
                return
            if has_meaningful_partial_content(partial_content):
                latest_partial_content = partial_content
                latest_partial_structured = (
                    partial["structured"]
                    if isinstance(partial.get("structured"), dict)
                    else None
                )
            update_loading_assistant_message(
                assistant_id,
                retrieval_summary={
                    "phase": "generating",
                    "stageLabel": str(partial.get("stageLabel") or "正在生成回答"),
                    "progress": float(partial.get("progress") or 74.0),
                    "generationStartedAt": generation_started_at,
                    "generationTimeoutSeconds": generation_timeout_seconds,
                    "providerUsed": generation_provider,
                    "modelUsed": generation_model,
                    "modelLabel": generation_model_label,
                },
                content=partial_content if has_meaningful_partial_content(partial_content) else None,
            )
            if run_id:
                update_kwargs: dict[str, object] = {
                    "phase": "generating_long_answer",
                    "progress": float(partial.get("progress") or 74.0),
                    "progress_floor": 58.0,
                    "progress_ceiling": 96.0,
                    "stage_label": str(partial.get("stageLabel") or "正在生成回答"),
                }
                if has_meaningful_partial_content(partial_content):
                    update_kwargs["long_answer"] = partial_content
                update_client_analysis_run(run_id, **update_kwargs)

        llm_started = perf_counter()
        llm_attempt_count = 0
        state.ai.reset_last_model_snapshot()
        compact_retry_attempted = False
        fallback_template_used = False
        final_failure_stage: str | None = None
        generation_failure_detail: str | None = None
        llm_error_kind: str | None = None
        partial_generation_preserved = False
        provider_used: str | None = generation_provider
        model_used: str | None = generation_model
        model_route = f"AI · {generation_model_label}"
        llm_invoked = True
        answer_mode = "grounded_answer" if evidence else "general_answer"
        evidence_status: Literal["sufficient", "partial", "none"] = "sufficient" if evidence else "none"
        failure_reason: str | None = None
        fallback_presentation_mode: Literal["full_answer", "compact_user_answer", "state_cards_only"] = "full_answer"
        structured = AiStructuredResponse(
            content="",
            judgment="",
            analysis="",
            actions="",
            timeline="",
        )
        if workspace_workflow == "file_search":
            provider_used = None
            model_used = None
            model_route = "文件查找"
            llm_invoked = False
            structured = AiStructuredResponse(
                content=build_file_search_user_summary(kernel_result.searchResult),
                judgment="本轮为文件查找结果，不生成战略综合回答。",
                analysis="用户意图为找文件/找原文，已返回命中文件与片段。",
                actions="可点击文件打开原文，或选择若干文件后生成综合回答。",
                timeline="即时可处理。",
            )
            answer_mode = "grounded_answer"
            evidence_status = "sufficient" if kernel_result.searchResult and kernel_result.searchResult.hits else "none"
        else:
            try:
                llm_attempt_count += 1
                structured = state.ai.generate_raw_evidence_response(
                    prompt_for_context,
                    open_model_system_instruction,
                    open_context,
                    on_partial=push_partial_analysis,
                    timeout_seconds=generation_timeout_seconds,
                    max_tokens=5600 if workspace_generation_mode == "consultant_synthesis" else 5200,
                    enable_thinking=True,
                )
            except AiInvocationError as error:
                provider_used = error.provider
                model_route = f"AI · {state.ai.model_label(error.provider, model_used)}"
                generation_failure_detail = str(error.detail or "").strip() or None
                preserved_content, preserved_structured = load_preserved_partial()
                if preserved_content:
                    structured = build_partial_generation_fallback(
                        prompt,
                        preserved_content,
                        error.detail,
                        partial_structured=preserved_structured,
                    )
                    answer_mode = "grounded_fallback"
                    evidence_status = "partial" if evidence else "none"
                    failure_reason = "llm_partial_preserved_after_retry"
                    final_failure_stage = "primary_generation_partial_preserved"
                    partial_generation_preserved = True
                else:
                    final_failure_stage = "raw_evidence_generation_failed"
                    generation_failure_detail = f"primary={error.detail}"
                    structured = AiStructuredResponse(
                        content="本轮模型没有成功完成回答。系统已命中相关资料，但没有生成可交付文本。你可以重试，或先处理资料缺口/候选动作。",
                        judgment="模型生成失败，不输出本地模板伪答案。",
                        analysis=f"主链失败：{error.detail}",
                        actions="请重试；如果连续失败，请检查模型配置、网络或上下文长度。",
                        timeline="可立即重试。",
                    )
                    answer_mode = "system_failure"
                    evidence_status = "partial" if evidence else "none"
                    failure_reason = "llm_generation_failed"
            except Exception as error:
                final_failure_stage = "primary_generation_exception"
                generation_failure_detail = str(error)
                structured = AiStructuredResponse(
                    content="这次模型没有成功完成回答。系统已经命中相关资料，但没有生成可交付文本。请重试。",
                    judgment="模型生成失败，不输出本地模板伪答案。",
                    analysis=f"错误信息：{str(error)}",
                    actions="请重试；如果连续失败，请检查模型配置、网络或上下文长度。",
                    timeline="可立即重试。",
                )
                answer_mode = "system_failure"
                evidence_status = "partial" if evidence else "none"
                failure_reason = "llm_generation_failed"
        if generation_failure_detail:
            llm_error_kind = classify_llm_error_kind(generation_failure_detail)

        answer_quality_report: dict[str, object] = {}
        quality_gate_warned = False
        if kernel_result.answerPlan and kernel_result.answerMaterial and answer_mode != "system_failure":
            answer_quality_report = validate_answer_quality(
                prompt=prompt_for_context,
                content=structured.content,
                answer_plan=kernel_result.answerPlan,
                evidence=evidence,
                answer_material=kernel_result.answerMaterial,
            )
            if retrieval_settings.qualityGateMode == "warn" and answer_quality_report.get("grade") in {"warn", "fail"}:
                quality_gate_warned = True
            elif retrieval_settings.qualityGateMode == "block" and answer_quality_report.get("grade") == "fail":
                final_failure_stage = "quality_gate_blocked"
                answer_mode = "system_failure"
                evidence_status = "partial" if evidence else "none"
                failure_reason = "quality_gate_blocked"
                structured = AiStructuredResponse(
                    content="本轮回答被质量门禁拦截，当前不输出不稳定正文。",
                    judgment="质量门禁 block 已生效。",
                    analysis="请先补齐关键证据与缺口，再重新生成回答。",
                    actions="补齐 missing context 或先确认候选判断后重试。",
                    timeline="完成补齐后可立即重试。",
                )

        if answer_mode == "system_failure" and not failure_reason:
            failure_reason = "llm_generation_failed"
        elif answer_mode == "grounded_fallback" and not failure_reason:
            failure_reason = "partial_materials"
        actual_generation_snapshot = state.ai.last_model_snapshot() if llm_invoked else {}
        if actual_generation_snapshot:
            actual_provider = str(actual_generation_snapshot.get("provider") or generation_provider)
            actual_model = str(actual_generation_snapshot.get("model") or generation_model)
            actual_model_label = str(actual_generation_snapshot.get("modelLabel") or state.ai.model_label(actual_provider, actual_model))
            generation_provider = actual_provider
            generation_model = actual_model
            generation_model_label = actual_model_label
            generation_profile_key = str(actual_generation_snapshot.get("profileKey") or generation_profile_key)
            generation_model_mode = str(actual_generation_snapshot.get("mode") or generation_model_mode)
            provider_used = actual_provider
            model_used = actual_model
            model_route = f"AI · {actual_model_label}"

        finalization = finalize_workspace_answer(
            content=structured.content,
            answer_mode=answer_mode,
            failure_reason=failure_reason,
            fallback_presentation_mode=fallback_presentation_mode,
            kernel_result=kernel_result,
            answer_quality=answer_quality_report if isinstance(answer_quality_report, dict) else None,
            selected_evidence_count=len(evidence),
            llm_error=generation_failure_detail,
        )
        structured = structured.model_copy(update={"content": finalization.content})
        answer_mode = finalization.answerMode
        failure_reason = finalization.failureReason
        fallback_presentation_mode = finalization.fallbackPresentationMode or fallback_presentation_mode
        evidence_status = normalize_workspace_evidence_status(
            initial_status=evidence_status,
            finalization=finalization,
            answer_quality=answer_quality_report if isinstance(answer_quality_report, dict) else None,
            selected_evidence_count=len(evidence),
        )
        answer_presentation = build_workspace_answer_presentation(
            content=structured.content,
            answer_material=kernel_result.answerMaterial,
            answer_plan=kernel_result.answerPlan,
        )
        workspace_answer_experience = build_workspace_answer_experience_payload(
            content=structured.content,
            finalization=finalization,
            answer_material=kernel_result.answerMaterial,
            answer_quality=answer_quality_report if isinstance(answer_quality_report, dict) else None,
            proposal_drafts=kernel_result.proposalDrafts,
            action_suggestions=kernel_result.actionSuggestions,
            answer_presentation=answer_presentation,
            answer_intent=kernel_result.answerPlan.intent if kernel_result.answerPlan else None,
        )
        client_name = workspace_snapshot.client.name if getattr(workspace_snapshot, "client", None) else ""
        if answer_mode == "system_failure":
            followup_result = WorkspaceFollowupResult(
                questions=[],
                scenario="general_consulting",
                generation_mode="skipped_system_failure",
                rejected_count=0,
            )
        else:
            followup_result = WorkspaceFollowupResult(
                questions=[],
                scenario=classify_workspace_followup_scenario(
                    prompt=prompt,
                    answer_content=structured.content,
                    workspace_workflow=workspace_workflow,
                    primary_sources=primary_sources,
                    missing_context=list(page_context_pack.missingContext[:6]) if page_context_pack is not None else [],
                ),
                generation_mode="deferred",
                rejected_count=0,
            )
        evidence, citation_meta = prioritize_answer_citations(
            prompt=prompt_for_context,
            answer_content=structured.content,
            evidence=evidence,
        )

        thread_memory_update_mode = "skipped_system_failure" if answer_mode == "system_failure" else "deferred"
        answer_material_summary = (
            kernel_result.answerMaterial.model_dump(mode="json")
            if kernel_result.answerMaterial is not None
            else {}
        )

        llm_elapsed_ms = round((perf_counter() - llm_started) * 1000, 2) if llm_attempt_count > 0 else 0.0
        total_elapsed_ms = round((perf_counter() - request_started) * 1000, 2)
        if fallback_presentation_mode not in {"full_answer", "compact_user_answer", "state_cards_only"}:
            fallback_presentation_mode = "full_answer"
        generation_policy_payload = generation_policy.model_dump(mode="json")
        generation_policy_payload.update(
            {
                "path": "data_center_primary",
                "mode": "data_center_primary",
                "legacyFallbackEnabled": use_legacy_fallback,
                "qualityGateMode": retrieval_settings.qualityGateMode,
                "partialPreserved": partial_generation_preserved,
            }
        )
        response_meta = build_workspace_dc_response_meta(
            kernel_result=kernel_result,
            answer_intent=answer_intent,
            retrieval_decision_reason=retrieval_decision_reason,
            data_center_primary_enabled=True,
            legacy_intent=legacy_intent,
            legacy_retrieval_reason=legacy_retrieval_reason,
            llm_attempt_count=llm_attempt_count,
            compact_retry_attempted=compact_retry_attempted,
            fallback_template_used=fallback_template_used,
            final_failure_stage=final_failure_stage,
            route_decision_source=route_decision_source,
            answer_mode=answer_mode,
            evidence_status=evidence_status,
            failure_reason=failure_reason,
            fallback_presentation_mode=fallback_presentation_mode,
            should_run_retrieval=should_run_retrieval,
            state_confidence=state_confidence,
            state_sources=state_sources,
            state_answer_sections=state_answer_sections.model_dump(mode="json"),
            state_source_summary=state_source_summary.model_dump(mode="json"),
            total_elapsed_ms=total_elapsed_ms,
            retrieval_elapsed_ms=retrieval_elapsed_ms,
            llm_elapsed_ms=llm_elapsed_ms,
            answer_quality=answer_quality_report,
            quality_gate_warned=quality_gate_warned,
            generation_policy=generation_policy_payload,
            llm_error_kind=llm_error_kind,
            generation_profile=generation_profile,
            partial_generation_preserved=partial_generation_preserved,
            source_integrity_match=(bool(source_integrity_match) if source_integrity_match is not None else None),
            workspace_workflow=workspace_workflow,
            workspace_generation_mode=workspace_generation_mode,
            workspace_route=workspace_route.model_dump(mode="json"),
            primary_sources=primary_sources,
            preview_summary=evidence_summary.summaryText,
            work_trace=live_work_trace,
            master_hit_count=int(evidence_summary.masterHitCount or 0),
            surrogate_hit_count=int(evidence_summary.surrogateHitCount or 0),
            raw_chunk_hit_count=int(evidence_summary.rawChunkHitCount or 0),
            material_access_mode=material_access_mode,
            suggested_followups=followup_result.questions,
            followup_scenario=followup_result.scenario,
            followup_generation_mode=followup_result.generation_mode,
            followup_rejected_count=followup_result.rejected_count,
            material_pack_profile=consultant_material_pack.profile if consultant_material_pack is not None else None,
            material_pack_source_counts=consultant_material_pack.source_counts if consultant_material_pack is not None else None,
            excluded_noise_count=consultant_material_pack.excluded_noise_count if consultant_material_pack is not None else 0,
            consultant_context_chars=consultant_material_pack.context_chars if consultant_material_pack is not None else 0,
            consultant_boundary_notes=consultant_material_pack.boundary_notes if consultant_material_pack is not None else None,
        )
        response_meta.update(
            {
                "kernelPrimaryUsed": True,
                "kernelPrimaryFallbackUsed": bool(answer_mode in {"grounded_fallback", "system_failure"}),
                "kernelPrimaryFallbackReason": (
                    failure_reason
                    if answer_mode in {"grounded_fallback", "system_failure"}
                    else None
                ),
                "workspaceAnswerFinalization": finalization.model_dump(mode="json"),
                "answerPresentation": answer_presentation,
                "workspaceAnswerExperience": workspace_answer_experience,
                "generationFailureDetail": generation_failure_detail,
                "providerUsed": provider_used,
                "modelUsed": model_used,
                "modelLabel": generation_model_label,
                "modelProfileKey": generation_profile_key,
                "aiModelMode": generation_model_mode,
                "sourceIntegrityReport": source_integrity_report,
                "llmErrorHiddenFromUserBecauseAnswerPassedQuality": bool(
                    generation_failure_detail
                    and finalization.answerMode == "grounded_answer"
                    and not finalization.shouldShowRetryBanner
                ),
                "judgmentQueryMode": judgment_query_mode,
                "evidenceSupportMode": route_decision.evidenceSupportMode or ("raw_doc_drilldown" if evidence else "none"),
                "kernelRouteIntent": route_decision.intent,
                "kernelAnswerPlanIntent": kernel_result.answerPlan.intent if kernel_result.answerPlan else None,
                "kernelAnswerQualityGrade": answer_quality_report.get("grade"),
                "kernelSelectedEvidenceCount": len(evidence),
                "selectedEvidenceCount": len(evidence),
                "chatAnswerPlanIntent": kernel_result.answerPlan.intent if kernel_result.answerPlan else map_route_intent_to_workspace_intent(route_decision.intent),
                "kernelConsistency": {
                    "routeIntentMatched": True,
                    "answerPlanMatched": True,
                    "selectedEvidenceOverlap": 1.0,
                    "legacyFallbackUsed": bool(use_legacy_fallback and answer_mode in {"grounded_fallback", "system_failure"}),
                },
                "retrievalStage": "data_center_kernel",
                "workspaceWorkflow": workspace_workflow,
                "generationMode": workspace_generation_mode,
                "workspaceRoute": workspace_route.model_dump(mode="json"),
                "primarySources": primary_sources,
                "materialPackProfile": consultant_material_pack.profile if consultant_material_pack is not None else response_meta.get("materialPackProfile"),
                "materialPackSourceCounts": consultant_material_pack.source_counts if consultant_material_pack is not None else response_meta.get("materialPackSourceCounts", {}),
                "excludedNoiseCount": consultant_material_pack.excluded_noise_count if consultant_material_pack is not None else response_meta.get("excludedNoiseCount", 0),
                "consultantContextChars": consultant_material_pack.context_chars if consultant_material_pack is not None else response_meta.get("consultantContextChars", 0),
                "consultantBoundaryNotes": consultant_material_pack.boundary_notes if consultant_material_pack is not None else response_meta.get("consultantBoundaryNotes", []),
                "dnaToolPurpose": dna_tool_context.purpose,
                "dnaToolChars": dna_tool_context.context_chars,
                "selectedDnaModules": dna_tool_context.selected_modules,
                "selectedDnaKinds": dna_tool_context.selected_kinds,
                "dnaToolSourceLevelSummary": dna_tool_context.source_level_summary,
                "dnaToolTimeScopeSummary": dna_tool_context.time_scope_summary,
                "dnaToolWarnings": dna_tool_context.warnings,
                "answerUsedEvidenceIds": citation_meta.get("answerUsedEvidenceIds", []),
                "pinnedCitationCount": citation_meta.get("pinnedCitationCount", 0),
                "citationPrioritizationReason": citation_meta.get("citationPrioritizationReason"),
                "threadMemoryApplied": thread_memory_applied,
                "threadMemoryVersion": thread_memory_pack.version,
                "threadMemoryResolvedReferences": [item.model_dump(mode="json") for item in thread_memory_resolved_references],
                "threadMemoryContextChars": len(thread_memory_context),
                "threadMemoryUpdateMode": thread_memory_update_mode,
                "phase": "completed" if answer_mode != "system_failure" else "failed",
                "progress": 100.0,
                "progressFloor": 100.0,
                "progressCeiling": 100.0,
                "stageLabel": (
                    "文件查找结果已生成"
                    if workspace_workflow == "file_search" and answer_mode != "system_failure"
                    else "回答已生成"
                    if answer_mode != "system_failure"
                    else "回答生成失败"
                ),
            }
        )

        timestamp = now_iso()
        state.db.execute(
            """
            UPDATE chat_messages
            SET content = ?, structured_data_json = ?, model_route = ?, llm_invoked = ?, provider_used = ?,
                answer_mode = ?, evidence_status = ?, failure_reason = ?, timing_json = ?, retrieval_summary_json = ?,
                evidence_json = ?, status = 'success', created_at = ?
            WHERE id = ?
            """,
            (
                structured.content,
                to_json(structured.model_dump(mode="json")),
                model_route,
                1 if llm_invoked else 0,
                provider_used,
                answer_mode,
                evidence_status,
                failure_reason,
                to_json({"totalMs": total_elapsed_ms, "retrievalMs": retrieval_elapsed_ms, "llmMs": llm_elapsed_ms}),
                to_json(response_meta),
                to_json([item.model_dump(mode="json") for item in evidence]),
                timestamp,
                assistant_id,
            ),
        )
        if answer_mode != "system_failure":
            _run_post_finalize_step(
                assistant_id,
                stage="post_answer_enrichment_submit",
                action=lambda: _schedule_post_answer_enrichment(
                    assistant_id=assistant_id,
                    client_id=client_id,
                    thread_id=thread_id,
                    prompt=prompt,
                    answer_content=structured.content,
                    answer_mode=answer_mode,
                    workspace_workflow=workspace_workflow,
                    workspace_generation_mode=workspace_generation_mode,
                    client_name=client_name,
                    primary_sources=primary_sources,
                    missing_context=list(page_context_pack.missingContext[:6]) if page_context_pack is not None else [],
                    search_result=kernel_result.searchResult,
                    answer_material_summary=answer_material_summary,
                ),
            )
        answer_run_id = new_id("ans")
        _run_post_finalize_step(
            assistant_id,
            stage="answer_run_insert",
            action=lambda: state.db.execute(
                """
                INSERT INTO answer_runs(
                    id, client_id, thread_id, prompt, status, coverage_score, retrieval_mode, llm_invoked,
                    provider_used, failure_reason, retrieval_json, created_at
                )
                VALUES(?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                (
                    answer_run_id,
                    client_id,
                    thread_id,
                    prompt,
                    "completed" if answer_mode in {"grounded_answer", "grounded_fallback", "general_answer"} else "failed",
                    float(1.0 if evidence else 0.0),
                    route_decision.retrievalMode,
                    1 if llm_invoked else 0,
                    provider_used,
                    failure_reason,
                    to_json(response_meta),
                    timestamp,
                ),
            ),
        )
        _run_post_finalize_step(
            assistant_id,
            stage="chat_thread_timestamp",
            action=lambda: state.db.execute("UPDATE chat_threads SET updated_at = ? WHERE id = ?", (timestamp, thread_id)),
        )
        _run_post_finalize_step(
            assistant_id,
            stage="generation_runtime_record",
            action=lambda: record_generation_result(
                state.db,
                client_id=client_id,
                answer_intent=str(answer_intent or "general"),
                provider=provider_used if llm_invoked else None,
                model=model_used if llm_invoked else None,
                answer_mode=answer_mode,
                failure_reason=failure_reason,
                error_detail=generation_failure_detail or final_failure_stage,
                llm_invoked=llm_invoked,
                total_ms=float(total_elapsed_ms),
            ),
        )
        run_long_answer = structured.content if answer_mode != "system_failure" else None
        run_structured_summary = structured if answer_mode != "system_failure" else None
        run_long_answer_status = (
            "failed"
            if answer_mode == "system_failure"
            else "fallback"
            if answer_mode == "grounded_fallback"
            else "ready"
        )
        run_summary_status = run_long_answer_status
        if run_id:
            _run_post_finalize_step(
                assistant_id,
                stage="analysis_run_final_update",
                action=lambda: update_client_analysis_run(
                    run_id,
                    status="completed" if answer_mode != "system_failure" else "failed",
                    phase="completed" if answer_mode != "system_failure" else "failed",
                    progress=100.0,
                    progress_floor=100.0,
                    progress_ceiling=100.0,
                    stage_label="分析已完成" if answer_mode != "system_failure" else "回答生成失败",
                    elapsed_ms=total_elapsed_ms,
                    evidence_summary=evidence_summary,
                    long_answer=run_long_answer,
                    structured_summary=run_structured_summary,
                    long_answer_status=run_long_answer_status,
                    summary_status=run_summary_status,
                    answer_mode=answer_mode,
                    llm_invoked=llm_invoked,
                    provider_used=provider_used,
                    failure_reason=failure_reason,
                    timing={"totalMs": total_elapsed_ms, "retrievalMs": retrieval_elapsed_ms, "llmMs": llm_elapsed_ms},
                ),
            )
        _run_post_finalize_step(
            assistant_id,
            stage="chat_reply_activity",
            action=lambda: log_activity(
                "chat.reply",
                "chat_thread",
                thread_id,
                {
                    "clientId": client_id,
                    "prompt": prompt,
                    "coverage": 1.0 if evidence else 0.0,
                    "citationCount": len(evidence),
                    "answerMode": answer_mode,
                    "dataCenterPrimaryEnabled": True,
                    "workspaceWorkflow": workspace_workflow,
                },
            ),
        )
        if workspace_workflow != "file_search":
            _run_post_finalize_step(
                assistant_id,
                stage="chat_fact_extraction",
                action=lambda: _schedule_chat_fact_extraction(
                    state,
                    client_id=client_id,
                    thread_id=thread_id,
                    user_prompt=prompt,
                    assistant_content=structured.content,
                    answer_mode=answer_mode,
                ),
            )
        row = state.db.fetchone("SELECT * FROM chat_messages WHERE id = ?", (assistant_id,))
        assert row is not None
        return build_chat_message(row)

    def resolve_chat_answer(
        client_id: str,
        thread_id: str,
        prompt: str,
        assistant_id: str,
        search_id: str | None,
        request_started: float,
        run_id: str | None = None,
        working_document_ids: list[str] | None = None,
    ) -> ChatMessageRecord:
        # P2.16 REMOVE(raw-document-pack-main-chain): workspace/chat 主回答不再允许
        # 通过关闭 primary 或质量回退进入旧 raw_document_pack / generate_chat_response 链。
        # 显式 file_search 与 official_judgment_registry 仍在 data_center_primary 内分流。
        return resolve_chat_answer_data_center_primary(
            client_id,
            thread_id,
            prompt,
            assistant_id,
            search_id,
            request_started,
            run_id,
            working_document_ids,
        )

    def _assistant_message_has_final_answer(row) -> bool:
        if row is None:
            return False
        status = str(row["status"] or "")
        answer_mode = str(row["answer_mode"] or "")
        content = str(row["content"] or "").strip()
        failure_reason = str(row["failure_reason"] or "").strip()
        if status != "success":
            return False
        if not content:
            return False
        placeholder_texts = {
            "庆华正在整理背景材料，并组织分析答案……",
            "数据中心主链已就绪，正在组织回答……",
            "庆华暂时没能完成这次回答。",
        }
        if content in placeholder_texts:
            return False
        if answer_mode in {"grounded_answer", "grounded_fallback", "general_answer", "low_confidence_answer"}:
            return True
        if answer_mode == "system_failure":
            return False
        return bool(content and not failure_reason)

    def _append_post_finalize_warning(
        assistant_id: str,
        *,
        stage: str,
        error: Exception,
    ) -> None:
        row = state.db.fetchone(
            "SELECT retrieval_summary_json FROM chat_messages WHERE id = ?",
            (assistant_id,),
        )
        summary = from_json(str(row["retrieval_summary_json"] or "{}"), {}) if row else {}
        if not isinstance(summary, dict):
            summary = {}
        warnings = summary.get("postFinalizeWarnings")
        if not isinstance(warnings, list):
            warnings = []
        warnings.append(
            {
                "stage": stage,
                "error": str(error),
                "at": now_iso(),
            }
        )
        summary["postFinalizeWarnings"] = warnings[-8:]
        summary["postFinalizeWarningCount"] = len(warnings[-8:])
        state.db.execute(
            """
            UPDATE chat_messages
            SET retrieval_summary_json = ?
            WHERE id = ?
            """,
            (to_json(summary), assistant_id),
        )

    def _run_post_finalize_step(
        assistant_id: str,
        *,
        stage: str,
        action: Callable[[], None],
    ) -> None:
        try:
            action()
        except Exception as exc:
            logger.warning("[workspace-chat] post finalize warning stage=%s", stage, exc_info=True)
            _append_post_finalize_warning(assistant_id, stage=stage, error=exc)

    def _merge_assistant_retrieval_summary(assistant_id: str, updates: dict[str, object]) -> None:
        if not updates:
            return
        row = state.db.fetchone(
            "SELECT retrieval_summary_json FROM chat_messages WHERE id = ?",
            (assistant_id,),
        )
        summary = from_json(str(row["retrieval_summary_json"] or "{}"), {}) if row else {}
        if not isinstance(summary, dict):
            summary = {}
        summary.update(updates)
        summary["lastUpdatedAt"] = now_iso()
        state.db.execute(
            """
            UPDATE chat_messages
            SET retrieval_summary_json = ?
            WHERE id = ?
            """,
            (to_json(summary), assistant_id),
        )

    def _schedule_post_answer_enrichment(
        *,
        assistant_id: str,
        client_id: str,
        thread_id: str,
        prompt: str,
        answer_content: str,
        answer_mode: str,
        workspace_workflow: str,
        workspace_generation_mode: str,
        client_name: str,
        primary_sources: list[str],
        missing_context: list[str],
        search_result: DataCenterSearchResultRecord | None,
        answer_material_summary: dict[str, object],
    ) -> None:
        if answer_mode == "system_failure":
            return

        def run_enrichment() -> None:
            followup_mode = "failed"
            try:
                if workspace_workflow == "file_search":
                    scenario = classify_workspace_followup_scenario(
                        prompt=prompt,
                        answer_content=answer_content,
                        workspace_workflow=workspace_workflow,
                        primary_sources=primary_sources,
                        missing_context=missing_context,
                    )
                    raw_candidates = (
                        [str(item) for item in (search_result.suggestedFollowups or []) if str(item).strip()]
                        if search_result is not None
                        else []
                    )
                    followup_mode = "file_search" if raw_candidates else "fallback"
                    followup_result = build_workspace_followup_result_from_candidates(
                        raw_candidates,
                        scenario=scenario,
                        generation_mode=followup_mode,
                        client_name=client_name,
                        workspace_workflow=workspace_workflow,
                    )
                else:
                    followup_result = build_workspace_followup_questions(
                        prompt=prompt,
                        answer_content=answer_content,
                        workspace_workflow=workspace_workflow,
                        client_name=client_name,
                        primary_sources=primary_sources,
                        missing_context=missing_context,
                        search_result=search_result,
                        raise_on_generation_error=True,
                    )
                    followup_mode = followup_result.generation_mode
                _merge_assistant_retrieval_summary(
                    assistant_id,
                    {
                        "suggestedFollowups": followup_result.questions,
                        "followupScenario": followup_result.scenario,
                        "followupGenerationMode": followup_result.generation_mode,
                        "followupRejectedCount": followup_result.rejected_count,
                    },
                )
            except Exception as exc:
                logger.warning("[workspace-chat] followup enrichment failed", exc_info=True)
                _merge_assistant_retrieval_summary(
                    assistant_id,
                    {
                        "followupGenerationMode": followup_mode,
                    },
                )
                _append_post_finalize_warning(assistant_id, stage="followup_enrichment", error=exc)

            try:
                _, thread_memory_update_mode = update_thread_context_after_answer(
                    state.db,
                    ai_service=state.ai,
                    client_id=client_id,
                    thread_id=thread_id,
                    prompt=prompt,
                    answer_content=answer_content,
                    retrieval_summary={
                        "workspaceWorkflow": workspace_workflow,
                        "generationMode": workspace_generation_mode,
                        "primarySources": primary_sources,
                        "answerMaterialSummary": answer_material_summary,
                    },
                    answer_mode=answer_mode,
                    timestamp=now_iso(),
                    allow_model=workspace_workflow != "file_search",
                )
                _merge_assistant_retrieval_summary(
                    assistant_id,
                    {
                        "threadMemoryUpdateMode": thread_memory_update_mode,
                    },
                )
            except Exception as exc:
                logger.warning("[workspace-chat] thread memory enrichment failed", exc_info=True)
                _merge_assistant_retrieval_summary(
                    assistant_id,
                    {
                        "threadMemoryUpdateMode": "failed",
                    },
                )
                _append_post_finalize_warning(assistant_id, stage="thread_memory_enrichment", error=exc)

        executor = state.topic_insight_executor or state.chat_answer_executor
        if executor is not None:
            try:
                executor.submit(run_enrichment)
                return
            except Exception as exc:
                logger.warning("[workspace-chat] failed to submit post-answer enrichment", exc_info=True)
                _append_post_finalize_warning(assistant_id, stage="post_answer_enrichment_submit", error=exc)
        try:
            Thread(target=run_enrichment, name="workspace-answer-enrichment", daemon=True).start()
        except Exception as exc:
            logger.warning("[workspace-chat] failed to start post-answer enrichment thread", exc_info=True)
            _append_post_finalize_warning(assistant_id, stage="post_answer_enrichment_thread", error=exc)

    def background_resolve_chat_answer(
        client_id: str,
        thread_id: str,
        prompt: str,
        assistant_id: str,
        search_id: str | None,
        request_started: float,
        run_id: str | None = None,
        working_document_ids: list[str] | None = None,
    ) -> None:
        try:
            resolve_chat_answer(client_id, thread_id, prompt, assistant_id, search_id, request_started, run_id, working_document_ids)
        except Exception as error:
            if is_client_analysis_run_canceled(run_id):
                return
            logger.exception("[workspace-chat] background_resolve_chat_answer failed for assistant %s", assistant_id)
            user_safe_reason = sanitize_chat_failure_reason(error)
            raw_error_text = str(error)
            timestamp = now_iso()
            current_row = state.db.fetchone("SELECT * FROM chat_messages WHERE id = ?", (assistant_id,))
            existing_summary = from_json(str(current_row["retrieval_summary_json"] or "{}"), {}) if current_row else {}
            if not isinstance(existing_summary, dict):
                existing_summary = {}
            if _assistant_message_has_final_answer(current_row):
                existing_summary.update(
                    {
                        "postFinalizeError": raw_error_text,
                        "postFinalizeErrorAt": timestamp,
                        "postFinalizeFailureStage": "background_resolve_chat_answer",
                        "asyncPath": True,
                        "phase": existing_summary.get("phase") or "completed",
                        "stageLabel": "回答已生成；收尾诊断有警告",
                        "lastUpdatedAt": timestamp,
                    }
                )
                warnings = existing_summary.get("postFinalizeWarnings")
                if not isinstance(warnings, list):
                    warnings = []
                warnings.append(
                    {
                        "stage": "background_resolve_chat_answer",
                        "error": raw_error_text,
                        "at": timestamp,
                    }
                )
                existing_summary["postFinalizeWarnings"] = warnings[-8:]
                existing_summary["postFinalizeWarningCount"] = len(warnings[-8:])
                state.db.execute(
                    """
                    UPDATE chat_messages
                    SET retrieval_summary_json = ?,
                        status = 'success',
                        created_at = COALESCE(created_at, ?)
                    WHERE id = ?
                    """,
                    (to_json(existing_summary), timestamp, assistant_id),
                )
                if run_id:
                    update_client_analysis_run(
                        run_id,
                        status="completed",
                        phase="completed",
                        progress=100.0,
                        progress_floor=100.0,
                        progress_ceiling=100.0,
                        stage_label="回答已生成；收尾诊断有警告",
                        failure_reason=f"post_finalize_warning: {user_safe_reason}",
                        elapsed_ms=round((perf_counter() - request_started) * 1000, 2),
                        timing={"totalMs": round((perf_counter() - request_started) * 1000, 2), "retrievalMs": 0.0, "llmMs": 0.0},
                    )
                return
            existing_summary.update(
                {
                    "phase": "failed",
                    "progress": 100.0,
                    "progressFloor": 100.0,
                    "progressCeiling": 100.0,
                    "stageLabel": "回答生成失败",
                    "failureReason": user_safe_reason,
                    "lastUpdatedAt": timestamp,
                }
            )
            failure_finalization = finalize_workspace_answer(
                content="庆华暂时没能完成这次回答。",
                answer_mode="system_failure",
                failure_reason=user_safe_reason,
                fallback_presentation_mode="compact_user_answer",
                kernel_result=None,
                answer_quality={"grade": "fail"},
                selected_evidence_count=0,
                llm_error=user_safe_reason,
            )
            existing_summary["workspaceAnswerFinalization"] = failure_finalization.model_dump(mode="json")
            existing_summary["answerPresentation"] = build_workspace_answer_presentation(
                content=failure_finalization.content,
                answer_material=None,
            )
            existing_summary["workspaceAnswerExperience"] = build_workspace_answer_experience_payload(
                content=failure_finalization.content,
                finalization=failure_finalization,
                answer_material=None,
                answer_quality={"grade": "fail"},
                proposal_drafts=[],
                action_suggestions=[],
                answer_presentation=existing_summary.get("answerPresentation") if isinstance(existing_summary.get("answerPresentation"), dict) else None,
                answer_intent=None,
            )
            existing_summary["generationFailureDetail"] = raw_error_text
            state.db.execute(
                """
                UPDATE chat_messages
                SET content = ?, structured_data_json = ?, model_route = ?, llm_invoked = 0, provider_used = NULL,
                    answer_mode = 'system_failure', evidence_status = 'none', failure_reason = ?, timing_json = ?,
                    retrieval_summary_json = ?, evidence_json = '[]', status = 'success', created_at = ?
                WHERE id = ?
                """,
                (
                    failure_finalization.content,
                    to_json(
                        AiStructuredResponse(
                            content=failure_finalization.content,
                            judgment="模型调用失败，本次回答未成功生成。",
                            analysis="本次回答未能成功生成，请稍后重试。如果持续失败，请联系开发同学查看后端日志。",
                            actions="建议稍后重试；如果持续失败，请检查本地后端与 AI 配置。",
                            timeline="恢复后可立即重新生成。",
                        ).model_dump()
                    ),
                    "AI 调用失败",
                    user_safe_reason,
                    to_json({"totalMs": round((perf_counter() - request_started) * 1000, 2), "retrievalMs": 0.0, "llmMs": 0.0}),
                    to_json(existing_summary),
                    timestamp,
                    assistant_id,
                ),
            )
            if run_id:
                update_client_analysis_run(
                    run_id,
                    status="failed",
                    phase="failed",
                    progress=100.0,
                    progress_floor=100.0,
                    progress_ceiling=100.0,
                    stage_label="回答生成失败",
                    failure_reason=user_safe_reason,
                    long_answer_status="failed",
                    summary_status="failed",
                    elapsed_ms=round((perf_counter() - request_started) * 1000, 2),
                    timing={"totalMs": round((perf_counter() - request_started) * 1000, 2), "retrievalMs": 0.0, "llmMs": 0.0},
                )

    @app.get("/api/v1/clients/{client_id}/page-context", response_model=PageContextPackRecord)
    def get_client_page_context(
        client_id: str,
        page: Literal[
            "client_workspace",
            "workspace_chat",
            "task_detail",
            "task_ai",
            "meeting_detail",
            "event_line_detail",
            "project_module_detail",
            "project_flow_detail",
            "strategic_cockpit",
        ] = Query(default="client_workspace"),
        prompt: str = Query(default=""),
        includeRawEvidence: bool = Query(default=False),
        scopeId: str | None = Query(default=None),
        taskId: str | None = Query(default=None),
        meetingId: str | None = Query(default=None),
        eventLineId: str | None = Query(default=None),
        projectModuleId: str | None = Query(default=None),
        projectFlowId: str | None = Query(default=None),
    ) -> PageContextPackRecord:
        intent = infer_page_intent(prompt, page)
        include_raw = bool(includeRawEvidence or intent.requiresRawEvidence)
        if page in {"task_detail", "task_ai"}:
            task_id = str(taskId or scopeId or "").strip()
            if not task_id:
                raise HTTPException(status_code=400, detail="taskId is required for task page context")
            return build_task_page_context_pack(
                state.db,
                data_dir=state.data_dir,
                task_id=task_id,
                prompt=prompt,
                page=page,
                intent=intent,
                include_raw_evidence=include_raw,
            )
        if page == "meeting_detail":
            meeting_id = str(meetingId or scopeId or "").strip()
            if not meeting_id:
                raise HTTPException(status_code=400, detail="meetingId is required for meeting page context")
            meeting_row = state.db.fetchone("SELECT client_id FROM meetings WHERE id = ?", (meeting_id,))
            if meeting_row and str(meeting_row["client_id"] or "").strip() not in {"", client_id}:
                raise HTTPException(status_code=404, detail="Meeting not found in current client scope")
            return build_meeting_page_context_pack(
                state.db,
                data_dir=state.data_dir,
                meeting_id=meeting_id,
                prompt=prompt,
                include_raw_evidence=include_raw,
            )
        if page == "event_line_detail":
            event_line_id = str(eventLineId or scopeId or "").strip()
            if not event_line_id:
                raise HTTPException(status_code=400, detail="eventLineId is required for event line page context")
            return build_event_line_page_context_pack(
                state.db,
                data_dir=state.data_dir,
                event_line_id=event_line_id,
                prompt=prompt,
                page=page,
                intent=intent,
                include_raw_evidence=include_raw,
            )
        if page == "project_module_detail":
            module_id = str(projectModuleId or scopeId or "").strip()
            if not module_id:
                raise HTTPException(status_code=400, detail="projectModuleId is required for module page context")
            return build_project_module_page_context_pack(
                state.db,
                data_dir=state.data_dir,
                module_id=module_id,
                prompt=prompt,
                page=page,
                intent=intent,
                include_raw_evidence=include_raw,
            )
        if page == "project_flow_detail":
            flow_id = str(projectFlowId or scopeId or "").strip()
            if not flow_id:
                raise HTTPException(status_code=400, detail="projectFlowId is required for flow page context")
            return build_project_flow_page_context_pack(
                state.db,
                data_dir=state.data_dir,
                flow_id=flow_id,
                prompt=prompt,
                page=page,
                intent=intent,
                include_raw_evidence=include_raw,
            )

        workspace_snapshot = workspace_for_client(client_id)
        return build_client_page_context_pack(
            state.db,
            data_dir=state.data_dir,
            client_id=client_id,
            prompt=prompt,
            page=page,
            intent=intent,
            include_raw_evidence=include_raw,
            workspace=workspace_snapshot,
        )

