    @app.post("/api/v1/tasks/refresh-contexts", response_model=TaskContextRefreshResultRecord)
    def refresh_task_contexts() -> TaskContextRefreshResultRecord:
        if get_cloud_token():
            _pull_cloud_tasks_to_local()
        task_records = fetch_tasks(shared_task_where())
        clients = [build_client_summary(str(row["id"])) for row in state.db.fetchall("SELECT id FROM clients ORDER BY updated_at DESC")]
        event_lines = list_event_lines()
        project_structures: dict[str, ProjectStructureResponse] = {}
        updated_tasks = 0
        unchanged_tasks = 0
        failed_tasks = 0
        client_updated_tasks = 0
        event_line_updated_tasks = 0
        module_updated_tasks = 0
        flow_updated_tasks = 0
        for task in task_records:
            payload = _build_task_scope_refresh_payload(task, clients, event_lines, project_structures)
            if not payload:
                unchanged_tasks += 1
                continue
            try:
                update_task(task.id, TaskUpdatePayload(**payload))
                updated_tasks += 1
                if "clientId" in payload:
                    client_updated_tasks += 1
                if "eventLineId" in payload:
                    event_line_updated_tasks += 1
                if "projectModuleId" in payload:
                    module_updated_tasks += 1
                if "projectFlowId" in payload:
                    flow_updated_tasks += 1
            except Exception:
                failed_tasks += 1
        unchanged_tasks = max(0, len(task_records) - updated_tasks - failed_tasks)
        backfill_memory_foundation(state.db)
        return TaskContextRefreshResultRecord(
            totalTasks=len(task_records),
            updatedTasks=updated_tasks,
            unchangedTasks=unchanged_tasks,
            failedTasks=failed_tasks,
            clientUpdatedTasks=client_updated_tasks,
            eventLineUpdatedTasks=event_line_updated_tasks,
            moduleUpdatedTasks=module_updated_tasks,
            flowUpdatedTasks=flow_updated_tasks,
            updatedAt=now_iso(),
        )

    @app.post("/api/v1/tasks/bootstrap-event-lines", response_model=TaskEventLineBootstrapResultRecord)
    def bootstrap_task_event_lines() -> TaskEventLineBootstrapResultRecord:
        if get_cloud_token():
            _pull_cloud_tasks_to_local()
        task_records = fetch_tasks(shared_task_where())
        existing_event_lines = list_event_lines()
        event_line_by_signature = {
            f"{(item.primaryClientId or '').strip()}::{item.name.strip()}": item
            for item in existing_event_lines
            if item.name.strip()
        }
        created_event_lines = 0
        linked_tasks = 0
        skipped_tasks = 0
        failed_tasks = 0

        for task in task_records:
            if not _task_eligible_for_event_line_bootstrap(task):
                skipped_tasks += 1
                continue
            payload = _build_bootstrap_event_line_payload(task)
            signature = f"{(payload.primaryClientId or '').strip()}::{payload.name.strip()}"
            event_line = event_line_by_signature.get(signature)
            if event_line is None:
                try:
                    event_line = create_event_line(payload)
                    event_line_by_signature[signature] = event_line
                    created_event_lines += 1
                except Exception:
                    failed_tasks += 1
                    continue
            try:
                update_task(task.id, TaskUpdatePayload(eventLineId=event_line.id))
                linked_tasks += 1
            except Exception:
                failed_tasks += 1

        backfill_memory_foundation(state.db)
        return TaskEventLineBootstrapResultRecord(
            totalTasks=len(task_records),
            createdEventLines=created_event_lines,
            linkedTasks=linked_tasks,
            skippedTasks=skipped_tasks,
            failedTasks=failed_tasks,
            updatedAt=now_iso(),
        )

    @app.post("/api/v1/tasks", response_model=TaskRecord)
    def create_manual_task(payload: TaskPayload) -> TaskRecord:
        return create_task(payload)

    @app.patch("/api/v1/tasks/{task_id}", response_model=TaskRecord)
    def update_task(task_id: str, payload: TaskUpdatePayload) -> TaskRecord:
        existing_scope_row = state.db.fetchone(
            """
            SELECT client_id, event_line_id, project_module_id, project_flow_id
            FROM tasks
            WHERE id = ? OR cloud_id = ?
            ORDER BY updated_at DESC
            LIMIT 1
            """,
            (task_id, task_id),
        )
        if not get_cloud_token():
            row = state.db.fetchone("SELECT * FROM tasks WHERE id = ?", (task_id,))
            if not row:
                raise HTTPException(status_code=404, detail="Task not found")
            if payload.listId:
                list_row = state.db.fetchone("SELECT * FROM task_lists WHERE id = ?", (payload.listId,))
                if not list_row or list_row["archived_at"]:
                    raise HTTPException(status_code=400, detail="任务清单无效")
            resolved_tags = normalize_local_task_tags(
                payload.tagIds if payload.tagIds is not None else _parse_json_list(row["tag_ids_json"]),
                payload.tags if payload.tags is not None else None,
            )
            next_client_id = payload.clientId if "clientId" in payload.model_fields_set else (str(row["client_id"]) if row["client_id"] else None)
            next_event_line_id = payload.eventLineId if "eventLineId" in payload.model_fields_set else (str(row["event_line_id"]) if row["event_line_id"] else None)
            next_scope_mode = payload.scopeMode if payload.scopeMode is not None else str(row["scope_mode"] or "COLLAB_SHARED")
            if next_scope_mode == "PERSONAL_ONLY":
                next_client_id = None
                next_event_line_id = None
            client_id, event_line_id = _normalize_task_client_and_event_line_refs(
                next_client_id,
                next_event_line_id,
            )
            project_module_id = None if next_scope_mode == "PERSONAL_ONLY" else (payload.projectModuleId if "projectModuleId" in payload.model_fields_set else (str(row["project_module_id"]) if row["project_module_id"] else None))
            project_flow_id = None if next_scope_mode == "PERSONAL_ONLY" else (payload.projectFlowId if "projectFlowId" in payload.model_fields_set else (str(row["project_flow_id"]) if row["project_flow_id"] else None))
            project_module, project_flow = resolve_project_structure_refs(client_id, project_module_id, project_flow_id)
            project_context = build_task_project_context(
                client_id,
                str(row["source_type"]),
                str(row["source_id"]) if row["source_id"] else None,
                task_title=payload.title or str(row["title"]),
                task_desc=payload.desc if payload.desc is not None else str(row["description"]),
                project_module_id=project_module.id if project_module else None,
                project_flow_id=project_flow.id if project_flow else None,
            )
            event_line_context = _event_line_snapshot_context(state.db, event_line_id, None)
            attachment_count = int(state.db.scalar("SELECT COUNT(1) FROM task_attachments WHERE task_id = ?", (task_id,)) or 0)
            (
                business_category,
                current_blocker,
                next_action,
                recent_decision,
                evidence_count,
            ) = _resolve_task_action_os_fields(
                title=payload.title or str(row["title"]),
                desc=payload.desc if payload.desc is not None else str(row["description"]),
                source_type=str(row["source_type"]),
                business_category=payload.businessCategory if "businessCategory" in payload.model_fields_set else (str(row["business_category"]) if row["business_category"] else None),
                current_blocker=payload.currentBlocker if "currentBlocker" in payload.model_fields_set else (str(row["current_blocker"]) if row["current_blocker"] else None),
                next_action=payload.nextAction if "nextAction" in payload.model_fields_set else (str(row["next_action"]) if row["next_action"] else None),
                recent_decision=payload.recentDecision if "recentDecision" in payload.model_fields_set else (str(row["recent_decision"]) if row["recent_decision"] else None),
                evidence_count=payload.evidenceCount if "evidenceCount" in payload.model_fields_set else int(row["evidence_count"] or 0),
                project_context=project_context,
                event_line_context=event_line_context,
                attachment_count=attachment_count,
            )
            update_timestamp = now_iso()
            next_status = payload.status or row["status"]
            temporal_fields = derive_task_temporal_fields(
                start_date=payload.startDate if "startDate" in payload.model_fields_set else (str(row["start_date"]) if row["start_date"] else None),
                due_date=(
                    payload.dueDate
                    if "dueDate" in payload.model_fields_set
                    else normalize_due_date_input(payload.ddl)
                    if "ddl" in payload.model_fields_set
                    else (str(row["due_date"]) if row["due_date"] else None)
                ),
                duration_minutes=payload.durationMinutes if payload.durationMinutes is not None else int(row["duration_minutes"] or 60),
                deadline_at=payload.deadlineAt if "deadlineAt" in payload.model_fields_set else (str(row["deadline_at"]) if row["deadline_at"] else None),
                scheduled_start_at=payload.scheduledStartAt if "scheduledStartAt" in payload.model_fields_set else (str(row["scheduled_start_at"]) if row["scheduled_start_at"] else None),
                scheduled_end_at=payload.scheduledEndAt if "scheduledEndAt" in payload.model_fields_set else (str(row["scheduled_end_at"]) if row["scheduled_end_at"] else None),
                completed_at=payload.completedAt if "completedAt" in payload.model_fields_set else (str(row["completed_at"]) if row["completed_at"] else None),
                previous_completed_at=str(row["completed_at"]) if row["completed_at"] else None,
                status=str(next_status),
                timestamp=update_timestamp,
            )
            temporal_due_date = str(temporal_fields["due_date"]) if temporal_fields["due_date"] else None
            if "ddl" in payload.model_fields_set:
                next_ddl = payload.ddl or "待确认"
            elif any(field in payload.model_fields_set for field in ("dueDate", "startDate", "deadlineAt", "scheduledStartAt", "scheduledEndAt")):
                next_ddl = task_due_label(temporal_due_date) if temporal_due_date else "待确认"
            else:
                next_ddl = row["ddl"]
            merged = {
                "title": payload.title or row["title"],
                "description": payload.desc if payload.desc is not None else row["description"],
                "status": next_status,
                "priority": payload.priority or row["priority"],
                "list_id": payload.listId or row["list_id"],
                "scope_mode": next_scope_mode,
                "client_id": client_id,
                "event_line_id": event_line_id,
                "project_module_id": project_module.id if project_module else None,
                "project_flow_id": project_flow.id if project_flow else None,
                "ddl": next_ddl,
                "deadline_at": temporal_fields["deadline_at"],
                "scheduled_start_at": temporal_fields["scheduled_start_at"],
                "scheduled_end_at": temporal_fields["scheduled_end_at"],
                "completed_at": temporal_fields["completed_at"],
                "start_date": temporal_fields["start_date"],
                "due_date": temporal_due_date,
                "duration_minutes": temporal_fields["duration_minutes"],
                "owner_name": payload.ownerName or row["owner_name"],
                "business_category": business_category,
                "current_blocker": current_blocker,
                "next_action": next_action,
                "recent_decision": recent_decision,
                "evidence_count": evidence_count,
                "tags_json": to_json([tag.name for tag in resolved_tags]),
                "tag_ids_json": to_json([tag.id for tag in resolved_tags]),
                "updated_at": update_timestamp,
            }
            state.db.execute(
                """
                UPDATE tasks
                SET title = ?, description = ?, status = ?, priority = ?, list_id = ?, scope_mode = ?, client_id = ?, event_line_id = ?, project_module_id = ?, project_flow_id = ?, ddl = ?, deadline_at = ?, scheduled_start_at = ?, scheduled_end_at = ?, completed_at = ?, start_date = ?, due_date = ?, duration_minutes = ?, owner_name = ?, business_category = ?, current_blocker = ?, next_action = ?, recent_decision = ?, evidence_count = ?, tags_json = ?, tag_ids_json = ?, updated_at = ?
                WHERE id = ?
                """,
                (
                    merged["title"],
                    merged["description"],
                    merged["status"],
                    merged["priority"],
                    merged["list_id"],
                    merged["scope_mode"],
                    merged["client_id"],
                    merged["event_line_id"],
                    merged["project_module_id"],
                    merged["project_flow_id"],
                    merged["ddl"],
                    merged["deadline_at"],
                    merged["scheduled_start_at"],
                    merged["scheduled_end_at"],
                    merged["completed_at"],
                    merged["start_date"],
                    merged["due_date"],
                    merged["duration_minutes"],
                    merged["owner_name"],
                    merged["business_category"],
                    merged["current_blocker"],
                    merged["next_action"],
                    merged["recent_decision"],
                    merged["evidence_count"],
                    merged["tags_json"],
                    merged["tag_ids_json"],
                    merged["updated_at"],
                    task_id,
                ),
            )
            _sync_task_attachment_scope(
                state.db,
                state.data_dir,
                build_task_attachment,
                build_attachment_event_line_activity,
                ensure_standard_client_folders,
                task_id,
                client_id,
                event_line_id,
                cloud=False,
            )
            if merged["event_line_id"]:
                old_status = str(row["status"])
                new_status = merged["status"]
                status_changed = old_status != new_status
                if status_changed:
                    status_labels = {
                        "done": ("任务完成", f"任务已完成：{merged['title']}"),
                        "doing": ("任务开始执行", f"任务进入执行中：{merged['title']}"),
                        "todo": ("任务已排入计划", f"任务进入待办：{merged['title']}"),
                        "rejected": ("任务已退回", f"任务被退回：{merged['title']}"),
                        "inbox": ("任务退回收件箱", f"任务退回收件箱：{merged['title']}"),
                    }
                    ela_title, ela_summary = status_labels.get(
                        new_status,
                        ("任务状态变更", f"任务状态变更为 {new_status}：{merged['title']}"),
                    )
                    state.db.execute(
                        """
                        INSERT INTO event_line_activities(
                            id, event_line_id, source_type, source_id, happened_at, actor_id, actor_name, title, summary, metadata_json, is_key
                        ) VALUES(?, ?, 'task_activity', ?, ?, NULL, ?, ?, ?, ?, 0)
                        """,
                        (
                            new_id("ela"),
                            merged["event_line_id"],
                            task_id,
                            merged["updated_at"],
                            merged["owner_name"],
                            ela_title,
                            ela_summary,
                            to_json({"eventType": "status_change", "from": old_status, "to": new_status}),
                        ),
                    )
                else:
                    # Detect meaningful field changes and only record those with informational value
                    change_parts: list[str] = []
                    change_meta: dict[str, object] = {"eventType": "updated", "changes": []}
                    old_owner = str(row["owner_name"] or "")
                    new_owner = str(merged["owner_name"] or "")
                    if old_owner != new_owner and new_owner:
                        change_parts.append(f"负责人变更：{old_owner or '未指定'} → {new_owner}")
                        change_meta["changes"].append("owner")  # type: ignore[union-attr]
                    old_due = str(row["due_date"] or "")
                    new_due = str(merged["due_date"] or "")
                    if old_due != new_due:
                        change_parts.append(f"截止日期变更：{old_due or '未设定'} → {new_due or '已取消'}")
                        change_meta["changes"].append("due_date")  # type: ignore[union-attr]
                    old_title = str(row["title"] or "")
                    new_title = str(merged["title"] or "")
                    if old_title != new_title:
                        change_parts.append(f"标题变更：{old_title} → {new_title}")
                        change_meta["changes"].append("title")  # type: ignore[union-attr]
                    # Only write activity if there are meaningful changes
                    if change_parts:
                        ela_title = "、".join(c.split("：")[0] for c in change_parts)
                        ela_summary = "；".join(change_parts)
                        is_key = 1 if "owner" in change_meta.get("changes", []) or "due_date" in change_meta.get("changes", []) else 0  # type: ignore[operator]
                        state.db.execute(
                            """
                            INSERT INTO event_line_activities(
                                id, event_line_id, source_type, source_id, happened_at, actor_id, actor_name, title, summary, metadata_json, is_key
                            ) VALUES(?, ?, 'task_activity', ?, ?, NULL, ?, ?, ?, ?, ?)
                            """,
                            (
                                new_id("ela"),
                                merged["event_line_id"],
                                task_id,
                                merged["updated_at"],
                                merged["owner_name"],
                                ela_title,
                                ela_summary,
                                to_json(change_meta),
                                is_key,
                            ),
                        )
            log_activity("task.update", "task", task_id, payload.model_dump(exclude_none=True))
            updated_task = fetch_tasks("t.id = ?", (task_id,))[0]
            growth_user_id, growth_user_name = resolve_growth_actor()
            ingest_task_growth_candidate(
                state.db,
                user_id=growth_user_id,
                user_name=growth_user_name,
                task=updated_task,
                source_type="task_context_candidate",
                created_at=str(merged["updated_at"]),
                ai_service=state.ai,
            )
            old_client_id = str(row["client_id"] or "").strip() or None
            old_event_line_id = str(row["event_line_id"] or "").strip() or None
            old_project_module_id = str(row["project_module_id"] or "").strip() or None
            old_project_flow_id = str(row["project_flow_id"] or "").strip() or None
            new_client_id = str(updated_task.clientId or "").strip() or None
            new_event_line_id = str(updated_task.eventLineId or "").strip() or None
            new_project_module_id = str(updated_task.projectModuleId or "").strip() or None
            new_project_flow_id = str(updated_task.projectFlowId or "").strip() or None
            scope_changed = (
                old_client_id != new_client_id
                or old_event_line_id != new_event_line_id
                or old_project_module_id != new_project_module_id
                or old_project_flow_id != new_project_flow_id
            )
            _enqueue_workspace_refresh_safe(
                client_id=new_client_id,
                source_type="task_update",
                source_id=updated_task.id,
                reason="task_scope_changed" if scope_changed else "task_updated",
                scope_type="task",
                scope_id=updated_task.id,
                priority="normal",
            )
            if old_client_id and old_client_id != new_client_id:
                _enqueue_workspace_refresh_safe(
                    client_id=old_client_id,
                    source_type="task_update_scope_release",
                    source_id=updated_task.id,
                    reason="task_scope_changed",
                    scope_type="task",
                    scope_id=updated_task.id,
                    priority="normal",
                )
            if scope_changed:
                _safe_data_center_ingest(
                    "task_scope_release",
                    lambda: mark_ingested_source_inactive(
                        state.db,
                        source_type="task",
                        source_id=updated_task.id,
                        task_id=updated_task.id,
                        lifecycle_status="scope_released",
                    ),
                )
            _safe_data_center_ingest(
                "task",
                lambda: ingest_task_by_id(state.db, state.data_dir, updated_task.id),
            )
            return updated_task
        # Cloud path: try cloud sync, but don't block on failure
        cloud_status_map = {"todo": "todo", "doing": "doing", "done": "done", "inbox": "inbox", "rejected": "rejected"}
        payload_fields = payload.model_fields_set
        cloud_update_payload: dict[str, object | None] = {}
        cloud_field_map = {
            "title": "title",
            "desc": "description",
            "priority": "priority",
            "listId": "listId",
            "startDate": "startDate",
            "deadlineAt": "deadlineAt",
            "scheduledStartAt": "scheduledStartAt",
            "scheduledEndAt": "scheduledEndAt",
            "completedAt": "completedAt",
            "durationMinutes": "durationMinutes",
            "scopeMode": "scopeMode",
            "clientId": "clientId",
            "eventLineId": "eventLineId",
            "projectModuleId": "projectModuleId",
            "projectFlowId": "projectFlowId",
            "collaboratorIds": "collaboratorIds",
            "ownerId": "ownerId",
            "businessCategory": "businessCategory",
            "currentBlocker": "currentBlocker",
            "nextAction": "nextAction",
            "recentDecision": "recentDecision",
            "evidenceCount": "evidenceCount",
        }
        for local_field, cloud_field in cloud_field_map.items():
            if local_field in payload_fields:
                cloud_update_payload[cloud_field] = getattr(payload, local_field)
        if "dueDate" in payload_fields:
            cloud_update_payload["dueDate"] = payload.dueDate
        elif "ddl" in payload_fields:
            cloud_update_payload["dueDate"] = normalize_due_date_input(payload.ddl)
        if "status" in payload_fields and payload.status:
            cloud_update_payload["progressStatus"] = cloud_status_map.get(payload.status)
            if payload.status == "done" and "completedAt" not in payload_fields:
                cloud_update_payload["completedAt"] = now_iso()
            elif payload.status != "done" and "completedAt" not in payload_fields:
                cloud_update_payload["completedAt"] = None
        local_row_for_cloud = state.db.fetchone(
            """
            SELECT id, cloud_id
            FROM tasks
            WHERE id = ? OR cloud_id = ?
            ORDER BY updated_at DESC
            LIMIT 1
            """,
            (task_id, task_id),
        )
        local_task_id = str(local_row_for_cloud["id"]) if local_row_for_cloud and local_row_for_cloud["id"] else task_id
        cloud_task_id = (
            str(local_row_for_cloud["cloud_id"])
            if local_row_for_cloud and local_row_for_cloud["cloud_id"]
            else task_id
        )
        try:
            if not _resolve_task_cloud_event_line_dependency(local_task_id, cloud_update_payload):
                raise HTTPException(status_code=409, detail="等待事件线先同步到云端")
            response = cloud_request("PATCH", f"/api/v1/tasks/{cloud_task_id}", json_body=cloud_update_payload)
            if not isinstance(response, dict):
                raise HTTPException(status_code=502, detail="Invalid cloud task payload")
            synced_cloud_id = str(response.get("id") or cloud_task_id)
            synced_at = now_iso()
            state.db.execute(
                """
                UPDATE tasks
                SET sync_status = 'synced',
                    cloud_id = ?,
                    cloud_payload_json = NULL,
                    last_synced_at = ?,
                    last_cloud_version = ?,
                    pending_sync_action = '',
                    last_sync_error = ''
                WHERE id = ? OR cloud_id = ?
                """,
                (synced_cloud_id, synced_at, str(response.get("updatedAt") or response.get("createdAt") or ""), local_task_id, synced_cloud_id),
            )
            log_activity("task.update", "task", task_id, payload.model_dump(exclude_none=True))
            upserted_task_id = _upsert_cloud_task_shadow_local(response)
            if upserted_task_id:
                updated_task = fetch_tasks("t.id = ?", (upserted_task_id,))[0]
            else:
                updated_task = build_cloud_task(response, {})
        except Exception as error:
            # Cloud failed — if task exists locally, update local copy and return that
            local_row = state.db.fetchone("SELECT * FROM tasks WHERE id = ? OR cloud_id = ?", (task_id, task_id))
            if local_row:
                local_id = str(local_row["id"])
                fallback_due_date_was_set = "dueDate" in payload_fields or "ddl" in payload_fields
                fallback_due_date = (
                    payload.dueDate
                    if "dueDate" in payload_fields
                    else normalize_due_date_input(payload.ddl)
                    if "ddl" in payload_fields
                    else None
                )
                if "ddl" in payload_fields:
                    fallback_ddl = payload.ddl or "待确认"
                elif fallback_due_date_was_set:
                    fallback_ddl = task_due_label(fallback_due_date) if fallback_due_date else "待确认"
                else:
                    fallback_ddl = None
                fallback_progress_status = cloud_status_map.get(payload.status) if payload.status else None
                fallback_status = payload.status if payload.status else str(local_row["status"] or "todo")
                fallback_temporal_fields = derive_task_temporal_fields(
                    start_date=payload.startDate if "startDate" in payload_fields else (str(local_row["start_date"]) if local_row["start_date"] else None),
                    due_date=(
                        fallback_due_date
                        if fallback_due_date_was_set
                        else (str(local_row["due_date"]) if local_row["due_date"] else None)
                    ),
                    duration_minutes=payload.durationMinutes if payload.durationMinutes is not None else int(local_row["duration_minutes"] or 60),
                    deadline_at=payload.deadlineAt if "deadlineAt" in payload_fields else (str(local_row["deadline_at"]) if local_row["deadline_at"] else None),
                    scheduled_start_at=payload.scheduledStartAt if "scheduledStartAt" in payload_fields else (str(local_row["scheduled_start_at"]) if local_row["scheduled_start_at"] else None),
                    scheduled_end_at=payload.scheduledEndAt if "scheduledEndAt" in payload_fields else (str(local_row["scheduled_end_at"]) if local_row["scheduled_end_at"] else None),
                    completed_at=payload.completedAt if "completedAt" in payload_fields else (str(local_row["completed_at"]) if local_row["completed_at"] else None),
                    previous_completed_at=str(local_row["completed_at"]) if local_row["completed_at"] else None,
                    status=str(fallback_status),
                    timestamp=now_iso(),
                )
                fallback_due_value = str(fallback_temporal_fields["due_date"]) if fallback_temporal_fields["due_date"] else None
                if fallback_due_date_was_set:
                    fallback_due_date = fallback_due_value
                sync_error_message = str(getattr(error, "detail", "") or str(error) or type(error).__name__)[:500]
                state.db.execute(
                    """
                    UPDATE tasks
                    SET title = CASE WHEN ? THEN ? ELSE title END,
                        description = CASE WHEN ? THEN ? ELSE description END,
                        status = CASE WHEN ? THEN ? ELSE status END,
                        progress_status = CASE WHEN ? THEN ? ELSE progress_status END,
                        priority = CASE WHEN ? THEN ? ELSE priority END,
                        list_id = CASE WHEN ? THEN ? ELSE list_id END,
                        deadline_at = CASE WHEN ? THEN ? ELSE deadline_at END,
                        scheduled_start_at = CASE WHEN ? THEN ? ELSE scheduled_start_at END,
                        scheduled_end_at = CASE WHEN ? THEN ? ELSE scheduled_end_at END,
                        completed_at = CASE WHEN ? THEN ? ELSE completed_at END,
                        start_date = CASE WHEN ? THEN ? ELSE start_date END,
                        due_date = CASE WHEN ? THEN ? ELSE due_date END,
                        ddl = CASE WHEN ? THEN ? ELSE ddl END,
                        duration_minutes = CASE WHEN ? THEN ? ELSE duration_minutes END,
                        scope_mode = CASE WHEN ? THEN ? ELSE scope_mode END,
                        client_id = CASE WHEN ? THEN ? ELSE client_id END,
                        event_line_id = CASE WHEN ? THEN ? ELSE event_line_id END,
                        project_module_id = CASE WHEN ? THEN ? ELSE project_module_id END,
                        project_flow_id = CASE WHEN ? THEN ? ELSE project_flow_id END,
                        owner_id = CASE WHEN ? THEN ? ELSE owner_id END,
                        business_category = CASE WHEN ? THEN ? ELSE business_category END,
                        current_blocker = CASE WHEN ? THEN ? ELSE current_blocker END,
                        next_action = CASE WHEN ? THEN ? ELSE next_action END,
                        recent_decision = CASE WHEN ? THEN ? ELSE recent_decision END,
                        evidence_count = CASE WHEN ? THEN ? ELSE evidence_count END,
                        sync_status = 'pending',
                        cloud_payload_json = ?,
                        pending_sync_action = 'update',
                        last_sync_error = ?,
                        updated_at = ?
                    WHERE id = ?
                    """,
                    (
                        1 if "title" in payload_fields else 0,
                        payload.title,
                        1 if "desc" in payload_fields else 0,
                        payload.desc,
                        1 if "status" in payload_fields and payload.status is not None else 0,
                        payload.status,
                        1 if fallback_progress_status else 0,
                        fallback_progress_status,
                        1 if "priority" in payload_fields else 0,
                        payload.priority,
                        1 if "listId" in payload_fields else 0,
                        payload.listId,
                        1 if "deadlineAt" in payload_fields or fallback_due_date_was_set else 0,
                        fallback_temporal_fields["deadline_at"],
                        1 if "scheduledStartAt" in payload_fields or fallback_due_date_was_set else 0,
                        fallback_temporal_fields["scheduled_start_at"],
                        1 if "scheduledEndAt" in payload_fields or fallback_due_date_was_set else 0,
                        fallback_temporal_fields["scheduled_end_at"],
                        1 if "completedAt" in payload_fields or ("status" in payload_fields and payload.status is not None) else 0,
                        fallback_temporal_fields["completed_at"],
                        1 if "startDate" in payload_fields or fallback_due_date_was_set else 0,
                        fallback_temporal_fields["start_date"],
                        1 if fallback_due_date_was_set else 0,
                        fallback_due_date,
                        1 if fallback_ddl is not None else 0,
                        fallback_ddl,
                        1 if "durationMinutes" in payload_fields else 0,
                        payload.durationMinutes,
                        1 if "scopeMode" in payload_fields else 0,
                        payload.scopeMode,
                        1 if "clientId" in payload_fields else 0,
                        payload.clientId,
                        1 if "eventLineId" in payload_fields else 0,
                        payload.eventLineId,
                        1 if "projectModuleId" in payload_fields else 0,
                        payload.projectModuleId,
                        1 if "projectFlowId" in payload_fields else 0,
                        payload.projectFlowId,
                        1 if "ownerId" in payload_fields else 0,
                        payload.ownerId,
                        1 if "businessCategory" in payload_fields else 0,
                        payload.businessCategory,
                        1 if "currentBlocker" in payload_fields else 0,
                        payload.currentBlocker,
                        1 if "nextAction" in payload_fields else 0,
                        payload.nextAction,
                        1 if "recentDecision" in payload_fields else 0,
                        payload.recentDecision,
                        1 if "evidenceCount" in payload_fields else 0,
                        payload.evidenceCount,
                        to_json(cloud_update_payload),
                        sync_error_message,
                        now_iso(),
                        local_id,
                    ),
                )
                log_activity("task.update", "task", local_id, payload.model_dump(exclude_none=True))
                updated_task = fetch_tasks("t.id = ?", (local_id,))[0]
            else:
                raise HTTPException(status_code=502, detail="云端更新失败，且本地无此任务副本")
        growth_user_id, growth_user_name = resolve_growth_actor()
        ingest_task_growth_candidate(
            state.db,
            user_id=growth_user_id,
            user_name=growth_user_name,
            task=updated_task,
            source_type="task_context_candidate",
            created_at=now_iso(),
            ai_service=state.ai,
        )
        old_client_id = str(existing_scope_row["client_id"] or "").strip() if existing_scope_row and existing_scope_row["client_id"] else ""
        old_event_line_id = str(existing_scope_row["event_line_id"] or "").strip() if existing_scope_row and existing_scope_row["event_line_id"] else ""
        old_project_module_id = (
            str(existing_scope_row["project_module_id"] or "").strip()
            if existing_scope_row and existing_scope_row["project_module_id"]
            else ""
        )
        old_project_flow_id = (
            str(existing_scope_row["project_flow_id"] or "").strip()
            if existing_scope_row and existing_scope_row["project_flow_id"]
            else ""
        )
        new_client_id = str(updated_task.clientId or "").strip() or old_client_id or None
        new_event_line_id = str(updated_task.eventLineId or "").strip()
        new_project_module_id = str(updated_task.projectModuleId or "").strip()
        new_project_flow_id = str(updated_task.projectFlowId or "").strip()
        scope_changed = (
            old_client_id != (new_client_id or "")
            or old_event_line_id != new_event_line_id
            or old_project_module_id != new_project_module_id
            or old_project_flow_id != new_project_flow_id
        )
        _enqueue_workspace_refresh_safe(
            client_id=new_client_id,
            source_type="task_update",
            source_id=updated_task.id,
            reason="task_scope_changed" if scope_changed else "task_updated",
            scope_type="task",
            scope_id=updated_task.id,
            priority="normal",
        )
        if old_client_id and old_client_id != (new_client_id or ""):
            _enqueue_workspace_refresh_safe(
                client_id=old_client_id,
                source_type="task_update_scope_release",
                source_id=updated_task.id,
                reason="task_scope_changed",
                scope_type="task",
                scope_id=updated_task.id,
                priority="normal",
            )
        if scope_changed:
            _safe_data_center_ingest(
                "task_scope_release",
                lambda: mark_ingested_source_inactive(
                    state.db,
                    source_type="task",
                    source_id=updated_task.id,
                    task_id=updated_task.id,
                    lifecycle_status="scope_released",
                ),
            )
        _safe_data_center_ingest(
            "task",
            lambda: ingest_task_by_id(state.db, state.data_dir, updated_task.id),
        )
        Thread(target=_precompute_task_understanding, args=(task_id,), daemon=True).start()
        _cloud_task_board_cache["data"] = None
        return updated_task

    @app.delete("/api/v1/tasks/{task_id}")
    def delete_task(task_id: str) -> dict[str, bool]:
        refresh_scope_row = state.db.fetchone(
            """
            SELECT client_id, event_line_id, project_module_id, project_flow_id
            FROM tasks
            WHERE id = ? OR cloud_id = ?
            ORDER BY updated_at DESC
            LIMIT 1
            """,
            (task_id, task_id),
        )
        refresh_client_id = (
            str(refresh_scope_row["client_id"] or "").strip()
            if refresh_scope_row and refresh_scope_row["client_id"]
            else None
        )
        if not get_cloud_token():
            row = state.db.fetchone("SELECT * FROM tasks WHERE id = ?", (task_id,))
            if not row:
                raise HTTPException(status_code=404, detail="Task not found")
            task_title = str(row["title"] or "任务")
            event_line_id = str(row["event_line_id"]) if row["event_line_id"] else None
            client_id = str(row["client_id"]) if row["client_id"] else None
            _safe_data_center_ingest(
                "task_delete_lifecycle",
                lambda: mark_ingested_source_inactive(
                    state.db,
                    source_type="task",
                    source_id=task_id,
                    task_id=task_id,
                    lifecycle_status="deleted",
                ),
            )
            state.db.execute("DELETE FROM activity_logs WHERE entity_type = 'task' AND entity_id = ?", (task_id,))
            state.db.execute("DELETE FROM event_line_activities WHERE source_type = 'task_activity' AND source_id = ?", (task_id,))
            state.db.execute("DELETE FROM memory_facts WHERE scope_type = 'task' AND scope_id = ?", (task_id,))
            state.db.execute(
                """
                DELETE FROM memory_facts
                WHERE source_type = 'task'
                  AND source_id = ?
                """,
                (task_id,),
            )
            state.db.execute("DELETE FROM growth_signal_events WHERE task_id = ?", (task_id,))
            state.db.execute("DELETE FROM growth_evidence_records WHERE task_id = ?", (task_id,))
            state.db.execute("DELETE FROM tasks WHERE id = ?", (task_id,))
            log_activity("task.delete", "task", task_id, {"title": task_title, "eventLineId": event_line_id, "clientId": client_id})
            if event_line_id:
                refresh_event_line_memory_snapshot(state.db, event_line_id)
            if client_id:
                refresh_organization_notebook_snapshot(state.db, client_id)
            _enqueue_workspace_refresh_safe(
                client_id=client_id or refresh_client_id,
                source_type="task_delete",
                source_id=task_id,
                reason="task_deleted",
                scope_type="task",
                scope_id=task_id,
                priority="normal",
            )
            return {"deleted": True}
        # Cloud mode: try cloud delete, also clean up local data
        delete_row = state.db.fetchone(
            """
            SELECT id, cloud_id
            FROM tasks
            WHERE id = ? OR cloud_id = ?
            ORDER BY updated_at DESC
            LIMIT 1
            """,
            (task_id, task_id),
        )
        local_task_id = str(delete_row["id"]) if delete_row and delete_row["id"] else task_id
        cloud_task_id = str(delete_row["cloud_id"]) if delete_row and delete_row["cloud_id"] else task_id
        try:
            cloud_request("DELETE", f"/api/v1/tasks/{cloud_task_id}")
        except HTTPException:
            pass  # Cloud task may not exist (local-only) — still clean up locally
        # Clean up local data regardless
        _safe_data_center_ingest(
            "task_delete_lifecycle",
            lambda: mark_ingested_source_inactive(
                state.db,
                source_type="task",
                source_id=local_task_id,
                task_id=local_task_id,
                lifecycle_status="deleted",
            ),
        )
        state.db.execute("DELETE FROM task_attachments_cloud WHERE task_id IN (?, ?)", (local_task_id, cloud_task_id))
        state.db.execute("DELETE FROM tasks WHERE id = ? OR cloud_id = ?", (local_task_id, cloud_task_id))
        state.db.execute("DELETE FROM activity_logs WHERE entity_type = 'task' AND entity_id IN (?, ?)", (local_task_id, cloud_task_id))
        state.db.execute(
            "DELETE FROM event_line_activities WHERE source_type = 'task_activity' AND source_id IN (?, ?)",
            (local_task_id, cloud_task_id),
        )
        state.db.execute("DELETE FROM growth_signal_events WHERE task_id IN (?, ?)", (local_task_id, cloud_task_id))
        state.db.execute("DELETE FROM growth_evidence_records WHERE task_id IN (?, ?)", (local_task_id, cloud_task_id))
        _cloud_task_board_cache["data"] = None  # Invalidate cache
        log_activity("task.delete", "task", local_task_id, {})
        _enqueue_workspace_refresh_safe(
            client_id=refresh_client_id,
            source_type="task_delete",
            source_id=task_id,
            reason="task_deleted",
            scope_type="task",
            scope_id=task_id,
            priority="normal",
        )
        return {"deleted": True}

    @app.post("/api/v1/tasks/{task_id}/attachments", response_model=TaskRecord)
    def upload_task_attachment(
        task_id: str,
        file: UploadFile = File(...),
        clientId: str | None = Form(default=None),
        eventLineId: str | None = Form(default=None),
        taskTitle: str | None = Form(default=None),
    ) -> TaskRecord:
        local_task_row = state.db.fetchone("SELECT * FROM tasks WHERE id = ?", (task_id,))
        is_cloud_task = local_task_row is None
        # Allow offline upload — attachments are stored locally regardless of cloud status

        resolved_client_id = (
            str(local_task_row["client_id"]) if local_task_row and local_task_row["client_id"] else clientId
        )
        # Try to get clientId from event line if task doesn't have one
        if not resolved_client_id:
            el_id = str(local_task_row["event_line_id"]) if local_task_row and local_task_row["event_line_id"] else eventLineId
            if el_id:
                el_row = state.db.fetchone("SELECT primary_client_id FROM event_lines WHERE id = ?", (el_id,))
                if el_row and el_row["primary_client_id"]:
                    resolved_client_id = str(el_row["primary_client_id"])
        # Fall back to organization's default client
        if not resolved_client_id:
            org_client = state.db.fetchone("SELECT id FROM clients ORDER BY name LIMIT 1")
            if org_client:
                resolved_client_id = str(org_client["id"])
        build_client_summary(resolved_client_id)
        ensure_standard_client_folders(resolved_client_id)

        resolved_event_line_id = (
            str(local_task_row["event_line_id"]) if local_task_row and local_task_row["event_line_id"] else eventLineId
        )
        resolved_task_title = (
            str(local_task_row["title"]) if local_task_row and local_task_row["title"] else (taskTitle or file.filename or "任务附件")
        )
        upload_name = safe_filename(file.filename or f"{resolved_task_title}-附件")
        content = file.file.read()
        if not content:
            raise HTTPException(status_code=400, detail="上传失败：附件内容为空。")
        staged_path = stage_task_attachment_upload(resolved_client_id, upload_name, content)
        timestamp = now_iso()
        folder_row = state.db.fetchone(
            "SELECT id FROM client_folders WHERE client_id = ? AND label = ?",
            (resolved_client_id, "项目与业务"),
        )
        document_id = new_id("doc")
        excerpt_seed = ""
        if staged_path.suffix.lower() in {".md", ".txt", ".csv", ".json", ".yaml", ".yml", ".py", ".ts", ".tsx", ".js", ".jsx"}:
            excerpt_seed = content.decode("utf-8", errors="ignore")
        fallback_excerpt = (
            excerpt_seed.strip()[:140] or f"{upload_name} 已作为任务附件进入项目资料库，可用于后续检索、问答与事件线证据引用。"
        ) if excerpt_seed else f"{upload_name} 已作为任务附件进入项目资料库，可用于后续检索、问答与事件线证据引用。"
        state.db.execute(
            """
            INSERT INTO documents(id, client_id, folder_id, title, path, original_source_path, kind, source, excerpt, tags_json, created_at)
            VALUES(?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                document_id,
                resolved_client_id,
                str(folder_row["id"]) if folder_row else None,
                upload_name,
                str(staged_path),
                str(staged_path),
                staged_path.suffix.lower().lstrip(".") or "bin",
                "task_attachment",
                fallback_excerpt,
                to_json(["task_attachment", staged_path.suffix.lower().lstrip(".") or "bin"]),
                timestamp,
            ),
        )
        ingest_document_knowledge(
            state.db,
            data_dir=state.data_dir,
            client_id=resolved_client_id,
            import_id=None,
            document_id=document_id,
            source_path=staged_path,
            original_source_path=staged_path,
            title=upload_name,
            kind=staged_path.suffix.lower().lstrip(".") or "bin",
            source="task_attachment",
            fallback_excerpt=fallback_excerpt,
            created_at=timestamp,
            ai_service=None,
        )
        document_row = state.db.fetchone("SELECT * FROM documents WHERE id = ?", (document_id,))
        if not document_row:
            raise HTTPException(status_code=500, detail="附件归档失败。")
        attachment_id = new_id("tatt")
        table_name = "task_attachments_cloud" if is_cloud_task else "task_attachments"
        state.db.execute(
            f"""
            INSERT INTO {table_name}(id, task_id, client_id, event_line_id, document_id, title, path, kind, source, size_bytes, created_at)
            VALUES(?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                attachment_id,
                task_id,
                resolved_client_id,
                resolved_event_line_id,
                document_id,
                str(document_row["title"]),
                str(document_row["path"]),
                str(document_row["kind"]),
                str(document_row["source"]),
                len(content),
                timestamp,
            ),
        )
        state.db.execute(
            """
            INSERT INTO evidence_refs(id, client_id, meeting_id, document_id, title, excerpt, source_type, path, created_at)
            VALUES(?, ?, NULL, ?, ?, ?, ?, ?, ?)
            """,
            (
                new_id("ev"),
                resolved_client_id,
                document_id,
                str(document_row["title"]),
                str(document_row["excerpt"]),
                "task_attachment",
                str(document_row["path"]),
                timestamp,
            ),
        )
        if not is_cloud_task and resolved_event_line_id:
            state.db.execute(
                """
                INSERT INTO event_line_activities(
                    id, event_line_id, source_type, source_id, happened_at, actor_id, actor_name, title, summary, metadata_json, is_key, created_at
                ) VALUES(?, ?, 'attachment', ?, ?, NULL, ?, ?, ?, ?, 1, ?)
                """,
                (
                    new_id("ela"),
                    resolved_event_line_id,
                    attachment_id,
                    timestamp,
                    current_operator_name(),
                    f"上传附件：{document_row['title']}",
                    f"任务附件已进入项目资料库：{document_row['title']}",
                    to_json(
                        {
                            "taskId": task_id,
                            "documentId": document_id,
                            "clientId": resolved_client_id,
                            "path": str(document_row["path"]),
                        }
                    ),
                    timestamp,
                ),
            )
        log_activity(
            "task.attachment.upload",
            "task",
            task_id,
            {
                "attachmentId": attachment_id,
                "documentId": document_id,
                "clientId": resolved_client_id,
                "eventLineId": resolved_event_line_id,
                "title": str(document_row["title"]),
            },
        )
        _safe_data_center_ingest(
            "task_attachment",
            lambda: ingest_task_attachment_by_id(state.db, state.data_dir, attachment_id),
        )
        if resolved_event_line_id and get_cloud_token():
            import threading

            def _bg_upload():
                try:
                    cloud_upload_file(
                        f"/api/v1/tasks/{task_id}/attachments",
                        file_name=upload_name,
                        file_content=content,
                        content_type=file.content_type or "application/octet-stream",
                        form_fields={
                            "clientId": resolved_client_id or "",
                            "eventLineId": resolved_event_line_id,
                            "title": str(document_row["title"]),
                            "taskTitle": resolved_task_title,
                        },
                    )
                except Exception:
                    pass  # 云端上传失败不阻断本地流程

            threading.Thread(target=_bg_upload, daemon=True).start()

        # Async preprocess: extract text from attachment and write to event line memory
        att_kind = str(document_row["kind"])
        if att_kind in ("docx", "doc", "md", "txt", "pdf") and resolved_event_line_id:
            import threading as _thr

            def _bg_preprocess_attachment():
                try:
                    from app.services.local_memory import write_event_line_memory, read_event_line_memory
                    # Read file text
                    att_path = Path(str(document_row["path"]))
                    text = ""
                    if att_path.exists() and att_kind in ("md", "txt"):
                        text = att_path.read_text(encoding="utf-8", errors="ignore")
                    elif att_path.exists() and att_kind in ("docx", "doc"):
                        try:
                            from docx import Document as _DocxDoc
                            doc = _DocxDoc(str(att_path))
                            text = "\n".join(p.text for p in doc.paragraphs if p.text.strip())
                        except Exception:
                            pass
                    if not text or len(text) < 50:
                        return
                    # Cache text-content locally
                    _att_cache_write(attachment_id, json.dumps({"title": str(document_row["title"]), "text": text, "kind": att_kind}, ensure_ascii=False).encode("utf-8"), suffix=".text.json")
                    # AI summarize if available
                    health = state.ai.get_health()
                    if health.provider != "mock" and health.ready:
                        summary = state.ai._qwen_generate(
                            prompt=f"以下是一份工作文档（{document_row['title']}）的全文，请提炼出：1）核心议题 2）关键决策 3）下一步行动 4）主要风险或卡点。用简洁的要点格式输出。\n\n{text[:8000]}",
                            system_instruction="你是组织工作文档摘要助手。只输出结构化要点，不要输出原文。",
                            response_schema={"type": "object", "properties": {"topics": {"type": "string"}, "decisions": {"type": "string"}, "nextSteps": {"type": "string"}, "risks": {"type": "string"}}, "required": ["topics", "decisions", "nextSteps", "risks"]},
                            timeout_seconds=30.0,
                            max_tokens=800,
                            temperature=0.3,
                            top_p=0.9,
                            enable_thinking=False,
                        )
                        if isinstance(summary, dict):
                            el_row = state.db.fetchone("SELECT name, primary_client_name FROM event_lines WHERE id = ?", (resolved_event_line_id,))
                            el_name = str(el_row["name"]) if el_row else resolved_event_line_id
                            client_name = str(el_row["primary_client_name"]) if el_row else resolved_client_id
                            # Read existing memory and append
                            existing = read_event_line_memory(state.data_dir, resolved_client_id, resolved_event_line_id)
                            new_section = f"\n## 附件摘要：{document_row['title']}\n"
                            if summary.get("topics"):
                                new_section += f"**核心议题：** {summary['topics']}\n"
                            if summary.get("decisions"):
                                new_section += f"**关键决策：** {summary['decisions']}\n"
                            if summary.get("nextSteps"):
                                new_section += f"**下一步：** {summary['nextSteps']}\n"
                            if summary.get("risks"):
                                new_section += f"**风险/卡点：** {summary['risks']}\n"
                            content_to_write = (existing + new_section) if existing else f"## {el_name}\n{new_section}"
                            write_event_line_memory(state.data_dir, resolved_client_id, resolved_event_line_id, el_name, client_name, content_to_write)
                    # Extract golden quotes from attachment text
                    from app.services.local_memory import extract_quotes_from_text, save_pending_quotes
                    quotes = extract_quotes_from_text(state.ai, text, f"附件：{document_row['title']}")
                    if quotes:
                        save_pending_quotes(state.db, quotes)
                except Exception:
                    pass  # 预处理失败不影响主流程

            _thr.Thread(target=_bg_preprocess_attachment, daemon=True).start()

        # Invalidate task board cache
        _cloud_task_board_cache["data"] = None
        # Always rebuild task from local data first (local-first principle)
        if is_cloud_task:
            task_after_upload = fetch_cloud_task_by_id(task_id)
            # Ensure local attachments are included even if cloud hasn't synced yet
            local_atts = fetch_task_attachments(task_id, cloud=True)
            if len(local_atts) > len(task_after_upload.attachments):
                task_after_upload = task_after_upload.model_copy(update={"attachments": local_atts})
        else:
            task_after_upload = fetch_tasks("t.id = ?", (task_id,))[0]
        growth_user_id, growth_user_name = resolve_growth_actor()
        ingest_task_growth_candidate(
            state.db,
            user_id=growth_user_id,
            user_name=growth_user_name,
            task=task_after_upload,
            source_type="task_attachment_candidate",
            created_at=timestamp,
            ai_service=state.ai,
        )
        _enqueue_workspace_refresh_safe(
            client_id=resolved_client_id,
            source_type="task_attachment_upload",
            source_id=attachment_id,
            reason="task_attachment_uploaded",
            scope_type="task",
            scope_id=task_id,
            priority="normal",
        )
        return task_after_upload

    @app.delete("/api/v1/tasks/{task_id}/attachments/{attachment_id}")
    def delete_task_attachment(
        task_id: str,
        attachment_id: str,
        syncKnowledge: bool = Query(default=False),
    ) -> dict[str, object]:
        # 用户在任务详情点附件 × 按钮时调用。
        # syncKnowledge=true 时连带删除知识库（数据中心）里的文件 + 物理文件，
        # 让用户能"一键彻底清理"——不然附件 row 删了，知识库还残留就成了孤儿数据。
        # 弹窗里那个勾默认勾选，所以前端绝大多数请求会带 syncKnowledge=true。
        att_row = state.db.fetchone(
            """
            SELECT id, task_id, client_id, document_id, path, title
            FROM task_attachments
            WHERE id = ? AND task_id = ?
            UNION ALL
            SELECT id, task_id, client_id, document_id, path, title
            FROM task_attachments_cloud
            WHERE id = ? AND task_id = ?
            """,
            (attachment_id, task_id, attachment_id, task_id),
        )
        if not att_row:
            raise HTTPException(status_code=404, detail="附件不存在或已被删除")
        document_id = att_row["document_id"]
        att_path = att_row["path"]
        att_title = att_row["title"]
        # 先删两张可能命中的 attachment 行（cloud + local），保持幂等
        state.db.execute("DELETE FROM task_attachments WHERE id = ?", (attachment_id,))
        state.db.execute("DELETE FROM task_attachments_cloud WHERE id = ?", (attachment_id,))
        knowledge_deleted = False
        file_deleted = False
        if syncKnowledge:
            # 删数据中心：v2_documents 没有声明 FK 到 documents，所以两边都要显式删；
            # v2_chunks/v2_sections/v2_chunk_entities 通过 v2_documents 的 ON DELETE
            # CASCADE 会自动清理，无需手动 DELETE。
            if document_id:
                try:
                    state.db.execute("DELETE FROM v2_documents WHERE document_id = ?", (document_id,))
                    state.db.execute("DELETE FROM documents WHERE id = ?", (document_id,))
                    knowledge_deleted = True
                except Exception:
                    logger.exception("删除知识库文档失败 document_id=%s", document_id)
            # 删物理文件
            if att_path:
                try:
                    p = Path(att_path)
                    if p.exists() and p.is_file():
                        p.unlink()
                        file_deleted = True
                except Exception:
                    logger.exception("删除附件物理文件失败 path=%s", att_path)
        log_activity(
            "task.attachment.delete",
            "task",
            task_id,
            {
                "attachmentId": attachment_id,
                "documentId": document_id,
                "title": att_title,
                "syncKnowledge": syncKnowledge,
                "knowledgeDeleted": knowledge_deleted,
                "fileDeleted": file_deleted,
            },
        )
        return {
            "deleted": True,
            "knowledgeDeleted": knowledge_deleted,
            "fileDeleted": file_deleted,
        }

    @app.post(
        "/api/v1/tasks/{task_id}/attachments/from-markdown",
        response_model=TaskRecord,
    )
    def upload_task_attachment_from_markdown(
        task_id: str,
        payload: TaskAttachmentFromMarkdownPayload = Body(...),
    ) -> TaskRecord:
        # 录音 → 转写 → LLM 摘要返回 markdown 文本。前端不要在浏览器里组装 .docx
        # （需要新加 npm 依赖），而是把 markdown 原文 POST 给后端，由 python-docx
        # 渲染成 .docx 落盘。这样用户在任务详情里双击附件就能直接用 Word/Pages 打开，
        # 而不用面对一份 .md 源码。
        # 附件本身仍然走标准 upload_task_attachment 流程，知识库 ingest、
        # event_line 关联、云端同步、AI 摘要预处理等全套行为一致。
        from io import BytesIO
        from starlette.datastructures import Headers, UploadFile

        from app.services.markdown_to_docx import render_markdown_to_docx_bytes

        if not payload.markdown.strip():
            raise HTTPException(status_code=400, detail="markdown 内容为空")
        safe_title = (payload.title or "会议纪要").strip() or "会议纪要"
        docx_bytes = render_markdown_to_docx_bytes(payload.markdown, document_title=safe_title)
        filename = f"{safe_filename(safe_title)}.docx"
        headers = Headers(
            {"content-type": "application/vnd.openxmlformats-officedocument.wordprocessingml.document"}
        )
        upload_file = UploadFile(filename=filename, file=BytesIO(docx_bytes), headers=headers)
        return upload_task_attachment(
            task_id=task_id,
            file=upload_file,
            clientId=payload.clientId,
            eventLineId=payload.eventLineId,
            taskTitle=payload.taskTitle,
        )

    @app.post("/api/v1/tasks/{task_id}/confirm", response_model=TaskRecord)
    def confirm_task(task_id: str) -> TaskRecord:
        session_user = get_cached_session_user()
        if get_cloud_token():
            try:
                user = require_session_user()
                session_user = user
                response = cloud_request("POST", f"/api/v1/tasks/{task_id}/collaborators/{user.id}/accept")
                if isinstance(response, dict):
                    log_activity("task.confirm", "task", task_id, {"userId": user.id})
                    _upsert_cloud_task_shadow_local(response)
                    return build_cloud_task(response, {})
            except Exception:
                pass  # cloud down — confirm locally
        timestamp = now_iso()
        _mark_task_collaborator_handled(task_id, session_user.id if session_user else None, "accepted")
        state.db.execute(
            """
            UPDATE tasks
            SET status = CASE
                    WHEN status = 'done' OR progress_status = 'done' THEN 'done'
                    WHEN progress_status IN ('todo', 'doing') THEN progress_status
                    ELSE 'doing'
                END,
                progress_status = CASE
                    WHEN progress_status IN ('todo', 'doing', 'done') THEN progress_status
                    ELSE 'doing'
                END,
                updated_at = ?
            WHERE id = ?
            """,
            (timestamp, task_id),
        )
        log_activity("task.confirm", "task", task_id, {"userId": session_user.id if session_user else None})
        return fetch_tasks("t.id = ?", (task_id,))[0]

    @app.post("/api/v1/tasks/{task_id}/reject", response_model=TaskRecord)
    def reject_task(task_id: str, payload: TaskRejectPayload) -> TaskRecord:
        session_user = get_cached_session_user()
        if get_cloud_token():
            try:
                user = require_session_user()
                session_user = user
                response = cloud_request(
                    "POST",
                    f"/api/v1/tasks/{task_id}/collaborators/{user.id}/return",
                    json_body={"reason": payload.reason},
                )
                upsert_task_note(task_id, payload.reason)
                log_activity("task.reject", "task", task_id, {"reason": payload.reason, "userId": user.id})
                if isinstance(response, dict):
                    _upsert_cloud_task_shadow_local(response)
                    return build_cloud_task(response, {})
            except Exception:
                pass  # cloud down — reject locally
        timestamp = now_iso()
        _mark_task_collaborator_handled(task_id, session_user.id if session_user else None, "returned", reason=payload.reason)
        state.db.execute("UPDATE tasks SET status = 'rejected', updated_at = ? WHERE id = ?", (timestamp, task_id))
        upsert_task_note(task_id, payload.reason)
        log_activity("task.reject", "task", task_id, {"reason": payload.reason, "userId": session_user.id if session_user else None})
        return fetch_tasks("t.id = ?", (task_id,))[0]

