    def _cloud_is_available() -> bool:
        """Check if cloud backend is reachable (circuit breaker not active)."""
        import time as _time
        return _time.time() - _cloud_circuit_breaker["last_failure"] >= 60

    def _safe_cloud_request(method: str, path: str, **kwargs) -> object | None:
        """cloud_request wrapper: returns None on any failure instead of raising."""
        if not _cloud_is_available():
            return None
        try:
            return cloud_request(method, path, **kwargs)
        except Exception:
            return None

    @app.get("/api/v1/reviews", response_model=ReviewResponse)
    def list_reviews(
        weekLabel: str | None = Query(default=None),
        skipAi: bool = Query(default=False),
        perspective: Literal["organization", "department", "mine"] | None = Query(default=None),
        departmentId: str | None = Query(default=None),
    ) -> ReviewResponse:
        if get_cloud_token():
            cloud_search = []
            if weekLabel:
                cloud_search.append(f"weekLabel={quote(weekLabel)}")
            # Forward perspective + departmentId so the cloud sources work_items from the right scope
            # (members of the requested department, or whole org). Otherwise dept lead / admin gets
            # only their own items and `augment_review_response` can't expand them locally.
            if perspective:
                cloud_search.append(f"perspective={quote(perspective)}")
            if departmentId:
                cloud_search.append(f"departmentId={quote(departmentId)}")
            suffix = f"?{'&'.join(cloud_search)}" if cloud_search else ""
            payload = _safe_cloud_request("GET", f"/api/v1/reviews/dashboard{suffix}")
            if isinstance(payload, dict):
                try:
                    cloud_response = ReviewResponse(**payload)
                    reconciled_response = reconcile_cloud_review_response_with_local_tasks(cloud_response, weekLabel)
                    return augment_review_response(
                        reconciled_response,
                        weekLabel,
                        generate_weekly_overview=not skipAi,
                        perspective=perspective,
                        department_id=departmentId,
                    )
                except Exception:
                    pass
        target_week = weekLabel or current_review_week_label()
        base_response = local_review_dashboard_base(target_week, include_analysis=False)
        return augment_review_response(
            base_response,
            target_week,
            generate_weekly_overview=not skipAi,
            perspective=perspective,
            department_id=departmentId,
        )

    @app.post("/api/v1/reviews/weekly-overview/refresh", response_model=WeeklyOverviewRefreshStatusRecord)
    def refresh_weekly_overview(
        payload: WeeklyOverviewRefreshPayloadRecord | None = Body(default=None),
    ) -> WeeklyOverviewRefreshStatusRecord:
        request_payload = payload or WeeklyOverviewRefreshPayloadRecord()
        target_week = request_payload.weekLabel or current_review_week_label()
        active_perspective, active_department_id, viewer_user_id, cache_scope = _resolve_weekly_refresh_request(
            target_week,
            request_payload.perspective,
            request_payload.departmentId,
        )
        current_status = _weekly_refresh_status_from_cache(
            week_label=target_week,
            perspective=active_perspective,
            department_id=active_department_id,
            viewer_user_id=viewer_user_id,
            cache_scope=cache_scope,
        )
        if current_status.status == "running":
            return current_status
        running_status = WeeklyOverviewRefreshStatusRecord(
            weekLabel=target_week,
            perspective=active_perspective,
            departmentId=active_department_id,
            viewerUserId=viewer_user_id,
            status="running",
            startedAt=now_iso(),
            cacheKey=cache_scope,
        )
        _save_weekly_refresh_status(running_status)
        Thread(
            target=_run_weekly_overview_refresh,
            kwargs={
                "week_label": target_week,
                "perspective": active_perspective,
                "department_id": active_department_id,
                "viewer_user_id": viewer_user_id,
                "cache_scope": cache_scope,
                "force": bool(request_payload.force),
            },
            daemon=True,
        ).start()
        return running_status

