    # ───────────────────────────────────────────────────────────────────────
    # 报告生成器（report-gen）· R0.5 API skeleton
    # 对应执行计划：docs/报告生成器-Claude-Code执行计划-2026-05-12.md
    # 4 个 endpoint 全部先返回 501 占位，R1/R2/R3 阶段会逐个填充实现：
    #   R1 → draft_blueprint  (LLM A 主理人推导骨架)
    #   R2 → draft_sections   (LLM B 起草员并行填章节 + 信息图)
    #   R3 → render_report    (docx/pdf 渲染)
    #   全程 → get_report_run  (查询进度)
    # ───────────────────────────────────────────────────────────────────────

    @app.post("/api/v1/reports/draft-blueprint", response_model=ReportRunSummary)
    def report_draft_blueprint(payload: DraftBlueprintRequest) -> ReportRunSummary:
        """阶段一：基于事件线 / 客户报告期推导报告骨架（LLM 角色 A · 主理人）。

        入参：event_line_id 或 (client_id, period_start, period_end, intent_hint)
        出参：ReportRunSummary（含 run_id + blueprint，前端拿到后给主理人审阅，
              通过后用 run_id 调下一步 /draft-sections）
        """
        from app.services.report_blueprint_drafter import (
            BlueprintDraftError,
            draft_report_blueprint as _draft_blueprint_via_llm,
        )
        from app.services.report_context_builder import (
            build_report_prompt_context,
        )

        event_line_id = (payload.event_line_id or "").strip() or None
        client_id = (payload.client_id or "").strip() or None
        period_start = (payload.period_start or "").strip()
        period_end = (payload.period_end or "").strip()
        intent_hint = (payload.intent_hint or "").strip()
        audience_hint = (payload.audience_hint or "").strip()
        tone_hint = (payload.tone_hint or "").strip()

        if not client_id and event_line_id:
            el_row = state.db.fetchone(
                "SELECT primary_client_id FROM event_lines WHERE id = ?",
                (event_line_id,),
            )
            if el_row and el_row["primary_client_id"]:
                client_id = str(el_row["primary_client_id"]).strip() or None
            if not client_id:
                task_row = state.db.fetchone(
                    """
                    SELECT client_id FROM tasks
                    WHERE event_line_id = ? AND COALESCE(client_id, '') != ''
                    ORDER BY updated_at DESC LIMIT 1
                    """,
                    (event_line_id,),
                )
                if task_row and task_row["client_id"]:
                    client_id = str(task_row["client_id"]).strip() or None

        if not client_id:
            raise HTTPException(
                status_code=400,
                detail="client_id 未给定，且无法从事件线/任务反查到客户",
            )

        try:
            context = build_report_prompt_context(
                state.db,
                client_id=client_id,
                event_line_id=event_line_id,
                period_start=period_start,
                period_end=period_end,
                intent_hint=intent_hint,
                audience_hint=audience_hint,
                tone_hint=tone_hint,
            )
        except ValueError as ve:
            raise HTTPException(status_code=400, detail=str(ve))

        now_iso = datetime.utcnow().isoformat(timespec="seconds") + "Z"
        run_id = str(uuid4())
        state.db.execute(
            """
            INSERT INTO report_runs (
                id, client_id, event_line_id, period_start, period_end,
                intent_hint, audience_hint, tone_hint, status,
                created_at, updated_at
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, 'blueprint_pending', ?, ?)
            """,
            (
                run_id,
                client_id,
                event_line_id,
                period_start or None,
                period_end or None,
                intent_hint or None,
                audience_hint or None,
                tone_hint or None,
                now_iso,
                now_iso,
            ),
        )

        try:
            blueprint = _draft_blueprint_via_llm(state.ai, context=context)
        except BlueprintDraftError as exc:
            failed_at = datetime.utcnow().isoformat(timespec="seconds") + "Z"
            state.db.execute(
                "UPDATE report_runs SET status='failed', error_message=?, "
                "updated_at=? WHERE id=?",
                (str(exc)[:500], failed_at, run_id),
            )
            raise HTTPException(
                status_code=502,
                detail=f"草拟报告骨架失败：{exc}",
            )

        blueprint_json = blueprint.model_dump_json()
        finished_at = datetime.utcnow().isoformat(timespec="seconds") + "Z"
        state.db.execute(
            "UPDATE report_runs SET blueprint_json=?, status='blueprint_pending', "
            "updated_at=? WHERE id=?",
            (blueprint_json, finished_at, run_id),
        )
        for idx, section in enumerate(blueprint.sections):
            state.db.execute(
                """
                INSERT INTO report_section_runs
                    (id, report_run_id, section_idx, plan_json, status)
                VALUES (?, ?, ?, ?, 'pending')
                """,
                (str(uuid4()), run_id, idx, section.model_dump_json()),
            )

        return get_report_run(run_id)

    @app.post("/api/v1/reports/{report_run_id}/draft-sections", response_model=ReportRunSummary)
    def report_draft_sections(
        report_run_id: str,
        payload: DraftSectionsRequest,
        background_tasks: BackgroundTasks,
    ) -> ReportRunSummary:
        """阶段二：填充章节内容（并行，BackgroundTasks 异步执行）。

        请求立即返回 status='drafting' + 各节 sections_status='drafting'，
        前端 poll GET /reports/{id} 看实时进度（每节完成立即写 DB）。
        幂等：单章节级幂等，重跑指定 section_indices 用最新版替换。
        """
        from app.services.report_context_builder import (
            build_report_prompt_context,
        )
        from app.services.report_section_scheduler import (
            draft_sections_parallel,
        )

        run_row = state.db.fetchone(
            "SELECT * FROM report_runs WHERE id = ?", (report_run_id,)
        )
        if run_row is None:
            raise HTTPException(status_code=404, detail="报告任务不存在")
        if not run_row["blueprint_json"]:
            raise HTTPException(
                status_code=400,
                detail="尚未完成 blueprint，无法起草章节",
            )
        try:
            blueprint = ReportBlueprint.model_validate_json(
                run_row["blueprint_json"]
            )
        except Exception as exc:
            raise HTTPException(
                status_code=500, detail=f"blueprint_json 损坏：{exc}"
            )

        if not blueprint.sections:
            raise HTTPException(
                status_code=400, detail="blueprint 无章节"
            )

        section_indices = payload.section_indices
        if section_indices is None:
            target_indices = list(range(len(blueprint.sections)))
        else:
            target_indices = sorted(
                i for i in section_indices if 0 <= i < len(blueprint.sections)
            )
            if not target_indices:
                raise HTTPException(
                    status_code=400, detail="section_indices 全部越界"
                )

        try:
            context = build_report_prompt_context(
                state.db,
                client_id=str(run_row["client_id"]),
                event_line_id=run_row["event_line_id"],
                period_start=run_row["period_start"] or "",
                period_end=run_row["period_end"] or "",
                intent_hint=run_row["intent_hint"] or "",
                audience_hint=run_row["audience_hint"] or "",
                tone_hint=run_row["tone_hint"] or "",
            )
        except ValueError as ve:
            raise HTTPException(status_code=400, detail=str(ve))

        now_iso = datetime.utcnow().isoformat(timespec="seconds") + "Z"
        state.db.execute(
            "UPDATE report_runs SET status='drafting', error_message=NULL, "
            "updated_at=? WHERE id=?",
            (now_iso, report_run_id),
        )
        for idx in target_indices:
            state.db.execute(
                "UPDATE report_section_runs SET status='drafting', "
                "error_message=NULL, started_at=?, finished_at=NULL, "
                "content_json=NULL WHERE report_run_id=? AND section_idx=?",
                (now_iso, report_run_id, idx),
            )

        def _run_background() -> None:
            def progress_cb(
                idx: int,
                status: str,
                content,
                err,
            ) -> None:
                ts = datetime.utcnow().isoformat(timespec="seconds") + "Z"
                if status == "drafting":
                    return
                if status == "done" and content is not None:
                    state.db.execute(
                        "UPDATE report_section_runs SET status='done', "
                        "content_json=?, finished_at=? "
                        "WHERE report_run_id=? AND section_idx=?",
                        (
                            content.model_dump_json(),
                            ts,
                            report_run_id,
                            idx,
                        ),
                    )
                elif status == "failed":
                    state.db.execute(
                        "UPDATE report_section_runs SET status='failed', "
                        "error_message=?, finished_at=? "
                        "WHERE report_run_id=? AND section_idx=?",
                        (str(err or "")[:500], ts, report_run_id, idx),
                    )

            try:
                draft_sections_parallel(
                    state.ai,
                    blueprint=blueprint,
                    context=context,
                    section_indices=target_indices,
                    max_workers=payload.max_workers,
                    progress_cb=progress_cb,
                )
            except Exception as exc:
                logger.exception(
                    "draft-sections background run failed: %s", exc
                )
                fail_ts = datetime.utcnow().isoformat(timespec="seconds") + "Z"
                state.db.execute(
                    "UPDATE report_runs SET status='failed', error_message=?, "
                    "updated_at=? WHERE id=?",
                    (str(exc)[:500], fail_ts, report_run_id),
                )
                return

            final_rows = state.db.fetchall(
                "SELECT status FROM report_section_runs "
                "WHERE report_run_id=? ORDER BY section_idx",
                (report_run_id,),
            )
            statuses = [str(r["status"]) for r in final_rows]
            distinct = set(statuses)
            final_ts = datetime.utcnow().isoformat(timespec="seconds") + "Z"
            if not distinct or distinct == {"done"}:
                new_status = "drafting"  # 章节都好，等 R3 渲染切到 'rendered'
            elif "failed" in distinct and "done" not in distinct:
                new_status = "failed"
            else:
                new_status = "drafting"
            state.db.execute(
                "UPDATE report_runs SET status=?, updated_at=? WHERE id=?",
                (new_status, final_ts, report_run_id),
            )

        background_tasks.add_task(_run_background)

        return get_report_run(report_run_id)

    @app.post("/api/v1/reports/{report_run_id}/render", response_model=ReportRunSummary)
    def report_render(
        report_run_id: str,
        format: Literal["docx", "pdf", "md"] = Query(default="docx"),
    ) -> ReportRunSummary:
        """阶段三：渲染并落盘 docx / pdf / md。

        format=docx：生成 docx（核心产物）
        format=pdf：先生成 docx，再 LibreOffice headless 转 PDF（机器没装 LO 则 400）
        format=md：归档用 markdown 文件，图表 base64 内嵌（self-contained）
        """
        from app.models import ReportArtifact, SectionContent
        from app.services.report_docx_renderer import (
            DocxRenderError,
            convert_docx_to_pdf_via_libreoffice,
            render_report_artifact_to_docx,
            render_report_artifact_to_markdown,
        )

        run_row = state.db.fetchone(
            "SELECT * FROM report_runs WHERE id = ?", (report_run_id,)
        )
        if run_row is None:
            raise HTTPException(status_code=404, detail="报告任务不存在")
        if not run_row["blueprint_json"]:
            raise HTTPException(
                status_code=400, detail="尚未生成 blueprint，无法渲染"
            )

        section_rows = state.db.fetchall(
            "SELECT section_idx, status, content_json FROM report_section_runs "
            "WHERE report_run_id = ? ORDER BY section_idx",
            (report_run_id,),
        )
        if not section_rows:
            raise HTTPException(
                status_code=400, detail="尚无章节记录，无法渲染"
            )
        section_contents: list[SectionContent] = []
        for r in section_rows:
            if str(r["status"]) != "done" or not r["content_json"]:
                raise HTTPException(
                    status_code=400,
                    detail=(
                        f"章节 #{r['section_idx']} 尚未完成起草"
                        f" (status={r['status']})，无法渲染"
                    ),
                )
            try:
                section_contents.append(
                    SectionContent.model_validate_json(r["content_json"])
                )
            except Exception as exc:
                raise HTTPException(
                    status_code=500,
                    detail=f"章节 #{r['section_idx']} 内容损坏: {exc}",
                )

        try:
            blueprint = ReportBlueprint.model_validate_json(
                run_row["blueprint_json"]
            )
        except Exception as exc:
            raise HTTPException(
                status_code=500, detail=f"blueprint_json 损坏: {exc}"
            )

        client_row = state.db.fetchone(
            "SELECT name FROM clients WHERE id = ?",
            (str(run_row["client_id"]),),
        )
        client_name = (
            str(client_row["name"]) if client_row else None  # type: ignore[index]
        )

        artifact = ReportArtifact(
            blueprint=blueprint,
            sections=section_contents,
            output_files={},
            generated_at=datetime.utcnow().isoformat(timespec="seconds") + "Z",
            total_llm_tokens=int(run_row["total_llm_tokens"] or 0),
        )

        target_dir = (state.data_dir / "reports" / report_run_id).resolve()
        target_dir.mkdir(parents=True, exist_ok=True)
        safe_stem = re.sub(r"[\\/:*?\"<>|\s]+", "_", blueprint.title)[:60] or "report"

        docx_path: Path | None = None
        pdf_path: Path | None = None
        md_path: Path | None = None
        existing_docx = run_row["docx_path"]
        existing_pdf = run_row["pdf_path"]
        existing_md = run_row["md_path"]
        if existing_docx:
            docx_path = Path(existing_docx)
        if existing_pdf:
            pdf_path = Path(existing_pdf)
        if existing_md:
            md_path = Path(existing_md)

        try:
            if format == "docx":
                docx_path = render_report_artifact_to_docx(
                    artifact, target_dir / f"{safe_stem}.docx",
                    client_name=client_name,
                )
            elif format == "md":
                md_path = render_report_artifact_to_markdown(
                    artifact, target_dir / f"{safe_stem}.md",
                    client_name=client_name,
                )
            elif format == "pdf":
                if docx_path is None or not docx_path.exists():
                    docx_path = render_report_artifact_to_docx(
                        artifact, target_dir / f"{safe_stem}.docx",
                        client_name=client_name,
                    )
                pdf_path = convert_docx_to_pdf_via_libreoffice(
                    docx_path, target_dir
                )
                if pdf_path is None:
                    raise HTTPException(
                        status_code=400,
                        detail=(
                            "PDF 转换失败：机器未安装 LibreOffice 或 "
                            "soffice/libreoffice 不在 PATH。docx 已生成可直接下载。"
                        ),
                    )
        except DocxRenderError as exc:
            fail_ts = datetime.utcnow().isoformat(timespec="seconds") + "Z"
            state.db.execute(
                "UPDATE report_runs SET status='failed', error_message=?, "
                "updated_at=? WHERE id=?",
                (str(exc)[:500], fail_ts, report_run_id),
            )
            raise HTTPException(
                status_code=500, detail=f"渲染失败：{exc}"
            )

        now_ts = datetime.utcnow().isoformat(timespec="seconds") + "Z"
        state.db.execute(
            "UPDATE report_runs SET docx_path=?, pdf_path=?, md_path=?, "
            "status='rendered', error_message=NULL, updated_at=? WHERE id=?",
            (
                str(docx_path) if docx_path else None,
                str(pdf_path) if pdf_path else None,
                str(md_path) if md_path else None,
                now_ts,
                report_run_id,
            ),
        )

        return get_report_run(report_run_id)

    @app.get("/api/v1/reports/{report_run_id}/files/{file_format}")
    def report_download_file(report_run_id: str, file_format: str) -> Response:
        """下载已渲染的报告文件（docx / pdf / md）。"""
        from fastapi.responses import FileResponse

        if file_format not in {"docx", "pdf", "md"}:
            raise HTTPException(
                status_code=400, detail="format 必须是 docx/pdf/md"
            )
        row = state.db.fetchone(
            "SELECT docx_path, pdf_path, md_path FROM report_runs WHERE id = ?",
            (report_run_id,),
        )
        if row is None:
            raise HTTPException(status_code=404, detail="报告任务不存在")
        path_str = row[f"{file_format}_path"]
        if not path_str:
            raise HTTPException(
                status_code=404,
                detail=f"该报告尚未生成 {file_format} 文件，请先调 /render",
            )
        path = Path(path_str)
        if not path.exists():
            raise HTTPException(
                status_code=410, detail=f"文件已不在磁盘上：{path}"
            )
        media_type = {
            "docx": (
                "application/vnd.openxmlformats-officedocument."
                "wordprocessingml.document"
            ),
            "pdf": "application/pdf",
            "md": "text/markdown; charset=utf-8",
        }[file_format]
        return FileResponse(
            path=str(path),
            media_type=media_type,
            filename=path.name,
        )

    @app.get("/api/v1/reports/{report_run_id}", response_model=ReportRunSummary)
    def get_report_run(report_run_id: str) -> ReportRunSummary:
        """查询报告生成任务进度（含每章节状态）。"""
        row = state.db.fetchone(
            "SELECT * FROM report_runs WHERE id = ?", (report_run_id,),
        )
        if row is None:
            raise HTTPException(status_code=404, detail="报告任务不存在")
        # R0.5 阶段：只读 metadata；blueprint / sections_status 后续阶段会真填
        blueprint = None
        if row["blueprint_json"]:
            try:
                blueprint = ReportBlueprint.model_validate_json(row["blueprint_json"])
            except Exception:
                blueprint = None
        section_rows = state.db.fetchall(
            "SELECT status FROM report_section_runs WHERE report_run_id = ? ORDER BY section_idx",
            (report_run_id,),
        )
        return ReportRunSummary(
            id=str(row["id"]),
            client_id=str(row["client_id"]),
            event_line_id=row["event_line_id"],
            period_start=row["period_start"],
            period_end=row["period_end"],
            intent_hint=row["intent_hint"],
            status=str(row["status"]),  # type: ignore[arg-type]
            blueprint=blueprint,
            sections_status=[str(r["status"]) for r in section_rows],  # type: ignore[misc]
            output_files={
                k: v for k, v in {
                    "docx": row["docx_path"],
                    "pdf": row["pdf_path"],
                    "md": row["md_path"],
                }.items() if v
            },
            total_llm_tokens=int(row["total_llm_tokens"] or 0),
            created_at=str(row["created_at"]),
            updated_at=str(row["updated_at"]),
        )

